def cmd_interval_table_audit(args):
    """Show RuleSpecs that should be re-encoded with native interval tables."""
    report = build_interval_table_audit(
        args.root,
        include_selector_bounds=args.include_selector_bounds,
    )

    if args.json:
        print(json.dumps(report, indent=2, sort_keys=True))
    else:
        print("Interval table re-encoding audit")
        print(f"Root: {report['root']}")
        print(f"Files scanned: {report['files_scanned']}")
        print(
            f"Issues: {report['issue_count']} "
            f"({report['blocking_issue_count']} blocking)"
        )
        print(f"Kinds: {_format_counter(report['kind_counts'])}")
        print()
        if not report["issues"]:
            print("No interval-table re-encoding candidates found.")
        else:
            limit = max(0, int(args.limit))
            for issue in report["issues"][:limit]:
                literal = f" for `{issue['literal']}`" if issue.get("literal") else ""
                print(
                    f"{issue['repo']}/{issue['path']}: "
                    f"{issue['kind']} in `{issue['rule']}`{literal}"
                )
                print(f"  {issue['message']}")
            remaining = len(report["issues"]) - limit
            if remaining > 0:
                print(f"... {remaining} more issue(s) omitted")

    if args.fail_on_issues and report["blocking_issue_count"]:
        sys.exit(1)


def cmd_oracle_coverage(args):
    """Show oracle coverage classification across rulespec-* repos."""
    if args.oracle != "policyengine":
        print(f"Unsupported oracle: {args.oracle}")
        sys.exit(2)

    root = (args.root or _default_rulespec_inventory_root()).resolve()
    include_program_surfaces = getattr(args, "include_program_surfaces", False) is True
    fail_on_pending_program_surfaces = (
        getattr(args, "fail_on_pending_program_surfaces", False) is True
    )
    fail_on_unvalidated_populace_surfaces = (
        getattr(args, "fail_on_unvalidated_populace_surfaces", False) is True
    )
    fail_on_incomplete_comparable = (
        getattr(args, "fail_on_incomplete_comparable", False) is True
    )
    report = build_policyengine_coverage_report(
        root,
        program=args.program,
        include_program_surfaces=include_program_surfaces,
    )

    unmapped = int(report["status_counts"].get("unmapped", 0))
    untested_comparable = int(report.get("untested_comparable", 0))
    incomplete_comparable = int(report["status_counts"].get("incomplete_comparable", 0))
    pending_program_surfaces = int(
        (report.get("program_surfaces") or {}).get("active_pending_surfaces", 0)
    )
    unvalidated_populace_surfaces = int(
        (report.get("program_surfaces") or {}).get("unvalidated_populace_surfaces", 0)
    )
    should_fail = (
        (args.fail_on_unmapped and unmapped)
        or (args.fail_on_untested_comparable and untested_comparable)
        or (fail_on_incomplete_comparable and incomplete_comparable)
        or (
            fail_on_pending_program_surfaces
            and include_program_surfaces
            and pending_program_surfaces
        )
        or (
            fail_on_unvalidated_populace_surfaces
            and include_program_surfaces
            and unvalidated_populace_surfaces
        )
    )
    if args.json:
        print(json.dumps(report, indent=2, sort_keys=True))
        sys.exit(1 if should_fail else 0)

    print("PolicyEngine oracle coverage")
    print(f"Root: {report['root']}")
    if args.program:
        print(f"Program: {args.program}")
    print(f"Executable outputs: {report['total_outputs']}")
    print(f"Status: {_format_counter(report['status_counts'])}")
    print(f"Untested comparable outputs: {untested_comparable}")
    print(f"Incomplete comparable outputs: {incomplete_comparable}")
    print(f"Programs: {_format_counter(report['program_counts'])}")
    if report.get("program_surfaces"):
        surfaces = report["program_surfaces"]
        print(
            "PolicyEngine program surfaces: "
            f"{surfaces['total_surfaces']} "
            f"status={_format_counter(surfaces['status_counts'])} "
            f"pending={surfaces['pending_surfaces']} "
            f"active_pending={surfaces.get('active_pending_surfaces', 0)} "
            f"unvalidated_populace={surfaces.get('unvalidated_populace_surfaces', 0)}"
        )
        print(
            "PolicyEngine surface priorities: "
            f"{_format_counter(surfaces['priority_counts'])}"
        )
        if surfaces.get("populace_validation_counts"):
            print(
                "PolicyEngine Populace validation: "
                f"{_format_counter(surfaces['populace_validation_counts'])}"
            )
        policybench = surfaces.get("policybench")
        if policybench:
            print(
                "PolicyBench weights: "
                f"{policybench.get('weighting')} "
                f"snapshot={policybench.get('snapshot')}"
            )
        if surfaces.get("lifecycle_counts"):
            print(
                "PolicyEngine surface lifecycles: "
                f"{_format_counter(surfaces['lifecycle_counts'])}"
            )
    print()

    for repo in report["repos"]:
        print(
            f"{repo['repo']}: "
            f"outputs={repo['total_outputs']} "
            f"status={_format_counter(repo['status_counts'])}"
        )

    unmapped_items = [
        item for item in report["items"] if item.get("status") == "unmapped"
    ]
    if unmapped_items:
        print()
        print(f"Unmapped outputs (first {args.limit}):")
        for item in unmapped_items[: args.limit]:
            print(f"  - {item['legal_id']}")
        if len(unmapped_items) > args.limit:
            print(f"  - ... {len(unmapped_items) - args.limit} more")

    untested_items = [
        item
        for item in report["items"]
        if item.get("status") == "comparable" and not item.get("tested")
    ]
    if untested_items:
        print()
        print(f"Untested comparable outputs (first {args.limit}):")
        for item in untested_items[: args.limit]:
            print(f"  - {item['legal_id']}")
        if len(untested_items) > args.limit:
            print(f"  - ... {len(untested_items) - args.limit} more")

    incomplete_items = [
        item
        for item in report["items"]
        if item.get("status") == "incomplete_comparable"
    ]
    if incomplete_items:
        print()
        print(f"Incomplete comparable outputs (first {args.limit}):")
        for item in incomplete_items[: args.limit]:
            print(f"  - {item['legal_id']}")
            for issue in (item.get("upstream_completeness_issues") or [])[:3]:
                print(f"    - {issue}")
        if len(incomplete_items) > args.limit:
            print(f"  - ... {len(incomplete_items) - args.limit} more")

    program_surfaces = report.get("program_surfaces") or {}
    pending_surface_items = [
        item
        for item in program_surfaces.get("actionable_surfaces")
        or program_surfaces.get("items", [])
        if item.get("axiom_status")
        in {
            "deferred_jurisdiction",
            "pending_oracle_mapping",
            "pending_rulespec_encoding",
            "pending_source_ingestion",
        }
        and item.get("lifecycle", "active") == "active"
    ]
    if pending_surface_items:
        print()
        print(f"Active pending PolicyEngine program surfaces (first {args.limit}):")
        for item in pending_surface_items[: args.limit]:
            state = f" [{item['state']}]" if item.get("state") else ""
            weight = item.get("policybench_household_weight")
            weight_prefix = (
                f"{weight:.2f}% " if isinstance(weight, (int, float)) else ""
            )
            print(
                f"  - {weight_prefix}{item['variable']}{state}: "
                f"{item['axiom_status']} ({item['program_id']})"
            )
        if len(pending_surface_items) > args.limit:
            print(f"  - ... {len(pending_surface_items) - args.limit} more")

    unvalidated_populace_items = (report.get("program_surfaces") or {}).get(
        "unvalidated_populace_items"
    ) or []
    if unvalidated_populace_items:
        print()
        print(
            "Active wired PolicyEngine program surfaces without Populace "
            f"validation (first {args.limit}):"
        )
        for item in unvalidated_populace_items[: args.limit]:
            state = f" [{item['state']}]" if item.get("state") else ""
            weight = item.get("policybench_household_weight")
            weight_prefix = (
                f"{weight:.2f}% " if isinstance(weight, (int, float)) else ""
            )
            print(
                f"  - {weight_prefix}{item['variable']}{state}: "
                f"{item.get('populace_validation_status') or 'not_configured'} "
                f"({item['program_id']})"
            )
        if len(unvalidated_populace_items) > args.limit:
            print(f"  - ... {len(unvalidated_populace_items) - args.limit} more")

    sys.exit(1 if should_fail else 0)


