def cmd_repair_colorado_snap_federal_refs(args):
    """Apply signed deterministic repairs for Colorado SNAP federal ref drift."""
    repo_path = Path(args.repo).resolve()
    if _repo_jurisdiction_prefix(repo_path) != "us-co":
        print(
            "repair-colorado-snap-federal-refs must run against rulespec-us-co; "
            f"got {repo_path}"
        )
        sys.exit(1)

    manifest_groups = _colorado_snap_repair_manifest_groups(repo_path)
    for relative_output, _files in manifest_groups:
        rules_file = repo_path / relative_output
        if not rules_file.exists():
            print(f"RuleSpec file not found: {rules_file}")
            sys.exit(1)
    try:
        _ensure_no_unmanifested_preexisting_rulespec_changes(
            repo_path,
            manifest_groups,
        )
    except RuntimeError as exc:
        print(str(exc))
        sys.exit(1)

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()

    tracked_files = _unique_paths(
        [path for _relative_output, files in manifest_groups for path in files]
    )
    preexisting_changed_files = _changed_manifest_group_files(
        repo_path,
        manifest_groups,
    )
    originals = {
        path: path.read_text() if path.exists() else None for path in tracked_files
    }

    try:
        _repair_colorado_snap_policy_composition(
            repo_path / COLORADO_SNAP_PROGRAM_RELATIVE
        )
        _repair_colorado_snap_2051(repo_path / COLORADO_SNAP_CCR_ROOT / "4.205.1.yaml")
        _repair_colorado_snap_2072(repo_path / COLORADO_SNAP_CCR_ROOT / "4.207.2.yaml")
        _repair_colorado_snap_401(repo_path / COLORADO_SNAP_CCR_ROOT / "4.401.yaml")
        _repair_colorado_snap_4073(repo_path / COLORADO_SNAP_CCR_ROOT / "4.407.3.yaml")
        _repair_colorado_snap_8013(repo_path / COLORADO_SNAP_CCR_ROOT / "4.801.3.yaml")
        _repair_colorado_snap_program_tests(
            _rulespec_test_path(repo_path / COLORADO_SNAP_PROGRAM_RELATIVE)
        )
        _repair_colorado_snap_2072_tests(
            _rulespec_test_path(repo_path / COLORADO_SNAP_CCR_ROOT / "4.207.2.yaml")
        )
        _repair_colorado_snap_2073_tests(
            _rulespec_test_path(repo_path / COLORADO_SNAP_CCR_ROOT / "4.207.3.yaml")
        )
        _repair_colorado_snap_401_tests(
            _rulespec_test_path(repo_path / COLORADO_SNAP_CCR_ROOT / "4.401.yaml")
        )
        _repair_colorado_snap_4073_tests(
            _rulespec_test_path(repo_path / COLORADO_SNAP_CCR_ROOT / "4.407.3.yaml")
        )

        changed_by_command = _unique_paths(
            [
                path
                for path in tracked_files
                if _path_differs_from_original(path, originals.get(path))
            ]
        )
        changed_files = _unique_paths(preexisting_changed_files + changed_by_command)
        if not changed_files:
            print("No Colorado SNAP federal reference repairs found.")
            return
    except Exception:
        _restore_original_files(originals)
        raise

    manifest_paths = _write_colorado_snap_repair_manifests(
        repo_path=repo_path,
        signing_key=signing_key,
        axiom_encode_git=axiom_encode_git,
        manifest_groups=manifest_groups,
        changed_files=changed_files,
    )

    print("Applied Colorado SNAP federal reference repair")
    for path in changed_files:
        print(f"changed={path.relative_to(repo_path)}")
    for manifest_path in manifest_paths:
        print(f"manifest={manifest_path}")


def _colorado_snap_repair_manifest_groups(
    repo_path: Path,
) -> list[tuple[Path, list[Path]]]:
    groups: list[tuple[Path, list[Path]]] = []
    for relative_output in COLORADO_SNAP_REPAIR_RELATIVE_OUTPUTS:
        rules_file = repo_path / relative_output
        test_file = _rulespec_test_path(rules_file)
        files = [rules_file]
        if test_file.exists():
            files.append(test_file)
        groups.append((relative_output, files))
    return groups


def _changed_manifest_group_files(
    repo_path: Path,
    manifest_groups: list[tuple[Path, list[Path]]],
) -> list[Path]:
    changed = set(_git_changed_files(repo_path, base_ref=None, head_ref="HEAD"))
    for base_ref in ("origin/main", "main"):
        try:
            changed.update(
                _git_changed_files(repo_path, base_ref=base_ref, head_ref="HEAD")
            )
            break
        except RuntimeError:
            continue
    repo_prefix = _git_worktree_prefix(repo_path)
    return _unique_paths(
        [
            path
            for _relative_output, files in manifest_groups
            for path in files
            if _manifest_group_file_changed(
                path=path,
                repo_path=repo_path,
                repo_prefix=repo_prefix,
                changed=changed,
            )
        ]
    )


def _git_worktree_prefix(repo_path: Path) -> str:
    completed = subprocess.run(
        ["git", "rev-parse", "--show-prefix"],
        cwd=repo_path,
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        check=False,
    )
    if completed.returncode != 0:
        return ""
    return completed.stdout.strip().strip("/")


def _manifest_group_file_changed(
    *,
    path: Path,
    repo_path: Path,
    repo_prefix: str,
    changed: set[str],
) -> bool:
    relative_path = path.relative_to(repo_path).as_posix()
    if relative_path in changed:
        return True
    if repo_prefix and f"{repo_prefix}/{relative_path}" in changed:
        return True
    return False


def _write_colorado_snap_repair_manifests(
    *,
    repo_path: Path,
    signing_key: str,
    axiom_encode_git: dict[str, object],
    manifest_groups: list[tuple[Path, list[Path]]],
    changed_files: list[Path],
) -> list[Path]:
    changed = {path.resolve() for path in changed_files}
    manifest_paths: list[Path] = []
    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        for relative_output, files in manifest_groups:
            applied_files = [path for path in files if path.resolve() in changed]
            if not applied_files:
                continue
            generated_output = output_root / "deterministic-repair" / relative_output
            generated_output.parent.mkdir(parents=True, exist_ok=True)
            generated_output.write_text((repo_path / relative_output).read_text())
            result = argparse.Namespace(
                output_file=str(generated_output),
                runner="deterministic-repair",
                backend="deterministic",
                model=COLORADO_SNAP_FEDERAL_REF_REPAIR_MODEL,
                tool="axiom-encode repair-colorado-snap-federal-refs",
                citation=(
                    f"{_repo_jurisdiction_prefix(repo_path)}:"
                    f"{_relative_rulespec_import_target(relative_output)}"
                ),
                generation_prompt_sha256=None,
                trace_file=None,
                context_manifest_file=None,
            )
            manifest_paths.append(
                _write_applied_encoding_manifest(
                    result,
                    output_root=output_root,
                    policy_repo_path=repo_path,
                    relative_output=relative_output,
                    applied_files=applied_files,
                    run_id="deterministic-repair",
                    signing_key=signing_key,
                    axiom_encode_git=axiom_encode_git,
                )
            )
    return manifest_paths


def cmd_repair_california_snap_shelter_surface(args):
    """Apply signed deterministic repairs for California SNAP composition drift."""
    repo_path = Path(args.repo).resolve()
    if _repo_jurisdiction_prefix(repo_path) != "us-ca":
        print(
            "repair-california-snap-shelter-surface must run against "
            f"rulespec-us-ca; got {repo_path}"
        )
        sys.exit(1)

    manifest_groups = _california_snap_repair_manifest_groups(repo_path)
    guard_manifest_groups = _california_snap_repair_guard_manifest_groups(repo_path)
    for relative_output, _files in manifest_groups:
        rules_file = repo_path / relative_output
        old_sua = repo_path / CALIFORNIA_SNAP_OLD_SUA_RELATIVE
        if not rules_file.exists() and not (
            relative_output == CALIFORNIA_SNAP_SUA_RELATIVE and old_sua.exists()
        ):
            print(f"RuleSpec file not found: {rules_file}")
            sys.exit(1)
    try:
        _ensure_no_california_snap_sua_layout_collision(repo_path)
        _ensure_no_unmanifested_preexisting_rulespec_changes(
            repo_path,
            guard_manifest_groups,
            roots=tuple(sorted(RULESPEC_SOURCE_ROOTS | {"guidance"})),
        )
    except RuntimeError as exc:
        print(str(exc))
        sys.exit(1)

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()

    tracked_files = _unique_paths(
        [path for _relative_output, files in manifest_groups for path in files]
    )
    migration_files = [
        repo_path / CALIFORNIA_SNAP_OLD_SUA_RELATIVE,
        _rulespec_test_path(repo_path / CALIFORNIA_SNAP_OLD_SUA_RELATIVE),
        repo_path / _applied_encoding_manifest_path(CALIFORNIA_SNAP_OLD_SUA_RELATIVE),
    ]
    preexisting_changed_files = _changed_manifest_group_files(
        repo_path,
        guard_manifest_groups,
    )
    originals = {
        path: path.read_text() if path.exists() else None
        for path in _unique_paths(tracked_files + migration_files)
    }

    try:
        _migrate_california_snap_sua_layout(repo_path)
        _repair_california_snap_policy_composition(
            repo_path / CALIFORNIA_SNAP_PROGRAM_RELATIVE
        )
        _repair_california_snap_program_tests(
            _rulespec_test_path(repo_path / CALIFORNIA_SNAP_PROGRAM_RELATIVE)
        )

        changed_by_command = _unique_paths(
            [
                path
                for path in tracked_files
                if _path_differs_from_original(path, originals.get(path))
            ]
        )
        changed_files = _unique_paths(preexisting_changed_files + changed_by_command)
        if not changed_files:
            print("No California SNAP shelter surface repairs found.")
            return
    except Exception:
        _restore_original_files(originals)
        raise

    manifest_paths = _write_california_snap_repair_manifests(
        repo_path=repo_path,
        signing_key=signing_key,
        axiom_encode_git=axiom_encode_git,
        manifest_groups=manifest_groups,
        changed_files=changed_files,
    )

    print("Applied California SNAP shelter surface repair")
    for path in changed_files:
        print(f"changed={path.relative_to(repo_path)}")
    for manifest_path in manifest_paths:
        print(f"manifest={manifest_path}")


def _california_snap_repair_manifest_groups(
    repo_path: Path,
) -> list[tuple[Path, list[Path]]]:
    groups: list[tuple[Path, list[Path]]] = []
    for relative_output in CALIFORNIA_SNAP_REPAIR_RELATIVE_OUTPUTS:
        rules_file = repo_path / relative_output
        test_file = _rulespec_test_path(rules_file)
        files = [rules_file]
        if test_file.exists() or relative_output == CALIFORNIA_SNAP_SUA_RELATIVE:
            files.append(test_file)
        groups.append((relative_output, files))
    return groups


def _california_snap_repair_guard_manifest_groups(
    repo_path: Path,
) -> list[tuple[Path, list[Path]]]:
    old_rules_file = repo_path / CALIFORNIA_SNAP_OLD_SUA_RELATIVE
    old_test_file = _rulespec_test_path(old_rules_file)
    return _california_snap_repair_manifest_groups(repo_path) + [
        (CALIFORNIA_SNAP_OLD_SUA_RELATIVE, [old_rules_file, old_test_file])
    ]


def _ensure_no_california_snap_sua_layout_collision(repo_path: Path) -> None:
    collisions = [
        (
            repo_path / CALIFORNIA_SNAP_OLD_SUA_RELATIVE,
            repo_path / CALIFORNIA_SNAP_SUA_RELATIVE,
        ),
        (
            _rulespec_test_path(repo_path / CALIFORNIA_SNAP_OLD_SUA_RELATIVE),
            _rulespec_test_path(repo_path / CALIFORNIA_SNAP_SUA_RELATIVE),
        ),
    ]
    for old_file, new_file in collisions:
        if old_file.exists() and new_file.exists():
            raise RuntimeError(
                "Refusing to migrate California SNAP standard utility allowance "
                "while both old and new RuleSpec paths exist: "
                f"{old_file.relative_to(repo_path)} and {new_file.relative_to(repo_path)}"
            )


def _write_california_snap_repair_manifests(
    *,
    repo_path: Path,
    signing_key: str,
    axiom_encode_git: dict[str, object],
    manifest_groups: list[tuple[Path, list[Path]]],
    changed_files: list[Path],
) -> list[Path]:
    changed = {path.resolve() for path in changed_files}
    manifest_paths: list[Path] = []
    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        for relative_output, files in manifest_groups:
            applied_files = [path for path in files if path.resolve() in changed]
            if not applied_files:
                continue
            generated_output = output_root / "deterministic-repair" / relative_output
            generated_output.parent.mkdir(parents=True, exist_ok=True)
            generated_output.write_text((repo_path / relative_output).read_text())
            result = argparse.Namespace(
                output_file=str(generated_output),
                runner="deterministic-repair",
                backend="deterministic",
                model=CALIFORNIA_SNAP_SHELTER_SURFACE_REPAIR_MODEL,
                tool="axiom-encode repair-california-snap-shelter-surface",
                citation=(
                    f"{_repo_jurisdiction_prefix(repo_path)}:"
                    f"{_relative_rulespec_import_target(relative_output)}"
                ),
                generation_prompt_sha256=None,
                trace_file=None,
                context_manifest_file=None,
            )
            manifest_paths.append(
                _write_applied_encoding_manifest(
                    result,
                    output_root=output_root,
                    policy_repo_path=repo_path,
                    relative_output=relative_output,
                    applied_files=applied_files,
                    run_id="deterministic-repair",
                    signing_key=signing_key,
                    axiom_encode_git=axiom_encode_git,
                )
            )
    return manifest_paths


def cmd_repair_arizona_snap_composition(args):
    """Install the Arizona SNAP composition module with signed provenance."""
    repo_path = Path(args.repo).resolve()
    if _repo_jurisdiction_prefix(repo_path) != "us-az":
        print(
            "repair-arizona-snap-composition must run against rulespec-us-az; "
            f"got {repo_path}"
        )
        sys.exit(1)

    benefit_file = repo_path / ARIZONA_SNAP_BENEFIT_RELATIVE
    if not benefit_file.exists():
        print(f"Arizona SNAP benefit-amount RuleSpec file not found: {benefit_file}")
        sys.exit(1)

    rules_file = repo_path / ARIZONA_SNAP_PROGRAM_RELATIVE
    test_file = _rulespec_test_path(rules_file)
    manifest_groups = [(ARIZONA_SNAP_PROGRAM_RELATIVE, [rules_file, test_file])]
    try:
        _ensure_no_unmanifested_preexisting_rulespec_changes(repo_path, manifest_groups)
    except RuntimeError as exc:
        print(str(exc))
        sys.exit(1)

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    originals = {
        rules_file: rules_file.read_text() if rules_file.exists() else None,
        test_file: test_file.read_text() if test_file.exists() else None,
    }
    try:
        changed = _write_arizona_snap_composition_files(rules_file, test_file)
        refresh_manifest = False
        if not changed:
            if not _applied_manifest_matches_current_deterministic_repair(
                repo_path=repo_path,
                relative_output=ARIZONA_SNAP_PROGRAM_RELATIVE,
                applied_files=[rules_file, test_file],
                model=ARIZONA_SNAP_COMPOSITION_MODEL,
                axiom_encode_git=axiom_encode_git,
                signing_key=signing_key,
            ):
                refresh_manifest = True
            else:
                print("No Arizona SNAP composition repairs found.")
                return

        validation = ValidatorPipeline(
            policy_repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
            enable_oracles=False,
            require_policy_proofs=False,
        ).validate(rules_file, skip_reviewers=True)
        if not validation.all_passed:
            issues = [
                result.error for result in validation.results.values() if result.error
            ]
            raise RuntimeError("\n".join(issues) or "validation failed")

        test_issues = _companion_test_issues(
            test_files=[test_file],
            repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
        )
        if test_issues:
            raise RuntimeError(
                "Companion tests failed after Arizona SNAP composition install:\n"
                + "\n".join(f"- {issue}" for issue in test_issues)
            )
    except Exception:
        _restore_original_files(originals)
        raise

    changed_by_command = _unique_paths(
        [
            path
            for path in changed
            if _path_differs_from_original(path, originals.get(path))
        ]
    )
    refresh_only = not changed_by_command and refresh_manifest
    if refresh_only:
        changed_by_command = [rules_file, test_file]
    if not changed_by_command:
        print("No Arizona SNAP composition repairs found.")
        return

    manifest_paths = _write_grouped_deterministic_repair_manifests(
        repo_path=repo_path,
        signing_key=signing_key,
        axiom_encode_git=axiom_encode_git,
        manifest_groups=manifest_groups,
        changed_files=changed_by_command,
        model=ARIZONA_SNAP_COMPOSITION_MODEL,
        tool="axiom-encode repair-arizona-snap-composition",
    )

    if refresh_only:
        print("Refreshed Arizona SNAP composition repair manifest")
    else:
        print("Applied Arizona SNAP composition repair")
        for path in changed_by_command:
            print(f"changed={path.relative_to(repo_path)}")
    for manifest_path in manifest_paths:
        print(f"manifest={manifest_path}")


def cmd_repair_minnesota_mfip_upstream_source_check(args):
    """Apply a signed deterministic upstream-source audit for Minnesota MFIP."""
    repo_path = Path(args.repo).resolve()
    if _repo_jurisdiction_prefix(repo_path) != "us":
        print(
            "repair-minnesota-mfip-upstream-source-check must run against "
            f"rulespec-us; got {repo_path}"
        )
        sys.exit(1)

    relative_output = MINNESOTA_MFIP_RELATIVE_OUTPUT
    rules_file = repo_path / relative_output
    test_file = _rulespec_test_path(rules_file)
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)

    manifest_groups = [(relative_output, [rules_file, test_file])]
    try:
        _ensure_no_unmanifested_preexisting_rulespec_changes(
            repo_path,
            manifest_groups,
        )
    except RuntimeError as exc:
        print(str(exc))
        sys.exit(1)

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    originals = {
        path: path.read_text() if path.exists() else None
        for path in (rules_file, test_file)
    }
    try:
        changed = _repair_minnesota_mfip_upstream_source_check_file(rules_file)
        refresh_manifest = False
        if not changed:
            if not _applied_manifest_matches_current_deterministic_repair(
                repo_path=repo_path,
                relative_output=relative_output,
                applied_files=[
                    path for path in (rules_file, test_file) if path.exists()
                ],
                model=MINNESOTA_MFIP_UPSTREAM_SOURCE_CHECK_MODEL,
                axiom_encode_git=axiom_encode_git,
                signing_key=signing_key,
            ):
                refresh_manifest = True
            else:
                print("No Minnesota MFIP upstream-source repairs found.")
                return

        validation = ValidatorPipeline(
            policy_repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
            enable_oracles=False,
            require_policy_proofs=False,
        ).validate(rules_file, skip_reviewers=True)
        if not validation.all_passed:
            issues = [
                result.error for result in validation.results.values() if result.error
            ]
            raise RuntimeError("\n".join(issues) or "validation failed")

        if test_file.exists():
            test_issues = _companion_test_issues(
                test_files=[test_file],
                repo_path=repo_path,
                axiom_rules_path=axiom_rules_path,
            )
            if test_issues:
                raise RuntimeError(
                    "Companion tests failed after Minnesota MFIP upstream-source "
                    "repair:\n" + "\n".join(f"- {issue}" for issue in test_issues)
                )
    except Exception:
        _restore_original_files(originals)
        raise

    changed_by_command = _unique_paths(
        [
            path
            for path in (rules_file, test_file)
            if _path_differs_from_original(path, originals.get(path))
        ]
    )
    refresh_only = not changed_by_command and refresh_manifest
    if refresh_only:
        changed_by_command = [path for path in (rules_file, test_file) if path.exists()]
    if not changed_by_command:
        print("No Minnesota MFIP upstream-source repairs found.")
        return

    manifest_paths = _write_grouped_deterministic_repair_manifests(
        repo_path=repo_path,
        signing_key=signing_key,
        axiom_encode_git=axiom_encode_git,
        manifest_groups=manifest_groups,
        changed_files=changed_by_command,
        model=MINNESOTA_MFIP_UPSTREAM_SOURCE_CHECK_MODEL,
        tool="axiom-encode repair-minnesota-mfip-upstream-source-check",
    )

    if refresh_only:
        print("Refreshed Minnesota MFIP upstream-source repair manifest")
    else:
        print("Applied Minnesota MFIP upstream-source repair")
        for path in changed_by_command:
            print(f"changed={path.relative_to(repo_path)}")
    for manifest_path in manifest_paths:
        print(f"manifest={manifest_path}")


def _repair_minnesota_mfip_upstream_source_check_file(rules_file: Path) -> bool:
    content = rules_file.read_text()
    if MINNESOTA_MFIP_UPSTREAM_SOURCE_CHECK_BLOCK in content:
        return False
    if "\n    upstream_source_check:\n" in f"\n{content}":
        raise RuntimeError(
            "Minnesota MFIP RuleSpec already has a different upstream_source_check"
        )

    source_line = f"    corpus_citation_path: {MINNESOTA_MFIP_MANUAL_SOURCE}\n"
    marker = "  source_verification:\n" + source_line
    if marker not in content:
        raise RuntimeError(
            "Minnesota MFIP RuleSpec does not have the expected manual "
            f"source_verification path: {MINNESOTA_MFIP_MANUAL_SOURCE}"
        )

    rules_file.write_text(
        content.replace(
            marker,
            marker + MINNESOTA_MFIP_UPSTREAM_SOURCE_CHECK_BLOCK,
            1,
        )
    )
    return True


def _applied_manifest_matches_current_deterministic_repair(
    *,
    repo_path: Path,
    relative_output: Path,
    applied_files: list[Path],
    model: str,
    axiom_encode_git: dict[str, object],
    signing_key: str,
) -> bool:
    content_root = _rulespec_apply_content_root(repo_path, relative_output)
    manifest_path = content_root / _applied_encoding_manifest_path(relative_output)
    if not manifest_path.exists():
        return False
    try:
        payload = json.loads(manifest_path.read_text())
    except (json.JSONDecodeError, OSError):
        return False
    if payload.get("schema_version") != APPLIED_ENCODING_MANIFEST_SCHEMA:
        return False
    if payload.get("model") != model:
        return False
    if payload.get("axiom_encode_version") != __version__:
        return False
    signature_issue = _applied_encoding_manifest_signature_issue(payload, signing_key)
    if signature_issue:
        return False

    payload_git = payload.get("axiom_encode_git")
    if not isinstance(payload_git, dict):
        return False
    for key in ("commit", "dirty_tracked", "version", "version_commit"):
        if key in axiom_encode_git and payload_git.get(key) != axiom_encode_git.get(
            key
        ):
            return False

    expected_hashes = {
        path.relative_to(content_root).as_posix(): _sha256_file(path)
        for path in applied_files
        if path.exists()
    }
    applied_entries = payload.get("applied_files")
    if not isinstance(applied_entries, list):
        return False
    actual_hashes = {
        str(entry.get("path")): str(entry.get("sha256"))
        for entry in applied_entries
        if isinstance(entry, dict)
        and isinstance(entry.get("path"), str)
        and isinstance(entry.get("sha256"), str)
    }
    return actual_hashes == expected_hashes


def _write_arizona_snap_composition_files(
    rules_file: Path,
    test_file: Path,
) -> list[Path]:
    rules_file.parent.mkdir(parents=True, exist_ok=True)
    changed: list[Path] = []
    rules_content = _arizona_snap_composition_rulespec()
    test_content = _arizona_snap_composition_tests()
    if not rules_file.exists() or rules_file.read_text() != rules_content:
        rules_file.write_text(rules_content)
        changed.append(rules_file)
    if not test_file.exists() or test_file.read_text() != test_content:
        test_file.write_text(test_content)
        changed.append(test_file)
    return changed


def _arizona_snap_composition_rulespec() -> str:
    return """format: rulespec/v1
module:
  kind: composition
  source_verification:
    corpus_citation_path: us-az/manual/des/faa5/na-eligibility-and-benefit-determination/block-9
  summary: |-
    Arizona Nutrition Assistance FY 2026 benefit calculation composition. This
    module exposes the final regular-month SNAP/NA allotment surface for oracle
    comparison by composing the encoded Arizona benefit-amount rule and boundary
    bridge outputs for gross income, net income, eligibility, maximum allotment,
    minimum allotment, and shelter deduction values. Those upstream bridge
    values remain inputs until the full Arizona NA eligibility chain is encoded.
imports:
  - us-az:policies/des/faa5/na-eligibility-and-benefit-determination/benefit-amount
rules:
  - name: snap_gross_monthly_income
    kind: derived
    entity: Household
    dtype: Money
    period: Month
    unit: USD
    source: Arizona Nutrition Assistance FY 2026 benefit calculation composition
    versions:
      - effective_from: '2025-10-01'
        formula: |-
          max(0, snap_gross_monthly_earned_income + snap_total_monthly_unearned_income)

  - name: snap_net_income
    kind: derived
    entity: Household
    dtype: Money
    period: Month
    unit: USD
    source: Arizona Nutrition Assistance FY 2026 benefit calculation composition
    versions:
      - effective_from: '2025-10-01'
        formula: |-
          max(0, na_net_income)

  - name: snap_eligible
    kind: derived
    entity: Household
    dtype: Judgment
    period: Month
    source: Arizona Nutrition Assistance FY 2026 benefit calculation composition
    versions:
      - effective_from: '2025-10-01'
        formula: |-
          na_budgetary_unit_is_eligible

  - name: snap_maximum_allotment
    kind: derived
    entity: Household
    dtype: Money
    period: Month
    unit: USD
    source: Arizona Nutrition Assistance FY 2026 benefit calculation composition
    versions:
      - effective_from: '2025-10-01'
        formula: |-
          max(0, thrifty_food_plan_amount_for_budgetary_unit_size)

  - name: snap_excess_shelter_deduction
    kind: derived
    entity: Household
    dtype: Money
    period: Month
    unit: USD
    source: Arizona Nutrition Assistance FY 2026 benefit calculation composition
    versions:
      - effective_from: '2025-10-01'
        formula: |-
          max(0, snap_excess_shelter_deduction_for_net_income)

  - name: snap_regular_month_allotment
    kind: derived
    entity: Household
    dtype: Money
    period: Month
    unit: USD
    source: FAA5 NA Eligibility and Benefit Determination, block 9
    versions:
      - effective_from: '2025-10-01'
        formula: |-
          benefit_amount_after_allotment_test
"""


