def _derived_money_bridge_rule(
    name: str,
    formula: str,
    *,
    source: str = "Colorado SNAP federal surface bridge",
) -> dict[str, object]:
    return _bridge_rule(
        name=name,
        kind="derived",
        dtype="Money",
        formula=formula,
        source=source,
        entity="Household",
        period="Month",
        unit="USD",
    )


def _derived_judgment_bridge_rule(
    name: str,
    formula: str,
    *,
    source: str = "Colorado SNAP federal surface bridge",
) -> dict[str, object]:
    return _bridge_rule(
        name=name,
        kind="derived",
        dtype="Judgment",
        formula=formula,
        source=source,
        entity="Household",
        period="Month",
    )


def _parameter_bridge_rule(name: str, dtype: str, formula: str) -> dict[str, object]:
    return _bridge_rule(
        name=name,
        kind="parameter",
        dtype=dtype,
        formula=formula,
        source="Colorado SNAP federal surface bridge",
    )


def _parameter_judgment_bridge_rule(name: str, formula: str) -> dict[str, object]:
    return _bridge_rule(
        name=name,
        kind="parameter",
        dtype="Judgment",
        formula=formula,
        source="Colorado SNAP federal surface bridge",
        entity="Household",
        period="Month",
    )


def _bridge_rule(
    *,
    name: str,
    kind: str,
    dtype: str,
    formula: str,
    source: str,
    entity: str | None = None,
    period: str | None = None,
    unit: str | None = None,
) -> dict[str, object]:
    rule: dict[str, object] = {
        "name": name,
        "kind": kind,
        "dtype": dtype,
    }
    if entity is not None:
        rule["entity"] = entity
    if period is not None:
        rule["period"] = period
    if unit is not None:
        rule["unit"] = unit
    rule["source"] = source
    rule["versions"] = [{"effective_from": "2025-10-01", "formula": formula}]
    return rule


def _append_rule_if_missing(
    payload: dict[str, object],
    rule: dict[str, object],
    *,
    before_rule: str | None = None,
) -> None:
    rules = payload.setdefault("rules", [])
    if not isinstance(rules, list):
        raise RuntimeError("RuleSpec payload has non-list rules field")
    name = str(rule.get("name") or "")
    if any(
        isinstance(existing, dict) and existing.get("name") == name
        for existing in rules
    ):
        return
    if before_rule:
        for index, existing in enumerate(rules):
            if isinstance(existing, dict) and existing.get("name") == before_rule:
                rules.insert(index, rule)
                return
    rules.append(rule)


def _ensure_yaml_import_text(
    content: str,
    import_target: str,
    *,
    before_import: str | None = None,
) -> str:
    import_indent = _yaml_sequence_item_indent(content, "imports")
    content = _remove_misindented_yaml_sequence_item_text(
        content,
        section="imports",
        item=import_target,
        item_indent=import_indent,
    )
    import_line = f"{import_indent}- {import_target}\n"
    if re.search(
        rf"(?m)^{re.escape(import_indent)}-\s+{re.escape(import_target)}$",
        content,
    ):
        return content
    if before_import is not None:
        before_match = re.search(
            rf"(?m)^{re.escape(import_indent)}-\s+{re.escape(before_import)}$",
            content,
        )
        if before_match is not None:
            line_start = before_match.start()
            return f"{content[:line_start]}{import_line}{content[line_start:]}"
    rules_marker = "rules:\n"
    if rules_marker not in content:
        raise RuntimeError("RuleSpec payload missing rules section")
    if re.search(r"(?m)^imports:\s*$", content):
        return content.replace(rules_marker, import_line + rules_marker, 1)
    return content.replace(rules_marker, f"imports:\n{import_line}{rules_marker}", 1)


def _append_rules_text_if_missing(
    content: str,
    rules: list[dict[str, object]],
) -> str:
    for rule in rules:
        content = _insert_rule_text_if_missing(content, rule)
    return content


def _upsert_rules_text(
    content: str,
    rules: list[dict[str, object]],
) -> str:
    for rule in rules:
        content = _upsert_rule_text(content, rule)
    return content


def _upsert_rule_text(
    content: str,
    rule: dict[str, object],
    *,
    before_rule: str | None = None,
) -> str:
    name = str(rule.get("name") or "")
    rule_indent = _yaml_sequence_item_indent(content, "rules")
    marker = f"{rule_indent}- name: {name}\n"
    start = content.find(marker)
    if start == -1:
        return _insert_rule_text_if_missing(content, rule, before_rule=before_rule)
    next_start = content.find(f"\n{rule_indent}- name: ", start + len(marker))
    end = len(content) if next_start == -1 else next_start + 1
    return (
        f"{content[:start]}"
        f"{_render_generated_rule_yaml(rule, item_indent=rule_indent)}"
        f"{content[end:]}"
    )


def _insert_rule_text_if_missing(
    content: str,
    rule: dict[str, object],
    *,
    before_rule: str | None = None,
) -> str:
    name = str(rule.get("name") or "")
    rule_indent = _yaml_sequence_item_indent(content, "rules")
    if re.search(rf"(?m)^\s*-\s+name:\s+{re.escape(name)}$", content):
        return content
    rendered = _render_generated_rule_yaml(rule, item_indent=rule_indent)
    if before_rule is not None:
        marker = re.search(
            rf"(?m)^{re.escape(rule_indent)}-\s+name:\s+{re.escape(before_rule)}$",
            content,
        )
        if marker is not None:
            return f"{content[: marker.start()]}{rendered}{content[marker.start() :]}"
    if not content.endswith("\n"):
        content += "\n"
    return f"{content}{rendered}"


def _yaml_sequence_item_indent(content: str, section: str) -> str:
    match = re.search(
        rf"(?ms)^{re.escape(section)}:\s*\n(?P<body>.*?)(?=^[A-Za-z_][^:\n]*:\s*$|\Z)",
        content,
    )
    if match is None:
        return "  "
    for line in match.group("body").splitlines():
        item = re.match(r"^(\s*)-\s+", line)
        if item is not None:
            return item.group(1)
    return "  "


def _remove_misindented_yaml_sequence_item_text(
    content: str,
    *,
    section: str,
    item: str,
    item_indent: str,
) -> str:
    match = re.search(
        rf"(?ms)^{re.escape(section)}:\s*\n(?P<body>.*?)(?=^[A-Za-z_][^:\n]*:\s*$|\Z)",
        content,
    )
    if match is None:
        return content
    repaired_lines: list[str] = []
    changed = False
    for line in match.group("body").splitlines(keepends=True):
        item_match = re.match(r"^(\s*)-\s+(.+?)(\r?\n)?$", line)
        if (
            item_match is not None
            and item_match.group(1) != item_indent
            and item_match.group(2).strip() == item
        ):
            changed = True
            continue
        repaired_lines.append(line)
    if not changed:
        return content
    return (
        content[: match.start("body")]
        + "".join(repaired_lines)
        + content[match.end("body") :]
    )


def _render_generated_rule_yaml(
    rule: dict[str, object], *, item_indent: str = "  "
) -> str:
    body_indent = f"{item_indent}  "
    nested_sequence_indent = body_indent if item_indent == "" else f"{body_indent}  "
    nested_mapping_indent = f"{nested_sequence_indent}  "
    formula_indent = f"{nested_mapping_indent}  "
    lines = [f"{item_indent}- name: {rule['name']}"]
    for key in ("kind", "entity", "dtype", "period", "unit", "source"):
        value = rule.get(key)
        if value is not None:
            lines.append(f"{body_indent}{key}: {value}")
    metadata = rule.get("metadata")
    if metadata is not None:
        lines.extend(
            _render_generated_rule_metadata_yaml(
                metadata,
                body_indent=body_indent,
            )
        )
    versions = rule.get("versions")
    if not isinstance(versions, list) or not versions:
        raise RuntimeError("Generated rule missing versions")
    version = versions[0]
    if not isinstance(version, dict) or "formula" not in version:
        raise RuntimeError("Generated rule missing formula")
    lines.extend(
        [
            f"{body_indent}versions:",
            f"{nested_sequence_indent}- effective_from: '{version.get('effective_from', '2025-10-01')}'",
            f"{nested_mapping_indent}formula: |-",
        ]
    )
    formula_lines = str(version["formula"]).splitlines() or [""]
    lines.extend(f"{formula_indent}{line}" for line in formula_lines)
    return "\n".join(lines) + "\n"


def _render_generated_rule_metadata_yaml(
    metadata: object,
    *,
    body_indent: str,
) -> list[str]:
    if not isinstance(metadata, dict):
        raise RuntimeError("Generated rule metadata must be a mapping")
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        raise RuntimeError("Generated rule metadata only supports proof mappings")
    atoms = proof.get("atoms")
    if not isinstance(atoms, list) or not atoms:
        raise RuntimeError("Generated rule proof metadata requires atoms")
    lines = [
        f"{body_indent}metadata:",
        f"{body_indent}  proof:",
        f"{body_indent}    atoms:",
    ]
    for atom in atoms:
        if not isinstance(atom, dict):
            raise RuntimeError("Generated rule proof atom must be a mapping")
        source = atom.get("source")
        if not isinstance(source, dict):
            raise RuntimeError("Generated rule proof atom requires a source mapping")
        corpus_citation_path = source.get("corpus_citation_path")
        span = source.get("span")
        if corpus_citation_path is None or span is None:
            raise RuntimeError("Generated rule proof source requires path and span")
        lines.extend(
            [
                f"{body_indent}      - path: {atom.get('path', 'versions[0].formula')}",
                f"{body_indent}        kind: {atom.get('kind', 'formula')}",
                f"{body_indent}        source:",
                f"{body_indent}          corpus_citation_path: {corpus_citation_path}",
                f"{body_indent}          span: {_yaml_single_quoted_scalar(str(span))}",
            ]
        )
    return lines


def _yaml_single_quoted_scalar(value: str) -> str:
    return "'" + value.replace("'", "''") + "'"


def _generated_formula_proof_metadata(
    *,
    corpus_citation_path: str,
    span: str,
) -> dict[str, object]:
    return {
        "proof": {
            "atoms": [
                {
                    "path": "versions[0].formula",
                    "kind": "formula",
                    "source": {
                        "corpus_citation_path": corpus_citation_path,
                        "span": span,
                    },
                }
            ]
        }
    }


def _ensure_yaml_mapping_line_after_key(
    content: str,
    *,
    key: str,
    value: str,
    after_key: str,
) -> str:
    if re.search(rf"(?m)^\s+{re.escape(key)}:", content):
        return content
    match = re.search(
        rf"(?m)^(\s+){re.escape(after_key)}:\s+[^\n]*\n",
        content,
    )
    if match is None:
        raise RuntimeError(f"Cannot insert `{key}` after missing `{after_key}`")
    return f"{content[: match.end()]}{match.group(1)}{key}: {value}\n{content[match.end() :]}"


def _repair_colorado_snap_program_tests(path: Path) -> None:
    content = path.read_text()
    content = re.sub(
        r"(?m)^\s+us:regulations/7-cfr/273/10#input\."
        r"(household_initial_month|state_agency_rounds_thirty_percent_net_income_up):"
        r"\s+[^\n]+\n",
        "",
        content,
    )
    content = content.replace(
        "us:regulations/7-cfr/273/10#snap_gross_monthly_income:",
        "us:regulations/7-cfr/273/10#snap_total_gross_income:",
    )
    content = re.sub(
        r"(?m)^\s+us:regulations/7-cfr/273/10#snap_monthly_household_income:\s+[^\n]+\n",
        "",
        content,
    )
    content = content.replace(
        "us:regulations/7-cfr/273/10#snap_excess_shelter_deduction:",
        "us:regulations/7-cfr/273/10#snap_excess_shelter_deduction_for_net_income:",
    )
    for key, value, after_key in [
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_gross_monthly_earned_income",
            "1000",
            "us-co:regulations/10-ccr-2506-1/4.403#snap_countable_earned_income",
        ),
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_total_monthly_unearned_income",
            "0",
            "us-co:regulations/10-ccr-2506-1/4.404#snap_countable_unearned_income",
        ),
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_income_exclusions",
            "0",
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_total_monthly_unearned_income",
        ),
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_gross_monthly_income",
            "1000",
            "us:regulations/7-cfr/273/10#snap_total_gross_income",
        ),
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_monthly_household_income",
            "1000",
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_gross_monthly_income",
        ),
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_allowable_monthly_dependent_care_expenses",
            "0",
            "us:policies/usda/snap/fy-2026-cola/deductions#snap_standard_deduction",
        ),
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_allowable_monthly_child_support_payments",
            "0",
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_allowable_monthly_dependent_care_expenses",
        ),
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_total_medical_expenses",
            "0",
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_allowable_monthly_child_support_payments",
        ),
        (
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_excess_shelter_deduction",
            "744",
            "us:regulations/7-cfr/273/10#snap_excess_shelter_deduction_for_net_income",
        ),
    ]:
        content = _ensure_yaml_mapping_line_after_key(
            content,
            key=key,
            value=value,
            after_key=after_key,
        )
    content = _split_colorado_snap_program_utility_outputs(content)
    path.write_text(content)


def _split_colorado_snap_program_utility_outputs(content: str) -> str:
    marker = "- name: additional_household_member_uses_usda_additional_member_amount\n"
    if marker not in content:
        raise RuntimeError("Cannot split Colorado SNAP utility outputs; marker missing")
    for case_name in (
        "ongoing_month_derives_utility_allowance",
        "ongoing_month_derives_standard_utility_allowance",
    ):
        content = re.sub(
            rf"(?ms)^- name: {re.escape(case_name)}\n.*?(?=^{re.escape(marker)})",
            "",
            content,
        )
    standard_utility_output = (
        "us-co:regulations/10-ccr-2506-1/4.407.31#snap_standard_utility_allowance"
    )
    content = re.sub(
        rf"(?m)^\s+{re.escape(standard_utility_output)}:\s+594\n",
        "",
        content,
    )
    content = _ensure_yaml_mapping_line_after_key(
        content,
        key=(
            "us-co:regulations/10-ccr-2506-1/4.407.31"
            "#snap_heating_cooling_utility_allowance_eligible"
        ),
        value="holds",
        after_key=(
            "us-co:policies/cdhs/snap/fy-2026-benefit-calculation#snap_eligible"
        ),
    )
    if "&base_snap_case" not in content:
        content = content.replace("  input:\n", "  input: &base_snap_case\n", 1)
    utility_case = """- name: ongoing_month_derives_standard_utility_allowance
  period: 2026-01
  input:
    <<: *base_snap_case
  output:
    us-co:regulations/10-ccr-2506-1/4.407.31#snap_standard_utility_allowance: 594
"""
    return content.replace(marker, f"{utility_case}{marker}", 1)


def _repair_colorado_snap_2072_tests(path: Path) -> None:
    cases = _read_yaml_cases(path)
    for case in cases:
        inputs = case.get("input")
        if isinstance(inputs, dict):
            _remove_keys(
                inputs,
                {
                    "us:regulations/7-cfr/273/10#input.snap_countable_earned_income",
                    "us:regulations/7-cfr/273/10#input.snap_countable_unearned_income",
                    "us:statutes/7/2014/e/2#input.work_supplementation_earned_income",
                    "us:statutes/7/2014/e/6/A#input.dependent_care_deduction",
                    "us:statutes/7/2014/e/6/A#input.child_support_deduction",
                    "us:statutes/7/2014/e/6/A#input.medical_deduction",
                    "us:regulations/7-cfr/273/10#input.snap_allowable_shelter_costs",
                },
            )
            _set_snap_net_income_inputs(inputs, 0, include_standard_deduction=False)
            _set_cfr_snap_net_income_inputs(inputs, 0)
            _remove_keys(
                inputs,
                {
                    "us:regulations/7-cfr/273/10#input.household_initial_month",
                    "us:regulations/7-cfr/273/10#input.state_agency_rounds_thirty_percent_net_income_up",
                    "us:regulations/7-cfr/273/10#snap_net_monthly_income",
                },
            )
        outputs = case.get("output")
        if isinstance(outputs, dict):
            maximum_allotment = outputs.get(
                "us:policies/usda/snap/fy-2026-cola/maximum-allotments"
                "#snap_maximum_allotment"
            )
            if maximum_allotment is not None:
                outputs.setdefault(
                    "us-co:regulations/10-ccr-2506-1/4.207.2"
                    "#snap_maximum_allotment_for_household_size",
                    maximum_allotment,
                )
                if (
                    isinstance(inputs, dict)
                    and inputs.get(
                        "us:policies/usda/snap/fy-2026-cola/maximum-allotments"
                        "#input.household_size"
                    )
                    == 1
                ):
                    outputs.setdefault(
                        "us-co:regulations/10-ccr-2506-1/4.207.2"
                        "#snap_maximum_allotment_for_one_person_household",
                        maximum_allotment,
                    )
            if isinstance(inputs, dict):
                initial_month = inputs.get(
                    "us-co:regulations/10-ccr-2506-1/4.207.2"
                    "#input.initial_application_month"
                )
                if initial_month is True:
                    outputs.setdefault(
                        "us-co:regulations/10-ccr-2506-1/4.207.2"
                        "#household_initial_month",
                        "holds",
                    )
                    if (
                        outputs.get(
                            "us-co:regulations/10-ccr-2506-1/4.207.2"
                            "#snap_initial_month_proration_exception"
                        )
                        != "holds"
                    ):
                        outputs.setdefault(
                            "us-co:regulations/10-ccr-2506-1/4.207.2"
                            "#snap_initial_month_proration_applies",
                            "holds",
                        )
                elif initial_month is False:
                    outputs.setdefault(
                        "us-co:regulations/10-ccr-2506-1/4.207.2"
                        "#household_initial_month",
                        "not_holds",
                    )
            _move_mapping_value(
                outputs,
                "us:regulations/7-cfr/273/10#snap_initial_month_allotment_after_minimum_issuance",
                "us-co:regulations/10-ccr-2506-1/4.207.2#snap_initial_month_allotment_after_minimum_issuance",
            )
            _move_mapping_value(
                outputs,
                "us:regulations/7-cfr/273/10#snap_initial_month_minimum_issuance_threshold",
                "us:regulations/7-cfr/273/10#snap_initial_month_minimum_issuance",
            )
            _remove_keys(
                outputs,
                {
                    "us-co:regulations/10-ccr-2506-1/4.207.2"
                    "#state_agency_rounds_thirty_percent_net_income_up",
                },
            )
    _write_yaml_payload(path, cases)


def _set_cfr_snap_net_income_inputs(
    mapping: dict[object, object],
    net_income: object,
) -> None:
    mapping["us:regulations/7-cfr/273/10#input.snap_gross_monthly_earned_income"] = (
        net_income
    )
    mapping["us:regulations/7-cfr/273/10#input.snap_total_monthly_unearned_income"] = 0
    mapping["us:regulations/7-cfr/273/10#input.snap_income_exclusions"] = 0
    mapping[
        "us:regulations/7-cfr/273/10#input.household_entitled_to_excess_medical_deduction"
    ] = False
    mapping["us:regulations/7-cfr/273/10#input.snap_total_medical_expenses"] = 0
    mapping[
        "us:regulations/7-cfr/273/10#input.snap_allowable_monthly_dependent_care_expenses"
    ] = 0
    mapping[
        "us:regulations/7-cfr/273/10#input.snap_allowable_monthly_child_support_payments"
    ] = 0
    mapping[
        "us:regulations/7-cfr/273/10#input.snap_claimed_homeless_shelter_deduction"
    ] = 0
    mapping[
        "us:regulations/7-cfr/273/10#input.snap_total_allowable_shelter_expenses"
    ] = 0


def _repair_colorado_snap_2073_tests(path: Path) -> None:
    cases = _read_yaml_cases(path)
    for case in cases:
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        net_income = inputs.pop("us:statutes/7/2017/a#input.snap_net_income", None)
        if net_income is not None:
            _set_snap_net_income_inputs(inputs, net_income)
    _write_yaml_payload(path, cases)


def _repair_colorado_snap_401_tests(path: Path) -> None:
    cases = _read_yaml_cases(path)
    for case in cases:
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        earned = inputs.pop(
            "us:regulations/7-cfr/273/10#input.snap_countable_earned_income",
            None,
        )
        unearned = inputs.pop(
            "us:regulations/7-cfr/273/10#input.snap_countable_unearned_income",
            None,
        )
        shelter = inputs.pop(
            "us:regulations/7-cfr/273/10#input.snap_allowable_shelter_costs",
            None,
        )
        _remove_keys(
            inputs,
            {
                "us:policies/usda/snap/fy-2026-cola/deductions#input.household_size",
                "us:statutes/7/2014/e/2#input.work_supplementation_earned_income",
                "us:statutes/7/2014/e/6/A#input.dependent_care_deduction",
                "us:statutes/7/2014/e/6/A#input.child_support_deduction",
                "us:statutes/7/2014/e/6/A#input.medical_deduction",
            },
        )
        if earned is not None or unearned is not None or shelter is not None:
            gross = _numeric_test_value(earned) + _numeric_test_value(unearned)
            inputs["us:regulations/7-cfr/273/9#input.snap_gross_monthly_income"] = gross
            inputs["us:regulations/7-cfr/273/9#input.snap_net_income"] = max(
                0,
                gross - _numeric_test_value(shelter),
            )
        outputs = case.get("output")
        if (
            isinstance(outputs, dict)
            and (
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#snap_elderly_disabled_separate_household_allowed"
            )
            in outputs
        ):
            group_size_key = (
                "us-co:regulations/10-ccr-2506-1/4.401#input.co_resident_group_size"
            )
            inputs.setdefault(
                group_size_key,
                inputs.get(
                    "us:policies/usda/snap/fy-2026-cola/income-eligibility-standards"
                    "#input.household_size",
                    1,
                ),
            )
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#co_resident_gross_income_limit_165_percent_fpl_48_states_dc",
                _snap_fy2026_165_percent_fpl_limit(inputs[group_size_key]),
            )
    _upsert_test_case(
        cases,
        {
            "name": "separate_household_allowed_uses_co_resident_group_size",
            "period": "2026-01",
            "input": {
                "us:policies/usda/snap/fy-2026-cola/income-eligibility-standards"
                "#input.household_size": 1,
                "us-co:regulations/10-ccr-2506-1/4.401#input.co_resident_group_size": 3,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#input.elderly_disabled_person_unable_to_purchase_and_prepare_meals": True,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#input.co_resident_gross_income": 3000,
            },
            "output": {
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#co_resident_gross_income_limit_165_percent_fpl_48_states_dc": 3665,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#snap_elderly_disabled_separate_household_allowed": "holds",
            },
        },
    )
    _upsert_test_case(
        cases,
        {
            "name": "separate_household_denied_when_co_resident_group_income_exceeds_limit",
            "period": "2026-01",
            "input": {
                "us:policies/usda/snap/fy-2026-cola/income-eligibility-standards"
                "#input.household_size": 1,
                "us-co:regulations/10-ccr-2506-1/4.401#input.co_resident_group_size": 3,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#input.elderly_disabled_person_unable_to_purchase_and_prepare_meals": True,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#input.co_resident_gross_income": 3666,
            },
            "output": {
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#co_resident_gross_income_limit_165_percent_fpl_48_states_dc": 3665,
                "us-co:regulations/10-ccr-2506-1/4.401"
                "#snap_elderly_disabled_separate_household_allowed": "not_holds",
            },
        },
    )
    _write_yaml_payload(path, cases)


def _snap_fy2026_165_percent_fpl_limit(group_size: object) -> int:
    size = int(_numeric_test_value(group_size))
    table = {
        1: 2152,
        2: 2909,
        3: 3665,
        4: 4421,
        5: 5177,
        6: 5934,
        7: 6690,
        8: 7446,
    }
    return table[max(min(size, 8), 1)] + (max(size - 8, 0) * 757)


def _repair_colorado_snap_4073_tests(path: Path) -> None:
    cases = _read_yaml_cases(path)
    for case in cases:
        case_name = str(case.get("name") or "")
        inputs = case.get("input")
        if isinstance(inputs, dict):
            _remove_keys(
                inputs,
                {
                    "us:regulations/7-cfr/273/10#input.snap_countable_earned_income",
                    "us:regulations/7-cfr/273/10#input.snap_countable_unearned_income",
                    "us:statutes/7/2014/e/2#input.work_supplementation_earned_income",
                    "us:statutes/7/2014/e/6/A#input.dependent_care_deduction",
                    "us:statutes/7/2014/e/6/A#input.child_support_deduction",
                    "us:statutes/7/2014/e/6/A#input.medical_deduction",
                },
            )
            inputs.setdefault(
                "us:regulations/7-cfr/273/10#input.snap_gross_monthly_earned_income",
                0,
            )
            inputs.setdefault(
                "us:regulations/7-cfr/273/10#input.snap_total_monthly_unearned_income",
                0,
            )
            inputs.setdefault(
                "us:regulations/7-cfr/273/10#input.snap_income_exclusions",
                0,
            )
            inputs.setdefault(
                "us:regulations/7-cfr/273/10#input.snap_allowable_monthly_dependent_care_expenses",
                0,
            )
            inputs.setdefault(
                "us:regulations/7-cfr/273/10#input.snap_allowable_monthly_child_support_payments",
                0,
            )
            inputs.setdefault(
                "us:regulations/7-cfr/273/10#input.snap_total_medical_expenses",
                0,
            )
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            continue
        if case_name in {
            "non_elderly_household_shelter_deduction_is_capped",
            "homeless_household_uses_standard_estimate",
            "homeless_household_with_verified_higher_costs_uses_actual_costs",
            "homeless_household_with_free_shelter_all_month_gets_no_shelter_cost",
        }:
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#household_entitled_to_excess_medical_deduction",
                "not_holds",
            )
        elif case_name == "elderly_or_disabled_household_shelter_deduction_is_uncapped":
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#household_entitled_to_excess_medical_deduction",
                "holds",
            )
        if case_name == "homeless_household_uses_standard_estimate":
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#snap_claimed_homeless_shelter_deduction",
                198.99,
            )
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#snap_total_allowable_shelter_expenses",
                0,
            )
        elif case_name in {
            "non_elderly_household_shelter_deduction_is_capped",
            "elderly_or_disabled_household_shelter_deduction_is_uncapped",
        }:
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#snap_claimed_homeless_shelter_deduction",
                0,
            )
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#snap_total_allowable_shelter_expenses",
                1000,
            )
        elif (
            case_name
            == "homeless_household_with_verified_higher_costs_uses_actual_costs"
        ):
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#snap_claimed_homeless_shelter_deduction",
                0,
            )
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#snap_total_allowable_shelter_expenses",
                300,
            )
        elif (
            case_name
            == "homeless_household_with_free_shelter_all_month_gets_no_shelter_cost"
        ):
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#snap_claimed_homeless_shelter_deduction",
                0,
            )
            outputs.setdefault(
                "us-co:regulations/10-ccr-2506-1/4.407.3#snap_total_allowable_shelter_expenses",
                0,
            )
        _remove_mapping_key(
            outputs, "us:regulations/7-cfr/273/10#snap_half_adjusted_income"
        )
        _move_mapping_value(
            outputs,
            "us:regulations/7-cfr/273/10#snap_uncapped_excess_shelter_deduction",
            "us:regulations/7-cfr/273/10#snap_excess_shelter_cost",
        )
        old_excess = "us:regulations/7-cfr/273/10#snap_excess_shelter_deduction"
        if old_excess in outputs:
            if case_name == "homeless_household_uses_standard_estimate":
                _remove_mapping_key(outputs, old_excess)
            else:
                _move_mapping_value(
                    outputs,
                    old_excess,
                    "us:regulations/7-cfr/273/10#snap_excess_shelter_deduction_for_net_income",
                )
    _write_yaml_payload(path, cases)


def _read_yaml_mapping(path: Path) -> dict[str, object]:
    payload = yaml.safe_load(path.read_text()) or {}
    if not isinstance(payload, dict):
        raise RuntimeError(f"{path} must contain a YAML mapping")
    return payload


def _read_yaml_cases(path: Path) -> list[dict[str, object]]:
    payload = yaml.safe_load(path.read_text()) or []
    if not isinstance(payload, list):
        raise RuntimeError(f"{path} must contain a YAML case list")
    return payload


def _find_test_case(
    cases: list[dict[str, object]],
    name: str,
) -> dict[str, object] | None:
    for case in cases:
        if isinstance(case, dict) and case.get("name") == name:
            return case
    return None


def _upsert_test_case(
    cases: list[dict[str, object]],
    new_case: dict[str, object],
) -> None:
    name = new_case.get("name")
    for index, case in enumerate(cases):
        if isinstance(case, dict) and case.get("name") == name:
            cases[index] = new_case
            return
    cases.append(new_case)


def _write_yaml_payload(path: Path, payload: object) -> None:
    path.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))


def _move_mapping_value(
    mapping: dict[object, object], old_key: str, new_key: str
) -> None:
    if old_key not in mapping:
        return
    value = mapping.pop(old_key)
    mapping.setdefault(new_key, value)


def _remove_mapping_key(mapping: dict[object, object], key: str) -> None:
    mapping.pop(key, None)


def _remove_keys(mapping: dict[object, object], keys: set[str]) -> None:
    for key in keys:
        mapping.pop(key, None)


def _set_snap_net_income_inputs(
    mapping: dict[object, object],
    net_income: object,
    *,
    include_standard_deduction: bool = True,
) -> None:
    mapping["us:statutes/7/2014/e/6/A#input.snap_monthly_household_income"] = net_income
    if include_standard_deduction:
        mapping["us:statutes/7/2014/e/6/A#input.snap_standard_deduction"] = 0
    else:
        mapping.pop("us:statutes/7/2014/e/6/A#input.snap_standard_deduction", None)
    mapping["us:statutes/7/2014/e/6/A#input.dependent_care_deduction"] = 0
    mapping["us:statutes/7/2014/e/6/A#input.child_support_deduction"] = 0
    mapping["us:statutes/7/2014/e/6/A#input.medical_deduction"] = 0
    mapping["us:statutes/7/2014/e/6/A#input.snap_excess_shelter_deduction"] = 0
    mapping["us:statutes/7/2014/e/2#input.snap_countable_earned_income"] = 0
    mapping["us:statutes/7/2014/e/2#input.work_supplementation_earned_income"] = 0


def _numeric_test_value(value: object) -> float:
    if isinstance(value, int | float):
        return float(value)
    if value is None:
        return 0
    return float(str(value).replace(",", ""))


def cmd_repair_nonnegative_floors(args):
    """Apply a signed deterministic zero-floor repair to a RuleSpec file."""
    repo_path = Path(args.repo).resolve()
    rules_file = Path(args.file)
    if not rules_file.is_absolute():
        rules_file = repo_path / rules_file
    rules_file = rules_file.resolve()
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    try:
        relative_output = rules_file.relative_to(repo_path)
    except ValueError:
        print(f"RuleSpec file {rules_file} is not under repo {repo_path}")
        sys.exit(1)

    original_content = rules_file.read_text()
    test_file = _rulespec_test_path(rules_file)
    original_test_content = test_file.read_text() if test_file.exists() else None
    repaired_content, repaired_rules = repair_nonnegative_amount_reductions(
        original_content
    )
    if repaired_content == original_content:
        print("No nonnegative floor repairs found.")
        return

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(repaired_content)

        rules_file.write_text(repaired_content)
        applied_files = [rules_file]
        repaired_test_cases = _append_generated_zero_branch_tests_if_missing(
            rules_file=rules_file,
            test_file=test_file,
            repo_path=repo_path,
            relative_output=relative_output,
        )
        if repaired_test_cases:
            applied_files.append(test_file)
        validation = ValidatorPipeline(
            policy_repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
            enable_oracles=False,
            require_policy_proofs=True,
        ).validate(rules_file, skip_reviewers=True)
        if not validation.all_passed:
            rules_file.write_text(original_content)
            if original_test_content is not None:
                test_file.write_text(original_test_content)
            issues = [
                result.error for result in validation.results.values() if result.error
            ]
            print("Repair failed validation; restored original file.")
            for issue in issues:
                print(f"- {issue}")
            sys.exit(1)

        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="nonnegative-floor-v1",
            tool="axiom-encode repair-nonnegative-floors",
            citation=_rulespec_anchor_base_for_output(repo_path, relative_output),
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=applied_files,
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    print(
        "Applied nonnegative floor repair to "
        f"{relative_output}: {', '.join(repaired_rules)}"
    )
    print(f"manifest={manifest_path}")


def _repair_snap_273_10_allotment_rules(content: str) -> str:
    content = _ensure_yaml_import_text(
        content,
        "us:policies/usda/snap/fy-2026-cola/maximum-allotments",
        before_import="us:regulations/7-cfr/273/9",
    )
    content = content.replace(
        "snap_maximum_allotment_for_household_size",
        "snap_maximum_allotment",
    )
    return content.replace(
        "snap_maximum_allotment_for_one_person_household",
        "snap_one_person_thrifty_food_plan_cost",
    )


def _repair_snap_273_10_allotment_tests(content: str) -> str:
    household_size_input = (
        "    us:policies/usda/snap/fy-2026-cola/maximum-allotments"
        "#input.household_size: 1\n"
    )
    content = content.replace(
        "    us:regulations/7-cfr/273/10#input.snap_maximum_allotment_for_household_size: 298\n",
        household_size_input,
    )
    content = content.replace(
        "    us:regulations/7-cfr/273/10#input.snap_maximum_allotment_for_one_person_household: 298\n",
        household_size_input,
    )
    while household_size_input + household_size_input in content:
        content = content.replace(
            household_size_input + household_size_input,
            household_size_input,
        )
    return content


def cmd_repair_snap_273_10_allotment(args):
    """Apply a signed deterministic repair for the 273.10 allotment input drift."""
    repo_path = Path(args.repo).resolve()
    if _repo_jurisdiction_prefix(repo_path) != "us":
        print(
            "repair-snap-273-10-allotment must run against rulespec-us; "
            f"got {repo_path}"
        )
        sys.exit(1)

    relative_output = Path("regulations/7-cfr/273/10.yaml")
    rules_file = repo_path / relative_output
    test_file = _rulespec_test_path(rules_file)
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    if not test_file.exists():
        print(f"RuleSpec companion test file not found: {test_file}")
        sys.exit(1)

    original_content = rules_file.read_text()
    original_test_content = test_file.read_text()
    repaired_content = _repair_snap_273_10_allotment_rules(original_content)
    repaired_test_content = _repair_snap_273_10_allotment_tests(original_test_content)

    applied_files = [rules_file, test_file]
    if (
        repaired_content == original_content
        and repaired_test_content == original_test_content
    ):
        manifest_path = repo_path / _applied_encoding_manifest_path(relative_output)
        if manifest_path.exists():
            current_hashes = {
                rules_file.relative_to(repo_path).as_posix(): _sha256_file(rules_file),
                test_file.relative_to(repo_path).as_posix(): _sha256_file(test_file),
            }
            payload = json.loads(manifest_path.read_text())
            manifest_hashes = {
                item.get("path"): item.get("sha256")
                for item in payload.get("applied_files", [])
                if isinstance(item, dict)
            }
            if all(
                manifest_hashes.get(path) == sha for path, sha in current_hashes.items()
            ):
                print("No 7 CFR 273.10 maximum-allotment repairs found.")
                return

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(repaired_content)
        generated_test = _rulespec_test_path(generated_output)
        generated_test.write_text(repaired_test_content)

        rules_file.write_text(repaired_content)
        test_file.write_text(repaired_test_content)

        try:
            validation = ValidatorPipeline(
                policy_repo_path=repo_path,
                axiom_rules_path=axiom_rules_path,
                enable_oracles=False,
                require_policy_proofs=True,
            ).validate(rules_file, skip_reviewers=True)
            if not validation.all_passed:
                issues = [
                    result.error
                    for result in validation.results.values()
                    if result.error
                ]
                print("Repair failed validation; restored original files.")
                for issue in issues:
                    print(f"- {issue}")
                sys.exit(1)
        finally:
            if "validation" not in locals() or not validation.all_passed:
                rules_file.write_text(original_content)
                test_file.write_text(original_test_content)

        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="snap-273-10-allotment-v1",
            tool="axiom-encode repair-snap-273-10-allotment",
            citation="us:regulations/7-cfr/273/10",
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=applied_files,
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    print("Applied 7 CFR 273.10 maximum-allotment repair")
    print(f"changed={relative_output}")
    print(f"changed={_rulespec_test_path(relative_output)}")
    print(f"manifest={manifest_path}")


SNAP_273_9_RELATIVE = Path("regulations/7-cfr/273/9.yaml")


def _repair_snap_273_9_income_rules(content: str) -> str:
    content = _ensure_yaml_import_text(
        content,
        "us:regulations/7-cfr/273/10",
        before_import="us:policies/usda/snap/fy-2026-cola/income-eligibility-standards",
    )
    content = content.replace(
        "snap_gross_monthly_income <= snap_gross_income_limit_130_percent_fpl_48_states_dc",
        "snap_total_gross_income <= snap_gross_income_limit_130_percent_fpl_48_states_dc",
    )
    return content.replace(
        "formula: snap_net_income <= snap_net_income_limit_100_percent_fpl_48_states_dc",
        "formula: snap_net_monthly_income <= snap_net_income_limit_100_percent_fpl_48_states_dc",
    )


def _snap_273_9_derived_income_inputs(
    *,
    gross: int,
    shelter_expenses: int | float,
) -> str:
    return (
        "    us:policies/usda/snap/fy-2026-cola/deductions#input.household_size: 1\n"
        "    us:regulations/7-cfr/273/10#input.snap_gross_monthly_earned_income: 0\n"
        f"    us:regulations/7-cfr/273/10#input.snap_total_monthly_unearned_income: {gross}\n"
        "    us:regulations/7-cfr/273/10#input.snap_income_exclusions: 0\n"
        "    us:regulations/7-cfr/273/10#input.household_entitled_to_excess_medical_deduction: false\n"
        "    us:regulations/7-cfr/273/10#input.snap_total_medical_expenses: 0\n"
        "    us:regulations/7-cfr/273/10#input.snap_allowable_monthly_dependent_care_expenses: 0\n"
        "    us:regulations/7-cfr/273/10#input.snap_allowable_monthly_child_support_payments: 0\n"
        "    us:regulations/7-cfr/273/10#input.snap_claimed_homeless_shelter_deduction: 0\n"
        f"    us:regulations/7-cfr/273/10#input.snap_total_allowable_shelter_expenses: {shelter_expenses}\n"
    )


def _repair_snap_273_9_income_tests(content: str) -> str:
    replacements = {
        (
            "    us:regulations/7-cfr/273/9#input.snap_gross_monthly_income: 1696\n"
            "    us:regulations/7-cfr/273/9#input.snap_net_income: 1305\n"
        ): _snap_273_9_derived_income_inputs(gross=1696, shelter_expenses=925.5),
        (
            "    us:regulations/7-cfr/273/9#input.snap_gross_monthly_income: 1697\n"
            "    us:regulations/7-cfr/273/9#input.snap_net_income: 1305\n"
        ): _snap_273_9_derived_income_inputs(gross=1697, shelter_expenses=927),
        (
            "    us:regulations/7-cfr/273/9#input.snap_gross_monthly_income: 10000\n"
            "    us:regulations/7-cfr/273/9#input.snap_net_income: 1305\n"
        ): _snap_273_9_derived_income_inputs(gross=10000, shelter_expenses=13391.5),
        (
            "    us:regulations/7-cfr/273/9#input.snap_gross_monthly_income: 1000\n"
            "    us:regulations/7-cfr/273/9#input.snap_net_income: 1306\n"
        ): _snap_273_9_derived_income_inputs(gross=1696, shelter_expenses=0),
    }
    for old, new in replacements.items():
        content = content.replace(old, new)
    return content


