def _repair_medicaid_primary_category_composition_tests(
    content: str,
) -> tuple[str, list[str]]:
    cases = yaml.safe_load(content)
    if not isinstance(cases, list):
        raise ValueError("RuleSpec companion tests must be a list")

    changed: list[str] = []
    for case in cases:
        if not isinstance(case, dict):
            continue
        inputs = case.setdefault("input", {})
        if not isinstance(inputs, dict):
            raise ValueError("RuleSpec test input must be a mapping")
        for key, value in _MEDICAID_PRIMARY_FALSE_INPUTS.items():
            if key not in inputs:
                inputs[key] = value
                changed.append(str(case.get("name") or "<unnamed>"))

    names = {case.get("name") for case in cases if isinstance(case, dict)}
    template = None
    for case in cases:
        if (
            isinstance(case, dict)
            and case.get("name") == "no composed mandatory category eligible"
        ):
            template = case
            break
    if template is None:
        raise ValueError("Missing no composed mandatory category eligible test")

    if "optional youth category eligible" not in names:
        youth_case = copy.deepcopy(template)
        youth_case["name"] = "optional youth category eligible"
        inputs = youth_case.setdefault("input", {})
        if not isinstance(inputs, dict):
            raise ValueError("RuleSpec test input must be a mapping")
        inputs.update(_MEDICAID_PRIMARY_FALSE_INPUTS)
        inputs.update(_MEDICAID_PRIMARY_YOUTH_TRUE_INPUTS)
        youth_case["output"] = {
            "us:statutes/42/1396a/a/10#optional_youth_medicaid_category_eligible": "holds",
            "us:statutes/42/1396a/a/10#is_medicaid_eligible": "holds",
        }
        cases.append(youth_case)
        changed.append("optional youth category eligible")

    if "optional medically needy category eligible" not in names:
        medically_needy_case = copy.deepcopy(template)
        medically_needy_case["name"] = "optional medically needy category eligible"
        inputs = medically_needy_case.setdefault("input", {})
        if not isinstance(inputs, dict):
            raise ValueError("RuleSpec test input must be a mapping")
        inputs.update(_MEDICAID_PRIMARY_FALSE_INPUTS)
        inputs.update(_MEDICAID_PRIMARY_MEDICALLY_NEEDY_TRUE_INPUTS)
        medically_needy_case["output"] = {
            "us:statutes/42/1396a/a/10#is_medicaid_eligible": "holds"
        }
        cases.append(medically_needy_case)
        changed.append("optional medically needy category eligible")

    if "optional working disabled category eligible" not in names:
        working_disabled_case = copy.deepcopy(template)
        working_disabled_case["name"] = "optional working disabled category eligible"
        inputs = working_disabled_case.setdefault("input", {})
        if not isinstance(inputs, dict):
            raise ValueError("RuleSpec test input must be a mapping")
        inputs.update(_MEDICAID_PRIMARY_FALSE_INPUTS)
        inputs.update(_MEDICAID_PRIMARY_WORKING_DISABLED_TRUE_INPUTS)
        working_disabled_case["output"] = {
            "us:statutes/42/1396a/a/10#optional_working_disabled_medicaid_category_eligible": "holds",
            "us:statutes/42/1396a/a/10#is_medicaid_eligible": "holds",
        }
        cases.append(working_disabled_case)
        changed.append("optional working disabled category eligible")

    if "optional SSI excess earnings category eligible" not in names:
        ssi_excess_case = copy.deepcopy(template)
        ssi_excess_case["name"] = "optional SSI excess earnings category eligible"
        inputs = ssi_excess_case.setdefault("input", {})
        if not isinstance(inputs, dict):
            raise ValueError("RuleSpec test input must be a mapping")
        inputs.update(_MEDICAID_PRIMARY_FALSE_INPUTS)
        inputs.update(_MEDICAID_PRIMARY_SSI_EXCESS_EARNINGS_TRUE_INPUTS)
        ssi_excess_case["output"] = {
            "us:statutes/42/1396a/a/10#optional_ssi_excess_earnings_medicaid_category_eligible": "holds",
            "us:statutes/42/1396a/a/10#is_medicaid_eligible": "holds",
        }
        cases.append(ssi_excess_case)
        changed.append("optional SSI excess earnings category eligible")

    return _dump_rulespec_repair_yaml(cases), changed


def cmd_repair_medicaid_community_engagement_effective_date(args):
    """Apply signed deterministic Medicaid community-engagement timing repairs."""
    repo_path = Path(args.repo).resolve()
    if _repo_jurisdiction_prefix(repo_path) != "us":
        print(
            "repair-medicaid-community-engagement-effective-date must run against "
            f"rulespec-us; got {repo_path}"
        )
        sys.exit(1)

    rules_file = repo_path / MEDICAID_A10_RELATIVE
    test_file = _rulespec_test_path(rules_file)
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    if not test_file.exists():
        print(f"RuleSpec companion test file not found: {test_file}")
        sys.exit(1)

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)
    manifest_groups = [(MEDICAID_A10_RELATIVE, [rules_file, test_file])]
    _ensure_no_unmanifested_preexisting_rulespec_changes(repo_path, manifest_groups)

    original_content = rules_file.read_text()
    original_test_content = test_file.read_text()
    originals = {rules_file: original_content, test_file: original_test_content}

    repaired_content, repaired_rules = (
        _repair_medicaid_community_engagement_effective_date_rules(original_content)
    )
    changed_by_command: list[Path] = []
    try:
        rules_file.write_text(repaired_content)

        validation = ValidatorPipeline(
            policy_repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
            enable_oracles=False,
            require_policy_proofs=True,
        ).validate(rules_file, skip_reviewers=True)
        if not validation.all_passed:
            validation_issues = [
                result.error for result in validation.results.values() if result.error
            ]
            raise RuntimeError(
                "Validation failed after Medicaid community-engagement repair:\n"
                + "\n".join(f"- {issue}" for issue in validation_issues)
            )

        test_issues = _companion_test_issues(
            test_files=[test_file],
            repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
        )
        if test_issues:
            raise RuntimeError(
                "Companion tests failed after Medicaid community-engagement repair:\n"
                + "\n".join(f"- {issue}" for issue in test_issues)
            )
    except Exception:
        _restore_original_files(originals)
        raise

    changed_by_command = _unique_paths(
        [
            path
            for path in (rules_file, test_file)
            if _path_differs_from_original(path, originals.get(path))
        ]
    )
    refresh_manifest_files: list[Path] = []
    if not changed_by_command:
        applied_files = [rules_file, test_file]
        if not _applied_manifest_matches_current_deterministic_repair(
            repo_path=repo_path,
            relative_output=MEDICAID_A10_RELATIVE,
            applied_files=applied_files,
            model=MEDICAID_COMMUNITY_ENGAGEMENT_EFFECTIVE_DATE_REPAIR_MODEL,
            axiom_encode_git=axiom_encode_git,
            signing_key=signing_key,
        ):
            refresh_manifest_files.extend(applied_files)
        else:
            print("No Medicaid community-engagement effective-date repairs found.")
            return
    refresh_only = bool(refresh_manifest_files)
    if refresh_only:
        changed_by_command = _unique_paths(refresh_manifest_files)

    manifest_paths = _write_grouped_deterministic_repair_manifests(
        repo_path=repo_path,
        signing_key=signing_key,
        axiom_encode_git=axiom_encode_git,
        manifest_groups=manifest_groups,
        changed_files=changed_by_command,
        model=MEDICAID_COMMUNITY_ENGAGEMENT_EFFECTIVE_DATE_REPAIR_MODEL,
        tool="axiom-encode repair-medicaid-community-engagement-effective-date",
    )

    if refresh_only:
        print("Refreshed Medicaid community-engagement effective-date repair manifest")
    else:
        print("Applied Medicaid community-engagement effective-date repair")
    if repaired_rules and not refresh_only:
        print(f"changed_rules={', '.join(repaired_rules)}")
    if not refresh_only:
        for path in changed_by_command:
            print(f"changed={path.relative_to(repo_path)}")
    for manifest_path in manifest_paths:
        print(f"manifest={manifest_path}")


def _repair_medicaid_community_engagement_effective_date_rules(
    content: str,
) -> tuple[str, list[str]]:
    payload = yaml.safe_load(content)
    if not isinstance(payload, dict):
        raise ValueError("RuleSpec payload must be a mapping")
    rules = payload.get("rules")
    if not isinstance(rules, list):
        raise ValueError("RuleSpec payload must contain rules")

    medicaid_rule = next(
        (
            rule
            for rule in rules
            if isinstance(rule, dict) and rule.get("name") == "is_medicaid_eligible"
        ),
        None,
    )
    if medicaid_rule is None:
        raise ValueError("Missing is_medicaid_eligible rule")

    versions = medicaid_rule.get("versions")
    if not isinstance(versions, list) or not versions:
        raise ValueError("is_medicaid_eligible must have versions")
    original_formula = (
        versions[0].get("formula") if isinstance(versions[0], dict) else None
    )
    if not isinstance(original_formula, str):
        raise ValueError("is_medicaid_eligible first version must have formula")

    gated_adult_group = (
        "(adult_group_eligible and demonstrated_community_engagement_for_month)"
    )
    if len(versions) >= 2 and versions[0].get("formula") != original_formula:
        raise ValueError("Unexpected Medicaid eligibility version shape")
    if (
        len(versions) >= 2
        and MEDICAID_COMMUNITY_ENGAGEMENT_RULE in str(versions[1].get("formula"))
        and MEDICAID_COMMUNITY_ENGAGEMENT_RULE not in str(versions[0].get("formula"))
    ):
        return content, []
    if gated_adult_group not in original_formula:
        raise ValueError("Missing adult-group community-engagement formula branch")

    past_formula = original_formula.replace(
        gated_adult_group, "adult_group_eligible", 1
    )
    future_formula = original_formula
    medicaid_rule["versions"] = [
        {
            "effective_from": versions[0].get("effective_from", "2014-01-01"),
            "formula": past_formula,
        },
        {
            "effective_from": "2026-12-31",
            "formula": future_formula,
        },
    ]

    proof = medicaid_rule.get("metadata", {}).get("proof", {})
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        raise ValueError("is_medicaid_eligible proof atoms must be a list")
    repaired_atoms: list[dict[str, Any]] = []
    for atom in atoms:
        if not isinstance(atom, dict):
            repaired_atoms.append(atom)
            continue
        if atom.get("path") != "versions[0].formula":
            repaired_atoms.append(atom)
            continue
        imported = atom.get("import")
        if (
            isinstance(imported, dict)
            and imported.get("target") == MEDICAID_COMMUNITY_ENGAGEMENT_TARGET
        ):
            future_atom = copy.deepcopy(atom)
            future_atom["path"] = "versions[1].formula"
            repaired_atoms.append(future_atom)
            continue
        repaired_atoms.append(atom)
        future_atom = copy.deepcopy(atom)
        future_atom["path"] = "versions[1].formula"
        repaired_atoms.append(future_atom)
    proof["atoms"] = repaired_atoms

    return (
        _replace_rulespec_rule_block(
            content,
            rule_name="is_medicaid_eligible",
            rendered_rule=_render_rulespec_rule_block(medicaid_rule),
        ),
        ["is_medicaid_eligible"],
    )


def _cms_effective_magi_limit_relative_target(
    repo_path: Path,
    target: Path,
) -> Path:
    if target.is_absolute():
        try:
            relative = target.resolve().relative_to(repo_path)
        except ValueError as exc:
            raise RuntimeError(f"Target is not inside repo: {target}") from exc
    else:
        relative = target
    if ".." in relative.parts or not relative.parts:
        raise RuntimeError(f"Invalid target path: {target}")
    if relative.suffix != ".yaml":
        raise RuntimeError(f"Target must be a RuleSpec YAML file: {target}")
    return relative


def cmd_repair_cms_effective_magi_limits(args):
    """Apply signed deterministic CMS effective MAGI limit repairs."""
    repo_path = Path(args.repo).resolve()
    if _repo_jurisdiction_prefix(repo_path) != "us":
        print(
            "repair-cms-effective-magi-limits must run against "
            f"rulespec-us; got {repo_path}"
        )
        sys.exit(1)

    try:
        relative_output = _cms_effective_magi_limit_relative_target(
            repo_path,
            Path(args.target),
        )
    except RuntimeError as exc:
        print(str(exc))
        sys.exit(1)

    rules_file = repo_path / relative_output
    test_file = _rulespec_test_path(rules_file)
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    if not test_file.exists():
        print(f"RuleSpec companion test file not found: {test_file}")
        sys.exit(1)

    original_content = rules_file.read_text()
    original_test_content = test_file.read_text()
    repaired_content, repaired_rules, issue = _repair_cms_effective_magi_limit_rules(
        original_content
    )
    if issue is not None:
        print(issue)
        sys.exit(1)
    citation = _rulespec_anchor_base_for_output(repo_path, relative_output)
    repaired_test_content, repaired_tests = _repair_cms_effective_magi_limit_tests(
        original_test_content,
        citation=citation,
        rules=repaired_rules,
    )
    applied_files = [rules_file, test_file]

    content_changed = (
        repaired_content != original_content
        or repaired_test_content != original_test_content
    )
    if not content_changed and not getattr(args, "refresh_manifest", False):
        print("No CMS effective MAGI limit repairs found.")
        return

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)
    _ensure_no_unmanifested_preexisting_rulespec_changes(
        repo_path,
        [(relative_output, applied_files)],
    )

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(repaired_content)
        generated_test = _rulespec_test_path(generated_output)
        generated_test.write_text(repaired_test_content)

        rules_file.write_text(repaired_content)
        test_file.write_text(repaired_test_content)

        try:
            validation = ValidatorPipeline(
                policy_repo_path=repo_path,
                axiom_rules_path=axiom_rules_path,
                enable_oracles=False,
                require_policy_proofs=True,
            ).validate(rules_file, skip_reviewers=True)
            if not validation.all_passed:
                issues = [
                    result.error
                    for result in validation.results.values()
                    if result.error
                ]
                print("Repair failed validation; restored original files.")
                for issue in issues:
                    print(f"- {issue}")
                sys.exit(1)

            test_failures = _rulespec_companion_test_failures(
                test_file,
                root=repo_path,
                axiom_rules_path=axiom_rules_path,
            )
            if test_failures:
                print("Repair failed companion tests; restored original files.")
                for failure in test_failures[:20]:
                    case_name = failure.get("case") or "<unknown case>"
                    print(f"- {case_name}: {failure.get('message')}")
                sys.exit(1)
        finally:
            validation_passed = "validation" in locals() and validation.all_passed
            tests_passed = "test_failures" in locals() and not test_failures
            if not validation_passed or not tests_passed:
                rules_file.write_text(original_content)
                test_file.write_text(original_test_content)

        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="cms-effective-magi-limits-v1",
            tool="axiom-encode repair-cms-effective-magi-limits",
            citation=citation,
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=applied_files,
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    changed_names = sorted(
        {rule["name"] for rule in repaired_rules} | set(repaired_tests)
    )
    if content_changed:
        print("Applied CMS effective MAGI limit repair")
    else:
        print("Refreshed CMS effective MAGI limit repair manifest")
    if changed_names:
        print(f"changed_rules={', '.join(changed_names)}")
    print(f"changed={relative_output}")
    print(f"changed={_rulespec_test_path(relative_output)}")
    print(f"manifest={manifest_path}")


