def _applied_manifest_missing_file(
    repo_path: Path,
    relative_output: Path,
    applied_file: Path,
) -> bool:
    manifest_path = repo_path / _applied_encoding_manifest_path(relative_output)
    if not manifest_path.exists():
        return True
    with contextlib.suppress(json.JSONDecodeError, OSError, ValueError):
        payload = json.loads(manifest_path.read_text())
        applied_files = payload.get("applied_files")
        if not isinstance(applied_files, list):
            return True
        relative = applied_file.relative_to(repo_path).as_posix()
        return not any(
            isinstance(item, dict) and item.get("path") == relative
            for item in applied_files
        )
    return True


def _applied_manifest_has_model(
    repo_path: Path,
    relative_output: Path,
    *,
    model: str,
) -> bool:
    manifest_path = repo_path / _applied_encoding_manifest_path(relative_output)
    if not manifest_path.exists():
        return False
    with contextlib.suppress(json.JSONDecodeError, OSError, ValueError):
        payload = json.loads(manifest_path.read_text())
        return payload.get("model") == model
    return False


def _applied_manifest_paths_for_files(
    repo_path: Path,
    *,
    relative_files: set[str],
) -> set[str]:
    manifest_paths: set[str] = set()
    if not relative_files:
        return manifest_paths
    for relative_manifest_path in _all_applied_encoding_manifest_paths(repo_path):
        manifest_path = repo_path / relative_manifest_path
        with contextlib.suppress(json.JSONDecodeError, OSError, ValueError):
            payload = json.loads(manifest_path.read_text())
            applied_files = payload.get("applied_files")
            if not isinstance(applied_files, list):
                continue
            if any(
                isinstance(item, dict) and item.get("path") in relative_files
                for item in applied_files
            ):
                manifest_paths.add(relative_manifest_path)
    return manifest_paths


def _prune_unused_imports(content: str) -> tuple[str, list[str]]:
    unused_imports = _unused_import_items(content)
    if not unused_imports:
        return content, []

    unused = set(unused_imports)
    repaired_lines: list[str] = []
    in_imports = False
    imports_indent = 0
    removed: list[str] = []

    for line in content.splitlines(keepends=True):
        imports_match = re.match(r"^(\s*)imports:\s*$", line)
        if imports_match:
            in_imports = True
            imports_indent = len(imports_match.group(1))
            repaired_lines.append(line)
            continue

        if in_imports:
            stripped = line.strip()
            if stripped:
                indent = len(line) - len(line.lstrip())
                item_match = re.match(r"^\s*-\s+(.+?)\s*$", line)
                if item_match and indent >= imports_indent:
                    item = _strip_yaml_scalar_quotes(item_match.group(1).strip())
                    if item in unused:
                        removed.append(item)
                        continue
                elif indent <= imports_indent:
                    in_imports = False

        repaired_lines.append(line)

    return "".join(repaired_lines), removed


def _unused_import_items(content: str) -> list[str]:
    items: list[str] = []
    for issue in find_unused_import_issues(content):
        match = re.search(r"Unused import `([^`]+)`", issue)
        if match:
            items.append(match.group(1))
    return items


def _strip_yaml_scalar_quotes(value: str) -> str:
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {"'", '"'}:
        return value[1:-1]
    return value


def cmd_repair_proof_import_hashes(args):
    """Apply signed deterministic repairs for proof import hashes."""
    repo_path = Path(args.repo).resolve()
    rules_file = Path(args.file)
    if not rules_file.is_absolute():
        rules_file = repo_path / rules_file
    rules_file = rules_file.resolve()
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    try:
        relative_output = rules_file.relative_to(repo_path)
    except ValueError:
        print(f"RuleSpec file {rules_file} is not under repo {repo_path}")
        sys.exit(1)

    target_base = _rulespec_anchor_base_for_output(repo_path, relative_output)
    test_file = _rulespec_test_path(rules_file)
    original_test_content = test_file.read_text() if test_file.exists() else None
    original_content = rules_file.read_text()
    repaired_content, repair_count = _repair_proof_import_hashes(
        original_content,
        target_base=target_base,
        rules_file=rules_file,
        repo_path=repo_path,
    )
    refresh_only = repaired_content == original_content
    if refresh_only and not _applied_manifest_has_model(
        repo_path,
        relative_output,
        model="proof-import-hash-v1",
    ):
        print("No proof hash repairs found.")
        return

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    rules_file.write_text(repaired_content)
    validation = ValidatorPipeline(
        policy_repo_path=repo_path,
        axiom_rules_path=axiom_rules_path,
        enable_oracles=False,
        require_policy_proofs=False,
    ).validate(rules_file, skip_reviewers=True)
    if not validation.all_passed:
        for _ in range(20):
            issues = [
                result.error for result in validation.results.values() if result.error
            ]
            rewritten_import_output_refs = _rewrite_import_output_test_input_refs(
                test_file=test_file,
                repo_path=repo_path,
                issues=issues,
            )
            removed_refs = _remove_invalid_import_output_test_input_refs(
                test_file=test_file,
                repo_path=repo_path,
                issues=issues,
            )
            repaired_exclusion_refs = (
                _repair_stale_exclusion_dependency_test_input_refs(
                    test_file=test_file,
                    issues=issues,
                )
            )
            removed_invalid_refs = _remove_invalid_test_input_refs(
                test_file=test_file,
                issues=issues,
            )
            removed_unknown_outputs = _remove_unknown_test_output_refs(
                test_file=test_file,
                issues=issues,
            )
            completed_missing_inputs = _complete_missing_imported_test_inputs(
                rules_file=rules_file,
                test_file=test_file,
                repo_path=repo_path,
                validation=validation,
            )
            repaired_output_cases = _repair_imported_output_test_mismatches(
                rules_file=rules_file,
                test_file=test_file,
                policy_repo_path=repo_path,
                relative_output=relative_output,
                issues=issues,
            )
            if (
                not rewritten_import_output_refs
                and not removed_refs
                and not repaired_exclusion_refs
                and not removed_invalid_refs
                and not removed_unknown_outputs
                and not completed_missing_inputs
                and not repaired_output_cases
            ):
                break
            validation = ValidatorPipeline(
                policy_repo_path=repo_path,
                axiom_rules_path=axiom_rules_path,
                enable_oracles=False,
                require_policy_proofs=False,
            ).validate(rules_file, skip_reviewers=True)
            if validation.all_passed:
                break
    if not validation.all_passed:
        issues = [
            result.error for result in validation.results.values() if result.error
        ]
        if _only_pending_zero_branch_coverage_issues(issues):
            print(
                "Applied proof import hash repair with pending zero-branch coverage "
                "repair still required."
            )
        else:
            rules_file.write_text(original_content)
            if original_test_content is not None:
                test_file.write_text(original_test_content)
            print("Repair failed validation; restored original file.")
            for issue in issues:
                print(f"- {issue}")
            sys.exit(1)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(repaired_content)
        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="proof-import-hash-v1",
            tool="axiom-encode repair-proof-import-hashes",
            citation=target_base,
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        applied_files = [rules_file]
        if test_file.exists():
            applied_files.append(test_file)
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=applied_files,
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    if refresh_only:
        print(f"Refreshed proof hash repair manifest for {relative_output}")
    else:
        print(f"Applied proof hash repair to {relative_output}: {repair_count}")
    print(f"manifest={manifest_path}")


