def _retarget_ssa_poms_optional_supplement_state_file(
    *,
    rules_file: Path,
    test_file: Path,
    duplicate_names: set[str],
) -> bool:
    try:
        document = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return False
    if not isinstance(document, dict):
        return False
    rules = document.get("rules")
    if not isinstance(rules, list):
        return False

    removed_names: set[str] = set()
    remaining_rules: list[object] = []
    for rule in rules:
        name = str(rule.get("name") or "").strip() if isinstance(rule, dict) else ""
        if name in duplicate_names:
            removed_names.add(name)
            continue
        remaining_rules.append(rule)
    if not removed_names:
        return False

    content_root = find_policy_repo_root(rules_file)
    imports = document.get("imports")
    if not isinstance(imports, list):
        imports = []
        document["imports"] = imports
    existing_imports = {
        str(import_ref).strip().strip('"').strip("'")
        for import_ref in imports
        if isinstance(import_ref, str)
    }
    for name in sorted(removed_names):
        import_target = _SSA_POMS_OPTIONAL_SUPPLEMENT_COMMON_IMPORTS[name]
        if import_target not in existing_imports:
            imports.append(import_target)
            existing_imports.add(import_target)

    document["rules"] = remaining_rules
    content = yaml.safe_dump(document, sort_keys=False, allow_unicode=False)
    if content_root is not None:
        target_base = _rulespec_anchor_base_for_output(
            content_root,
            rules_file.relative_to(content_root),
        )
        content, _ = _repair_proof_import_hashes(
            content,
            target_base=target_base,
            rules_file=rules_file,
            repo_path=content_root,
        )
    rules_file.write_text(content)

    if content_root is not None:
        _remove_local_test_output_refs_for_names(
            test_file,
            target_base=target_base,
            names=removed_names,
        )
    return True


def _retarget_ssa_poms_optional_supplement_test_inputs(
    *,
    repo_path: Path,
    jurisdiction: str,
    original_contents: dict[Path, str | None],
) -> None:
    poms_dir = repo_path / jurisdiction / "policies/ssa/poms/si-01415-058/2026"
    if not poms_dir.exists():
        return
    common_target = _SSA_POMS_OPTIONAL_SUPPLEMENT_COMMON_TARGET_BASE
    replacements = {
        "recipient_eligible_for_optional_supplement": (
            f"{common_target}#input.recipient_eligible_for_optional_supplement"
        ),
        "recipient_waived_optional_supplement": (
            f"{common_target}#input.recipient_waived_optional_supplement"
        ),
    }
    for test_file in sorted(poms_dir.glob("*.test.yaml")):
        _remember_original_file(test_file, original_contents)
        try:
            cases = yaml.safe_load(test_file.read_text()) or []
        except (OSError, yaml.YAMLError, ValueError):
            continue
        if not isinstance(cases, list):
            continue
        changed = False
        for case in cases:
            if not isinstance(case, dict):
                continue
            inputs = case.get("input")
            if not isinstance(inputs, dict):
                continue
            for input_ref in list(inputs):
                input_ref_text = str(input_ref).strip().strip('"').strip("'")
                for input_name, replacement in replacements.items():
                    if input_ref_text.endswith(f"#input.{input_name}"):
                        value = inputs.pop(input_ref)
                        inputs[replacement] = value
                        changed = True
                        break
        if changed:
            test_file.write_text(
                yaml.safe_dump(cases, sort_keys=False, allow_unicode=False)
            )


def _try_repair_generated_upstream_placement_duplicates_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []
    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    try:
        real_rules_file = Path(policy_repo_path) / relative_output
        content_repo_path = find_policy_repo_root(
            real_rules_file
        ) or _generated_validation_repair_policy_repo_path(
            Path(policy_repo_path), relative_output
        )
        content_relative_output = real_rules_file.relative_to(content_repo_path)
    except ValueError:
        content_repo_path = _generated_validation_repair_policy_repo_path(
            Path(policy_repo_path), relative_output
        )
        content_relative_output = relative_output
    return _repair_upstream_placement_duplicate_imports(
        rules_file=rules_file,
        test_file=_rulespec_test_path(rules_file),
        repo_path=content_repo_path,
        relative_output=content_relative_output,
    )


def _try_repair_generated_upstream_placement_duplicates_and_proofs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    repaired = _try_repair_generated_upstream_placement_duplicates_for_apply(
        result,
        output_root=output_root,
        policy_repo_path=policy_repo_path,
    )
    if not repaired:
        return []
    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    try:
        content = rules_file.read_text()
    except OSError:
        return repaired
    repaired_content, repaired_rules = _repair_missing_source_proof_atoms(content)
    if repaired_content != content:
        rules_file.write_text(repaired_content)
        repaired.extend(f"proof:{name}" for name in repaired_rules)
    return repaired


_CHILD_FRAGMENT_REENCODING_ISSUE_PATTERN = re.compile(
    r"Child fragment re-encoded: .*? uses child-local input\(s\) "
    r"(?P<inputs>.+?) also used by `(?P<child_path>[^`]+)` without importing "
    r"a terminal child output\. Import and compose the child (?P<child_hint>.+?) "
    r"instead of copying the child formula or factual inputs"
)


def _try_repair_generated_child_fragment_reencoding_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    parsed_issues = [
        parsed
        for issue in issues
        if (parsed := _parse_child_fragment_reencoding_issue(str(issue))) is not None
    ]
    if not parsed_issues:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_child_fragment_reencoding_aliases(
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
        parsed_issues=parsed_issues,
    )


def _parse_child_fragment_reencoding_issue(
    issue: str,
) -> tuple[tuple[str, ...], str] | None:
    match = _CHILD_FRAGMENT_REENCODING_ISSUE_PATTERN.search(issue)
    if match is None:
        return None
    shared_inputs = tuple(re.findall(r"`([^`]+)`", match.group("inputs")))
    child_refs = tuple(
        _normalize_rulespec_child_hint_ref(ref)
        for ref in re.findall(r"`([^`]+)`", match.group("child_hint"))
        if "#" in ref
    )
    if not shared_inputs or len(child_refs) != 1:
        return None
    return shared_inputs, child_refs[0]


def _normalize_rulespec_child_hint_ref(ref: str) -> str:
    normalized = ref.strip().strip("'\"")
    match = re.match(
        r"^(?P<prefix>[a-z]{2}(?:-[a-z0-9_]+)*):(?P=prefix)/(?P<rest>.+)$",
        normalized,
    )
    if match is not None:
        return f"{match.group('prefix')}:{match.group('rest')}"
    return normalized


def _repair_child_fragment_reencoding_aliases(
    *,
    rules_file: Path,
    policy_repo_path: Path,
    relative_output: Path,
    parsed_issues: list[tuple[tuple[str, ...], str]],
) -> list[str]:
    """Rewrite parent aliases that copy child-local symbols to terminal imports."""
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    imports = payload.get("imports")
    if imports is None:
        imports = []
        payload["imports"] = imports
    if not isinstance(imports, list):
        return []

    repaired: list[str] = []
    for shared_inputs, child_ref in parsed_issues:
        child_name = child_ref.rsplit("#", 1)[1].strip()
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", child_name):
            continue

        shared = set(shared_inputs)
        pending_repaired: list[str] = []
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            rule_name = str(rule.get("name") or "")
            if not rule_name:
                continue
            rewrote = _rewrite_exact_rule_formula_and_proof_alias(
                rule,
                aliases=shared,
                child_ref=child_ref,
                child_name=child_name,
                replacement=child_name,
            )
            if not rewrote:
                continue
            pending_repaired.append(f"{rule_name}->{child_name}")
        if not pending_repaired:
            continue
        if child_ref not in imports:
            imports.append(child_ref)
            repaired.append(f"import:{child_ref}")
        repaired.extend(pending_repaired)

    if not repaired:
        return []

    content = yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
    content, removed_imports = _prune_unused_imports(content)
    for removed in removed_imports:
        repaired.append(f"remove_unused_import:{removed}")
    target_base = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    content, hash_repairs = _repair_proof_import_hashes(
        content,
        target_base=target_base,
        rules_file=rules_file,
        repo_path=policy_repo_path,
    )
    for index in range(hash_repairs):
        repaired.append(f"hash[{index}]")
    rules_file.write_text(content)
    return repaired


def _rewrite_exact_rule_formula_alias(
    rule: dict[str, object],
    *,
    aliases: set[str],
    replacement: str,
) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    changed = False
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        if formula.strip() not in aliases:
            continue
        version["formula"] = replacement
        changed = True
    return changed


def _rewrite_exact_rule_formula_and_proof_alias(
    rule: dict[str, object],
    *,
    aliases: set[str],
    child_ref: str,
    child_name: str,
    replacement: str,
) -> bool:
    """Rewrite a generated direct alias only when its proof can be rewired."""
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    alias_versions: list[dict[str, object]] = []
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        if formula.strip() in aliases:
            alias_versions.append(version)
    if not alias_versions:
        return False
    if not _rewrite_rule_proof_import_alias(
        rule,
        aliases=aliases,
        child_ref=child_ref,
        child_name=child_name,
    ):
        return False
    for version in alias_versions:
        version["formula"] = replacement
    return True


def _rewrite_rule_proof_import_alias(
    rule: dict[str, object],
    *,
    aliases: set[str],
    child_ref: str,
    child_name: str,
) -> bool:
    metadata = rule.get("metadata")
    proof = (
        metadata.get("proof")
        if isinstance(metadata, dict) and isinstance(metadata.get("proof"), dict)
        else rule.get("proof")
    )
    if not isinstance(proof, dict):
        return False
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return False
    changed = False
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        imported = atom.get("import")
        if not isinstance(imported, dict):
            continue
        output = str(imported.get("output") or "").strip()
        target = str(imported.get("target") or "").strip()
        target_name = target.rsplit("#", 1)[1] if "#" in target else ""
        if output not in aliases and target_name not in aliases:
            continue
        imported["target"] = child_ref
        imported["output"] = child_name
        imported["hash"] = "sha256:local"
        changed = True
    return changed


def cmd_repair_missing_deferred_outputs(args):
    """Apply signed deterministic repairs for missing source-gap deferred outputs."""

    def repair(context: argparse.Namespace) -> list[str]:
        repaired = _try_repair_generated_missing_deferred_outputs_for_apply(
            context.result,
            output_root=context.output_root,
            policy_repo_path=context.repo_path,
            issues=context.issues,
        )
        if repaired:
            return repaired
        return _try_repair_generated_mixed_missing_deferred_outputs_for_apply(
            context.result,
            output_root=context.output_root,
            policy_repo_path=context.repo_path,
            issues=context.issues,
        )

    _cmd_repair_generated_validation_issues(
        args,
        model="missing-deferred-output-v1",
        tool="axiom-encode repair-missing-deferred-outputs",
        no_repair_message="No missing deferred output repairs found.",
        success_label="missing deferred output",
        repair=repair,
    )


def cmd_repair_imported_test_inputs(args):
    """Apply signed deterministic repairs for missing imported test inputs."""
    repo_path = Path(args.repo).resolve()
    rules_file = Path(args.file)
    if not rules_file.is_absolute():
        rules_file = repo_path / rules_file
    rules_file = rules_file.resolve()
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    try:
        relative_output = rules_file.relative_to(repo_path)
    except ValueError:
        print(f"RuleSpec file {rules_file} is not under repo {repo_path}")
        sys.exit(1)

    test_file = _rulespec_test_path(rules_file)
    if not test_file.exists():
        print(f"Companion test file not found: {test_file}")
        sys.exit(1)

    original_test_content = test_file.read_text()
    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    pipeline = ValidatorPipeline(
        policy_repo_path=repo_path,
        axiom_rules_path=axiom_rules_path,
        enable_oracles=False,
        require_policy_proofs=False,
    )
    repaired = False
    for _ in range(20):
        validation = pipeline.validate(rules_file, skip_reviewers=True)
        if validation.all_passed:
            break
        issues = [
            result.error for result in validation.results.values() if result.error
        ]
        rewritten_import_output_refs = _rewrite_import_output_test_input_refs(
            test_file=test_file,
            repo_path=repo_path,
            issues=issues,
        )
        removed_refs = _remove_invalid_import_output_test_input_refs(
            test_file=test_file,
            repo_path=repo_path,
            issues=issues,
        )
        repaired_exclusion_refs = _repair_stale_exclusion_dependency_test_input_refs(
            test_file=test_file,
            issues=issues,
        )
        repaired_2014c_refs = _repair_snap_2014c_income_standard_test_inputs(
            test_file=test_file,
            relative_output=relative_output,
            issues=issues,
        )
        repaired_2739_refs = _repair_snap_2739_income_test_inputs(
            test_file=test_file,
            target_base=(
                f"{_repo_jurisdiction_prefix(repo_path)}:"
                f"{_relative_rulespec_import_target(relative_output)}"
            ),
            issues=issues,
        )
        removed_invalid_refs = _remove_invalid_test_input_refs(
            test_file=test_file,
            issues=issues,
        )
        completed_missing_inputs = _complete_missing_imported_test_inputs(
            rules_file=rules_file,
            test_file=test_file,
            repo_path=repo_path,
            validation=validation,
        )
        repaired_output_cases = _repair_imported_output_test_mismatches(
            rules_file=rules_file,
            test_file=test_file,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            issues=issues,
        )
        if (
            not rewritten_import_output_refs
            and not removed_invalid_refs
            and not removed_refs
            and not repaired_exclusion_refs
            and not repaired_2014c_refs
            and not repaired_2739_refs
            and not completed_missing_inputs
            and not repaired_output_cases
        ):
            break
        repaired = True

    if not repaired:
        print("No imported test input repairs found.")
        return

    validation = pipeline.validate(rules_file, skip_reviewers=True)
    if not validation.all_passed:
        test_file.write_text(original_test_content)
        issues = [
            result.error for result in validation.results.values() if result.error
        ]
        print("Repair failed validation; restored original test file.")
        for issue in issues:
            print(f"- {issue}")
        sys.exit(1)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(rules_file.read_text())
        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="imported-test-inputs-v1",
            tool="axiom-encode repair-imported-test-inputs",
            citation=(
                f"{_repo_jurisdiction_prefix(repo_path)}:"
                f"{_relative_rulespec_import_target(relative_output)}"
            ),
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=[rules_file, test_file],
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    print(f"Applied imported test input repair to {relative_output}")
    print(f"manifest={manifest_path}")


def cmd_repair_companion_test_references(args):
    """Apply signed deterministic repairs for stale companion test references."""
    repo_path = Path(args.repo).resolve()
    rules_file = Path(args.file)
    if not rules_file.is_absolute():
        rules_file = repo_path / rules_file
    rules_file = rules_file.resolve()
    if not rules_file.exists():
        print(f"RuleSpec file not found: {rules_file}")
        sys.exit(1)
    try:
        relative_output = rules_file.relative_to(repo_path)
    except ValueError:
        print(f"RuleSpec file {rules_file} is not under repo {repo_path}")
        sys.exit(1)

    test_file = _rulespec_test_path(rules_file)
    if not test_file.exists():
        print(f"Companion test file not found: {test_file}")
        sys.exit(1)

    original_test_content = test_file.read_text()
    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    repaired_refs: list[str] = []
    for _ in range(20):
        failures = _rulespec_companion_test_failures(
            test_file,
            root=repo_path,
            axiom_rules_path=axiom_rules_path,
        )
        if not failures:
            break
        issues = [str(failure.get("message") or "") for failure in failures]
        rewritten_inputs = _rewrite_stale_imported_test_input_refs(
            test_file=test_file,
            repo_path=repo_path,
            issues=issues,
        )
        removed_inputs = _remove_invalid_test_input_refs(
            test_file=test_file,
            issues=issues,
        )
        removed_outputs = _remove_unknown_test_output_refs(
            test_file=test_file,
            issues=issues,
        )
        completed_missing_inputs = False
        missing_input_failures = failures
        if rewritten_inputs or removed_inputs or removed_outputs:
            missing_input_failures = _rulespec_companion_test_failures(
                test_file,
                root=repo_path,
                axiom_rules_path=axiom_rules_path,
            )
        if missing_input_failures:
            completed_missing_inputs = _complete_missing_imported_test_inputs(
                rules_file=rules_file,
                test_file=test_file,
                repo_path=repo_path,
                validation=SimpleNamespace(
                    results={
                        f"companion_{index}": SimpleNamespace(
                            error=_companion_failure_validation_error(failure)
                        )
                        for index, failure in enumerate(missing_input_failures)
                    }
                ),
            )
        if (
            not rewritten_inputs
            and not removed_inputs
            and not removed_outputs
            and not completed_missing_inputs
        ):
            break
        repaired_refs.extend([f"input-rewrite:{ref}" for ref in rewritten_inputs])
        repaired_refs.extend([f"input:{ref}" for ref in removed_inputs])
        repaired_refs.extend([f"output:{ref}" for ref in removed_outputs])
        if completed_missing_inputs:
            repaired_refs.append("input:missing-imported-defaults")

    if not repaired_refs:
        print("No companion test reference repairs found.")
        return

    failures = _rulespec_companion_test_failures(
        test_file,
        root=repo_path,
        axiom_rules_path=axiom_rules_path,
    )
    if failures:
        test_file.write_text(original_test_content)
        print("Repair failed validation; restored original test file.")
        for failure in failures[:50]:
            print(f"- {failure.get('case')}: {failure.get('message')}")
        sys.exit(1)

    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        generated_output = output_root / "deterministic-repair" / relative_output
        generated_output.parent.mkdir(parents=True, exist_ok=True)
        generated_output.write_text(rules_file.read_text())
        result = argparse.Namespace(
            output_file=str(generated_output),
            runner="deterministic-repair",
            backend="deterministic",
            model="companion-test-references-v1",
            tool="axiom-encode repair-companion-test-references",
            citation=(
                f"{_repo_jurisdiction_prefix(repo_path)}:"
                f"{_relative_rulespec_import_target(relative_output)}"
            ),
            generation_prompt_sha256=None,
            trace_file=None,
            context_manifest_file=None,
        )
        manifest_path = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=repo_path,
            relative_output=relative_output,
            applied_files=[rules_file, test_file],
            run_id="deterministic-repair",
            signing_key=signing_key,
            axiom_encode_git=axiom_encode_git,
        )

    print(f"Applied companion test reference repair to {relative_output}")
    print(f"repaired={', '.join(sorted(set(repaired_refs)))}")
    print(f"manifest={manifest_path}")


def _companion_failure_validation_error(failure: dict[str, object]) -> str:
    message = str(failure.get("message") or "")
    case_name = str(failure.get("case") or "").strip()
    if not case_name or not message:
        return message
    if message.startswith(f"{case_name}:") or message.startswith("Test case `"):
        return message
    return f"{case_name}: {message}"


_SECTION_172_C_IMPORT = (
    "us:statutes/26/172/c#deduction_capacity_before_net_operating_loss"
)
_SECTION_172_C_PLACEHOLDER_INPUT = (
    "us:statutes/26/1212/a/1#input."
    "capital_loss_carryback_amount_that_does_not_increase_or_produce_"
    "net_operating_loss_under_section_172_c"
)
_SECTION_172_C_GROSS_INCOME_INPUT = "us:statutes/26/172/c#input.gross_income"
_SECTION_172_C_DEDUCTIONS_BEFORE_INPUT = (
    "us:statutes/26/172/c#input."
    "deductions_allowed_by_this_chapter_before_candidate_deduction_after_"
    "subsection_d_modifications"
)
_SECTION_172_C_PLACEHOLDER_SYMBOL = (
    "capital_loss_carryback_amount_that_does_not_increase_or_produce_"
    "net_operating_loss_under_section_172_c"
)
_SECTION_172_C_CAPACITY_SYMBOL = "deduction_capacity_before_net_operating_loss"


def cmd_repair_section_172_c_capacity(args):
    """Apply signed deterministic repairs for the 1212(a)(1) 172(c) dependency."""
    repo_path = Path(args.repo).resolve()
    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    axiom_rules_path = getattr(
        args, "axiom_rules_path", None
    ) or _resolve_runtime_axiom_rules_checkout(repo_path)

    path_172 = repo_path / "statutes/26/172/c.yaml"
    test_172 = _rulespec_test_path(path_172)
    path_1212 = repo_path / "statutes/26/1212/a/1.yaml"
    test_1212 = _rulespec_test_path(path_1212)
    path_1222 = repo_path / "statutes/26/1222.yaml"
    test_1222 = _rulespec_test_path(path_1222)
    manifest_groups = [
        (Path("statutes/26/172/c.yaml"), [path_172, test_172]),
        (Path("statutes/26/1212/a/1.yaml"), [path_1212, test_1212]),
        (Path("statutes/26/1222.yaml"), [path_1222, test_1222]),
    ]
    _ensure_no_unmanifested_preexisting_rulespec_changes(repo_path, manifest_groups)

    touched = [path_172, test_172, path_1212, test_1212, path_1222, test_1222]
    originals = {
        path: (path.read_text() if path.exists() else None) for path in touched
    }

    try:
        changed: list[Path] = []
        changed.extend(_write_section_172_c_capacity_files(path_172, test_172))
        changed.extend(_repair_1212_section_172_c_cross_reference(path_1212, test_1212))
        changed.extend(_repair_1222_section_172_c_test_inputs(test_1222))
        changed.extend(_refresh_1222_proof_import_hash(path_1222, repo_path))
        changed = _unique_paths(changed)
        if not changed:
            print("No section 172(c) capacity repairs found.")
            return

        pipeline = ValidatorPipeline(
            policy_repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
            enable_oracles=False,
            require_policy_proofs=True,
        )
        validation_files = [path_172, path_1212, path_1222]
        validation_issues: list[str] = []
        for rules_file in validation_files:
            validation = pipeline.validate(rules_file, skip_reviewers=True)
            if validation.all_passed:
                continue
            validation_issues.extend(
                result.error for result in validation.results.values() if result.error
            )
        if validation_issues:
            raise RuntimeError("\n".join(validation_issues))

        test_issues = _companion_test_issues(
            test_files=[test_172, test_1212, test_1222],
            repo_path=repo_path,
            axiom_rules_path=axiom_rules_path,
        )
        if test_issues:
            raise RuntimeError(
                "Companion tests failed after section 172(c) repair:\n"
                + "\n".join(f"- {issue}" for issue in test_issues)
            )
    except Exception:
        _restore_original_files(originals)
        raise

    changed_by_command = _unique_paths(
        [
            path
            for path in changed
            if _path_differs_from_original(path, originals.get(path))
        ]
    )
    if not changed_by_command:
        print("No section 172(c) capacity repairs found.")
        return

    manifest_paths = _write_section_172_c_capacity_manifests(
        repo_path=repo_path,
        signing_key=signing_key,
        axiom_encode_git=axiom_encode_git,
        manifest_groups=manifest_groups,
        changed_files=changed_by_command,
    )
    print("Applied section 172(c) capacity repair")
    for manifest_path in manifest_paths:
        print(f"manifest={manifest_path}")


def _ensure_no_unmanifested_preexisting_rulespec_changes(
    repo_path: Path,
    manifest_groups: list[tuple[Path, list[Path]]],
    *,
    roots: tuple[str, ...] = tuple(sorted(RULESPEC_SOURCE_ROOTS)),
) -> None:
    """Refuse to sign over target files already dirty outside encoder manifests."""
    try:
        changed = set(_git_changed_files(repo_path, base_ref=None, head_ref="HEAD"))
    except RuntimeError as exc:
        raise RuntimeError(
            "Cannot verify pre-existing RuleSpec target changes before signing."
        ) from exc

    dirty_targets: set[str] = set()
    relevant_manifest_paths: set[str] = set()
    for relative_output, files in manifest_groups:
        group_dirty = False
        for path in files:
            relative_path = path.relative_to(repo_path).as_posix()
            if relative_path in changed:
                dirty_targets.add(relative_path)
                group_dirty = True
        if group_dirty:
            relevant_manifest_paths.add(
                _applied_encoding_manifest_path(relative_output).as_posix()
            )
    if not dirty_targets:
        return

    relevant_manifest_paths.update(
        _applied_manifest_paths_for_files(repo_path, relative_files=dirty_targets)
    )
    issues = guard_generated_change_issues(
        repo_path,
        roots=roots,
        changed_files=sorted(dirty_targets | relevant_manifest_paths),
    )
    if not issues:
        return
    raise RuntimeError(
        "Refusing to sign over pre-existing RuleSpec target changes:\n"
        + "\n".join(f"- {issue}" for issue in issues)
    )


def _ensure_generated_dependency_files_safe(
    repo_path: Path,
    *,
    generated_files: dict[Path, str],
) -> None:
    """Refuse to replace non-generated dependency files with templates."""
    if not generated_files:
        return

    manifest_paths = _all_applied_encoding_manifest_paths(repo_path)
    manifest_entries, manifest_issues = _load_applied_encoding_manifest_entries(
        repo_path, manifest_paths
    )
    current_hashes: dict[str, set[str]] = {}
    if not manifest_issues:
        current_hashes = manifest_entries

    issues: list[str] = []
    for path, generated_content in generated_files.items():
        if not path.exists():
            continue
        current_content = path.read_text()
        if current_content == generated_content:
            continue
        relative_path = path.relative_to(repo_path).as_posix()
        current_hash = _sha256_file(path)
        if current_hash in current_hashes.get(relative_path, set()):
            continue
        issues.append(
            f"{relative_path} already exists with content that does not match "
            "the deterministic dependency template or a signed apply manifest"
        )

    if issues:
        raise RuntimeError(
            "Refusing to overwrite existing RuleSpec dependency files:\n"
            + "\n".join(f"- {issue}" for issue in issues)
        )


def _write_section_172_c_capacity_files(
    rules_file: Path, test_file: Path
) -> list[Path]:
    rules_file.parent.mkdir(parents=True, exist_ok=True)
    changed: list[Path] = []
    rules_content = _section_172_c_capacity_rulespec()
    test_content = _section_172_c_capacity_tests()
    if not rules_file.exists() or rules_file.read_text() != rules_content:
        rules_file.write_text(rules_content)
        changed.append(rules_file)
    if not test_file.exists() or test_file.read_text() != test_content:
        test_file.write_text(test_content)
        changed.append(test_file)
    return changed


