def _rewrite_stale_imported_test_input_refs(
    *,
    test_file: Path,
    repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Rewrite stale producer input refs to the producer's current input surface."""
    if not test_file.exists():
        return []
    invalid_refs = {
        ref for ref in _invalid_input_refs_from_issues(issues) if "#input." in ref
    }
    if not invalid_refs:
        return []

    replacements: dict[str, str] = {}
    for input_ref in sorted(invalid_refs):
        replacement = _stale_imported_test_input_replacement(
            input_ref,
            repo_path=repo_path,
        )
        if replacement:
            replacements[input_ref] = replacement
    if not replacements:
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    changed = False
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if _replace_mapping_keys_recursive(inputs, replacements):
            changed = True
    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return sorted(f"{old} -> {new}" for old, new in replacements.items())


def _stale_imported_test_input_replacement(
    input_ref: str,
    *,
    repo_path: Path,
) -> str | None:
    if "#input." not in input_ref:
        return None
    import_base, input_name = input_ref.split("#input.", 1)
    import_base = import_base.strip()
    input_name = input_name.strip()
    if not import_base or not input_name:
        return None
    import_file = _import_base_to_repo_file(import_base, repo_path=repo_path)
    if import_file is None or not import_file.exists():
        return None
    with contextlib.suppress(OSError, ValueError, yaml.YAMLError):
        target_inputs = _local_factual_input_names_from_rules_content(
            import_file.read_text()
        )
        replacement_name = _unique_stale_input_name_replacement(
            input_name,
            target_inputs,
        )
        if replacement_name:
            return f"{import_base}#input.{replacement_name}"
    return None


def _unique_stale_input_name_replacement(
    input_name: str,
    target_input_names: set[str],
) -> str | None:
    if input_name in target_input_names:
        return None
    candidates: list[tuple[float, str]] = []
    for target_input_name in sorted(target_input_names):
        score = _input_name_similarity(input_name, target_input_name)
        if score < 0.5:
            continue
        candidates.append((score, target_input_name))
    if not candidates:
        return None
    candidates.sort(reverse=True)
    best_score, best_name = candidates[0]
    if len(candidates) > 1 and candidates[1][0] == best_score:
        return None
    return best_name


def _stale_exclusion_dependency_input_replacement(input_ref: str) -> str | None:
    if "#input." not in input_ref:
        return None
    input_name = input_ref.split("#input.", 1)[1].strip()
    replacements = {
        _SECTION_151_911_PLACEHOLDER_SYMBOL: _SECTION_911_A_1_SOURCE_INPUT,
        _SECTION_151_931_PLACEHOLDER_SYMBOL: _SECTION_931_SOURCE_INPUT,
        _SECTION_151_933_PLACEHOLDER_SYMBOL: _SECTION_933_SOURCE_INPUT,
    }
    return replacements.get(input_name)


_UNREFERENCED_PROOF_IMPORT_RE = re.compile(
    r"Proof import not referenced:\s*`(?P<rule>[^`]+)`\s+"
    r"proof imports\s+`(?P<symbol>[^`]+)`"
)


def _remove_unreferenced_proof_import_atoms(
    *,
    rules_file: Path,
    issues: list[str],
) -> list[str]:
    if not rules_file.exists():
        return []
    stale_pairs: set[tuple[str, str]] = set()
    for issue in issues:
        for match in _UNREFERENCED_PROOF_IMPORT_RE.finditer(str(issue)):
            stale_pairs.add((match["rule"].strip(), match["symbol"].strip()))
    if not stale_pairs:
        return []

    original_content = rules_file.read_text()
    try:
        payload = yaml.safe_load(original_content) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired_content, removed = _remove_unreferenced_proof_import_atom_blocks(
        original_content,
        stale_pairs=stale_pairs,
    )
    if not removed:
        return []
    repaired_content, pruned_imports = _prune_unused_imports(repaired_content)
    rules_file.write_text(repaired_content)
    return sorted([*removed, *[f"unused_import:{item}" for item in pruned_imports]])


def _remove_unreferenced_proof_import_atom_blocks(
    content: str,
    *,
    stale_pairs: set[tuple[str, str]],
) -> tuple[str, list[str]]:
    lines = content.splitlines(keepends=True)
    repaired_lines: list[str] = []
    removed: list[str] = []
    current_rule = ""
    index = 0

    while index < len(lines):
        line = lines[index]
        rule_match = re.match(r"^\s*-\s+name:\s*(.+?)\s*$", line)
        if rule_match:
            current_rule = _strip_yaml_scalar_quotes(rule_match.group(1).strip())

        item_match = re.match(r"^(\s*)-\s+path:\s*", line)
        if current_rule and item_match:
            block_end = _yaml_list_item_block_end(
                lines,
                start=index,
                start_indent=len(item_match.group(1)),
            )
            block = "".join(lines[index:block_end])
            imported_symbol = _proof_import_atom_block_imported_symbol(block)
            if imported_symbol and (current_rule, imported_symbol) in stale_pairs:
                removed.append(f"{current_rule}:{imported_symbol}")
                index = block_end
                continue

        repaired_lines.append(line)
        index += 1

    return "".join(repaired_lines), removed


def _yaml_list_item_block_end(
    lines: list[str],
    *,
    start: int,
    start_indent: int,
) -> int:
    index = start + 1
    while index < len(lines):
        line = lines[index]
        if line.strip():
            indent = len(line) - len(line.lstrip())
            if indent <= start_indent:
                break
        index += 1
    return index


def _proof_import_atom_block_imported_symbol(block: str) -> str:
    if not re.search(r"(?m)^\s*kind:\s*import\s*$", block):
        return ""
    output_match = re.search(r"(?m)^\s*output:\s*(.+?)\s*$", block)
    if output_match:
        return _strip_yaml_scalar_quotes(output_match.group(1).strip())
    target_match = re.search(r"(?m)^\s*target:\s*(.+?)\s*$", block)
    if not target_match:
        return ""
    target = _strip_yaml_scalar_quotes(target_match.group(1).strip())
    if "#" not in target:
        return ""
    return target.rsplit("#", 1)[1].strip()


def _imported_output_names(rules_file: Path) -> set[str]:
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return set()
    return _imported_output_names_from_payload(payload)


def _imported_output_refs_by_name(rules_file: Path) -> dict[str, str]:
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return {}
    imports = payload.get("imports") if isinstance(payload, dict) else None
    if not isinstance(imports, list):
        return {}
    refs_by_name: dict[str, str] = {}
    for raw_import in imports:
        if not isinstance(raw_import, str) or "#" not in raw_import:
            continue
        fragment = raw_import.rsplit("#", 1)[1].strip()
        if re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", fragment):
            refs_by_name.setdefault(fragment, raw_import)
    return refs_by_name


def _imported_output_names_from_payload(payload: object) -> set[str]:
    imports = payload.get("imports") if isinstance(payload, dict) else None
    if not isinstance(imports, list):
        return set()
    names: set[str] = set()
    for raw_import in imports:
        if not isinstance(raw_import, str) or "#" not in raw_import:
            continue
        fragment = raw_import.rsplit("#", 1)[1].strip()
        if re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", fragment):
            names.add(fragment)
    return names


def _input_ref_targets_producer_output(
    input_ref: str,
    *,
    repo_path: Path,
) -> bool:
    """True when `<base>#input.X` names a rule produced by the file at <base>.

    Distinct from `_input_ref_is_import_output_placeholder` which checks the
    producer's *imports*. Here we check the producer's own `rules:` block —
    if X is produced as a rule output, the consumer should reference it
    without the `input.` prefix.
    """
    if "#input." not in input_ref:
        return False
    import_base, input_name = input_ref.split("#input.", 1)
    import_base = import_base.strip()
    input_name = input_name.strip()
    if not import_base or not input_name:
        return False
    import_file = _import_base_to_repo_file(import_base, repo_path=repo_path)
    if import_file is None or not import_file.exists():
        return False
    return input_name in _producer_rule_names(import_file)


def _producer_rule_names(rules_file: Path) -> set[str]:
    """Return the set of `rules[].name` values declared in a RuleSpec file."""
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return set()
    if not isinstance(payload, dict):
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    names: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = rule.get("name")
        if isinstance(name, str) and name:
            names.add(name)
    return names


def _deferred_output_names(rules_file: Path) -> set[str]:
    """Return output fragments declared under `module.deferred_outputs`."""
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return set()
    if not isinstance(payload, dict):
        return set()
    module = payload.get("module")
    if not isinstance(module, dict):
        return set()
    deferred_outputs = module.get("deferred_outputs")
    if not isinstance(deferred_outputs, list):
        return set()

    names: set[str] = set()
    for record in deferred_outputs:
        if not isinstance(record, dict):
            continue
        output = str(record.get("output") or "").strip()
        if "#" not in output:
            continue
        fragment = output.rsplit("#", 1)[1].strip()
        if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", fragment):
            names.add(fragment)
    return names


def _input_ref_is_import_output_placeholder(
    input_ref: str,
    *,
    repo_path: Path,
) -> bool:
    if "#input." not in input_ref:
        return False
    import_base, input_name = input_ref.split("#input.", 1)
    import_base = import_base.strip()
    input_name = input_name.strip()
    if not import_base or not input_name:
        return False
    import_file = _import_base_to_repo_file(import_base, repo_path=repo_path)
    if import_file is None or not import_file.exists():
        return False
    return input_name in _imported_output_names(import_file)


def _invalid_input_refs_from_issues(issues: list[str]) -> set[str]:
    refs: set[str] = set()
    patterns = (
        r"dataset input `(?P<input>[^`]+)` must use an absolute legal RuleSpec reference",
        r"input `(?P<input>[^`]+)` does not resolve to an input slot",
    )
    for issue in issues:
        text = str(issue)
        for pattern in patterns:
            for match in re.finditer(pattern, text):
                refs.add(match.group("input").strip())
    return refs


def _computed_output_input_refs_from_issues(issues: list[str]) -> set[str]:
    refs: set[str] = set()
    for issue in issues:
        text = str(issue)
        if "assigns computed RuleSpec output(s) as input" not in text:
            continue
        for ref in re.findall(r"`([^`]+#[A-Za-z_][A-Za-z0-9_]*)`", text):
            if "#input." not in ref and "#relation." not in ref:
                refs.add(ref.strip())
    return refs


def _unresolved_test_input_refs_from_issues(issues: list[str]) -> set[str]:
    refs: set[str] = set()
    pattern = (
        r"input `(?P<input>[^`]+)` points to a RuleSpec file that could not be "
        r"resolved"
    )
    for issue in issues:
        for match in re.finditer(pattern, str(issue)):
            refs.add(match.group("input").strip())
    return refs


def _current_target_replacement_for_near_ref_typo(
    input_ref: str,
    *,
    target_base: str,
) -> str | None:
    if "#input." not in input_ref:
        return None
    input_base, fragment = input_ref.split("#", 1)
    if input_base == target_base or not fragment.startswith("input."):
        return None

    input_jurisdiction = _rulespec_ref_jurisdiction(input_base)
    target_jurisdiction = _rulespec_ref_jurisdiction(target_base)
    if input_jurisdiction and input_jurisdiction != target_jurisdiction:
        return None

    input_tail = _rulespec_ref_without_jurisdiction(input_base).strip("/")
    target_tail = _rulespec_ref_without_jurisdiction(target_base).strip("/")
    if not input_tail or not target_tail:
        return None

    input_parts = Path(input_tail).parts
    target_parts = Path(target_tail).parts
    if (
        len(input_parts) != len(target_parts)
        or not input_parts
        or input_parts[0] != target_parts[0]
        or input_parts[-1] != target_parts[-1]
    ):
        return None

    similarity = difflib.SequenceMatcher(None, input_tail, target_tail).ratio()
    if similarity < 0.97:
        return None
    return f"{target_base}#{fragment}"


def _rulespec_ref_jurisdiction(ref: str) -> str | None:
    if ":" not in ref:
        return None
    prefix, tail = ref.split(":", 1)
    if "/" in prefix or "#" in prefix or not tail:
        return None
    return prefix


def _mixed_derived_output_case_names(issues: list[str]) -> set[str]:
    return {
        match.group("case").strip()
        for issue in issues
        for match in _MIXED_DERIVED_OUTPUT_ENTITIES_RE.finditer(str(issue))
    }


def _delegated_policy_setting_issue_texts(issues: list[str]) -> list[str]:
    return [
        str(issue)
        for issue in issues
        if _issue_mentions_delegated_policy_setting(str(issue))
    ]


def _ordered_unique_strings(values: list[str]) -> list[str]:
    return list(dict.fromkeys(str(value) for value in values if str(value)))


def _unknown_output_refs_from_issues(issues: list[str]) -> set[str]:
    refs: set[str] = set()
    for issue in issues:
        text = str(issue)
        for match in re.finditer(r"unknown executable output (?P<output>\S+)", text):
            refs.add(match.group("output").strip())
        for match in _UNRESOLVED_TEST_OUTPUT_ISSUE_PATTERN.finditer(text):
            refs.add(match.group(1).strip())
    return refs


def _expand_refs_with_matching_test_input_keys(
    value: object,
    refs: set[str],
) -> set[str]:
    if not refs:
        return set()
    tails = {_rulespec_ref_without_jurisdiction(ref) for ref in refs}
    expanded = set(refs)
    for key in _mapping_keys_recursive(value):
        key_text = str(key)
        if "#input." not in key_text:
            continue
        if _rulespec_ref_without_jurisdiction(key_text) in tails:
            expanded.add(key_text)
    return expanded


def _expand_refs_with_matching_test_output_keys(
    value: object,
    refs: set[str],
) -> set[str]:
    if not refs:
        return set()
    tails = {_rulespec_ref_without_jurisdiction(ref) for ref in refs}
    expanded = set(refs)
    for test_case in value if isinstance(value, list) else []:
        if not isinstance(test_case, dict):
            continue
        outputs = test_case.get("output")
        if not isinstance(outputs, dict):
            continue
        for key in outputs:
            key_text = str(key)
            if _rulespec_ref_without_jurisdiction(key_text) in tails:
                expanded.add(key_text)
    return expanded


def _mapping_keys_recursive(value: object) -> list[object]:
    keys: list[object] = []
    if isinstance(value, dict):
        for key, child in value.items():
            keys.append(key)
            keys.extend(_mapping_keys_recursive(child))
    elif isinstance(value, list):
        for item in value:
            keys.extend(_mapping_keys_recursive(item))
    return keys


def _rulespec_ref_without_jurisdiction(ref: str) -> str:
    if ":" not in ref:
        return ref
    prefix, tail = ref.split(":", 1)
    if "/" in prefix or "#" in prefix or not tail:
        return ref
    return tail


def _rulespec_ref_base_without_jurisdiction(ref: str) -> str:
    return _rulespec_ref_without_jurisdiction(ref.split("#", 1)[0].strip())


def _rulespec_ref_matches_base(ref: str, base: str) -> bool:
    ref_base = ref.split("#", 1)[0].strip()
    base = base.strip()
    return ref_base == base or (
        _rulespec_ref_base_without_jurisdiction(ref)
        == _rulespec_ref_base_without_jurisdiction(base)
    )


def _matching_mapping_key_by_rulespec_ref(
    mapping: dict[object, object],
    ref: str,
) -> object | None:
    if ref in mapping:
        return ref
    ref_tail = _rulespec_ref_without_jurisdiction(ref)
    for key in mapping:
        key_text = str(key)
        if _rulespec_ref_without_jurisdiction(key_text) == ref_tail:
            return key
    return None


def _remove_mapping_keys_recursive(value: object, keys: set[str]) -> bool:
    changed = False
    if isinstance(value, dict):
        for key in list(value.keys()):
            if str(key) in keys:
                del value[key]
                changed = True
                continue
            if _remove_mapping_keys_recursive(value[key], keys):
                changed = True
    elif isinstance(value, list):
        for item in value:
            if _remove_mapping_keys_recursive(item, keys):
                changed = True
    return changed


def _replace_mapping_keys_recursive(
    value: object, replacements: dict[str, str]
) -> bool:
    changed = False
    if isinstance(value, dict):
        for key in list(value.keys()):
            key_text = str(key)
            if key_text in replacements:
                old_value = value.pop(key)
                new_key = replacements[key_text]
                if new_key not in value:
                    value[new_key] = old_value
                changed = True
                continue
            if _replace_mapping_keys_recursive(value[key], replacements):
                changed = True
    elif isinstance(value, list):
        for item in value:
            if _replace_mapping_keys_recursive(item, replacements):
                changed = True
    return changed


def _zero_branch_output_names_from_issues(issues: list[str]) -> list[str]:
    output_names: list[str] = []
    seen: set[str] = set()
    for issue in issues:
        match = re.search(
            r"Zero branch test coverage missing:\s*`(?P<name>[^`]+)`",
            str(issue),
        )
        if not match:
            continue
        name = match["name"].strip()
        if not name or name in seen:
            continue
        seen.add(name)
        output_names.append(name)
    return output_names


def _local_factual_input_names_from_rules_content(rules_content: str) -> set[str]:
    try:
        payload = yaml.safe_load(rules_content) or {}
    except yaml.YAMLError:
        return set()
    if not isinstance(payload, dict):
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    factual_inputs: set[str] = set()

    defined_symbols = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    defined_symbols.update(_imported_output_names_from_payload(payload))
    dsl_symbols = {
        "abs",
        "and",
        "ceil",
        "count_where",
        "else",
        "elif",
        "false",
        "floor",
        "if",
        "len",
        "match",
        "max",
        "min",
        "not",
        "or",
        "round",
        "sum",
        "sum_where",
        "true",
    }
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            scrubbed_formula = re.sub(r"'[^']*'|\"[^\"]*\"", " ", formula)
            identifiers = set(
                re.findall(r"\b[A-Za-z_][A-Za-z0-9_]*\b", scrubbed_formula)
            )
            factual_inputs.update(identifiers - defined_symbols - dsl_symbols)
    return factual_inputs


def _has_zero_output_test(test_cases: object, target: str) -> bool:
    if not isinstance(test_cases, list):
        return False
    normalized_target = target.strip()
    for test_case in test_cases:
        if not isinstance(test_case, dict):
            continue
        outputs = test_case.get("output")
        if not isinstance(outputs, dict):
            continue
        for key, value in outputs.items():
            if str(key).strip() != normalized_target:
                continue
            if _is_generated_zero_expected_value(value):
                return True
    return False


def _is_generated_zero_expected_value(value: object) -> bool:
    if isinstance(value, bool) or value is None:
        return False
    if isinstance(value, list | tuple):
        return any(_is_generated_zero_expected_value(item) for item in value)
    if isinstance(value, int | float):
        return float(value) == 0.0
    if isinstance(value, str):
        with contextlib.suppress(ValueError):
            return float(value.strip()) == 0.0
        return False
    if isinstance(value, dict):
        raw_value = value.get("value")
        if isinstance(raw_value, dict):
            return _is_generated_zero_expected_value(raw_value.get("value"))
        return _is_generated_zero_expected_value(raw_value)
    return False


def cmd_retire(args):
    """Delete live RuleSpec files and sign deletion entries for the guard."""
    repo_path = Path(args.policy_repo_path).resolve()
    signing_key = _require_applied_encoding_manifest_signing_key()
    roots = tuple(sorted(RULESPEC_SOURCE_ROOTS))

    targets: list[Path] = []
    for raw in args.paths:
        relative = Path(raw)
        if relative.is_absolute():
            try:
                relative = relative.relative_to(repo_path)
            except ValueError:
                raise SystemExit(
                    f"{raw} is not inside the policy repo {repo_path}"
                ) from None
        if not _is_protected_rulespec_yaml_path(relative, roots=roots):
            raise SystemExit(f"{relative.as_posix()} is not a protected RuleSpec path")
        if not (repo_path / relative).exists():
            raise SystemExit(f"{relative.as_posix()} does not exist")
        targets.append(relative)
        if relative.suffixes[-2:] != [".test", ".yaml"]:
            companion = relative.with_name(relative.stem + ".test.yaml")
            if (repo_path / companion).exists():
                targets.append(companion)

    seen: set[str] = set()
    unique_targets: list[Path] = []
    for target in targets:
        if target.as_posix() not in seen:
            seen.add(target.as_posix())
            unique_targets.append(target)

    manifests_rewritten: list[Path] = []
    for target in unique_targets:
        if target.suffixes[-2:] == [".test", ".yaml"]:
            continue
        companion = target.with_name(target.stem + ".test.yaml")
        covered = [entry for entry in unique_targets if entry in (target, companion)]
        manifest_path = repo_path / _applied_encoding_manifest_path(target)
        # Carry the encoding's prior manifest forward so the audit chain
        # (model, run id, encode provenance) survives the retirement.
        retired_manifest = None
        if manifest_path.exists():
            with contextlib.suppress(json.JSONDecodeError, OSError):
                retired_manifest = json.loads(manifest_path.read_text())
        payload = {
            "schema_version": APPLIED_ENCODING_MANIFEST_SCHEMA,
            "tool": "axiom-encode retire",
            "reason": args.reason,
            "axiom_encode_git": _git_repo_provenance(_axiom_encode_repo_root()),
            "applied_files": [
                {"path": entry.as_posix(), "deleted": True} for entry in covered
            ],
            "retired_manifest": retired_manifest,
        }
        _sign_applied_encoding_manifest(payload, signing_key)
        manifest_path.parent.mkdir(parents=True, exist_ok=True)
        manifest_path.write_text(json.dumps(payload, indent=2) + "\n")
        manifests_rewritten.append(manifest_path.relative_to(repo_path))

    for target in unique_targets:
        (repo_path / target).unlink()
        print(f"retired {target.as_posix()}")
    for manifest in manifests_rewritten:
        print(f"signed {manifest.as_posix()}")


def guard_generated_change_issues(
    repo_path: Path,
    *,
    base_ref: str | None = None,
    head_ref: str = "HEAD",
    roots: tuple[str, ...] = tuple(sorted(RULESPEC_SOURCE_ROOTS)),
    changed_files: list[str] | None = None,
    all_files: bool = False,
) -> list[str]:
    """Return issues for RuleSpec changes that do not match apply manifests."""
    repo_path = Path(repo_path)
    if all_files:
        changed = []
        protected = _all_protected_rulespec_yaml_paths(repo_path, roots=roots)
    else:
        changed = (
            changed_files
            if changed_files is not None
            else _git_changed_files(repo_path, base_ref=base_ref, head_ref=head_ref)
        )
        protected = [
            path
            for path in changed
            if _is_protected_rulespec_yaml_path(Path(path), roots=roots)
        ]
    if not protected:
        return []

    manifest_paths = (
        _all_applied_encoding_manifest_paths(repo_path, roots=roots)
        if all_files
        else [
            path
            for path in changed
            if _is_applied_encoding_manifest_path(Path(path), roots=roots)
        ]
    )
    if not manifest_paths:
        if all_files:
            return [
                f"{path} is missing a matching {APPLIED_ENCODING_MANIFEST_DIR.as_posix()} manifest"
                for path in protected
            ]
        return [
            f"{path} changed without a matching {APPLIED_ENCODING_MANIFEST_DIR.as_posix()} manifest"
            for path in protected
        ]

    # Manifests deleted in the same change set are not consulted: the
    # protected files they covered must be accounted for (as content or
    # deletion entries) by a changed manifest that still exists. Missing
    # manifests are only reported when coverage actually fails below.
    surviving_manifest_paths = [
        path for path in manifest_paths if (repo_path / path).exists()
    ]
    missing_manifest_paths = [
        path for path in manifest_paths if not (repo_path / path).exists()
    ]
    manifest_entries, manifest_issues = _load_applied_encoding_manifest_entries(
        repo_path, surviving_manifest_paths, roots=roots
    )
    if manifest_issues:
        return manifest_issues

    issues: list[str] = []
    for path in protected:
        expected_hashes = manifest_entries.get(path)
        if expected_hashes is None:
            if all_files:
                issues.append(
                    f"{path} is missing a matching {APPLIED_ENCODING_MANIFEST_DIR.as_posix()} manifest"
                )
            else:
                issues.append(
                    f"{path} changed but is not listed in a changed encoder apply manifest"
                )
            continue
        current_path = repo_path / path
        if APPLIED_ENCODING_DELETED_MARKER in expected_hashes:
            if current_path.exists():
                issues.append(
                    f"{path} is listed as deleted in an encoder apply manifest "
                    "but still exists in the working tree"
                )
            continue
        if not current_path.exists():
            issues.append(f"{path} changed but does not exist in the working tree")
            continue
        current_hash = _sha256_file(current_path)
        if current_hash not in expected_hashes:
            issues.append(
                f"{path} content does not match the encoder apply manifest sha256"
            )
    if issues:
        issues.extend(
            f"{Path(path).as_posix()} does not exist in the working tree"
            for path in missing_manifest_paths
        )
    return issues


def _all_protected_rulespec_yaml_paths(
    repo_path: Path, *, roots: tuple[str, ...]
) -> list[str]:
    paths: set[str] = set()
    base_dirs: set[Path] = set()
    for parent in [repo_path, *[path for path in repo_path.iterdir() if path.is_dir()]]:
        if parent.name in {".git", ".axiom", ".venv", "__pycache__"}:
            continue
        base_dirs.update(parent / root for root in roots)
    for base in sorted(base_dirs):
        if not base.exists() or not base.is_dir():
            continue
        for suffix in ("*.yaml", "*.yml"):
            for path in base.rglob(suffix):
                if not path.is_file():
                    continue
                relative = path.relative_to(repo_path)
                if _is_protected_rulespec_yaml_path(relative, roots=roots):
                    paths.add(relative.as_posix())
    return sorted(paths)


def _all_applied_encoding_manifest_paths(
    repo_path: Path, *, roots: tuple[str, ...] = tuple(sorted(RULESPEC_SOURCE_ROOTS))
) -> list[str]:
    manifest_roots = [repo_path / APPLIED_ENCODING_MANIFEST_DIR]
    manifest_roots.extend(
        repo_path / root / APPLIED_ENCODING_MANIFEST_DIR for root in roots
    )
    paths: set[str] = set()
    for manifest_root in manifest_roots:
        if not manifest_root.exists():
            continue
        paths.update(
            path.relative_to(repo_path).as_posix()
            for path in manifest_root.rglob("*.json")
            if path.is_file()
        )
    return sorted(paths)


def _git_changed_files(
    repo_path: Path, *, base_ref: str | None, head_ref: str
) -> list[str]:
    if base_ref:
        diff_range = f"{base_ref}...{head_ref}"
        command = ["git", "diff", "--name-only", "--diff-filter=ACDMRT", diff_range]
    else:
        command = ["git", "diff", "--name-only", "--diff-filter=ACDMRT", head_ref]
    completed = subprocess.run(
        command,
        cwd=repo_path,
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        check=False,
    )
    if completed.returncode != 0 and base_ref:
        completed = subprocess.run(
            ["git", "diff", "--name-only", "--diff-filter=ACDMRT", base_ref, head_ref],
            cwd=repo_path,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
        )
    if completed.returncode != 0:
        raise RuntimeError(completed.stderr.strip() or "git diff failed")
    changed = [line.strip() for line in completed.stdout.splitlines() if line.strip()]
    if base_ref is None:
        untracked = subprocess.run(
            ["git", "ls-files", "--others", "--exclude-standard"],
            cwd=repo_path,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
        )
        if untracked.returncode != 0:
            raise RuntimeError(untracked.stderr.strip() or "git ls-files failed")
        changed.extend(
            line.strip() for line in untracked.stdout.splitlines() if line.strip()
        )
    return sorted(set(changed))


def _protected_rulespec_root_index(path: Path, *, roots: tuple[str, ...]) -> int | None:
    parts = path.parts
    if len(parts) < 2:
        return None
    if parts[0] not in roots:
        if (
            len(parts) >= 3
            and parts[1] in roots
            and re.fullmatch(r"[a-z]{2}(?:-[a-z0-9_]+)*", parts[0])
        ):
            return 1
        return None
    return 0


def _is_protected_rulespec_yaml_path(path: Path, *, roots: tuple[str, ...]) -> bool:
    return (
        path.suffix in {".yaml", ".yml"}
        and _protected_rulespec_root_index(path, roots=roots) is not None
    )


def _is_applied_encoding_manifest_path(path: Path, *, roots: tuple[str, ...]) -> bool:
    if path.suffix != ".json":
        return False
    return _applied_encoding_manifest_root_prefix(path, roots=roots) is not None


def _applied_encoding_manifest_root_prefix(
    path: Path, *, roots: tuple[str, ...]
) -> str | None:
    parts = path.parts
    manifest_parts = APPLIED_ENCODING_MANIFEST_DIR.parts
    if parts[: len(manifest_parts)] == manifest_parts:
        return ""
    if (
        len(parts) > len(manifest_parts)
        and parts[0] in roots
        and parts[1 : 1 + len(manifest_parts)] == manifest_parts
    ):
        return parts[0]
    return None


def _load_applied_encoding_manifest_entries(
    repo_path: Path,
    manifest_paths: list[str],
    *,
    roots: tuple[str, ...] = tuple(sorted(RULESPEC_SOURCE_ROOTS)),
) -> tuple[dict[str, set[str]], list[str]]:
    entries: dict[str, set[str]] = defaultdict(set)
    issues: list[str] = []
    signing_key = _applied_encoding_manifest_signing_key()
    if not signing_key:
        return (
            entries,
            [
                f"{APPLIED_ENCODING_SIGNING_KEY_ENV} is required to verify encoder apply manifests"
            ],
        )

    for manifest_path in manifest_paths:
        manifest_label = Path(manifest_path).as_posix()
        root_prefix = _applied_encoding_manifest_root_prefix(
            Path(manifest_path), roots=roots
        )
        if root_prefix is None:
            continue
        path = repo_path / manifest_path
        if not path.exists():
            issues.append(f"{manifest_label} does not exist in the working tree")
            continue
        try:
            payload = json.loads(path.read_text())
        except json.JSONDecodeError:
            issues.append(f"{manifest_label} is not valid JSON")
            continue
        if payload.get("schema_version") != APPLIED_ENCODING_MANIFEST_SCHEMA:
            issues.append(f"{manifest_label} is not an encoder apply manifest")
            continue
        signature_issue = _applied_encoding_manifest_signature_issue(
            payload, signing_key
        )
        if signature_issue:
            issues.append(f"{manifest_label} {signature_issue}")
            continue
        applied_files = payload.get("applied_files")
        if not isinstance(applied_files, list):
            issues.append(f"{manifest_label} does not list applied files")
            continue
        for item in applied_files:
            if not isinstance(item, dict):
                continue
            file_path = item.get("path")
            file_hash = item.get("sha256")
            if isinstance(file_path, str) and item.get("deleted") is True:
                entries[_prefix_applied_manifest_path(file_path, root_prefix)].add(
                    APPLIED_ENCODING_DELETED_MARKER
                )
            elif isinstance(file_path, str) and isinstance(file_hash, str):
                entries[_prefix_applied_manifest_path(file_path, root_prefix)].add(
                    file_hash
                )
    return dict(entries), issues


def _prefix_applied_manifest_path(file_path: str, root_prefix: str) -> str:
    if not root_prefix:
        return file_path
    return Path(root_prefix, file_path).as_posix()


def _applied_encoding_manifest_signing_key() -> str | None:
    key = os.getenv(APPLIED_ENCODING_SIGNING_KEY_ENV, "")
    return key if key else None


def _require_applied_encoding_manifest_signing_key() -> str:
    key = _applied_encoding_manifest_signing_key()
    if not key:
        raise RuntimeError(
            f"{APPLIED_ENCODING_SIGNING_KEY_ENV} is required to apply generated RuleSpec changes"
        )
    return key


def _unsigned_applied_encoding_manifest_bytes(payload: dict) -> bytes:
    unsigned_payload = dict(payload)
    unsigned_payload.pop("signature", None)
    return json.dumps(
        unsigned_payload,
        sort_keys=True,
        separators=(",", ":"),
        ensure_ascii=True,
    ).encode()


def _applied_encoding_manifest_signature(payload: dict, signing_key: str) -> str:
    return hmac.new(
        signing_key.encode(),
        _unsigned_applied_encoding_manifest_bytes(payload),
        hashlib.sha256,
    ).hexdigest()


def _sign_applied_encoding_manifest(payload: dict, signing_key: str) -> None:
    payload["signature"] = {
        "algorithm": APPLIED_ENCODING_SIGNATURE_ALGORITHM,
        "key_id": APPLIED_ENCODING_SIGNATURE_KEY_ID,
        "value": _applied_encoding_manifest_signature(payload, signing_key),
    }


def _applied_encoding_manifest_signature_issue(
    payload: dict, signing_key: str
) -> str | None:
    signature = payload.get("signature")
    if not isinstance(signature, dict):
        return "is missing an encoder apply manifest signature"
    if signature.get("algorithm") != APPLIED_ENCODING_SIGNATURE_ALGORITHM:
        return "uses an unsupported encoder apply manifest signature algorithm"
    if signature.get("key_id") != APPLIED_ENCODING_SIGNATURE_KEY_ID:
        return "uses an unknown encoder apply manifest signing key"
    expected = _applied_encoding_manifest_signature(payload, signing_key)
    actual = signature.get("value")
    if not isinstance(actual, str) or not hmac.compare_digest(actual, expected):
        return "has an invalid encoder apply manifest signature"
    return None


def _axiom_encode_repo_root() -> Path:
    return Path(__file__).resolve().parents[2]


def _git_repo_provenance(path: Path) -> dict[str, object] | None:
    """Return exact git provenance for manifest auditing."""
    repo = Path(path)
    try:
        root = subprocess.run(
            ["git", "-C", str(repo), "rev-parse", "--show-toplevel"],
            capture_output=True,
            check=True,
            text=True,
        ).stdout.strip()
        commit = subprocess.run(
            ["git", "-C", str(repo), "rev-parse", "HEAD"],
            capture_output=True,
            check=True,
            text=True,
        ).stdout.strip()
        status = subprocess.run(
            ["git", "-C", str(repo), "status", "--porcelain", "--untracked-files=no"],
            capture_output=True,
            check=True,
            text=True,
        ).stdout
    except (OSError, subprocess.CalledProcessError):
        return None
    return {
        "root": root,
        "commit": commit,
        "dirty_tracked": bool(status.strip()),
    }


_AXIOM_ENCODE_VERSION_FILES = (
    "pyproject.toml",
    "src/axiom_encode/__init__.py",
    "uv.lock",
)
_AXIOM_ENCODE_VERSIONED_PREFIXES = ("src/axiom_encode/",)
_AXIOM_ENCODE_VERSIONED_FILES = {
    "pyproject.toml",
    "uv.lock",
}


def _require_axiom_encode_version_provenance(
    repo_root: Path,
) -> dict[str, str]:
    """Require encoder-affecting code changes to be behind a version bump."""
    repo = Path(repo_root)
    current_versions = _axiom_encode_versions_at_ref(repo, "HEAD")
    pyproject_version = current_versions.get("pyproject")
    package_version = current_versions.get("package")
    lock_version = current_versions.get("lock")
    if not pyproject_version or not package_version or not lock_version:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: axiom-encode version metadata is "
            "incomplete; pyproject.toml, src/axiom_encode/__init__.py, and "
            "uv.lock must declare the encoder version."
        )
    if (
        pyproject_version != package_version
        or pyproject_version != lock_version
        or pyproject_version != __version__
    ):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: axiom-encode version metadata is "
            f"inconsistent (pyproject={pyproject_version}, "
            f"package={package_version}, lock={lock_version}, "
            f"runtime={__version__})."
        )

    version_commit = _latest_axiom_encode_version_commit(repo)
    if not version_commit:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: no committed axiom-encode version "
            "bump was found; bump the encoder version before using --apply."
        )

    changed_since_version = _git_name_only(
        repo,
        "diff",
        "--name-only",
        "--diff-filter=ACMRT",
        f"{version_commit}..HEAD",
    )
    unversioned_encoder_changes = [
        path for path in changed_since_version if _is_axiom_encode_versioned_path(path)
    ]
    if unversioned_encoder_changes:
        display = ", ".join(f"`{path}`" for path in unversioned_encoder_changes[:8])
        if len(unversioned_encoder_changes) > 8:
            display += f", and {len(unversioned_encoder_changes) - 8} more"
        raise RuntimeError(
            "Cannot apply generated RuleSpec: encoder-affecting files changed "
            "after the latest axiom-encode version bump "
            f"({version_commit[:12]}): {display}. Bump the encoder version "
            "and commit that bump before using --apply."
        )

    return {
        "version": pyproject_version,
        "version_commit": version_commit,
    }


def _latest_axiom_encode_version_commit(repo: Path) -> str | None:
    commits = _git_name_only(
        repo,
        "log",
        "--format=%H",
        "--",
        *_AXIOM_ENCODE_VERSION_FILES,
    )
    for commit in commits:
        current = _axiom_encode_versions_at_ref(repo, commit)
        if not current.get("pyproject") or not current.get("package"):
            continue
        parent = _git_first_parent(repo, commit)
        if parent is None:
            return commit
        previous = _axiom_encode_versions_at_ref(repo, parent)
        if _axiom_encode_version_increased(current, previous):
            return commit
    return None


def _axiom_encode_version_increased(
    current: dict[str, str | None],
    previous: dict[str, str | None],
) -> bool:
    current_version = current.get("pyproject")
    previous_version = previous.get("pyproject")
    if not current_version:
        return False
    if not previous_version:
        return True
    current_key = _parse_numeric_version(current_version)
    previous_key = _parse_numeric_version(previous_version)
    if current_key is None or previous_key is None:
        return current_version > previous_version
    return current_key > previous_key


def _parse_numeric_version(version: str) -> tuple[int, ...] | None:
    parts = version.split(".")
    if not parts or any(not re.fullmatch(r"\d+", part) for part in parts):
        return None
    return tuple(int(part) for part in parts)


def _git_first_parent(repo: Path, commit: str) -> str | None:
    try:
        line = subprocess.run(
            ["git", "-C", str(repo), "rev-list", "--parents", "-n", "1", commit],
            capture_output=True,
            check=True,
            text=True,
        ).stdout.strip()
    except (OSError, subprocess.CalledProcessError):
        return None
    parts = line.split()
    return parts[1] if len(parts) > 1 else None


def _axiom_encode_versions_at_ref(repo: Path, ref: str) -> dict[str, str | None]:
    return {
        "pyproject": _extract_pyproject_version(
            _git_show_text(repo, ref, "pyproject.toml") or ""
        ),
        "package": _extract_package_init_version(
            _git_show_text(repo, ref, "src/axiom_encode/__init__.py") or ""
        ),
        "lock": _extract_uv_lock_version(_git_show_text(repo, ref, "uv.lock") or ""),
    }


def _git_show_text(repo: Path, ref: str, path: str) -> str | None:
    try:
        return subprocess.run(
            ["git", "-C", str(repo), "show", f"{ref}:{path}"],
            capture_output=True,
            check=True,
            text=True,
        ).stdout
    except (OSError, subprocess.CalledProcessError):
        return None


def _git_name_only(repo: Path, *args: str) -> list[str]:
    try:
        completed = subprocess.run(
            ["git", "-C", str(repo), *args],
            capture_output=True,
            check=True,
            text=True,
        )
    except (OSError, subprocess.CalledProcessError) as exc:
        stderr = getattr(exc, "stderr", "") or ""
        raise RuntimeError(stderr.strip() or "git provenance command failed") from exc
    return [line.strip() for line in completed.stdout.splitlines() if line.strip()]


def _extract_pyproject_version(content: str) -> str | None:
    match = re.search(r'(?m)^version\s*=\s*"([^"]+)"\s*$', content)
    return match.group(1) if match else None


def _extract_package_init_version(content: str) -> str | None:
    match = re.search(r'(?m)^__version__\s*=\s*"([^"]+)"\s*$', content)
    return match.group(1) if match else None


def _extract_uv_lock_version(content: str) -> str | None:
    package_block = re.search(
        r'(?ms)^\[\[package\]\]\s*^name\s*=\s*"axiom-encode"\s*^version\s*=\s*"([^"]+)"',
        content,
    )
    return package_block.group(1) if package_block else None


def _is_axiom_encode_versioned_path(path: str) -> bool:
    return path in _AXIOM_ENCODE_VERSIONED_FILES or path.startswith(
        _AXIOM_ENCODE_VERSIONED_PREFIXES
    )


def _require_clean_axiom_encode_git_provenance() -> dict[str, object]:
    provenance = _git_repo_provenance(_axiom_encode_repo_root())
    if provenance is None or not provenance.get("commit"):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: axiom-encode git provenance is "
            "unavailable; commit the encoder build before using --apply."
        )
    if provenance.get("dirty_tracked"):
        raise RuntimeError(
            "Cannot apply generated RuleSpec from a dirty axiom-encode checkout; "
            "commit or discard encoder changes before using --apply."
        )
    version_provenance = _require_axiom_encode_version_provenance(
        Path(str(provenance["root"]))
    )
    provenance.update(version_provenance)
    return provenance


