def _try_repair_generated_embedded_scalar_literals_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path | None = None,
    issues: list[str],
) -> list[str]:
    """Extract CI-reported formula scalar literals into named parameters."""
    records = _embedded_scalar_literal_issue_records(issues)
    if not records:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    original_content = rules_file.read_text()
    try:
        payload = yaml.safe_load(original_content) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    source_paths = _rulespec_module_source_paths(payload)

    target_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    existing_names = {
        str(rule.get("name") or "").strip() for rule in rules if isinstance(rule, dict)
    }
    repaired: list[str] = []
    for record in records:
        changed = _extract_embedded_scalar_literal_record(
            rules,
            record,
            target_anchor=target_anchor,
            existing_names=existing_names,
            corpus_citation_path=source_paths[0] if source_paths else None,
        )
        if changed:
            repaired.append(changed)
            existing_names.add(changed)

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _embedded_scalar_literal_issue_records(
    issues: list[str],
) -> list[dict[str, str]]:
    records: list[dict[str, str]] = []
    pattern = re.compile(
        r"Embedded scalar literal:\s+"
        r"(?P<rule>[A-Za-z_][A-Za-z0-9_]*)\s+line\s+\d+\s+"
        r"embeds\s+(?P<literal>-?\d+(?:\.\d+)?)\s+in\s+`(?P<expression>[^`]+)`"
    )
    for issue in issues:
        match = pattern.search(issue)
        if match is None:
            continue
        records.append(match.groupdict())
    return records


def _embedded_scalar_literal_issue_keys(
    issues: list[str],
) -> set[tuple[str, str, str]]:
    return {
        (record["rule"], record["literal"], record["expression"])
        for record in _embedded_scalar_literal_issue_records(issues)
    }


def _repair_embedded_scalar_literals(
    content: str,
    *,
    relative_output: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> tuple[str, list[str]]:
    records = _embedded_scalar_literal_issue_records(issues)
    if not records:
        return content, []
    try:
        payload = yaml.safe_load(content) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return content, []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return content, []
    source_paths = _rulespec_module_source_paths(payload)
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return content, []

    target_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    existing_names = {
        str(rule.get("name") or "").strip() for rule in rules if isinstance(rule, dict)
    }
    repaired: list[str] = []
    for record in records:
        changed = _extract_embedded_scalar_literal_record(
            rules,
            record,
            target_anchor=target_anchor,
            existing_names=existing_names,
            corpus_citation_path=source_paths[0] if source_paths else None,
        )
        if changed:
            repaired.append(changed)
            existing_names.add(changed)

    if not repaired:
        return content, []
    return (
        yaml.safe_dump(payload, sort_keys=False, allow_unicode=False),
        repaired,
    )


def _try_repair_generated_bare_snapunit_entity_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Scope generated assistance-group rules to Household when SnapUnit is undeclared."""
    records = _bare_snapunit_entity_issue_records(issues)
    if not records:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        content = rules_file.read_text()
        payload = yaml.safe_load(content) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    if _declares_or_imports_snapunit_relation(payload):
        return []
    source_text_value = extract_embedded_source_text(content)
    if not source_text_value:
        module = payload.get("module")
        if isinstance(module, dict):
            fallback_source_text = module.get("source_text")
            if isinstance(fallback_source_text, str):
                source_text_value = fallback_source_text
            if not source_text_value:
                fallback_summary = module.get("summary")
                if isinstance(fallback_summary, str):
                    source_text_value = fallback_summary
    source_text = (source_text_value or "").lower()
    if "snapunit" in source_text or "snap unit" in source_text:
        return []
    if "basic food" in source_text:
        return []
    if "assistance group" not in source_text and "household" not in source_text:
        return []

    requested_names = {record["rule"] for record in records}
    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        if str(rule.get("entity") or "").strip() != "SnapUnit":
            continue
        if name not in requested_names and not _rule_mentions_assistance_group(rule):
            continue
        rule["entity"] = "Household"
        repaired.append(name)

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _try_repair_generated_unsupported_entity_outputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Defer generated outputs that use an undeclared filtered entity."""
    records = _unsupported_entity_issue_records(issues)
    if not records:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    rules_by_name = {
        str(rule.get("name") or "").strip(): rule
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    unsupported_entities_by_rule: dict[str, str] = {}
    for record in records:
        rule_name = str(record.get("rule") or "").strip()
        entity = str(record.get("entity") or "").strip()
        rule = rules_by_name.get(rule_name)
        if not isinstance(rule, dict):
            continue
        if str(rule.get("entity") or "").strip() != entity:
            continue
        unsupported_entities_by_rule[rule_name] = entity
    if not unsupported_entities_by_rule:
        return []

    affected_rules = _expand_unsupported_entity_generated_rules(
        rules_by_name=rules_by_name,
        unsupported_entities_by_rule=unsupported_entities_by_rule,
    )
    if not affected_rules:
        return []

    base_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    module = payload.setdefault("module", {})
    if not isinstance(module, dict):
        return []
    deferred_outputs = module.setdefault("deferred_outputs", [])
    if not isinstance(deferred_outputs, list):
        return []
    existing_outputs = {
        str(record.get("output") or "").strip()
        for record in deferred_outputs
        if isinstance(record, dict)
    }

    unsupported_entities = sorted(set(unsupported_entities_by_rule.values()))
    entity_list = ", ".join(unsupported_entities)
    ordered_affected_rules = [
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("name") or "").strip() in affected_rules
    ]
    deferred_targets: list[str] = []
    for rule_name in ordered_affected_rules:
        rule = rules_by_name.get(rule_name)
        if not isinstance(rule, dict):
            continue
        output = _deferred_output_target_for_generated_rule(
            rule_name=rule_name,
            rule=rule,
            base_anchor=base_anchor,
        )
        if not output:
            continue
        if output not in existing_outputs:
            deferred_outputs.append(
                {
                    "output": output,
                    "reason": (
                        "Generated output depends on an undeclared filtered "
                        f"entity ({entity_list}). It is deferred until that "
                        "entity relation is encoded or imported instead of "
                        "inventing the entity surface locally."
                    ),
                }
            )
            existing_outputs.add(output)
        deferred_targets.append(output)

    if not deferred_targets:
        return []

    payload["rules"] = [
        rule
        for rule in rules
        if not (
            isinstance(rule, dict)
            and str(rule.get("name") or "").strip() in affected_rules
        )
    ]
    if not payload["rules"]:
        module.setdefault("status", "deferred")
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    _remove_generated_test_outputs_for_deferred_rules(
        test_file=_rulespec_test_path(rules_file),
        base_anchor=base_anchor,
        rule_names=affected_rules,
    )
    return deferred_targets


def _unsupported_entity_issue_records(issues: list[str]) -> list[dict[str, str]]:
    records: list[dict[str, str]] = []
    pattern = re.compile(
        r"Filtered entity dependency missing:\s+"
        r"`(?P<rule>[A-Za-z_][A-Za-z0-9_]*)`\s+uses\s+"
        r"`entity:\s+(?P<entity>[A-Za-z_][A-Za-z0-9_]*)`"
    )
    for issue in issues:
        match = pattern.search(str(issue))
        if match is None:
            continue
        records.append(match.groupdict())
    return records


def _expand_unsupported_entity_generated_rules(
    *,
    rules_by_name: dict[str, dict[str, Any]],
    unsupported_entities_by_rule: dict[str, str],
) -> set[str]:
    affected = set(unsupported_entities_by_rule)
    unsupported_entities = set(unsupported_entities_by_rule.values())
    changed = True
    while changed:
        changed = False
        affected_suffixes = {
            _top_level_source_suffix_from_rule_source(
                str(rules_by_name[rule_name].get("source") or ""),
            )
            for rule_name in affected
            if rule_name in rules_by_name
        }
        affected_suffixes.discard("")

        for rule_name, rule in rules_by_name.items():
            if rule_name in affected:
                continue
            identifiers = _generated_rule_formula_identifiers(rule)
            should_add_dependent = bool(identifiers.intersection(affected))
            should_add_dependency = any(
                rule_name in _generated_rule_formula_identifiers(rules_by_name[name])
                for name in affected
                if name in rules_by_name
            )
            if not should_add_dependent and not should_add_dependency:
                continue
            if not _is_unsupported_entity_helper_rule(
                rule,
                unsupported_entities=unsupported_entities,
                affected_suffixes=affected_suffixes,
            ):
                continue
            affected.add(rule_name)
            changed = True
    return affected


def _is_unsupported_entity_helper_rule(
    rule: dict[str, Any],
    *,
    unsupported_entities: set[str],
    affected_suffixes: set[str],
) -> bool:
    kind = str(rule.get("kind") or "").strip().lower()
    if kind not in {"derived", "parameter", "source_value", "data_relation"}:
        return False
    entity = str(rule.get("entity") or "").strip()
    if entity in unsupported_entities:
        return True
    if entity:
        return False
    source_suffix = _top_level_source_suffix_from_rule_source(
        str(rule.get("source") or ""),
    )
    return bool(source_suffix and source_suffix in affected_suffixes)


def _try_repair_generated_predecessor_scalar_limits_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path | None = None,
    issues: list[str],
) -> list[str]:
    """Rewrite generated scalar limits that are one below an existing maximum."""
    literals = _ungrounded_numeric_literal_issue_values(issues)
    if not literals:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    target_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    return _repair_predecessor_scalar_limits(
        rules_file,
        ungrounded_literals=literals,
        target_anchor=target_anchor,
    )


def _try_repair_generated_source_child_corpus_paths_for_apply(
    result,
    *,
    output_root: Path,
    rules_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Point generated source verification at the matching child corpus row."""
    repaired_sources = _try_repair_generated_source_subparagraph_rule_sources_for_apply(
        result,
        issues=issues,
    )
    if repaired_sources:
        return repaired_sources

    literals = _ungrounded_numeric_literal_issue_values(issues)
    if not literals:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    child_corpus_path = _relative_output_to_child_corpus_citation_path(
        relative_output,
        rules_repo_path=rules_repo_path,
    )
    if child_corpus_path is None:
        return []
    child_source_text = _local_source_text_for_corpus_path(
        child_corpus_path,
        rules_repo_path=rules_repo_path,
    )
    if not child_source_text:
        return []
    source_numbers = extract_numbers_from_text(child_source_text)
    if not all(
        numeric_value_is_grounded(float(value), source_numbers) for value in literals
    ):
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    existing_source_paths = _rulespec_module_source_paths(payload)
    parent_paths = [
        path
        for path in existing_source_paths
        if _corpus_citation_path_is_parent_of(path, child_corpus_path)
    ]
    if not parent_paths:
        return []

    changed = _replace_corpus_citation_paths(
        payload,
        old_paths=set(parent_paths),
        new_path=child_corpus_path,
    )
    if not changed:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return [f"{path}->{child_corpus_path}" for path in parent_paths]


def _try_repair_generated_source_subparagraph_rule_sources_for_apply(
    result,
    *,
    issues: list[str],
) -> list[str]:
    """Add canonical child corpus citations to rules that cover source gaps."""
    source_gaps = [
        gap
        for issue in issues
        if "Source sub-paragraph coverage missing" in str(issue)
        for gap in [_parse_source_coverage_gap_issue(str(issue))]
        if gap is not None
    ]
    if not source_gaps:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list) or not rules:
        return []

    repaired: list[str] = []
    for citation, excerpt in source_gaps:
        label = _source_coverage_gap_top_level_label(citation)
        if not label:
            continue
        rule = _best_rule_for_source_coverage_gap(
            rules,
            label=label,
            excerpt=excerpt,
            citation=citation,
        )
        if rule is None:
            continue
        source = str(rule.get("source") or "").strip()
        if citation in source:
            continue
        rule["source"] = _append_source_citation(source, citation)
        name = str(rule.get("name") or "rules[]").strip()
        repaired.append(f"{name}->{citation}")

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _source_coverage_gap_top_level_label(citation: str) -> str:
    match = re.search(r"\(([A-Za-z0-9]+)\)\s*$", str(citation or ""))
    return match.group(1).lower() if match is not None else ""


def _append_source_citation(source: str, citation: str) -> str:
    citation = citation.strip()
    if not source:
        return citation
    if source.endswith((".", ";")):
        return f"{source} {citation}"
    return f"{source}; {citation}"


def _best_rule_for_source_coverage_gap(
    rules: list[object],
    *,
    label: str,
    excerpt: str,
    citation: str,
) -> dict[str, object] | None:
    best_rule: dict[str, object] | None = None
    best_score = 0
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if not _is_executable_rulespec_rule(rule):
            continue
        source = str(rule.get("source") or "").strip()
        if citation in source:
            continue
        score = _source_gap_rule_match_score(rule, label=label, excerpt=excerpt)
        if score > best_score:
            best_rule = rule
            best_score = score
    if best_score <= 0:
        return None
    return best_rule


_SOURCE_GAP_RULE_MATCH_STOPWORDS = {
    "a",
    "an",
    "and",
    "are",
    "as",
    "based",
    "be",
    "by",
    "can",
    "cannot",
    "each",
    "for",
    "from",
    "has",
    "if",
    "in",
    "is",
    "it",
    "level",
    "monthly",
    "of",
    "on",
    "or",
    "program",
    "sets",
    "size",
    "standard",
    "standards",
    "tanf",
    "the",
    "to",
    "used",
    "which",
}


def _source_gap_rule_match_score(
    rule: dict[str, object],
    *,
    label: str,
    excerpt: str,
) -> int:
    source = str(rule.get("source") or "")
    source_lower = source.lower()
    score = 0
    if re.search(rf"\({re.escape(label)}\)", source_lower):
        score += 50
    if re.search(rf"\(\d+\)\s*\({re.escape(label)}\)", source_lower):
        score += 20

    excerpt_tokens = _source_gap_match_tokens(excerpt)
    if not excerpt_tokens:
        return score
    name_tokens = _source_gap_match_tokens(str(rule.get("name") or ""))
    source_tokens = _source_gap_match_tokens(source)
    metadata_tokens = _source_gap_match_tokens(
        _rulespec_rule_metadata_search_text(rule)
    )
    score += 8 * len(excerpt_tokens & name_tokens)
    score += 3 * len(excerpt_tokens & source_tokens)
    score += 2 * len(excerpt_tokens & metadata_tokens)
    return score


def _source_gap_match_tokens(text: str) -> set[str]:
    tokens = {
        token
        for token in re.findall(r"[a-z0-9]+", str(text or "").lower())
        if len(token) > 2 and token not in _SOURCE_GAP_RULE_MATCH_STOPWORDS
    }
    if "employment" in tokens or "employed" in tokens:
        tokens.add("employment")
    return tokens


def _rulespec_rule_metadata_search_text(rule: dict[str, object]) -> str:
    metadata = rule.get("metadata")
    if not isinstance(metadata, (dict, list)):
        return ""

    values: list[str] = []

    def collect(value: object) -> None:
        if isinstance(value, str):
            values.append(value)
            return
        if isinstance(value, dict):
            for item in value.values():
                collect(item)
            return
        if isinstance(value, list):
            for item in value:
                collect(item)

    collect(metadata)
    return " ".join(values)


def _relative_output_to_child_corpus_citation_path(
    relative_output: Path,
    *,
    rules_repo_path: Path,
) -> str | None:
    """Convert a RuleSpec output path to its expected corpus citation path."""
    rel = Path(relative_output).with_suffix("")
    parts = rel.parts
    if len(parts) < 2:
        return None
    if parts[0] in RULESPEC_SOURCE_ROOTS:
        jurisdiction = _repo_jurisdiction_prefix(rules_repo_path)
        source_root = parts[0]
        tail = parts[1:]
    elif len(parts) >= 3 and parts[1] in RULESPEC_SOURCE_ROOTS:
        jurisdiction = parts[0]
        source_root = parts[1]
        tail = parts[2:]
    else:
        return None
    corpus_source_root = {
        "policies": "policy",
        "regulations": "regulation",
        "statutes": "statute",
    }.get(source_root)
    if corpus_source_root is None or not tail:
        return None
    return f"{jurisdiction}/{corpus_source_root}/{Path(*tail).as_posix()}"


def _local_source_text_for_corpus_path(
    corpus_citation_path: str,
    *,
    rules_repo_path: Path,
) -> str | None:
    for corpus_path in _candidate_local_axiom_corpus_paths(rules_repo_path):
        source_text = _fetch_local_corpus_source_text_from_repo(
            corpus_citation_path,
            corpus_path,
        )
        if source_text:
            return source_text
    return None


def _candidate_local_axiom_corpus_paths(rules_repo_path: Path) -> list[Path]:
    candidates: list[Path] = []
    env_path = os.environ.get("AXIOM_CORPUS_REPO")
    if env_path:
        candidates.append(Path(env_path).expanduser())
    rules_repo = Path(rules_repo_path).resolve()
    candidates.extend(
        [
            rules_repo.parent / "axiom-corpus",
            rules_repo.parent.parent / "axiom-corpus",
            _resolve_repo_checkout("axiom-corpus"),
        ]
    )
    seen: set[Path] = set()
    resolved: list[Path] = []
    for candidate in candidates:
        with contextlib.suppress(OSError):
            candidate = candidate.resolve()
        if candidate in seen or not candidate.exists():
            continue
        seen.add(candidate)
        resolved.append(candidate)
    return resolved


def _corpus_citation_path_is_parent_of(parent: str, child: str) -> bool:
    normalized_parent = parent.strip().strip("/")
    normalized_child = child.strip().strip("/")
    return bool(
        normalized_parent
        and normalized_child.startswith(f"{normalized_parent}/")
        and normalized_parent != normalized_child
    )


def _replace_corpus_citation_paths(
    value: object,
    *,
    old_paths: set[str],
    new_path: str,
) -> bool:
    normalized_old = {path.strip().strip("/") for path in old_paths if path.strip()}

    def normalize_path(path: object) -> str:
        return str(path or "").strip().strip("/")

    changed = False
    if isinstance(value, dict):
        for key, item in list(value.items()):
            if key == "corpus_citation_path" and isinstance(item, str):
                if normalize_path(item) in normalized_old:
                    value[key] = new_path
                    changed = True
                continue
            if key == "corpus_citation_paths" and isinstance(item, list):
                next_items: list[object] = []
                seen_paths: set[str] = set()
                for entry in item:
                    next_entry = (
                        new_path
                        if isinstance(entry, str)
                        and normalize_path(entry) in normalized_old
                        else entry
                    )
                    if isinstance(next_entry, str):
                        normalized = normalize_path(next_entry)
                        if normalized in seen_paths:
                            changed = True
                            continue
                        seen_paths.add(normalized)
                    if next_entry != entry:
                        changed = True
                    next_items.append(next_entry)
                if next_items != item:
                    value[key] = next_items
                continue
            if _replace_corpus_citation_paths(
                item, old_paths=old_paths, new_path=new_path
            ):
                changed = True
    elif isinstance(value, list):
        for item in value:
            if _replace_corpus_citation_paths(
                item, old_paths=old_paths, new_path=new_path
            ):
                changed = True
    return changed


def _ungrounded_numeric_literal_issue_values(issues: list[str]) -> set[int]:
    values: set[int] = set()
    pattern = re.compile(r"Ungrounded generated numeric literal:\s+(-?\d+)(?:\D|$)")
    for issue in issues:
        match = pattern.search(str(issue))
        if match is None:
            continue
        try:
            values.add(int(match.group(1)))
        except ValueError:
            continue
    return values


def _repair_predecessor_scalar_limits(
    rules_file: Path,
    *,
    ungrounded_literals: set[int],
    target_anchor: str | None = None,
) -> list[str]:
    if not rules_file.exists() or not ungrounded_literals:
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    numeric_parameter_formulas: dict[int, list[str]] = {}
    referenced_names = _formula_referenced_names(rules)
    maximum_parameter_names = [
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("name") or "").strip()
        and _is_maximum_parameter_name(str(rule.get("name") or "").strip())
    ]
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        name = str(rule.get("name") or "").strip()
        value = _single_integer_formula(rule)
        if not name or value is None:
            continue
        numeric_parameter_formulas.setdefault(value, []).append(name)

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        name = str(rule.get("name") or "").strip()
        if not (name.endswith("_scalar_limit") or _is_maximum_parameter_name(name)):
            continue
        if name not in referenced_names:
            continue
        literal = _single_integer_formula(rule)
        if literal is None or literal not in ungrounded_literals:
            continue
        predecessor_of = _single_predecessor_maximum_parameter(
            numeric_parameter_formulas.get(literal + 1, [])
        )
        if predecessor_of is None:
            predecessor_of = _single_predecessor_maximum_name_parameter(
                name,
                maximum_parameter_names,
            )
        if predecessor_of is None:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        changed = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            if str(version.get("formula") or "").strip() == str(literal):
                version["formula"] = f"{predecessor_of} - 1"
                changed = True
        if not changed:
            continue
        if target_anchor:
            _add_formula_proof_import(
                rule,
                target=f"{target_anchor}#{predecessor_of}",
                output=predecessor_of,
            )
        repaired.append(name)

    repaired = list(dict.fromkeys(repaired))
    if repaired:
        rules_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )
    return repaired


def _formula_referenced_names(rules: list[Any]) -> set[str]:
    rule_names = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    referenced: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        own_name = str(rule.get("name") or "").strip()
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            for token in re.findall(r"\b[A-Za-z_][A-Za-z0-9_]*\b", formula):
                if token != own_name and token in rule_names:
                    referenced.add(token)
    return referenced


def _single_integer_formula(rule: dict[str, Any]) -> int | None:
    versions = rule.get("versions")
    if not isinstance(versions, list) or not versions:
        return None
    values: set[int] = set()
    for version in versions:
        if not isinstance(version, dict):
            return None
        formula = version.get("formula")
        if not isinstance(formula, str):
            return None
        text = formula.strip()
        if not re.fullmatch(r"-?\d+", text):
            return None
        try:
            values.add(int(text))
        except ValueError:
            return None
    if len(values) != 1:
        return None
    return next(iter(values))


def _single_predecessor_maximum_parameter(candidates: list[str]) -> str | None:
    maximum_candidates = [
        candidate for candidate in candidates if _is_maximum_parameter_name(candidate)
    ]
    if len(maximum_candidates) != 1:
        return None
    return maximum_candidates[0]


def _is_maximum_parameter_name(name: str) -> bool:
    return name.startswith("maximum_") or name.startswith("max_")


def _single_predecessor_maximum_name_parameter(
    name: str,
    maximum_parameter_names: list[str],
) -> str | None:
    """Infer a grounded maximum predecessor from a generated maximum helper name."""
    if not _is_maximum_parameter_name(name):
        return None
    name_tokens = name.split("_")
    candidates: list[str] = []
    for candidate in maximum_parameter_names:
        if candidate == name:
            continue
        candidate_tokens = candidate.split("_")
        if len(candidate_tokens) >= len(name_tokens):
            continue
        if not _tokens_are_ordered_subsequence(candidate_tokens, name_tokens):
            continue
        if not _maximum_names_share_structural_suffix(candidate_tokens, name_tokens):
            continue
        candidates.append(candidate)
    if len(candidates) != 1:
        return None
    return candidates[0]


def _tokens_are_ordered_subsequence(
    candidate_tokens: list[str],
    name_tokens: list[str],
) -> bool:
    position = 0
    for token in name_tokens:
        if position < len(candidate_tokens) and candidate_tokens[position] == token:
            position += 1
    return position == len(candidate_tokens)


def _maximum_names_share_structural_suffix(
    candidate_tokens: list[str],
    name_tokens: list[str],
) -> bool:
    suffix_length = min(3, len(candidate_tokens), len(name_tokens))
    return (
        suffix_length > 0
        and candidate_tokens[-suffix_length:] == name_tokens[-suffix_length:]
    )


def _bare_snapunit_entity_issue_records(issues: list[str]) -> list[dict[str, str]]:
    records: list[dict[str, str]] = []
    pattern = re.compile(
        r"Filtered entity dependency missing:\s+"
        r"`(?P<rule>[A-Za-z_][A-Za-z0-9_]*)`\s+uses\s+`entity:\s+SnapUnit`"
    )
    for issue in issues:
        match = pattern.search(issue)
        if match is None:
            continue
        records.append(match.groupdict())
    return records


def _declares_or_imports_snapunit_relation(payload: dict[str, Any]) -> bool:
    imports = payload.get("imports")
    if isinstance(imports, list):
        for item in imports:
            if isinstance(item, str) and item.rsplit("#", 1)[-1].strip() == "snap_unit":
                return True
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return False
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived_relation":
            continue
        relation = rule.get("derived_relation")
        if not isinstance(relation, dict):
            continue
        if str(relation.get("entity") or "").strip() == "SnapUnit":
            return True
    return False


def _rule_mentions_assistance_group(rule: dict[str, Any]) -> bool:
    text_parts: list[str] = []
    for key in ("name", "source"):
        value = rule.get(key)
        if isinstance(value, str):
            text_parts.append(value)
    proof = rule.get("metadata", {}).get("proof")
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    if isinstance(atoms, list):
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source = atom.get("source")
            if not isinstance(source, dict):
                continue
            excerpt = source.get("excerpt")
            if isinstance(excerpt, str):
                text_parts.append(excerpt)
    haystack = " ".join(text_parts).lower()
    return "assistance_group" in haystack or "assistance group" in haystack


def _extract_embedded_scalar_literal_record(
    rules: list[Any],
    record: dict[str, str],
    *,
    target_anchor: str,
    existing_names: set[str],
    corpus_citation_path: str | None = None,
) -> str | None:
    rule_name = record["rule"]
    literal = record["literal"]
    expression = record["expression"]
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        if str(rule.get("name") or "").strip() != rule_name:
            continue
        parameter_name = _embedded_scalar_parameter_name(rule_name, expression)
        if not parameter_name:
            return None
        parameter_formula = (
            _grounded_formula_literal_for_scalar_expression(rule, expression) or literal
        )
        replace_expression = parameter_formula != literal
        existing_parameter_name = _existing_embedded_scalar_parameter_name(
            rules,
            base_name=parameter_name,
            literal=parameter_formula,
        )
        insert_parameter = existing_parameter_name is None
        if existing_parameter_name is not None:
            parameter_name = existing_parameter_name
        else:
            parameter_name = _unique_generated_rule_name(
                parameter_name,
                existing_names,
            )
        versions = rule.get("versions")
        if not isinstance(versions, list) or not versions:
            return None
        changed = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            if replace_expression:
                replacement = _replace_embedded_scalar_expression(
                    formula,
                    expression=expression,
                    parameter_name=parameter_name,
                )
            else:
                replacement = _replace_embedded_scalar_literal(
                    formula,
                    literal=literal,
                    expression=expression,
                    parameter_name=parameter_name,
                )
            if replacement != formula:
                version["formula"] = replacement
                changed = True
        if not changed:
            return None
        _add_formula_proof_import(
            rule,
            target=f"{target_anchor}#{parameter_name}",
            output=parameter_name,
        )
        if insert_parameter:
            parameter_rule = _embedded_scalar_parameter_rule(
                rule,
                name=parameter_name,
                literal=parameter_formula,
                corpus_citation_path=corpus_citation_path,
            )
            rules.insert(index, parameter_rule)
        return parameter_name
    return None


def _grounded_formula_literal_for_scalar_expression(
    rule: dict[str, Any],
    expression: str,
) -> str | None:
    """Collapse generated fraction helpers when the source grounds the value."""
    value = _simple_fraction_expression_value(expression)
    if value is None:
        return None
    source_numbers: set[float] = set()
    proof = rule.get("metadata", {}).get("proof")
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    if isinstance(atoms, list):
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source = atom.get("source")
            if not isinstance(source, dict):
                continue
            excerpt = source.get("excerpt")
            if isinstance(excerpt, str):
                source_numbers.update(extract_numbers_from_text(excerpt))
    if not source_numbers or not numeric_value_is_grounded(value, source_numbers):
        return None
    return _format_grounded_scalar_formula_literal(value)


def _simple_fraction_expression_value(expression: str) -> float | None:
    match = re.fullmatch(
        r"\s*(-?\d+(?:\.\d+)?)\s*/\s*(-?\d+(?:\.\d+)?)\s*",
        expression,
    )
    if match is None:
        return None
    try:
        denominator = Decimal(match.group(2))
    except InvalidOperation:
        return None
    if denominator == 0:
        return None
    try:
        numerator = Decimal(match.group(1))
        with localcontext() as ctx:
            ctx.prec = 18
            return float(numerator / denominator)
    except (InvalidOperation, ValueError, OverflowError):
        return None


def _format_grounded_scalar_formula_literal(value: float) -> str:
    if math.isfinite(value) and math.isclose(value, round(value), abs_tol=1e-12):
        return str(int(round(value)))
    return f"{value:.6f}".rstrip("0").rstrip(".")


def _embedded_scalar_parameter_name(rule_name: str, expression: str) -> str | None:
    if re.search(r"\bmin\s*\(", expression) and rule_name.endswith("_size_category"):
        return f"{rule_name.removesuffix('_size_category')}_max_household_size"
    if re.search(r"\bmax\s*\(", expression):
        return f"{rule_name}_floor"
    return f"{rule_name}_scalar_limit"


def _existing_embedded_scalar_parameter_name(
    rules: list[Any],
    *,
    base_name: str,
    literal: str,
) -> str | None:
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("name") or "").strip() != base_name:
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            return None
        versions = rule.get("versions")
        if not isinstance(versions, list):
            return None
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if str(formula).strip() == literal:
                return base_name
    return None


def _replace_embedded_scalar_literal(
    formula: str,
    *,
    literal: str,
    expression: str,
    parameter_name: str,
) -> str:
    expression_replacement = re.sub(
        rf"(?<![A-Za-z0-9_.]){re.escape(literal)}(?![A-Za-z0-9_.])",
        parameter_name,
        expression,
    )
    if (
        expression.strip() != literal
        and expression_replacement != expression
        and expression in formula
    ):
        formula = formula.replace(expression, expression_replacement, 1)
    return re.sub(
        rf"(?<![A-Za-z0-9_.]){re.escape(literal)}(?![A-Za-z0-9_.])",
        parameter_name,
        formula,
    )


def _replace_embedded_scalar_expression(
    formula: str,
    *,
    expression: str,
    parameter_name: str,
) -> str:
    if expression.strip() and expression in formula:
        return formula.replace(expression, parameter_name)
    return formula


def _embedded_scalar_parameter_rule(
    source_rule: dict[str, Any],
    *,
    name: str,
    literal: str,
    corpus_citation_path: str | None = None,
) -> dict[str, Any]:
    first_effective_from = "0001-01-01"
    versions = source_rule.get("versions")
    if isinstance(versions, list):
        for version in versions:
            if not isinstance(version, dict):
                continue
            effective_from = version.get("effective_from")
            if isinstance(effective_from, str) and effective_from.strip():
                first_effective_from = effective_from.strip()
                break
    parameter_rule: dict[str, Any] = {
        "name": name,
        "kind": "parameter",
        "dtype": "Count",
        "source": source_rule.get("source"),
        "metadata": {
            "proof": {
                "atoms": [
                    _source_atom_for_embedded_scalar_parameter(
                        source_rule,
                        literal=literal,
                        corpus_citation_path=corpus_citation_path,
                    )
                ]
            }
        },
        "versions": [
            {
                "effective_from": first_effective_from,
                "formula": literal,
            }
        ],
    }
    if not parameter_rule["source"]:
        parameter_rule.pop("source", None)
    return parameter_rule


def _source_atom_for_embedded_scalar_parameter(
    source_rule: dict[str, Any],
    *,
    literal: str,
    corpus_citation_path: str | None = None,
) -> dict[str, Any]:
    proof = source_rule.get("metadata", {}).get("proof")
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    fallback_source: dict[str, Any] | None = None
    if isinstance(atoms, list):
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source = atom.get("source")
            if not isinstance(source, dict):
                continue
            if fallback_source is None:
                fallback_source = dict(source)
            excerpt = source.get("excerpt")
            if isinstance(excerpt, str) and literal in excerpt:
                return {
                    "path": "versions[0].formula",
                    "kind": "parameter",
                    "source": dict(source),
                }
    if fallback_source is not None:
        return {
            "path": "versions[0].formula",
            "kind": "parameter",
            "source": fallback_source,
        }
    if corpus_citation_path:
        source: dict[str, Any] = {"corpus_citation_path": corpus_citation_path}
        span = source_rule.get("source")
        if isinstance(span, str) and span.strip():
            source["span"] = span.strip()
        return {
            "path": "versions[0].formula",
            "kind": "parameter",
            "source": source,
        }
    return {
        "path": "versions[0].formula",
        "kind": "parameter",
    }


def _add_formula_proof_import(
    rule: dict[str, Any],
    *,
    target: str,
    output: str,
) -> None:
    metadata = rule.setdefault("metadata", {})
    if not isinstance(metadata, dict):
        metadata = {}
        rule["metadata"] = metadata
    proof = metadata.setdefault("proof", {})
    if not isinstance(proof, dict):
        proof = {}
        metadata["proof"] = proof
    atoms = proof.setdefault("atoms", [])
    if not isinstance(atoms, list):
        atoms = []
        proof["atoms"] = atoms
    if any(
        isinstance(atom, dict)
        and isinstance(atom.get("import"), dict)
        and atom["import"].get("target") == target
        for atom in atoms
    ):
        return
    atoms.append(
        {
            "path": "versions[0].formula",
            "kind": "import",
            "import": {
                "target": target,
                "output": output,
                "hash": "sha256:local",
            },
        }
    )


def _try_repair_generated_delegated_policy_settings_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path | None = None,
    issues: list[str],
) -> list[str]:
    """Insert canonical state `sets` edges for generated delegated settings."""
    if not any(_issue_mentions_delegated_policy_setting(issue) for issue in issues):
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    original_content = rules_file.read_text()
    try:
        payload = yaml.safe_load(original_content) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    target_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    resolved_setting_targets = _resolved_executable_delegated_setting_targets(
        _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS,
        current_payload=payload,
        current_rules_file=rules_file,
        policy_repo_path=policy_repo_path,
    )
    unresolved_setting_targets = {
        normalized
        for setting_target in _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS
        if (normalized := _normalize_source_relation_target_ref(setting_target.target))
        not in resolved_setting_targets
    }
    repaired: list[str] = []
    repaired.extend(
        _drop_unresolved_delegated_setting_sets_relations(
            payload,
            rules,
            unresolved_targets=unresolved_setting_targets,
        )
    )
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return repaired
    existing_names = {
        str(rule.get("name") or "").strip() for rule in rules if isinstance(rule, dict)
    }
    source_relation_additions: list[dict[str, Any]] = []
    wrapper_additions: list[dict[str, Any]] = []
    retargeted_wrappers, retargeted_relations = (
        _repair_delegated_setting_relation_targets(
            rules,
            current_payload=payload,
            current_rules_file=rules_file,
            policy_repo_path=policy_repo_path,
            target_anchor=target_anchor,
            existing_names=existing_names,
            resolvable_targets=set(resolved_setting_targets),
        )
    )
    if retargeted_wrappers:
        wrapper_additions.extend(retargeted_wrappers)
        for wrapper_rule in retargeted_wrappers:
            wrapper_name = str(wrapper_rule.get("name") or "").strip()
            if wrapper_name:
                existing_names.add(wrapper_name)
    repaired.extend(retargeted_relations)
    for setting_target in _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS:
        normalized_setting_target = _normalize_source_relation_target_ref(
            setting_target.target
        )
        target_rule = resolved_setting_targets.get(normalized_setting_target or "")
        if target_rule is None:
            continue
        target_kind = _rulespec_rule_kind(target_rule)
        existing_relation = _generated_source_relation_for_target(
            rules,
            setting_target.target,
        )
        if existing_relation is not None:
            existing_repair = _repair_delegated_setting_relation_value_kind(
                existing_relation,
                rules,
                current_payload=payload,
                current_rules_file=rules_file,
                policy_repo_path=policy_repo_path,
                target_anchor=target_anchor,
                target_rule=target_rule,
                target_kind=target_kind,
                existing_names=existing_names,
            )
            if existing_repair is not None:
                wrapper_additions.append(existing_repair)
                wrapper_name = str(existing_repair.get("name") or "").strip()
                if wrapper_name:
                    existing_names.add(wrapper_name)
                    repaired.append(wrapper_name)
            if _ensure_rulespec_payload_import(payload, setting_target.target):
                repaired.append(f"import:{setting_target.target.split('#', 1)[0]}")
            continue
        local_rule_names = _matching_delegated_setting_rule_names(
            rules,
            setting_target.rule_name_patterns,
        )
        if not local_rule_names:
            continue
        value_rule = _preferred_delegated_setting_value_rule(rules, local_rule_names)
        if value_rule is None:
            continue
        value_name = str(value_rule.get("name") or "").strip()
        if not value_name:
            continue
        target_symbol = setting_target.target.rsplit("#", 1)[-1]
        relation_stem = target_symbol.removesuffix("_state_option")
        if target_kind == "derived" and _rulespec_rule_kind(value_rule) == "parameter":
            wrapper_rule = _delegated_setting_derived_value_wrapper(
                rules,
                value_rule=value_rule,
                target_rule=target_rule,
                target_anchor=target_anchor,
                relation_stem=relation_stem,
                existing_names=existing_names,
            )
            if wrapper_rule is not None:
                value_rule = wrapper_rule
                value_name = str(wrapper_rule.get("name") or "").strip()
                existing_names.add(value_name)
                wrapper_additions.append(wrapper_rule)
        relation_name = _unique_generated_rule_name(
            f"sets_{relation_stem}",
            existing_names,
        )
        existing_names.add(relation_name)
        source_relation_rule: dict[str, Any] = {
            "name": relation_name,
            "kind": "source_relation",
            "source_relation": {
                "type": "sets",
                "target": setting_target.target,
                "authority": "state",
                "value": f"{target_anchor}#{value_name}",
                "basis": {
                    "delegation": "us:regulations/7-cfr/273/9#snap_state_standard_utility_allowance_delegation",
                },
            },
        }
        source = value_rule.get("source")
        if isinstance(source, str) and source.strip():
            source_relation_rule["source"] = source.strip()
        source_relation_additions.append(source_relation_rule)
        repaired.append(relation_name)
        if _ensure_rulespec_payload_import(payload, setting_target.target):
            repaired.append(f"import:{setting_target.target.split('#', 1)[0]}")

    if not source_relation_additions and not wrapper_additions and not repaired:
        return []
    import_only_repair = (
        not source_relation_additions
        and not wrapper_additions
        and all(item.startswith("import:") for item in repaired)
    )
    if import_only_repair:
        import_targets = [
            item.removeprefix("import:")
            for item in repaired
            if item.removeprefix("import:").strip()
        ]
        preserved_content = _add_rulespec_imports_preserving_content(
            original_content,
            import_targets,
        )
        if preserved_content is not None:
            rules_file.write_text(preserved_content)
            return repaired

    insert_at = 0
    while insert_at < len(rules):
        rule = rules[insert_at]
        if not isinstance(rule, dict):
            break
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            break
        insert_at += 1
    payload["rules"] = [
        *rules[:insert_at],
        *source_relation_additions,
        *wrapper_additions,
        *rules[insert_at:],
    ]
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _issue_mentions_delegated_policy_setting(issue: str) -> bool:
    if "Delegated policy setting missing source_relation" in issue:
        return True
    if "Delegated policy setting wrong source_relation target" in issue:
        return True
    if (
        "RuleSpec source relation" in issue
        and "sets target" in issue
        and "#snap_utility_allowance_for_shelter_costs" in issue
    ):
        return True
    if "RuleSpec source relation" not in issue:
        return False
    return (
        any(
            setting_target.target in issue
            for setting_target in _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS
        )
        or "us:regulations/7-cfr/273/9#snap_utility_allowance_for_shelter_costs"
        in issue
    )


def _unresolved_delegated_setting_sets_issue_texts(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path | None,
) -> list[str]:
    try:
        payload = yaml.safe_load(content) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    resolved_targets = _resolved_executable_delegated_setting_targets(
        _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS,
        current_payload=payload,
        current_rules_file=rules_file,
        policy_repo_path=policy_repo_path,
    )
    unresolved_targets = {
        normalized
        for setting_target in _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS
        if (normalized := _normalize_source_relation_target_ref(setting_target.target))
        not in resolved_targets
    }
    if not unresolved_targets:
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        if str(source_relation.get("type") or "").strip().lower() != "sets":
            continue
        target = _normalize_source_relation_target_ref(source_relation.get("target"))
        if target not in unresolved_targets:
            continue
        name = str(rule.get("name") or target).strip()
        issues.append(
            "RuleSpec source relation "
            f"`{name}` sets target `{target}`, but the target does not resolve "
            "to an executable parameter or derived rule in the merged program"
        )
    return issues


def _missing_delegated_setting_import_issue_texts(
    content: str,
    *,
    rules_file: Path,
    policy_repo_path: Path | None,
) -> list[str]:
    try:
        payload = yaml.safe_load(content) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    resolved_targets = _resolved_executable_delegated_setting_targets(
        _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS,
        current_payload=payload,
        current_rules_file=rules_file,
        policy_repo_path=policy_repo_path,
    )
    if not resolved_targets:
        return []

    issues: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        if str(source_relation.get("type") or "").strip().lower() != "sets":
            continue
        target = _normalize_source_relation_target_ref(source_relation.get("target"))
        if target not in resolved_targets:
            continue
        if _rulespec_payload_imports_target(payload, target):
            continue
        import_target = target.split("#", 1)[0].strip()
        name = str(rule.get("name") or target).strip()
        issues.append(
            "RuleSpec source relation "
            f"`{name}` sets target `{target}`, but this module does not import "
            f"`{import_target}`"
        )
    return issues


def _rulespec_payload_imports_target(payload: dict[str, Any], target: str) -> bool:
    import_target = target.split("#", 1)[0].strip()
    if not import_target:
        return False
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return False
    return import_target in {
        str(item).split("#", 1)[0].strip() for item in imports if isinstance(item, str)
    }


def _ensure_rulespec_payload_import(payload: dict[str, Any], target: str) -> bool:
    import_target = target.split("#", 1)[0].strip()
    if not import_target:
        return False
    imports = payload.get("imports")
    if imports is None:
        payload["imports"] = [import_target]
        return True
    if not isinstance(imports, list):
        return False
    normalized_imports = {
        str(item).split("#", 1)[0].strip() for item in imports if isinstance(item, str)
    }
    if import_target in normalized_imports:
        return False
    imports.append(import_target)
    return True


def _add_rulespec_imports_preserving_content(
    content: str,
    import_targets: list[str],
) -> str | None:
    unique_targets = _ordered_unique_strings(
        [target.strip() for target in import_targets if target.strip()]
    )
    if not unique_targets:
        return content
    try:
        payload = yaml.safe_load(content) or {}
    except yaml.YAMLError:
        return None
    if not isinstance(payload, dict):
        return None
    imports = payload.get("imports")
    existing_imports = (
        {
            str(item).split("#", 1)[0].strip()
            for item in imports
            if isinstance(item, str)
        }
        if isinstance(imports, list)
        else set()
    )
    missing = [target for target in unique_targets if target not in existing_imports]
    if not missing:
        return content

    lines = content.splitlines()
    import_line = next(
        (
            index
            for index, line in enumerate(lines)
            if line.strip() == "imports:" and not line.startswith((" ", "\t"))
        ),
        None,
    )
    rendered = [f"  - {target}" for target in missing]
    if import_line is None:
        suffix = "\n" if content.endswith("\n") else "\n"
        return f"{content}{suffix}imports:\n" + "\n".join(rendered) + "\n"

    insert_at = import_line + 1
    while insert_at < len(lines):
        line = lines[insert_at]
        if line.startswith((" ", "\t")) or not line.strip():
            insert_at += 1
            continue
        break
    next_lines = [*lines[:insert_at], *rendered, *lines[insert_at:]]
    return "\n".join(next_lines) + ("\n" if content.endswith("\n") else "")


def _rulespec_rule_kind(rule: dict[str, Any] | None) -> str:
    if not isinstance(rule, dict):
        return ""
    return str(rule.get("kind") or "").strip().lower()


def _rulespec_rule_for_absolute_ref(
    reference: str,
    *,
    current_payload: dict[str, Any],
    current_rules_file: Path,
    policy_repo_path: Path | None,
) -> dict[str, Any] | None:
    target_ref = _parse_rulespec_target(reference)
    if target_ref is None or target_ref.symbol is None:
        return None
    target_payload: dict[str, Any] | None = None
    if _rulespec_generated_file_matches_target_ref(current_rules_file, target_ref):
        target_payload = current_payload
    else:
        target_file = _resolve_rulespec_target_file(target_ref, policy_repo_path)
        if target_file is not None and target_file.exists():
            target_payload = _rulespec_payload_from_file(target_file)
    if target_payload is None:
        return None
    rules = target_payload.get("rules")
    if not isinstance(rules, list):
        return None
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("name") or "").strip() == target_ref.symbol:
            return rule
    return None


def _rulespec_generated_file_matches_target_ref(
    rules_file: Path,
    target_ref: Any,
) -> bool:
    target_parts = target_ref.relative_path.parts
    path_parts = Path(rules_file).resolve().parts
    return (
        len(path_parts) >= len(target_parts)
        and path_parts[-len(target_parts) :] == target_parts
    )


def _delegated_setting_derived_value_wrapper(
    rules: list[Any],
    *,
    value_rule: dict[str, Any],
    target_rule: dict[str, Any] | None,
    target_anchor: str,
    relation_stem: str,
    existing_names: set[str],
) -> dict[str, Any] | None:
    value_name = str(value_rule.get("name") or "").strip()
    if not value_name:
        return None
    wrapper_name = _unique_generated_rule_name(
        f"{relation_stem}_state_value",
        existing_names,
    )
    effective_dates = _rulespec_rule_effective_dates(value_rule)
    if not effective_dates:
        return None
    eligible_rule = _delegated_setting_eligibility_rule(rules, value_name)
    eligible_name = (
        str(eligible_rule.get("name") or "").strip()
        if isinstance(eligible_rule, dict)
        else ""
    )
    formula = value_name
    if eligible_name:
        formula = f"if {eligible_name}: {value_name} else: 0"

    wrapper_rule: dict[str, Any] = {
        "name": wrapper_name,
        "kind": "derived",
        "versions": [
            {
                "effective_from": effective_from,
                "formula": formula,
            }
            for effective_from in effective_dates
        ],
        "metadata": {
            "proof": {
                "atoms": [
                    {
                        "path": "versions[0].formula",
                        "kind": "import",
                        "import": {
                            "target": f"{target_anchor}#{value_name}",
                            "output": value_name,
                            "hash": "sha256:local",
                        },
                    }
                ]
            }
        },
    }
    for field in ("entity", "dtype", "period", "unit"):
        value = (
            target_rule.get(field)
            if isinstance(target_rule, dict) and target_rule.get(field) is not None
            else value_rule.get(field)
        )
        if value is not None:
            wrapper_rule[field] = value
    source = value_rule.get("source")
    if isinstance(source, str) and source.strip():
        wrapper_rule["source"] = source.strip()
    if eligible_name:
        wrapper_rule["metadata"]["proof"]["atoms"].append(
            {
                "path": "versions[0].formula",
                "kind": "import",
                "import": {
                    "target": f"{target_anchor}#{eligible_name}",
                    "output": eligible_name,
                    "hash": "sha256:local",
                },
            }
        )
    return wrapper_rule


def _rulespec_rule_effective_dates(rule: dict[str, Any]) -> list[str]:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return []
    dates: list[str] = []
    for version in versions:
        if not isinstance(version, dict):
            continue
        effective_from = version.get("effective_from")
        if isinstance(effective_from, str) and effective_from.strip():
            dates.append(effective_from.strip())
    return dates


def _delegated_setting_eligibility_rule(
    rules: list[Any],
    value_name: str,
) -> dict[str, Any] | None:
    candidate_names = [f"{value_name}_eligible", f"{value_name}_applies"]
    for suffix in ("_amount", "_for_unit_size", "_standard"):
        if value_name.endswith(suffix):
            candidate_names.append(f"{value_name.removesuffix(suffix)}_eligible")
            candidate_names.append(f"{value_name.removesuffix(suffix)}_applies")
    if "basic_utility_allowance" in value_name:
        candidate_names.append("snap_basic_utility_allowance_eligible")
        candidate_names.append("snap_basic_utility_allowance_applies")
    if "telephone" in value_name:
        candidate_names.append("snap_telephone_allowance_eligible")
        candidate_names.append("snap_telephone_allowance_applies")

    seen: set[str] = set()
    for candidate_name in candidate_names:
        if candidate_name in seen:
            continue
        seen.add(candidate_name)
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            if str(rule.get("name") or "").strip() != candidate_name:
                continue
            if _rulespec_rule_kind(rule) == "derived":
                return rule
    return None


def _generated_rules_include_source_relation_target(
    rules: list[Any],
    target: str,
) -> bool:
    return _generated_source_relation_for_target(rules, target) is not None


def _generated_source_relation_for_target(
    rules: list[Any],
    target: str,
) -> dict[str, Any] | None:
    normalized_target = _normalize_source_relation_target_ref(target)
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        if str(source_relation.get("type") or "").strip().lower() != "sets":
            continue
        if (
            _normalize_source_relation_target_ref(source_relation.get("target"))
            == normalized_target
        ):
            return rule
    return None


def _resolved_executable_delegated_setting_targets(
    setting_targets: tuple[Any, ...],
    *,
    current_payload: dict[str, Any],
    current_rules_file: Path,
    policy_repo_path: Path | None,
) -> dict[str, dict[str, Any]]:
    resolved: dict[str, dict[str, Any]] = {}
    for setting_target in setting_targets:
        normalized_target = _normalize_source_relation_target_ref(setting_target.target)
        if not normalized_target:
            continue
        target_rule = _rulespec_rule_for_absolute_ref(
            setting_target.target,
            current_payload=current_payload,
            current_rules_file=current_rules_file,
            policy_repo_path=policy_repo_path,
        )
        if target_rule is None or not _is_executable_rulespec_rule(target_rule):
            continue
        resolved[normalized_target] = target_rule
    return resolved


def _drop_unresolved_delegated_setting_sets_relations(
    payload: dict[str, Any],
    rules: list[Any],
    *,
    unresolved_targets: set[str],
) -> list[str]:
    if not unresolved_targets:
        return []

    retained_rules: list[Any] = []
    dropped: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            retained_rules.append(rule)
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            retained_rules.append(rule)
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            retained_rules.append(rule)
            continue
        if str(source_relation.get("type") or "").strip().lower() != "sets":
            retained_rules.append(rule)
            continue
        target_ref = _normalize_source_relation_target_ref(
            source_relation.get("target")
        )
        if target_ref not in unresolved_targets:
            retained_rules.append(rule)
            continue
        dropped.append(str(rule.get("name") or target_ref).strip())

    if not dropped:
        return []
    payload["rules"] = retained_rules
    return dropped


def _repair_delegated_setting_relation_targets(
    rules: list[Any],
    *,
    current_payload: dict[str, Any],
    current_rules_file: Path,
    policy_repo_path: Path | None,
    target_anchor: str,
    existing_names: set[str],
    resolvable_targets: set[str] | None = None,
) -> tuple[list[dict[str, Any]], list[str]]:
    """Retarget generated SNAP utility `sets` relations to canonical hooks."""
    canonical_targets = {
        _normalize_source_relation_target_ref(setting_target.target)
        for setting_target in _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS
    }
    wrapper_additions: list[dict[str, Any]] = []
    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        if str(source_relation.get("type") or "").strip().lower() != "sets":
            continue
        target_ref = _normalize_source_relation_target_ref(
            source_relation.get("target")
        )
        if not target_ref or target_ref in canonical_targets:
            continue
        value_ref = str(source_relation.get("value") or "").strip()
        if not value_ref:
            continue
        value_rule = _rulespec_rule_for_absolute_ref(
            value_ref,
            current_payload=current_payload,
            current_rules_file=current_rules_file,
            policy_repo_path=policy_repo_path,
        )
        if value_rule is None:
            continue
        value_name = str(value_rule.get("name") or "").strip()
        setting_target = _delegated_setting_target_for_value_name(value_name)
        if setting_target is None:
            continue
        normalized_setting_target = _normalize_source_relation_target_ref(
            setting_target.target
        )
        if (
            resolvable_targets is not None
            and normalized_setting_target not in resolvable_targets
        ):
            continue
        target_rule = _rulespec_rule_for_absolute_ref(
            setting_target.target,
            current_payload=current_payload,
            current_rules_file=current_rules_file,
            policy_repo_path=policy_repo_path,
        )
        if target_rule is None or not _is_executable_rulespec_rule(target_rule):
            continue
        target_kind = _rulespec_rule_kind(target_rule)
        target_symbol = setting_target.target.rsplit("#", 1)[-1]
        relation_stem = target_symbol.removesuffix("_state_option")
        if target_kind == "derived" and _rulespec_rule_kind(value_rule) == "parameter":
            wrapper_rule = _delegated_setting_derived_value_wrapper(
                rules,
                value_rule=value_rule,
                target_rule=target_rule,
                target_anchor=target_anchor,
                relation_stem=relation_stem,
                existing_names=existing_names,
            )
            if wrapper_rule is not None:
                wrapper_name = str(wrapper_rule.get("name") or "").strip()
                if wrapper_name:
                    existing_names.add(wrapper_name)
                    source_relation["value"] = f"{target_anchor}#{wrapper_name}"
                    wrapper_additions.append(wrapper_rule)
                    repaired.append(wrapper_name)
        source_relation["target"] = setting_target.target
        source_relation["authority"] = "state"
        basis = source_relation.get("basis")
        if not isinstance(basis, dict):
            basis = {}
            source_relation["basis"] = basis
        basis["delegation"] = (
            "us:regulations/7-cfr/273/9#"
            "snap_state_standard_utility_allowance_delegation"
        )
        relation_name = str(rule.get("name") or f"sets_{relation_stem}").strip()
        if relation_name:
            repaired.append(relation_name)
        if _ensure_rulespec_payload_import(current_payload, setting_target.target):
            repaired.append(f"import:{setting_target.target.split('#', 1)[0]}")
    return wrapper_additions, repaired


def _delegated_setting_target_for_value_name(
    value_name: str,
) -> Any | None:
    if not value_name:
        return None
    probe_rule = {"name": value_name, "kind": "derived", "dtype": "Money"}
    for setting_target in _SNAP_UTILITY_ALLOWANCE_SETTING_TARGETS:
        if _matching_delegated_setting_rule_names(
            [probe_rule],
            setting_target.rule_name_patterns,
        ):
            return setting_target
    return None


def _repair_delegated_setting_relation_value_kind(
    relation_rule: dict[str, Any],
    rules: list[Any],
    *,
    current_payload: dict[str, Any],
    current_rules_file: Path,
    policy_repo_path: Path | None,
    target_anchor: str,
    target_rule: dict[str, Any] | None,
    target_kind: str,
    existing_names: set[str],
) -> dict[str, Any] | None:
    source_relation = relation_rule.get("source_relation")
    if not isinstance(source_relation, dict):
        return None
    value_ref = str(source_relation.get("value") or "").strip()
    if not value_ref:
        return None
    value_rule = _rulespec_rule_for_absolute_ref(
        value_ref,
        current_payload=current_payload,
        current_rules_file=current_rules_file,
        policy_repo_path=policy_repo_path,
    )
    if value_rule is None:
        return None
    if target_kind != "derived" or _rulespec_rule_kind(value_rule) != "parameter":
        return None
    target_ref = str(source_relation.get("target") or "").strip()
    if "#" not in target_ref:
        return None
    relation_stem = target_ref.rsplit("#", 1)[-1].removesuffix("_state_option")
    wrapper_rule = _delegated_setting_derived_value_wrapper(
        rules,
        value_rule=value_rule,
        target_rule=target_rule,
        target_anchor=target_anchor,
        relation_stem=relation_stem,
        existing_names=existing_names,
    )
    if wrapper_rule is None:
        return None
    wrapper_name = str(wrapper_rule.get("name") or "").strip()
    if not wrapper_name:
        return None
    source_relation["value"] = f"{target_anchor}#{wrapper_name}"
    return wrapper_rule


def _preferred_delegated_setting_value_rule(
    rules: list[Any],
    local_rule_names: list[str],
) -> dict[str, Any] | None:
    local_names = set(local_rule_names)
    candidates: list[tuple[int, int, dict[str, Any]]] = []
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if name not in local_names or not _is_executable_rulespec_rule(rule):
            continue
        score = _delegated_setting_value_rule_score(rule)
        candidates.append((score, -index, rule))
    if not candidates:
        return None
    candidates.sort(key=lambda item: (item[0], item[1]), reverse=True)
    return candidates[0][2]


_PREFERRED_DELEGATED_SETTING_VALUE_NAMES = {
    "snap_standard_utility_allowance",
    "heating_cooling_standard_utility_allowance",
    "snap_limited_utility_allowance",
    "non_heating_non_cooling_basic_utility_allowance",
    "snap_basic_utility_allowance",
    "snap_individual_utility_allowance",
    "telephone_utility_allowance",
    "snap_one_utility_allowance",
}


def _delegated_setting_value_rule_score(rule: dict[str, Any]) -> int:
    name = str(rule.get("name") or "").strip()
    kind = str(rule.get("kind") or "").strip().lower()
    score = 0
    if name in _PREFERRED_DELEGATED_SETTING_VALUE_NAMES:
        score += 100
    if kind == "derived":
        score += 40
    if name.startswith("snap_"):
        score += 10
    if name.endswith("_amount"):
        score -= 20
    if name.endswith("_for_unit_size"):
        score -= 30
    return score


def _unique_generated_rule_name(base: str, existing_names: set[str]) -> str:
    if base not in existing_names:
        return base
    suffix = 2
    while f"{base}_{suffix}" in existing_names:
        suffix += 1
    return f"{base}_{suffix}"


def _try_repair_generated_source_relation_delegations_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path | None = None,
    issues: list[str],
) -> list[str]:
    """Fill or drop missing delegation basis on generated implementation edges."""
    if not any(
        _issue_mentions_missing_source_relation_delegation(issue) for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    retained_rules: list[object] = []
    changed = False
    for rule in rules:
        if not isinstance(rule, dict):
            retained_rules.append(rule)
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            retained_rules.append(rule)
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            retained_rules.append(rule)
            continue
        if str(source_relation.get("type") or "").strip().lower() != "implements":
            retained_rules.append(rule)
            continue
        target = str(source_relation.get("target") or "").strip()
        if not target:
            retained_rules.append(rule)
            continue
        delegation = _source_relation_delegation_basis_for_target(
            target,
            policy_repo_path=policy_repo_path,
        )
        if not delegation:
            if _may_drop_generated_federal_regulation_implements_relation(
                rule,
                payload=payload,
            ):
                repaired.append(str(rule.get("name") or target))
                changed = True
                continue
            retained_rules.append(rule)
            continue
        basis = source_relation.get("basis")
        if isinstance(basis, dict) and str(basis.get("delegation") or "").strip():
            retained_rules.append(rule)
            continue
        if not isinstance(basis, dict):
            basis = {}
            source_relation["basis"] = basis
        basis["delegation"] = delegation
        repaired.append(str(rule.get("name") or target))
        changed = True
        retained_rules.append(rule)

    if not repaired:
        return []
    if changed:
        payload["rules"] = retained_rules
        rules_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )
    return repaired


def _try_repair_generated_invalid_source_relation_types_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Normalize generated source relation synonyms unsupported by RuleSpec."""
    if not any(_issue_mentions_unknown_source_relation_type(issue) for issue in issues):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        relation_type = str(source_relation.get("type") or "").strip().lower()
        if relation_type != "incorporates":
            continue
        source_relation["type"] = "cites"
        for unsupported_key in (
            "edition",
            "later_amendments_or_editions_incorporated",
        ):
            source_relation.pop(unsupported_key, None)
        repaired.append(str(rule.get("name") or source_relation.get("target") or ""))

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _may_drop_generated_federal_regulation_implements_relation(
    rule: dict[str, object],
    *,
    payload: dict[str, object],
) -> bool:
    """Return true for unsupported broad CFR implementation provenance edges."""
    source_relation = rule.get("source_relation")
    if not isinstance(source_relation, dict):
        return False
    if source_relation.get("value"):
        return False
    basis = source_relation.get("basis")
    if isinstance(basis, dict) and str(basis.get("delegation") or "").strip():
        return False
    target = str(source_relation.get("target") or "").strip()
    if _is_broad_federal_regulation_range_ref(target):
        return True
    if not target.startswith("us:statutes/"):
        return False
    module = payload.get("module")
    if not isinstance(module, dict):
        return False
    source_verification = module.get("source_verification")
    if not isinstance(source_verification, dict):
        return False
    if not any(
        path.startswith("us/regulation/")
        for path in _rulespec_module_source_paths(payload)
    ):
        return False
    source = str(rule.get("source") or "").strip().lower()
    return bool(re.search(r"\bc\.?\s*f\.?\s*r\.?\b", source, flags=re.IGNORECASE))


def _is_broad_federal_regulation_range_ref(target: str) -> bool:
    normalized = _normalize_source_relation_target_ref(target)
    if not normalized or "#" in normalized:
        return False
    if not normalized.startswith("us:regulations/"):
        return False
    parts = [part.strip().lower() for part in normalized.split("/") if part.strip()]
    if "7-cfr" not in parts:
        return False
    return any(re.fullmatch(r"\d+[a-z]?(?:-|–|—)\d+[a-z]?", part) for part in parts)


def _source_relation_delegation_basis_for_target(
    target: str,
    *,
    policy_repo_path: Path | None,
) -> str | None:
    """Return a concrete delegation slot for a source-relation target."""
    normalized_target = _normalize_source_relation_target_ref(target)
    if not normalized_target:
        return None
    if policy_repo_path is None:
        return None
    module_target, _, target_symbol = normalized_target.partition("#")

    target_file = _rulespec_file_for_absolute_module_ref(
        normalized_target,
        policy_repo_path=policy_repo_path,
    )
    if target_file is None or not target_file.exists():
        return None
    try:
        payload = yaml.safe_load(target_file.read_text()) or {}
    except (OSError, yaml.YAMLError):
        return None
    if not isinstance(payload, dict):
        return None

    rule_delegations: set[str] = set()
    deferred_delegations: set[str] = set()
    rules = payload.get("rules")
    if isinstance(rules, list):
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            source_relation = rule.get("source_relation")
            if not isinstance(source_relation, dict):
                continue
            if str(source_relation.get("type") or "").strip().lower() != "delegates":
                continue
            name = str(rule.get("name") or "").strip()
            if name:
                candidate = f"{module_target}#{name}"
                delegate_target = _normalize_source_relation_target_ref(
                    source_relation.get("target")
                )
                if name == target_symbol or delegate_target == normalized_target:
                    return candidate
                if not target_symbol:
                    rule_delegations.add(candidate)

    module = payload.get("module")
    deferred_outputs = (
        module.get("deferred_outputs") if isinstance(module, dict) else None
    )
    if isinstance(deferred_outputs, list):
        prefix = module_target + "#"
        for output in deferred_outputs:
            if not isinstance(output, dict):
                continue
            output_ref = _normalize_source_relation_target_ref(output.get("output"))
            if not output_ref:
                continue
            if output_ref == normalized_target:
                deferred_delegations.add(output_ref)
            elif not target_symbol and output_ref.startswith(prefix):
                deferred_delegations.add(output_ref)

    if len(rule_delegations) == 1:
        return next(iter(rule_delegations))
    if len(rule_delegations) > 1:
        return None
    if len(deferred_delegations) == 1:
        return next(iter(deferred_delegations))
    return None


def _normalize_source_relation_target_ref(value: object) -> str | None:
    if not isinstance(value, str):
        return None
    normalized = value.strip()
    if not normalized:
        return None
    base, separator, symbol = normalized.partition("#")
    if base.endswith((".yaml", ".yml")):
        base = str(Path(base).with_suffix(""))
    return f"{base}{separator}{symbol}" if separator else base


def _rulespec_file_for_absolute_module_ref(
    target: str,
    *,
    policy_repo_path: Path,
) -> Path | None:
    module_ref = str(target or "").strip().split("#", 1)[0]
    if not module_ref or ":" not in module_ref:
        return None
    prefix, relative = module_ref.split(":", 1)
    prefix = prefix.strip()
    relative = relative.strip("/")
    if not prefix or not relative:
        return None
    relative_file = Path(relative)
    if relative_file.suffix not in {".yaml", ".yml"}:
        relative_file = Path(f"{relative}.yaml")
    current_repo = Path(policy_repo_path).expanduser()

    candidate_roots = [
        current_repo,
        current_repo.parent,
        current_repo / "_axiom",
        current_repo.parent / "_axiom",
    ]
    if current_repo.parent.name.startswith("rulespec-"):
        # A monorepo jurisdiction directory: sibling checkouts live next to
        # the monorepo checkout itself.
        candidate_roots.append(current_repo.parent.parent)
        candidate_roots.append(current_repo.parent.parent / "_axiom")
    env_roots = os.environ.get("AXIOM_RULESPEC_REPO_ROOTS", "")
    candidate_roots.extend(
        Path(root).expanduser() for root in env_roots.split(os.pathsep) if root
    )
    candidates: list[Path] = [
        content_dir / relative_file
        for root in candidate_roots
        for content_dir in candidate_jurisdiction_content_dirs(root, prefix)
    ]

    seen_candidates: set[Path] = set()
    for candidate in candidates:
        if candidate in seen_candidates:
            continue
        seen_candidates.add(candidate)
        if candidate.exists():
            return candidate
    return candidates[0] if candidates else None


def _missing_input_names_from_issues(issues: list[str]) -> set[str]:
    names: set[str] = set()
    for issue in issues:
        text = str(issue)
        if "execution failed: missing input `" not in text:
            continue
        for match in re.finditer(r"missing input `([A-Za-z_][A-Za-z0-9_]*)`", text):
            names.add(match.group(1))
    return names


def _issue_mentions_missing_source_relation_delegation(issue: str) -> bool:
    text = str(issue)
    unquoted = text.replace("`", "")
    return (
        "must declare source_relation.basis.delegation" in unquoted
        and "source relation" in unquoted.lower()
    )


def _issue_mentions_unknown_source_relation_type(issue: str) -> bool:
    normalized = str(issue).lower()
    return "source_relation.type" in normalized and "unknown variant" in normalized


def _issue_mentions_versioned_derived_formula(issue: str) -> bool:
    text = str(issue)
    return "multiple formula versions" in text and (
        "derived variable" in text or "Versioned derived formula unsupported" in text
    )


def _issue_mentions_boolean_comparison_in_scalar_position(issue: str) -> bool:
    text = str(issue)
    return "binary op" in text and "in scalar position" in text


def _issue_mentions_negated_comparison_in_scalar_position(issue: str) -> bool:
    text = str(issue)
    return "`not` in scalar position" in text or "not in scalar position" in text


def _issue_mentions_judgment_scalar_request(issue: str) -> bool:
    return "is judgment, but a scalar was requested" in str(issue).lower()


def _issue_mentions_judgment_conditional_shape(issue: str) -> bool:
    text = str(issue).lower()
    return (
        "expression shape not supported in judgment position" in text
        and "discriminant" in text
    ) or (
        "judgment conditional formula unsupported" in text and "if ... else ..." in text
    )


def _boolean_comparison_rule_names_from_issues(issues: list[str]) -> set[str]:
    names: set[str] = set()
    for issue in issues:
        text = str(issue)
        if not _issue_mentions_boolean_comparison_in_scalar_position(text):
            continue
        for pattern in (
            r"RuleSpec rule `([A-Za-z_][A-Za-z0-9_]*)`",
            r"rule `([A-Za-z_][A-Za-z0-9_]*)`",
            r"output `[^#`]+#([A-Za-z_][A-Za-z0-9_]*)`",
            r"variable `([A-Za-z_][A-Za-z0-9_]*)`",
        ):
            names.update(re.findall(pattern, text))
    return names


def _judgment_scalar_rule_names_from_issues(issues: list[str]) -> set[str]:
    names: set[str] = set()
    for issue in issues:
        text = str(issue)
        if not _issue_mentions_judgment_scalar_request(text):
            continue
        for match in re.finditer(
            r"(?:derived|parameter|rule|variable)\s+[`']"
            r"([A-Za-z_][A-Za-z0-9_]*)[`']\s+is judgment",
            text,
            flags=re.IGNORECASE,
        ):
            names.add(match.group(1))
    return names


def _single_boolean_comparison_candidate_rule_name(rules_file: Path) -> set[str]:
    if not rules_file.exists():
        return set()
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return set()
    if not isinstance(payload, dict):
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()

    candidates = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("name") or "").strip()
        and str(rule.get("kind") or "").strip().lower() == "derived"
        and str(rule.get("dtype") or "").strip() == "Boolean"
        and _rule_has_top_level_comparison_formula(rule)
    }
    return candidates if len(candidates) == 1 else set()


def _local_judgment_rule_names(rules_file: Path) -> set[str]:
    if not rules_file.exists():
        return set()
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return set()
    if not isinstance(payload, dict):
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    return {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("name") or "").strip()
        and str(rule.get("dtype") or "").strip().lower() == "judgment"
    }


def _convert_versioned_boolean_parameters_to_indicators(
    rules_file: Path,
    *,
    names: set[str] | None = None,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    requested = set(names or ())
    converted: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if requested and name not in requested:
            continue
        if rule.get("kind") != "parameter" or rule.get("dtype") != "Boolean":
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list) or not versions:
            continue
        normalized_formulas: list[str] = []
        for version in versions:
            if not isinstance(version, dict):
                normalized_formulas = []
                break
            formula = version.get("formula")
            if isinstance(formula, bool):
                normalized = "true" if formula else "false"
            else:
                normalized = str(formula or "").strip().lower()
            if normalized not in {"true", "false"}:
                normalized_formulas = []
                break
            normalized_formulas.append(normalized)
        if not normalized_formulas:
            continue

        rule["dtype"] = "Integer"
        for version, normalized in zip(versions, normalized_formulas, strict=True):
            version["formula"] = "1" if normalized == "true" else "0"
        converted.append(name)

    if not converted:
        return []

    converted_set = set(converted)
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            version["formula"] = _rewrite_boolean_indicator_references(
                formula,
                names=converted_set,
            )

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return converted


def _rewrite_boolean_indicator_references(formula: str, *, names: set[str]) -> str:
    rewritten = str(formula)
    for name in sorted(names, key=len, reverse=True):
        escaped = re.escape(name)
        rewritten = re.sub(
            rf"\bif\s+not\s+{escaped}\s*:",
            f"if {name} <= 0:",
            rewritten,
        )
        rewritten = re.sub(
            rf"\bif\s+{escaped}\s*:",
            f"if {name} > 0:",
            rewritten,
        )
        rewritten = re.sub(
            rf"(?<![A-Za-z0-9_])not\s+{escaped}(?![A-Za-z0-9_])",
            f"{name} <= 0",
            rewritten,
        )
        rewritten = re.sub(
            rf"(?<![A-Za-z0-9_]){escaped}(?![A-Za-z0-9_])\s+and\b",
            f"{name} > 0 and",
            rewritten,
        )
        rewritten = re.sub(
            rf"\band\s+{escaped}(?![A-Za-z0-9_])",
            f"and {name} > 0",
            rewritten,
        )
        rewritten = re.sub(
            rf"(?<![A-Za-z0-9_]){escaped}(?![A-Za-z0-9_])\s+or\b",
            f"{name} > 0 or",
            rewritten,
        )
        rewritten = re.sub(
            rf"\bor\s+{escaped}(?![A-Za-z0-9_])",
            f"or {name} > 0",
            rewritten,
        )
    return rewritten


def _collapse_additive_versioned_derived_formulas(
    rules_file: Path,
    test_file: Path | None = None,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    rewritten_rules: list[object] = []
    selector_repairs: list[tuple[str, list[dict[str, str]]]] = []
    for rule in rules:
        if not isinstance(rule, dict):
            rewritten_rules.append(rule)
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            rewritten_rules.append(rule)
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            rewritten_rules.append(rule)
            continue
        formula_versions = [
            (index, version, str(version.get("formula") or "").strip())
            for index, version in enumerate(versions)
            if isinstance(version, dict)
            and isinstance(version.get("formula"), str)
            and str(version.get("formula") or "").strip()
        ]
        if len(formula_versions) <= 1:
            rewritten_rules.append(rule)
            continue
        collapsed_formula = None
        collapsed_selectors: list[dict[str, str]] = []
        collapsed = _collapse_additive_formula_versions(rule, formula_versions)
        if collapsed is not None:
            collapsed_formula, collapsed_selectors = collapsed
        factored_rate_rule: dict[str, object] | None = None
        selector_predicates: list[dict[str, str]] = []
        if collapsed_formula is None:
            factored = _factor_conditional_rate_formula_versions(rule, formula_versions)
            if factored is None:
                selector = _collapse_selector_formula_versions(rule, formula_versions)
                if selector is None:
                    rewritten_rules.append(rule)
                    continue
                collapsed_formula, selector_predicates = selector
            else:
                factored_rate_rule, collapsed_formula, selector_predicates = factored
        elif collapsed_selectors:
            selector_predicates = collapsed_selectors

        first_index, first_version, _ = formula_versions[0]
        collapsed_version = dict(first_version)
        collapsed_version["formula"] = collapsed_formula
        rule["versions"] = [collapsed_version]
        _retarget_formula_proof_atoms_to_first_version(rule)
        if factored_rate_rule is not None:
            rewritten_rules.append(factored_rate_rule)
            repaired.append(str(factored_rate_rule.get("name") or "factored_rate"))
        if selector_predicates:
            selector_repairs.append(
                (
                    str(rule.get("name") or "selector_rule"),
                    selector_predicates,
                )
            )
        rewritten_rules.append(rule)
        repaired.append(str(rule.get("name") or f"rules[{first_index}]"))

    if repaired:
        payload["rules"] = rewritten_rules
        rules_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )
        if test_file is not None and selector_repairs:
            _add_selector_version_test_inputs(test_file, selector_repairs)
    return repaired


def _collapse_additive_formula_versions(
    rule: dict[str, object],
    formula_versions: list[tuple[int, dict[str, object], str]],
) -> tuple[str, list[dict[str, str]]] | None:
    """Join formula versions that only add or omit top-level terms.

    This deliberately handles only the simple, source-preserving shape generated
    for dated base-rate-plus-adjustment rules. More complex temporal branches
    should be regenerated by the model instead of silently rewritten.
    """
    if len(formula_versions) <= 1:
        return None
    split_versions: list[list[str]] = []
    for _, _, formula in formula_versions:
        stripped = formula.strip()
        if not stripped or "\n" in stripped or stripped.startswith("if "):
            return None
        terms = _split_top_level_addition_terms(stripped)
        if not terms:
            return None
        split_versions.append(terms)

    base_terms = split_versions[0]
    guarded_terms: list[str] = []
    selectors: list[dict[str, str]] = []
    for ordinal, ((_, version, _), terms) in enumerate(
        zip(formula_versions[1:], split_versions[1:], strict=True),
        start=2,
    ):
        if any(base_term not in terms for base_term in base_terms):
            return None
        effective_from = str(version.get("effective_from") or "").strip()
        if not effective_from:
            return None
        predicate = _version_selector_predicate_name(rule, ordinal)
        selectors.append(
            {
                "effective_from": effective_from,
                "predicate": predicate,
                "formula": "",
            }
        )
        for term in terms:
            if term in base_terms:
                continue
            guarded = f"(if {predicate}: {term} else: 0)"
            if guarded not in guarded_terms:
                guarded_terms.append(guarded)
    if not guarded_terms:
        return None
    return " + ".join([*base_terms, *guarded_terms]), selectors


def _factor_conditional_rate_formula_versions(
    rule: dict[str, object],
    formula_versions: list[tuple[int, dict[str, object], str]],
) -> tuple[dict[str, object], str, list[dict[str, str]]] | None:
    parsed_versions: list[tuple[dict[str, object], str, str, str, list[str]]] = []
    for _, version, formula in formula_versions:
        parsed = _parse_conditional_rate_formula(formula)
        if parsed is None:
            return None
        condition, base_amount, base_rate, adjustments = parsed
        parsed_versions.append(
            (version, condition, base_amount, base_rate, adjustments)
        )

    conditions = {condition for _, condition, _, _, _ in parsed_versions}
    base_amounts = {base_amount for _, _, base_amount, _, _ in parsed_versions}
    if len(conditions) != 1 or len(base_amounts) != 1:
        return None

    parameter_name = f"{rule.get('name')}_base_percentage"
    rate_parameter: dict[str, object] = {
        "name": parameter_name,
        "kind": "parameter",
        "dtype": "Number",
        "source": rule.get("source"),
        "versions": [
            {
                "effective_from": version.get("effective_from"),
                "formula": base_rate,
            }
            for version, _, _, base_rate, _ in parsed_versions
        ],
    }
    metadata = copy.deepcopy(rule.get("metadata"))
    if isinstance(metadata, dict):
        rate_parameter["metadata"] = metadata

    adjustment_terms: list[str] = []
    selectors: list[dict[str, str]] = []
    for ordinal, (version, _, _, _, adjustments) in enumerate(
        parsed_versions,
        start=1,
    ):
        if not adjustments:
            continue
        effective_from = str(version.get("effective_from") or "").strip()
        if not effective_from:
            return None
        predicate = _version_selector_predicate_name(rule, ordinal)
        selectors.append(
            {
                "effective_from": effective_from,
                "predicate": predicate,
                "formula": "",
            }
        )
        guarded_expression = " + ".join(adjustments)
        if len(adjustments) > 1:
            guarded_expression = f"({guarded_expression})"
        guarded_adjustment = f"(if {predicate}: {guarded_expression} else: 0)"
        if guarded_adjustment not in adjustment_terms:
            adjustment_terms.append(guarded_adjustment)

    for _, _, _, _, adjustments in parsed_versions:
        for adjustment in adjustments:
            if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", adjustment):
                return None

    rate_terms = [parameter_name, *adjustment_terms]
    rate_expression = " + ".join(rate_terms)
    if len(rate_terms) > 1:
        rate_expression = f"({rate_expression})"

    condition = next(iter(conditions))
    base_amount = next(iter(base_amounts))
    formula = f"if {condition}: {base_amount} * {rate_expression} else: 0"
    return rate_parameter, formula, selectors


def _collapse_selector_formula_versions(
    rule: dict[str, object],
    formula_versions: list[tuple[int, dict[str, object], str]],
) -> tuple[str, list[dict[str, str]]] | None:
    selector_versions: list[dict[str, str]] = []
    for ordinal, (_, version, formula) in enumerate(formula_versions, start=1):
        expression = formula.strip()
        if expression == "0":
            continue
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", expression):
            return None
        effective_from = str(version.get("effective_from") or "").strip()
        if not effective_from:
            return None
        selector_versions.append(
            {
                "effective_from": effective_from,
                "predicate": _version_selector_predicate_name(rule, ordinal),
                "formula": expression,
            }
        )
    if not selector_versions:
        return None

    formula = "0"
    for selector in selector_versions:
        formula = f"if {selector['predicate']}: {selector['formula']} else: {formula}"
    return formula, selector_versions


def _version_selector_predicate_name(
    rule: dict[str, object],
    ordinal: int,
) -> str:
    rule_name = str(rule.get("name") or "rule").strip() or "rule"
    return f"taxable_year_uses_{rule_name}_version_{ordinal}"


def _add_selector_version_test_inputs(
    test_file: Path,
    selector_repairs: list[tuple[str, list[dict[str, str]]]],
) -> None:
    if not test_file.exists():
        return
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(payload, list):
        return

    changed = False
    for case in payload:
        if not isinstance(case, dict):
            continue
        start = _test_case_start_date(case)
        target_prefix = _test_case_rulespec_prefix(case)
        if start is None or not target_prefix:
            continue
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            inputs = {}
            case["input"] = inputs
        for _, selectors in selector_repairs:
            active = _active_selector_predicate_for_period(selectors, start)
            for selector in selectors:
                key = f"{target_prefix}#input.{selector['predicate']}"
                value = selector["predicate"] == active
                if inputs.get(key) == value:
                    continue
                inputs[key] = value
                changed = True

    if changed:
        test_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )


def _test_case_start_date(case: dict[str, object]) -> date | None:
    return _test_period_start_date(case.get("period"))


def _test_case_rulespec_prefix(case: dict[str, object]) -> str | None:
    for section_name in ("input", "output"):
        section = case.get(section_name)
        if not isinstance(section, dict):
            continue
        for key in section:
            text = str(key)
            if "#" in text:
                return text.rsplit("#", 1)[0]
    return None


def _active_selector_predicate_for_period(
    selectors: list[dict[str, str]],
    start: date,
) -> str | None:
    active: tuple[date, str] | None = None
    for selector in selectors:
        effective_from = _parse_iso_date(selector.get("effective_from"))
        if effective_from is None or effective_from > start:
            continue
        if active is None or effective_from >= active[0]:
            active = (effective_from, selector["predicate"])
    return active[1] if active is not None else None


_CONDITIONAL_RATE_FORMULA_RE = re.compile(
    r"^if (?P<condition>.+): (?P<base_amount>.+?) \* (?P<rate>.+) else: 0$",
    flags=re.DOTALL,
)


def _parse_conditional_rate_formula(
    formula: str,
) -> tuple[str, str, str, list[str]] | None:
    normalized = re.sub(r"\s+", " ", formula.strip())
    match = _CONDITIONAL_RATE_FORMULA_RE.match(normalized)
    if match is None:
        return None
    condition = match.group("condition").strip()
    base_amount = match.group("base_amount").strip()
    rate = _strip_balanced_outer_parentheses(match.group("rate").strip())
    terms = _split_top_level_addition_terms(rate)
    if not terms:
        return None
    base_rate = terms[0]
    if not re.fullmatch(r"\d+(?:\.\d+)?", base_rate):
        return None
    adjustments = terms[1:]
    if not all(re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", term) for term in adjustments):
        return None
    return condition, base_amount, base_rate, adjustments


def _strip_balanced_outer_parentheses(value: str) -> str:
    stripped = value.strip()
    if not (stripped.startswith("(") and stripped.endswith(")")):
        return stripped
    depth = 0
    for index, char in enumerate(stripped):
        if char == "(":
            depth += 1
        elif char == ")":
            depth -= 1
            if depth == 0 and index != len(stripped) - 1:
                return stripped
    return stripped[1:-1].strip()


def _split_top_level_addition_terms(formula: str) -> list[str]:
    terms: list[str] = []
    start = 0
    depth = 0
    for index, char in enumerate(formula):
        if char == "(":
            depth += 1
        elif char == ")" and depth > 0:
            depth -= 1
        elif char == "+" and depth == 0:
            term = formula[start:index].strip()
            if not term:
                return []
            terms.append(term)
            start = index + 1
    term = formula[start:].strip()
    if not term:
        return []
    terms.append(term)
    return terms


def _retarget_formula_proof_atoms_to_first_version(rule: dict[str, object]) -> None:
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        path = atom.get("path")
        if isinstance(path, str) and re.fullmatch(
            r"(?:versions|values)\[\d+\]\.(?:formula|value)",
            path,
        ):
            atom["path"] = "versions[0].formula"


def _promote_boolean_comparison_predicates_to_judgment(
    rules_file: Path,
    test_file: Path | None = None,
    *,
    names: set[str] | None = None,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    requested = set(names or ())
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if requested and name not in requested:
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        if str(rule.get("dtype") or "").strip() != "Boolean":
            continue
        if not _rule_has_comparison_formula(rule):
            continue
        rule["dtype"] = "Judgment"
        repaired.append(name or "judgment_rule")

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    if test_file is not None:
        _rewrite_boolean_test_values_as_judgments(test_file, set(repaired))
    return repaired


_NEGATED_COMPARISON_PATTERN = re.compile(
    r"(?<![A-Za-z0-9_])not\s+"
    r"(?P<left>[A-Za-z_][A-Za-z0-9_]*|-?\d+(?:\.\d+)?)"
    r"\s*(?P<op>>=|<=|==|!=|>|<)\s*"
    r"(?P<right>[A-Za-z_][A-Za-z0-9_]*|-?\d+(?:\.\d+)?)"
)

_INVERTED_COMPARISON_OPERATORS = {
    ">": "<=",
    ">=": "<",
    "<": ">=",
    "<=": ">",
    "==": "!=",
    "!=": "==",
}


def _rewrite_negated_comparison_formulas(rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_changed = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            rewritten = _rewrite_negated_comparison_formula(formula)
            if rewritten != formula:
                version["formula"] = rewritten
                rule_changed = True
        if rule_changed:
            repaired.append(str(rule.get("name") or "formula_rule"))

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _rewrite_negated_comparison_formula(formula: str) -> str:
    def _replace(match: re.Match[str]) -> str:
        left = match.group("left")
        op = match.group("op")
        right = match.group("right")
        return f"{left} {_INVERTED_COMPARISON_OPERATORS[op]} {right}"

    return _NEGATED_COMPARISON_PATTERN.sub(_replace, str(formula))


_NEGATED_SUM_WHERE_PREDICATE_PATTERN = re.compile(
    r"sum_where\(\s*"
    r"(?P<relation>[A-Za-z_][A-Za-z0-9_]*)\s*,\s*"
    r"(?P<amount>[A-Za-z_][A-Za-z0-9_]*)\s*,\s*"
    r"not\s+(?P<predicate>[A-Za-z_][A-Za-z0-9_]*)\s*"
    r"\)"
)


def _issue_mentions_negated_sum_where_predicate(issue: str) -> bool:
    text = str(issue).lower()
    return "sum_where arg 3 must be a variable name" in text


def _rewrite_negated_sum_where_predicates(rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    rules_by_name = {
        str(rule.get("name")).strip(): rule
        for rule in rules
        if isinstance(rule, dict)
        and isinstance(rule.get("name"), str)
        and str(rule.get("name")).strip()
    }
    existing_names = set(rules_by_name)
    helper_by_predicate: dict[str, str] = {}
    repaired: list[str] = []

    for rule in list(rules):
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_changed = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            updated = _replace_negated_sum_where_predicates_in_formula(
                formula,
                rules=rules,
                rules_by_name=rules_by_name,
                existing_names=existing_names,
                helper_by_predicate=helper_by_predicate,
            )
            if updated != formula:
                version["formula"] = updated
                rule_changed = True
        if rule_changed:
            repaired.append(str(rule.get("name") or "formula_rule"))

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _replace_negated_sum_where_predicates_in_formula(
    formula: str,
    *,
    rules: list[Any],
    rules_by_name: dict[str, Any],
    existing_names: set[str],
    helper_by_predicate: dict[str, str],
) -> str:
    def _replace(match: re.Match[str]) -> str:
        relation = match.group("relation")
        amount = match.group("amount")
        predicate = match.group("predicate")
        helper_name = helper_by_predicate.get(predicate)
        if helper_name is None:
            predicate_rule = rules_by_name.get(predicate)
            if not isinstance(predicate_rule, dict):
                return match.group(0)
            helper_name = _negated_sum_where_helper_name(predicate, existing_names)
            helper_rule = _negated_sum_where_predicate_rule(
                predicate_rule,
                name=helper_name,
                predicate=predicate,
            )
            insert_at = rules.index(predicate_rule) + 1
            rules.insert(insert_at, helper_rule)
            rules_by_name[helper_name] = helper_rule
            existing_names.add(helper_name)
            helper_by_predicate[predicate] = helper_name
        return f"sum_where({relation}, {amount}, {helper_name})"

    return _NEGATED_SUM_WHERE_PREDICATE_PATTERN.sub(_replace, formula)


def _negated_sum_where_helper_name(predicate: str, existing_names: set[str]) -> str:
    if predicate.endswith("_excluded"):
        base = f"{predicate.removesuffix('_excluded')}_included"
    else:
        base = f"not_{predicate}"
    return _unique_generated_rule_name(base, existing_names)


def _negated_sum_where_predicate_rule(
    predicate_rule: dict[str, Any],
    *,
    name: str,
    predicate: str,
) -> dict[str, Any]:
    helper: dict[str, Any] = {
        "name": name,
        "kind": "derived",
        "entity": predicate_rule.get("entity"),
        "dtype": "Judgment",
        "period": predicate_rule.get("period"),
        "source": predicate_rule.get("source"),
        "metadata": {
            "proof": {
                "atoms": [
                    _source_atom_for_negated_sum_where_predicate(predicate_rule),
                ]
            }
        },
        "versions": [
            {
                "effective_from": _first_effective_from(predicate_rule),
                "formula": f"not {predicate}",
            }
        ],
    }
    if not helper["entity"]:
        helper.pop("entity", None)
    if not helper["period"]:
        helper.pop("period", None)
    if not helper["source"]:
        helper.pop("source", None)
    return helper


def _first_effective_from(rule: dict[str, Any]) -> str:
    versions = rule.get("versions")
    if isinstance(versions, list):
        for version in versions:
            if not isinstance(version, dict):
                continue
            effective_from = version.get("effective_from")
            if isinstance(effective_from, str) and effective_from.strip():
                return effective_from.strip()
    return "0001-01-01"


def _source_atom_for_negated_sum_where_predicate(
    rule: dict[str, Any],
) -> dict[str, Any]:
    proof = rule.get("metadata", {}).get("proof")
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    if isinstance(atoms, list):
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source = atom.get("source")
            if isinstance(source, dict):
                return {
                    "path": "versions[0].formula",
                    "kind": "formula",
                    "source": dict(source),
                }
    return {
        "path": "versions[0].formula",
        "kind": "formula",
    }


def _rewrite_judgment_numeric_comparisons(
    rules_file: Path,
    *,
    names: set[str],
) -> list[str]:
    if not rules_file.exists() or not names:
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_changed = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            rewritten = _rewrite_judgment_numeric_comparison_formula(
                formula,
                names=names,
            )
            if rewritten != formula:
                version["formula"] = rewritten
                rule_changed = True
        if rule_changed:
            repaired.append(str(rule.get("name") or "formula_rule"))

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _rewrite_judgment_conditional_formulas(rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        if str(rule.get("dtype") or "").strip() != "Judgment":
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_changed = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            rewritten = _rewrite_inline_judgment_conditional_formula(formula)
            if rewritten is None:
                continue
            version["formula"] = rewritten
            rule_changed = True
        if rule_changed:
            repaired.append(str(rule.get("name") or "judgment_rule"))

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _rewrite_inline_judgment_conditional_formula(formula: str) -> str | None:
    stripped = " ".join(str(formula).strip().split())
    if not stripped:
        return None

    rewritten = _rewrite_judgment_conditional_expression(stripped)
    if rewritten == stripped:
        return None
    return rewritten


def _rewrite_judgment_conditional_expression(expression: str) -> str:
    stripped = expression.strip()
    if not stripped:
        return stripped

    if stripped.startswith("if "):
        branch_formula = _rewrite_top_level_judgment_conditional(stripped)
        if branch_formula is not None:
            return branch_formula

    comparison_formula = _rewrite_scalar_conditional_comparison_in_judgment(stripped)
    if comparison_formula != stripped:
        return _rewrite_judgment_conditional_expression(comparison_formula)

    split = _split_inline_if_expression_span(stripped)
    if split is None:
        return stripped
    start, end, condition, true_branch, false_branch = split
    true_formula = _rewrite_judgment_conditional_expression(true_branch)
    false_formula = _rewrite_judgment_conditional_expression(false_branch)
    replacement = (
        f"((({condition}) and {true_formula})\n"
        f"  or (not ({condition}) and {false_formula}))"
    )
    return f"{stripped[:start].rstrip()}{replacement}{stripped[end:].lstrip()}"


def _rewrite_scalar_conditional_comparison_in_judgment(expression: str) -> str:
    split = _split_inline_if_expression_span(expression)
    if split is None:
        return expression
    start, end, condition, true_branch, false_branch = split
    term_start, term_end = _top_level_boolean_term_span_containing(
        expression,
        start,
    )
    raw_term = expression[term_start:term_end]
    leading = len(raw_term) - len(raw_term.lstrip())
    trailing = len(raw_term) - len(raw_term.rstrip())
    trimmed_start = term_start + leading
    trimmed_end = term_end - trailing
    term = expression[trimmed_start:trimmed_end]
    if _top_level_comparison_operator(term) is None:
        return expression
    relative_start = start - trimmed_start
    relative_end = end - trimmed_start
    if relative_start < 0 or relative_end > len(term):
        return expression

    true_term = f"{term[:relative_start]}{true_branch}{term[relative_end:]}".strip()
    false_term = f"{term[:relative_start]}{false_branch}{term[relative_end:]}".strip()
    if not true_term or not false_term:
        return expression
    replacement = (
        f"((({condition}) and {true_term})\n  or (not ({condition}) and {false_term}))"
    )
    return f"{expression[:trimmed_start]}{replacement}{expression[trimmed_end:]}"


def _top_level_boolean_term_span_containing(
    text: str,
    position: int,
) -> tuple[int, int]:
    depth = 0
    quote: str | None = None
    start = 0
    end = len(text)
    index = 0
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote and (index == 0 or text[index - 1] != "\\"):
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth == 0 and (
            _formula_word_at(text, index, "and") or _formula_word_at(text, index, "or")
        ):
            if index < position:
                start = index + (3 if text[index : index + 3].lower() == "and" else 2)
                index = start
                continue
            end = index
            break
        index += 1
    return start, end


def _top_level_comparison_operator(text: str) -> tuple[int, str] | None:
    depth = 0
    quote: str | None = None
    operators = ("<=", ">=", "==", "!=", "<", ">")
    index = 0
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote and (index == 0 or text[index - 1] != "\\"):
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth == 0:
            for operator in operators:
                if text.startswith(operator, index):
                    return index, operator
        index += 1
    return None


def _rewrite_top_level_judgment_conditional(expression: str) -> str | None:
    branches = _inline_if_judgment_branches(expression, [])
    if not branches:
        return None
    disjuncts: list[str] = []
    for conditions, result in branches:
        cleaned_result = _rewrite_judgment_conditional_expression(result.strip())
        if not cleaned_result or cleaned_result.startswith("if "):
            return None
        terms = [*_parenthesized_condition_terms(conditions), cleaned_result]
        disjuncts.append("(" + " and ".join(terms) + ")")
    return "\n  or ".join(disjuncts)


def _inline_if_judgment_branches(
    expression: str,
    conditions: list[str],
) -> list[tuple[list[str], str]] | None:
    split = _split_inline_if_expression(expression)
    if split is None:
        return [(conditions, expression)]
    condition, true_branch, false_branch = split
    true_branches = _inline_if_judgment_branches(
        true_branch,
        [*conditions, condition],
    )
    false_branches = _inline_if_judgment_branches(
        false_branch,
        [*conditions, f"not ({condition})"],
    )
    if true_branches is None or false_branches is None:
        return None
    return [*true_branches, *false_branches]


def _split_inline_if_expression(expression: str) -> tuple[str, str, str] | None:
    text = expression.strip()
    split = _split_inline_if_expression_at(text, 0)
    if split is None or split[1] != len(text):
        return None
    _start, _end, condition, true_branch, false_branch = split
    return condition, true_branch, false_branch


def _split_inline_if_expression_span(
    expression: str,
) -> tuple[int, int, str, str, str] | None:
    index = 0
    while index < len(expression):
        if not _formula_word_at(expression, index, "if"):
            index += 1
            continue
        split = _split_inline_if_expression_at(expression, index)
        if split is not None:
            return split
        index += 1
    return None


def _split_inline_if_expression_at(
    text: str,
    start: int,
) -> tuple[int, int, str, str, str] | None:
    if not _formula_word_at(text, start, "if"):
        return None
    base_depth = _formula_bracket_depth_before(text, start)
    head_end = start + len("if")
    colon_index = _find_top_level_token(
        text,
        ":",
        start=head_end,
        base_depth=base_depth,
    )
    if colon_index is None:
        return None
    else_match = _find_inline_else_token(
        text,
        colon_index + 1,
        base_depth=base_depth,
    )
    if else_match is None:
        return None
    else_index, else_colon_index = else_match
    end = _find_inline_if_expression_end(
        text,
        else_colon_index + 1,
        base_depth=base_depth,
    )
    condition = text[head_end:colon_index].strip()
    true_branch = text[colon_index + 1 : else_index].strip()
    false_branch = text[else_colon_index + 1 : end].strip()
    if not condition or not true_branch or not false_branch:
        return None
    return start, end, condition, true_branch, false_branch


def _find_top_level_token(
    text: str,
    token: str,
    *,
    start: int = 0,
    base_depth: int = 0,
) -> int | None:
    depth = base_depth
    quote: str | None = None
    index = max(start, 0)
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote:
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth == base_depth and text.startswith(token, index):
            return index
        index += 1
    return None


def _find_inline_else_token(
    text: str,
    start: int,
    *,
    base_depth: int,
) -> tuple[int, int] | None:
    depth = base_depth
    quote: str | None = None
    nested_conditionals = 0
    index = max(start, 0)
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote:
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth != base_depth:
            index += 1
            continue
        if _formula_word_at(text, index, "if"):
            nested_conditionals += 1
            index += len("if")
            continue
        if _formula_word_at(text, index, "else"):
            colon_index = _find_inline_else_colon(text, index + len("else"))
            if colon_index is None:
                index += 1
                continue
            if nested_conditionals:
                nested_conditionals -= 1
                index = colon_index + 1
                continue
            return index, colon_index
        index += 1
    return None


def _find_inline_else_colon(text: str, start: int) -> int | None:
    index = start
    while index < len(text) and text[index].isspace():
        index += 1
    return index if index < len(text) and text[index] == ":" else None


def _find_inline_if_expression_end(
    text: str,
    start: int,
    *,
    base_depth: int,
) -> int:
    depth = base_depth
    quote: str | None = None
    index = max(start, 0)
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote:
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth == base_depth:
                return index
            depth -= 1
            index += 1
            continue
        if char == "," and depth == base_depth:
            return index
        index += 1
    return len(text)


def _formula_bracket_depth_before(text: str, position: int) -> int:
    depth = 0
    quote: str | None = None
    for index, char in enumerate(text[: max(position, 0)]):
        if quote:
            if char == quote and (index == 0 or text[index - 1] != "\\"):
                quote = None
            continue
        if char in {"'", '"'}:
            quote = char
        elif char in "([{":
            depth += 1
        elif char in ")]}" and depth:
            depth -= 1
    return depth


def _formula_word_at(text: str, index: int, word: str) -> bool:
    end = index + len(word)
    if text[index:end].lower() != word.lower():
        return False
    before = text[index - 1] if index > 0 else ""
    after = text[end] if end < len(text) else ""
    return not (before.isalnum() or before == "_") and not (
        after.isalnum() or after == "_"
    )


def _parenthesized_condition_terms(conditions: list[str]) -> list[str]:
    terms: list[str] = []
    for condition in conditions:
        stripped = condition.strip()
        if not stripped:
            continue
        if stripped.startswith("not (") and stripped.endswith(")"):
            terms.append(stripped)
        else:
            terms.append(f"({stripped})")
    return terms


def _rewrite_judgment_numeric_comparison_formula(
    formula: str,
    *,
    names: set[str],
) -> str:
    rewritten = str(formula)
    for name in sorted(names, key=len, reverse=True):
        escaped = re.escape(name)
        name_token = rf"(?<![A-Za-z0-9_]){escaped}(?![A-Za-z0-9_])"
        zero = r"(?<![A-Za-z0-9_.])0(?:\.0+)?(?![A-Za-z0-9_.])"
        one = r"(?<![A-Za-z0-9_.])1(?:\.0+)?(?![A-Za-z0-9_.])"
        replacements = (
            (rf"{name_token}\s*==\s*{zero}", f"not {name}"),
            (rf"\b{zero}\s*==\s*{name_token}", f"not {name}"),
            (rf"{name_token}\s*!=\s*{zero}", name),
            (rf"\b{zero}\s*!=\s*{name_token}", name),
            (rf"{name_token}\s*==\s*{one}", name),
            (rf"\b{one}\s*==\s*{name_token}", name),
            (rf"{name_token}\s*!=\s*{one}", f"not {name}"),
            (rf"\b{one}\s*!=\s*{name_token}", f"not {name}"),
            (rf"{name_token}\s*==\s*false\b", f"not {name}"),
            (rf"\bfalse\s*==\s*{name_token}", f"not {name}"),
            (rf"{name_token}\s*!=\s*false\b", name),
            (rf"\bfalse\s*!=\s*{name_token}", name),
            (rf"{name_token}\s*==\s*true\b", name),
            (rf"\btrue\s*==\s*{name_token}", name),
            (rf"{name_token}\s*!=\s*true\b", f"not {name}"),
            (rf"\btrue\s*!=\s*{name_token}", f"not {name}"),
        )
        for pattern, replacement in replacements:
            rewritten = re.sub(pattern, replacement, rewritten, flags=re.IGNORECASE)
    return rewritten


def _rule_has_comparison_formula(rule: dict[str, object]) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    return any(
        isinstance(version, dict)
        and isinstance(version.get("formula"), str)
        and re.search(r"(?:<=|>=|==|!=|<|>)", version["formula"])
        for version in versions
    )


def _rule_has_top_level_comparison_formula(rule: dict[str, object]) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    return any(
        isinstance(version, dict)
        and isinstance(version.get("formula"), str)
        and _formula_has_top_level_comparison(version["formula"])
        for version in versions
    )


def _formula_has_top_level_comparison(formula: str) -> bool:
    normalized = re.sub(r"\s+", " ", str(formula).strip())
    if normalized.startswith("if ") or " else:" in normalized:
        return False
    depth = 0
    index = 0
    while index < len(normalized):
        char = normalized[index]
        if char == "(":
            depth += 1
        elif char == ")" and depth > 0:
            depth -= 1
        elif depth == 0:
            pair = normalized[index : index + 2]
            if pair in {"<=", ">=", "==", "!="}:
                return True
            if char in {"<", ">"}:
                return True
        index += 1
    return False


def _rewrite_boolean_test_values_as_judgments(
    test_file: Path,
    rule_names: set[str],
) -> None:
    if not test_file.exists():
        return
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(payload, list):
        return

    changed = False
    for case in payload:
        if not isinstance(case, dict):
            continue
        for section_name in ("input", "output"):
            section = case.get(section_name)
            if not isinstance(section, dict):
                continue
            for key, value in list(section.items()):
                rule_name = str(key).rsplit("#", 1)[-1]
                if rule_name not in rule_names or not isinstance(value, bool):
                    continue
                section[key] = "holds" if value else "not_holds"
                changed = True

    if changed:
        test_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )


def _try_repair_generated_module_layout_for_apply(
    result,
    *,
    output_root: Path,
) -> dict[str, list[str]]:
    """Promote model-emitted top-level RuleSpec members out of ``module``."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return {}

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _promote_module_layout_members(rules_file=rules_file)


def _promote_module_layout_members(*, rules_file: Path) -> dict[str, list[str]]:
    if not rules_file.exists():
        return {}

    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return {}
    if not isinstance(payload, dict):
        return {}

    module = payload.get("module")
    if not isinstance(module, dict):
        return {}

    promoted: dict[str, list[str]] = {}
    if "imports" in module:
        module_imports = module.pop("imports")
        if isinstance(module_imports, list):
            import_refs = [
                str(item).strip() for item in module_imports if str(item).strip()
            ]
            if import_refs:
                existing_imports = payload.get("imports")
                existing = (
                    [
                        str(item).strip()
                        for item in existing_imports
                        if str(item).strip()
                    ]
                    if isinstance(existing_imports, list)
                    else []
                )
                merged_imports = [*import_refs]
                merged_imports.extend(
                    item for item in existing if item not in merged_imports
                )
                payload["imports"] = merged_imports
                promoted["imports"] = import_refs

    if "rules" in module:
        module_rules = module.pop("rules")
        if isinstance(module_rules, list):
            rule_names = _rulespec_rule_labels(module_rules)
            if rule_names:
                existing_rules = payload.get("rules")
                if isinstance(existing_rules, list):
                    payload["rules"] = [*existing_rules, *module_rules]
                else:
                    payload["rules"] = module_rules
                promoted["rules"] = rule_names

    if not promoted:
        return {}

    reordered: dict[str, object] = {}
    inserted: set[str] = set()
    for key, value in payload.items():
        if key in {"imports", "rules"}:
            continue
        reordered[key] = value
        if key == "format":
            for promoted_key in ("imports", "rules"):
                if promoted_key in payload:
                    reordered[promoted_key] = payload[promoted_key]
                    inserted.add(promoted_key)
    for promoted_key in ("imports", "rules"):
        if promoted_key in payload and promoted_key not in inserted:
            reordered[promoted_key] = payload[promoted_key]

    rules_file.write_text(
        yaml.safe_dump(reordered, sort_keys=False, allow_unicode=False)
    )
    return promoted


def _rulespec_rule_labels(rules: list[object]) -> list[str]:
    labels: list[str] = []
    for index, rule in enumerate(rules):
        name = rule.get("name") if isinstance(rule, dict) else None
        label = str(name).strip() if isinstance(name, str) and name.strip() else ""
        labels.append(label or f"rules[{index}]")
    return labels


def _try_repair_generated_nested_test_tables_for_apply(
    result,
    *,
    output_root: Path,
) -> list[str]:
    """Hoist model-emitted ``input.tables`` companion rows before apply."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _hoist_nested_test_tables(test_file)


def _hoist_nested_test_tables(test_file: Path) -> list[str]:
    if not test_file.exists():
        return []

    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []

    if isinstance(payload, dict) and isinstance(payload.get("cases"), list):
        cases = payload["cases"]
    elif isinstance(payload, list):
        cases = payload
    else:
        return []

    repaired_cases: list[str] = []
    for index, test_case in enumerate(cases, start=1):
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if not isinstance(inputs, dict):
            continue
        nested_tables = inputs.get("tables")
        if not isinstance(nested_tables, dict):
            continue
        existing_tables = test_case.get("tables")
        if existing_tables not in (None, "") and existing_tables != {}:
            continue
        inputs.pop("tables")
        test_case["tables"] = nested_tables
        if not inputs:
            test_case["input"] = {}
        repaired_cases.append(str(test_case.get("name") or f"case {index}"))

    if not repaired_cases:
        return []

    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired_cases


def _try_repair_generated_table_relation_tests_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Split table-row relation inputs into scalar root-entity test cases."""
    if not any(
        "tables." in str(issue)
        and "#relation." in str(issue)
        and "must be scalar" in str(issue)
        for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _split_table_row_relation_test_cases(test_file)


_UNDECLARED_RELATION_INPUT_ISSUE_PATTERN = re.compile(
    r"relation input `(?P<reference>[^`]+#relation\.(?P<name>[A-Za-z_][A-Za-z0-9_]*))` "
    r"does not resolve to a declared relation"
)


def _try_repair_generated_missing_data_relations_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Declare generated local relations proven by formulas and companion tests.

    Model output can contain a valid relation aggregate such as
    `sum_where(dependent_care_recipients, ...)` and companion
    `#relation.dependent_care_recipients` rows, but omit the corresponding
    `kind: data_relation` rule. Repair only that narrow, CI-proven case.
    """
    relation_names = _undeclared_relation_names_from_issues(issues)
    if not relation_names:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    existing_relations = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("kind") or "").strip().lower() == "data_relation"
    }

    repaired: list[str] = []
    for relation_name in relation_names:
        if relation_name in existing_relations:
            continue
        if not _rulespec_rules_reference_relation(rules, relation_name):
            continue
        relation_rule = _build_inferred_data_relation_rule(rules, relation_name)
        if relation_rule is None:
            continue
        insert_at = _first_rule_index_referencing_relation(rules, relation_name)
        rules.insert(insert_at, relation_rule)
        existing_relations.add(relation_name)
        repaired.append(relation_name)

    if not repaired:
        return []

    test_file = _rulespec_test_path(rules_file)
    _remove_stale_relation_scalar_inputs(test_file, repaired)
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _undeclared_relation_names_from_issues(issues: list[str]) -> list[str]:
    relation_names: list[str] = []
    seen: set[str] = set()
    for issue in issues:
        match = _UNDECLARED_RELATION_INPUT_ISSUE_PATTERN.search(str(issue))
        if match is None:
            continue
        name = match.group("name").strip()
        if name and name not in seen:
            seen.add(name)
            relation_names.append(name)
    return relation_names


def _rulespec_rules_reference_relation(
    rules: list[object],
    relation_name: str,
) -> bool:
    return any(
        _formula_references_relation(formula, relation_name)
        for rule in rules
        if isinstance(rule, dict)
        for formula in _rulespec_rule_formula_strings(rule)
    )


def _first_rule_index_referencing_relation(
    rules: list[object],
    relation_name: str,
) -> int:
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        if any(
            _formula_references_relation(formula, relation_name)
            for formula in _rulespec_rule_formula_strings(rule)
        ):
            return index
    return 0


def _build_inferred_data_relation_rule(
    rules: list[object],
    relation_name: str,
) -> dict[str, object] | None:
    by_name = {
        str(rule.get("name") or "").strip(): rule
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    related_entities: list[str] = []
    enclosing_entities: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        formulas = _rulespec_rule_formula_strings(rule)
        if not any(
            _formula_references_relation(formula, relation_name) for formula in formulas
        ):
            continue
        enclosing_entity = str(rule.get("entity") or "").strip()
        if enclosing_entity:
            enclosing_entities.append(enclosing_entity)
        for formula in formulas:
            for identifier in _relation_aggregate_argument_identifiers(
                formula,
                relation_name,
            ):
                related_entity = _rulespec_rule_entity(by_name.get(identifier))
                if related_entity and related_entity != enclosing_entity:
                    related_entities.append(related_entity)

    relation: dict[str, object] = {
        "name": relation_name,
        "kind": "data_relation",
        "data_relation": {
            "predicate": relation_name,
            "arity": 2,
        },
    }
    related_entity = _first_common_value(related_entities)
    enclosing_entity = _first_common_value(enclosing_entities)
    if related_entity and enclosing_entity:
        relation["data_relation"] = {
            "predicate": relation_name,
            "arity": 2,
            "arguments": [
                {
                    "name": _singular_relation_argument_name(relation_name),
                    "entity": related_entity,
                },
                {
                    "name": _snake_case_identifier(enclosing_entity),
                    "entity": enclosing_entity,
                },
            ],
        }
    return relation


def _formula_references_relation(formula: str, relation_name: str) -> bool:
    escaped = re.escape(relation_name)
    return bool(
        re.search(
            rf"\b(?:count_where|len|sum|sum_where)\s*\(\s*{escaped}\b",
            formula,
        )
        or re.search(rf"\b{escaped}\.[A-Za-z_][A-Za-z0-9_]*\b", formula)
    )


def _relation_aggregate_argument_identifiers(
    formula: str,
    relation_name: str,
) -> list[str]:
    escaped = re.escape(relation_name)
    identifiers: list[str] = []
    for match in re.finditer(
        rf"\bsum_where\s*\(\s*{escaped}\s*,\s*"
        r"(?P<amount>[A-Za-z_][A-Za-z0-9_]*)\s*,\s*"
        r"(?P<predicate>[A-Za-z_][A-Za-z0-9_]*)\s*\)",
        formula,
    ):
        identifiers.extend([match.group("amount"), match.group("predicate")])
    for match in re.finditer(
        rf"\bcount_where\s*\(\s*{escaped}\s*,\s*"
        r"(?P<predicate>[A-Za-z_][A-Za-z0-9_]*)\s*\)",
        formula,
    ):
        identifiers.append(match.group("predicate"))
    return identifiers


def _rulespec_rule_entity(rule: object) -> str | None:
    if not isinstance(rule, dict):
        return None
    entity = str(rule.get("entity") or "").strip()
    return entity or None


def _first_common_value(values: list[str]) -> str | None:
    if not values:
        return None
    counts = Counter(values)
    return max(counts, key=lambda item: (counts[item], -values.index(item)))


def _singular_relation_argument_name(relation_name: str) -> str:
    if relation_name.endswith("_children"):
        return f"{relation_name.removesuffix('_children')}_child"
    if relation_name == "children":
        return "child"
    if relation_name.endswith("ies"):
        return f"{relation_name[:-3]}y"
    if relation_name.endswith("s") and not relation_name.endswith("ss"):
        return relation_name[:-1]
    return relation_name


def _snake_case_identifier(value: str) -> str:
    value = re.sub(r"(.)([A-Z][a-z]+)", r"\1_\2", value)
    value = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", value)
    return value.replace("-", "_").lower()


def _remove_stale_relation_scalar_inputs(
    test_file: Path,
    relation_names: list[str],
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if isinstance(payload, dict) and isinstance(payload.get("cases"), list):
        cases = payload["cases"]
    elif isinstance(payload, list):
        cases = payload
    else:
        return []

    relation_set = set(relation_names)
    removed: list[str] = []
    for index, case in enumerate(cases, start=1):
        if not isinstance(case, dict):
            continue
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        case_name = str(case.get("name") or f"case {index}")
        for key in list(inputs):
            fragment = _rulespec_test_key_fragment(key)
            if not fragment.startswith("input."):
                continue
            input_name = fragment.removeprefix("input.").strip()
            if input_name not in relation_set:
                continue
            value = inputs.get(key)
            if isinstance(value, list):
                continue
            inputs.pop(key, None)
            removed.append(f"{case_name}:{input_name}")

    if not removed:
        return []
    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return removed


_SCALAR_RELATION_ROW_ISSUE_PATTERN = re.compile(
    r"Test case `(?P<case>[^`]+)` input invalid: relation "
    r"`(?P<relation>[^`]+)` item #(?P<index>\d+) must be a mapping"
)

_TEST_INPUT_ASSIGNMENT_MISSING_CASE_PATTERN = re.compile(
    r"Test input assignment missing:\s*`(?P<case>[^`]+)`"
)


def _try_repair_generated_scalar_relation_rows_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Replace scalar relation rows with companion-test row mappings.

    Generated tests occasionally write relation inputs as `- true` or `- 300`.
    The engine needs each relation row to be a mapping of child facts. Prefer
    exact row-shape validator issues, and fall back to missing-input-assignment
    issues only when the named generated test case still contains scalar rows.
    """
    parsed_issues = [
        parsed
        for issue in issues
        if (parsed := _parse_scalar_relation_row_issue(str(issue))) is not None
    ]
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if not parsed_issues:
        parsed_issues = _scalar_relation_row_issues_from_missing_input_assignment(
            test_file,
            issues=issues,
        )
    if not parsed_issues:
        return []
    return _repair_scalar_relation_rows(
        rules_file=rules_file,
        test_file=test_file,
        policy_repo_path=policy_repo_path,
        parsed_issues=parsed_issues,
    )


_CHILD_NUMERIC_REENCODING_ISSUE_PATTERN = re.compile(
    r"Child fragment numeric output re-encoded: .*? in rule\(s\) "
    r"(?P<parents>.+?)\. Import and reference the child "
    r"(?P<child_hint>.+?) instead of copying the child value"
)


def _try_repair_generated_child_numeric_reencoding_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    parsed_issues = [
        parsed
        for issue in issues
        if (parsed := _parse_child_numeric_reencoding_issue(str(issue))) is not None
    ]
    if not parsed_issues:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_child_numeric_reencoding_parent_aliases(
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
        parsed_issues=parsed_issues,
    )


def _parse_child_numeric_reencoding_issue(
    issue: str,
) -> tuple[tuple[str, ...], str] | None:
    match = _CHILD_NUMERIC_REENCODING_ISSUE_PATTERN.search(issue)
    if match is None:
        return None
    parent_names = tuple(re.findall(r"`([^`]+)`", match.group("parents")))
    child_refs = tuple(
        ref for ref in re.findall(r"`([^`]+)`", match.group("child_hint")) if "#" in ref
    )
    if not parent_names or len(child_refs) != 1:
        return None
    return parent_names, child_refs[0]


def _repair_child_numeric_reencoding_parent_aliases(
    *,
    rules_file: Path,
    policy_repo_path: Path,
    relative_output: Path | None = None,
    parsed_issues: list[tuple[tuple[str, ...], str]],
) -> list[str]:
    """Remove parent helpers that re-derive child-owned numeric concepts.

    This intentionally handles only a narrow generated pattern:
    a parent-local helper that copied a numeric child literal, plus optional
    `1 / helper` wrappers. Broader rewrites should stay as validation failures
    and be re-encoded.
    """
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    replacements: dict[str, str] = {}
    remove_names: set[str] = set()
    for parent_names, child_ref in parsed_issues:
        if "#" not in child_ref:
            continue
        child_name = child_ref.rsplit("#", 1)[1].strip()
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", child_name):
            continue
        for parent_name in parent_names:
            if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", parent_name):
                continue
            remove_names.add(parent_name)
            replacements[parent_name] = child_name
        replacements.update(
            _child_numeric_reencoding_wrapper_replacements(
                rules,
                parent_names=set(parent_names),
                child_name=child_name,
            )
        )

    if not remove_names and not replacements:
        return []
    remove_names.update(replacements)
    removed_rules: list[str] = []
    remaining_rules: list[object] = []
    for rule in rules:
        if isinstance(rule, dict) and str(rule.get("name") or "") in remove_names:
            removed_rules.append(str(rule.get("name") or ""))
            continue
        remaining_rules.append(rule)
    if not removed_rules:
        return []
    payload["rules"] = remaining_rules

    local_ref_prefix = _rulespec_local_ref_prefix_for_generated_file(
        rules_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
    )
    child_ref_by_name = {
        child_name: child_ref
        for _parent_names, child_ref in parsed_issues
        for child_name in [child_ref.rsplit("#", 1)[1].strip()]
    }
    full_ref_replacements = {
        f"{local_ref_prefix}{local_name}": child_ref_by_name[child_name]
        for local_name, child_name in replacements.items()
        if child_name in child_ref_by_name
    }
    payload = _rewrite_child_numeric_reencoding_references(
        payload,
        name_replacements=replacements,
        full_ref_replacements=full_ref_replacements,
    )
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return removed_rules


def _child_numeric_reencoding_wrapper_replacements(
    rules: list[object],
    *,
    parent_names: set[str],
    child_name: str,
) -> dict[str, str]:
    replacements: dict[str, str] = {}
    if len(parent_names) != 1:
        return replacements
    parent_name = next(iter(parent_names))
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "")
        if not name or name == parent_name:
            continue
        formulas = _rulespec_rule_formula_strings(rule)
        if not formulas:
            continue
        if all(
            _formula_is_one_over_identifier(formula, parent_name)
            for formula in formulas
        ):
            replacements[name] = child_name
    return replacements


def _rulespec_rule_formula_strings(rule: dict[str, object]) -> list[str]:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return []
    formulas: list[str] = []
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str):
            formulas.append(formula)
    return formulas


def _formula_is_one_over_identifier(formula: str, identifier: str) -> bool:
    compact = re.sub(r"\s+", "", formula.strip())
    return compact == f"1/{identifier}"


def _rulespec_local_ref_prefix_for_generated_file(
    rules_file: Path,
    *,
    policy_repo_path: Path,
    relative_output: Path | None = None,
) -> str:
    if relative_output is not None:
        relative = relative_output
    else:
        try:
            relative = rules_file.resolve().relative_to(policy_repo_path.resolve())
        except ValueError:
            relative = rules_file
    return f"{_repo_jurisdiction_prefix(policy_repo_path)}:{relative.with_suffix('').as_posix()}#"


def _rewrite_child_numeric_reencoding_references(
    value: object,
    *,
    name_replacements: dict[str, str],
    full_ref_replacements: dict[str, str],
) -> object:
    if isinstance(value, dict):
        return {
            key: _rewrite_child_numeric_reencoding_references(
                item,
                name_replacements=name_replacements,
                full_ref_replacements=full_ref_replacements,
            )
            for key, item in value.items()
        }
    if isinstance(value, list):
        return [
            _rewrite_child_numeric_reencoding_references(
                item,
                name_replacements=name_replacements,
                full_ref_replacements=full_ref_replacements,
            )
            for item in value
        ]
    if not isinstance(value, str):
        return value
    if value in full_ref_replacements:
        return full_ref_replacements[value]
    for old_name, new_name in name_replacements.items():
        value = re.sub(
            rf"(?<![A-Za-z0-9_]){re.escape(old_name)}(?![A-Za-z0-9_])",
            new_name,
            value,
        )
    return value


def _parse_scalar_relation_row_issue(
    issue: str,
) -> tuple[str, str, int] | None:
    match = _SCALAR_RELATION_ROW_ISSUE_PATTERN.search(issue)
    if match is None:
        return None
    return (
        match.group("case"),
        match.group("relation"),
        int(match.group("index")),
    )


def _scalar_relation_row_issues_from_missing_input_assignment(
    test_file: Path,
    *,
    issues: list[str],
) -> list[tuple[str, str, int]]:
    case_names = {
        match.group("case").strip()
        for issue in issues
        if (match := _TEST_INPUT_ASSIGNMENT_MISSING_CASE_PATTERN.search(str(issue)))
    }
    if not case_names or not test_file.exists():
        return []
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if isinstance(payload, dict) and isinstance(payload.get("cases"), list):
        cases = payload["cases"]
    elif isinstance(payload, list):
        cases = payload
    else:
        return []

    parsed_issues: list[tuple[str, str, int]] = []
    for case in cases:
        if not isinstance(case, dict):
            continue
        case_name = str(case.get("name") or "").strip()
        if case_name not in case_names:
            continue
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        for relation_ref, rows in inputs.items():
            relation_key = str(relation_ref)
            if "#relation." not in relation_key or not isinstance(rows, list):
                continue
            for index, row in enumerate(rows, start=1):
                if not isinstance(row, dict):
                    parsed_issues.append((case_name, relation_key, index))
    return parsed_issues


def _repair_scalar_relation_rows(
    *,
    rules_file: Path | None = None,
    test_file: Path,
    policy_repo_path: Path,
    parsed_issues: list[tuple[str, str, int]],
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, list):
        return []

    repairs_by_case_relation: dict[tuple[str, str], set[int]] = defaultdict(set)
    for case_name, relation_ref, row_index in parsed_issues:
        repairs_by_case_relation[(case_name, relation_ref)].add(row_index)

    repaired: list[str] = []
    for case in payload:
        if not isinstance(case, dict):
            continue
        case_name = str(case.get("name") or "")
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        for relation_ref, rows in list(inputs.items()):
            relation_key = str(relation_ref)
            repair_rows = repairs_by_case_relation.get((case_name, relation_key))
            if not repair_rows or not isinstance(rows, list):
                continue
            for row_index in sorted(repair_rows):
                list_index = row_index - 1
                if list_index < 0 or list_index >= len(rows):
                    continue
                scalar_value = rows[list_index]
                if isinstance(scalar_value, dict):
                    continue
                replacement = _relation_row_replacement_from_companion_tests(
                    relation_key,
                    scalar_value,
                    policy_repo_path=policy_repo_path,
                )
                if replacement is None:
                    replacement = _relation_row_replacement_from_generated_rules(
                        relation_key,
                        scalar_value,
                        rules_file=rules_file,
                    )
                if replacement is None:
                    continue
                rows[list_index] = replacement
                repaired.append(f"{case_name}:{relation_key}[{row_index}]")

    if not repaired:
        return []
    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _repair_aca_36b_b_premium_assistance_compat(rules_file: Path) -> list[str]:
    """Normalize generated ACA 36B(b) premium-assistance shape.

    This is intentionally scoped to the 26 USC 36B(b) generated parent. It keeps
    the legal monthly cap in `premium_assistance_amount`, scopes the annual sum
    to paragraph (1), and avoids decimal noise from a literal `1 / 12` factor.
    """
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    module = payload.get("module")
    if not isinstance(module, dict):
        return []
    source_verification = module.get("source_verification")
    if not isinstance(source_verification, dict):
        return []
    if source_verification.get("corpus_citation_path") != "us/statute/26/36B":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    rule_names = {
        str(rule.get("name") or "")
        for rule in rules
        if isinstance(rule, dict) and rule.get("name")
    }
    if "premium_assistance_credit_amount" not in rule_names:
        return []
    if "premium_assistance_amount" not in rule_names:
        return []

    repairs: list[str] = []
    imports = payload.get("imports")
    if isinstance(imports, list):
        filtered_imports = [
            item
            for item in imports
            if str(item).strip() != "us:statutes/26/36B/b/3/A#applicable_percentage"
        ]
        if len(filtered_imports) != len(imports):
            repairs.append("remove_applicable_percentage_import")
            if filtered_imports:
                payload["imports"] = filtered_imports
            else:
                payload.pop("imports", None)

    payload = _rewrite_aca_36b_b_compat_references(payload)
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return repairs

    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "")
        if name == "required_contribution_annual_to_monthly_divisor":
            if _set_first_formula(rule, "12"):
                repairs.append("monthly_divisor_formula")
        elif name == "required_monthly_contribution":
            if _set_first_formula(
                rule,
                "(household_income_for_taxable_year / required_contribution_annual_to_monthly_divisor) * applicable_percentage_for_taxable_year",
            ):
                repairs.append("required_monthly_contribution_formula")
            removed = _remove_rule_proof_import(
                rule, "us:statutes/26/36B/b/3/A#applicable_percentage"
            )
            if removed:
                repairs.append("remove_applicable_percentage_proof_import")
        elif name == "premium_assistance_credit_amount":
            if rule.get("source") != "paragraph (1)":
                rule["source"] = "paragraph (1)"
                repairs.append("annual_credit_source")

    if not repairs:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repairs


def _try_repair_generated_aca_36b_b_premium_assistance_compat_for_apply(
    result,
    *,
    output_root: Path,
) -> list[str]:
    """Apply the 26 USC 36B(b) compatibility repair to generated apply output."""
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []
    if relative_output != Path("statutes/26/36B/b.yaml"):
        return []
    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_aca_36b_b_premium_assistance_compat(rules_file)


def _rewrite_aca_36b_b_compat_references(value: object) -> object:
    replacements = {
        "required_contribution_monthly_fraction": (
            "required_contribution_annual_to_monthly_divisor"
        ),
        "required_monthly_contribution_amount": "required_monthly_contribution",
        "applicable_percentage *": "applicable_percentage_for_taxable_year *",
    }
    if isinstance(value, dict):
        return {
            key: _rewrite_aca_36b_b_compat_references(item)
            for key, item in value.items()
        }
    if isinstance(value, list):
        return [_rewrite_aca_36b_b_compat_references(item) for item in value]
    if not isinstance(value, str):
        return value
    for old, new in replacements.items():
        value = value.replace(old, new)
    return value


def _set_first_formula(rule: dict[str, object], formula: str) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    for version in versions:
        if not isinstance(version, dict):
            continue
        if version.get("formula") == formula:
            return False
        version["formula"] = formula
        return True
    return False


def _remove_rule_proof_import(rule: dict[str, object], target: str) -> bool:
    metadata = rule.get("metadata")
    proof = (
        metadata.get("proof")
        if isinstance(metadata, dict) and isinstance(metadata.get("proof"), dict)
        else rule.get("proof")
    )
    if not isinstance(proof, dict):
        return False
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return False
    filtered_atoms = []
    removed = False
    for atom in atoms:
        if isinstance(atom, dict) and isinstance(atom.get("import"), dict):
            if str(atom["import"].get("target") or "").strip() == target:
                removed = True
                continue
        filtered_atoms.append(atom)
    if removed:
        proof["atoms"] = filtered_atoms
    return removed


def _relation_row_replacement_from_companion_tests(
    relation_ref: str,
    scalar_value: object,
    *,
    policy_repo_path: Path,
) -> dict[str, object] | None:
    exemplar_rows = _relation_rows_from_companion_tests(
        relation_ref,
        policy_repo_path=policy_repo_path,
    )
    if not exemplar_rows:
        return None
    for row in exemplar_rows:
        if _relation_row_matches_scalar_value(row, scalar_value):
            return copy.deepcopy(row)
    if isinstance(scalar_value, bool):
        template = copy.deepcopy(exemplar_rows[0])
        changed = False
        for key, value in list(template.items()):
            if isinstance(value, bool):
                template[key] = scalar_value
                changed = True
        if changed:
            return template
    return None


def _relation_row_replacement_from_generated_rules(
    relation_ref: str,
    scalar_value: object,
    *,
    rules_file: Path | None,
) -> dict[str, object] | None:
    """Infer a relation row mapping when a generated formula uses one child fact.

    Companion tests are preferred because they preserve established row shape.
    New generated files can define a relation and immediately test it before any
    companion exists; in that case a scalar row like `- 30000` is unambiguous
    only when the formulas reference exactly one child fact through
    `relation_name.child_fact` or a boolean aggregate such as
    `count_where(relation_name, child_fact)`.
    """
    if rules_file is None or not rules_file.exists():
        return None
    relation_name = _relation_name_from_relation_ref(relation_ref)
    if not relation_name:
        return None
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return None
    child_names = _single_relation_child_fact_names(payload, relation_name)
    if len(child_names) != 1:
        return None
    relation_base = relation_ref.split("#", 1)[0].strip()
    child_ref = f"{relation_base}#input.{next(iter(child_names))}"
    return {child_ref: copy.deepcopy(scalar_value)}


def _relation_name_from_relation_ref(relation_ref: str) -> str:
    fragment = relation_ref.split("#", 1)[1] if "#" in relation_ref else relation_ref
    fragment = fragment.strip()
    if fragment.startswith("relation."):
        return fragment.removeprefix("relation.").strip()
    return ""


def _single_relation_child_fact_names(
    payload: object,
    relation_name: str,
) -> set[str]:
    if not isinstance(payload, dict) or not relation_name:
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    escaped_relation = re.escape(relation_name)
    child_pattern = re.compile(
        rf"(?<![A-Za-z0-9_]){escaped_relation}\."
        r"(?P<child>[A-Za-z_][A-Za-z0-9_]*)\b"
    )
    aggregate_pattern = re.compile(
        rf"\b(?:count_where|any_where|all_where)\(\s*{escaped_relation}\s*,\s*"
        r"(?P<child>[A-Za-z_][A-Za-z0-9_]*)\b(?!\s*\.)"
    )
    child_names: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            child_names.update(
                match.group("child") for match in child_pattern.finditer(formula)
            )
            child_names.update(
                match.group("child") for match in aggregate_pattern.finditer(formula)
            )
    return child_names


def _relation_row_matches_scalar_value(
    row: dict[str, object],
    scalar_value: object,
) -> bool:
    if isinstance(scalar_value, bool):
        return any(value is scalar_value for value in row.values())
    return False


def _relation_rows_from_companion_tests(
    relation_ref: str,
    *,
    policy_repo_path: Path,
) -> list[dict[str, object]]:
    relation_test_file = _companion_test_file_for_relation_ref(
        relation_ref,
        policy_repo_path=policy_repo_path,
    )
    if relation_test_file is None or not relation_test_file.exists():
        return []
    try:
        payload = yaml.safe_load(relation_test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, list):
        return []
    rows: list[dict[str, object]] = []
    for case in payload:
        if not isinstance(case, dict):
            continue
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        relation_rows = inputs.get(relation_ref)
        if not isinstance(relation_rows, list):
            continue
        for row in relation_rows:
            if isinstance(row, dict):
                rows.append(copy.deepcopy(row))
    return rows


def _companion_test_file_for_relation_ref(
    relation_ref: str,
    *,
    policy_repo_path: Path,
) -> Path | None:
    relation_base = relation_ref.split("#", 1)[0].strip().strip("/")
    if ":" not in relation_base:
        return None
    prefix, relative = relation_base.split(":", 1)
    if not prefix or not relative:
        return None
    relative_path = Path(relative)
    if relative_path.suffix not in {".yaml", ".yml"}:
        relative_path = relative_path.with_suffix(".yaml")
    repo_roots = []
    current_prefix = _repo_jurisdiction_prefix(policy_repo_path)
    if prefix == current_prefix:
        repo_roots.append(policy_repo_path)
    # Sibling jurisdictions: monorepo jurisdiction dirs and legacy checkouts
    # next to the current repo (or next to its monorepo checkout).
    repo_roots.extend(
        candidate_jurisdiction_content_dirs(policy_repo_path.parent, prefix)
    )
    if policy_repo_path.parent.name.startswith("rulespec-"):
        repo_roots.extend(
            candidate_jurisdiction_content_dirs(policy_repo_path.parent.parent, prefix)
        )
    for repo_root in repo_roots:
        test_file = _rulespec_test_path(repo_root / relative_path)
        if test_file.exists():
            return test_file
    return None


def _split_table_row_relation_test_cases(test_file: Path) -> list[str]:
    if not test_file.exists():
        return []

    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []

    if isinstance(payload, dict) and isinstance(payload.get("cases"), list):
        cases = payload["cases"]
    elif isinstance(payload, list):
        cases = payload
    else:
        return []

    repaired_cases: list[str] = []
    updated_cases: list[object] = []
    changed = False
    for index, test_case in enumerate(cases, start=1):
        if not isinstance(test_case, dict):
            updated_cases.append(test_case)
            continue
        split_cases = _split_one_table_row_relation_test_case(test_case, index=index)
        if not split_cases:
            updated_cases.append(test_case)
            continue
        updated_cases.extend(split_cases)
        repaired_cases.append(str(test_case.get("name") or f"case {index}"))
        changed = True

    if not changed:
        return []
    if isinstance(payload, dict):
        payload["cases"] = updated_cases
    else:
        payload = updated_cases
    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired_cases


def _split_one_table_row_relation_test_case(
    test_case: dict,
    *,
    index: int,
) -> list[dict]:
    tables = test_case.get("tables")
    if not isinstance(tables, dict) or len(tables) != 1:
        return []
    table_entity, rows = next(iter(tables.items()))
    table_entity = str(table_entity)
    if not isinstance(rows, list) or not rows:
        return []
    if not all(isinstance(row, dict) for row in rows):
        return []
    if not any(
        any(_is_relation_input_key(row_key) for row_key in row)
        for row in rows
        if isinstance(row, dict)
    ):
        return []

    original_input = test_case.get("input") or {}
    if not isinstance(original_input, dict):
        return []
    original_output = test_case.get("output") or {}
    if not isinstance(original_output, dict):
        return []
    for expected_value in original_output.values():
        if isinstance(expected_value, list) and len(expected_value) != len(rows):
            return []

    base_name = str(test_case.get("name") or f"case {index}").strip() or f"case {index}"
    split_cases: list[dict] = []
    for row_index, row in enumerate(rows):
        case_copy = copy.deepcopy(test_case)
        case_copy.pop("tables", None)
        case_copy["name"] = f"{base_name} {table_entity} row {row_index + 1}"
        case_input = copy.deepcopy(original_input)
        case_input.update(copy.deepcopy(row))
        case_copy["input"] = case_input
        case_output: dict = {}
        for output_key, expected_value in original_output.items():
            if isinstance(expected_value, list):
                case_output[output_key] = copy.deepcopy(expected_value[row_index])
            else:
                case_output[output_key] = copy.deepcopy(expected_value)
        case_copy["output"] = case_output
        split_cases.append(case_copy)
    return split_cases


def _is_relation_input_key(key: object) -> bool:
    key_text = str(key)
    return "#relation." in key_text or ".relation." in key_text


def _try_repair_generated_proof_import_hashes_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Refresh stale proof import hashes in the generated target itself."""
    if not any("Proof import hash mismatch" in str(issue) for issue in issues):
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    target_base = (
        f"{_repo_jurisdiction_prefix(policy_repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    original = rules_file.read_text()
    repaired, repair_count = _repair_proof_import_hashes(
        original,
        target_base=target_base,
        rules_file=rules_file,
        repo_path=policy_repo_path,
    )
    if repair_count <= 0 or repaired == original:
        return []
    rules_file.write_text(repaired)
    return [f"hash[{index}]" for index in range(repair_count)]


def _try_repair_generated_invalid_proof_atom_kinds_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Normalize schema-invalid proof kind synonyms in generated output."""
    if not any("Proof atom kind invalid" in str(issue) for issue in issues):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    repairs: list[str] = []
    for rule in payload.get("rules") or []:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "<unnamed>")
        atoms = (
            ((rule.get("metadata") or {}).get("proof") or {}).get("atoms")
            if isinstance(rule.get("metadata"), dict)
            else None
        )
        if not isinstance(atoms, list):
            continue
        for index, atom in enumerate(atoms):
            if not isinstance(atom, dict):
                continue
            kind = str(atom.get("kind") or "").strip()
            if kind != "rate":
                continue
            atom["kind"] = "parameter"
            repairs.append(f"{rule_name}[{index}]:rate->parameter")

    if not repairs:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repairs


