def _try_repair_generated_input_field_access_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Rewrite generated `input.foo` formula accesses to local fact names."""
    if not any(
        "bare field access in scalar position" in str(issue) for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_input_field_accesses_in_formulas(rules_file=rules_file)


def _try_repair_generated_anaphoric_scope_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Rename broad generated predicates to preserve same-object scope."""
    repairs = _anaphoric_scope_repairs_from_issues(issues)
    if not repairs:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _repair_anaphoric_scope_identifiers(
        rules_file=rules_file,
        test_file=test_file,
        repairs=repairs,
    )


def _anaphoric_scope_repairs_from_issues(
    issues: list[str],
) -> list[dict[str, str]]:
    repairs: list[dict[str, str]] = []
    seen_identifiers: set[str] = set()
    for issue in issues:
        match = _ANAPHORIC_SCOPE_OMISSION_ISSUE_PATTERN.search(str(issue))
        if match is None:
            continue
        identifier = match.group("identifier")
        if identifier in seen_identifiers:
            continue
        seen_identifiers.add(identifier)
        scope_fragment = _anaphoric_scope_identifier_fragment(match.group("scope"))
        if not scope_fragment or _identifier_contains_fragment(
            identifier,
            scope_fragment,
        ):
            continue
        repairs.append(
            {
                "rule": match.group("rule"),
                "old": identifier,
                "new": _insert_identifier_scope_fragment(identifier, scope_fragment),
                "excerpt": match.group("excerpt"),
                "scope": match.group("scope"),
            }
        )
    return repairs


def _repair_anaphoric_scope_identifiers(
    *,
    rules_file: Path,
    test_file: Path,
    repairs: list[dict[str, str]],
) -> list[str]:
    if not rules_file.exists():
        return []
    changed: list[str] = []
    for path in (rules_file, test_file):
        if not path.exists():
            continue
        try:
            content = path.read_text()
        except OSError:
            continue
        repaired_content = content
        for repair in repairs:
            repaired_content = _replace_rulespec_identifier(
                repaired_content,
                old=repair["old"],
                new=repair["new"],
            )
        if repaired_content != content:
            path.write_text(repaired_content)

    _extend_anaphoric_scope_proof_excerpts(rules_file=rules_file, repairs=repairs)
    for repair in repairs:
        if _rulespec_file_contains_identifier(rules_file, repair["new"]) or (
            test_file.exists()
            and _rulespec_file_contains_identifier(test_file, repair["new"])
        ):
            changed.append(f"{repair['old']}->{repair['new']}")
    return changed


def _anaphoric_scope_identifier_fragment(scope_phrase: str) -> str:
    fragment = re.sub(r"[^a-z0-9]+", "_", scope_phrase.lower()).strip("_")
    return re.sub(r"_+", "_", fragment)


def _identifier_contains_fragment(identifier: str, fragment: str) -> bool:
    return bool(
        re.search(
            rf"(?:^|_){re.escape(fragment)}(?:_|$)",
            identifier,
            flags=re.IGNORECASE,
        )
    )


def _insert_identifier_scope_fragment(identifier: str, fragment: str) -> str:
    for separator in ("_during_", "_after_", "_before_", "_within_"):
        if separator in identifier:
            prefix, suffix = identifier.split(separator, 1)
            return f"{prefix}_{fragment}{separator}{suffix}"
    return f"{identifier}_{fragment}"


def _replace_rulespec_identifier(content: str, *, old: str, new: str) -> str:
    return re.sub(
        rf"(?<![A-Za-z0-9_]){re.escape(old)}(?![A-Za-z0-9_])",
        new,
        content,
    )


def _rulespec_file_contains_identifier(path: Path, identifier: str) -> bool:
    with contextlib.suppress(OSError):
        return bool(
            re.search(
                rf"(?<![A-Za-z0-9_]){re.escape(identifier)}(?![A-Za-z0-9_])",
                path.read_text(),
            )
        )
    return False


class _YamlExcerptScalarSpan(NamedTuple):
    rule: str
    excerpt: str
    start: int
    end: int


def _extend_anaphoric_scope_proof_excerpts(
    *,
    rules_file: Path,
    repairs: list[dict[str, str]],
) -> None:
    try:
        content = rules_file.read_text()
        payload = yaml.safe_load(content) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(payload, dict):
        return
    source_text = _extract_source_verification_text(content)
    if not source_text:
        return
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return

    excerpt_spans = _yaml_excerpt_scalar_spans(content)
    if not excerpt_spans:
        return
    used_span_indexes: set[int] = set()
    replacements: list[tuple[int, int, str]] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip()
        metadata = rule.get("metadata")
        proof = metadata.get("proof") if isinstance(metadata, dict) else None
        atoms = proof.get("atoms") if isinstance(proof, dict) else None
        if not isinstance(atoms, list):
            continue
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source = atom.get("source")
            if not isinstance(source, dict):
                continue
            excerpt = source.get("excerpt")
            if not isinstance(excerpt, str):
                continue
            for repair in repairs:
                if rule_name != repair["rule"] or excerpt != repair["excerpt"]:
                    continue
                if repair["scope"].lower() in excerpt.lower():
                    continue
                extended = _extend_excerpt_to_anaphoric_scope(
                    source_text=source_text,
                    excerpt=excerpt,
                    scope_phrase=repair["scope"],
                )
                if extended and extended != excerpt:
                    span_index, span = _find_yaml_excerpt_scalar_span(
                        excerpt_spans,
                        rule=rule_name,
                        excerpt=excerpt,
                        used_span_indexes=used_span_indexes,
                    )
                    if span is None:
                        continue
                    used_span_indexes.add(span_index)
                    replacements.append(
                        (
                            span.start,
                            span.end,
                            _render_yaml_excerpt_scalar_like(
                                content[span.start : span.end],
                                extended,
                            ),
                        )
                    )
    if replacements:
        repaired_content = content
        for start, end, replacement in sorted(replacements, reverse=True):
            repaired_content = (
                repaired_content[:start] + replacement + repaired_content[end:]
            )
        rules_file.write_text(repaired_content)


def _yaml_excerpt_scalar_spans(content: str) -> list[_YamlExcerptScalarSpan]:
    try:
        root = yaml.compose(content)
    except yaml.YAMLError:
        return []
    rules_node = _yaml_mapping_value(root, "rules")
    if not isinstance(rules_node, SequenceNode):
        return []

    spans: list[_YamlExcerptScalarSpan] = []
    for rule_node in rules_node.value:
        if not isinstance(rule_node, MappingNode):
            continue
        rule_name = _yaml_scalar_mapping_value(rule_node, "name")
        if not rule_name:
            continue
        metadata_node = _yaml_mapping_value(rule_node, "metadata")
        proof_node = _yaml_mapping_value(metadata_node, "proof")
        atoms_node = _yaml_mapping_value(proof_node, "atoms")
        if not isinstance(atoms_node, SequenceNode):
            continue
        for atom_node in atoms_node.value:
            source_node = _yaml_mapping_value(atom_node, "source")
            excerpt_node = _yaml_mapping_value(source_node, "excerpt")
            if not isinstance(excerpt_node, ScalarNode):
                continue
            excerpt = excerpt_node.value
            if not isinstance(excerpt, str):
                continue
            spans.append(
                _YamlExcerptScalarSpan(
                    rule=rule_name,
                    excerpt=excerpt,
                    start=excerpt_node.start_mark.index,
                    end=excerpt_node.end_mark.index,
                )
            )
    return spans


def _yaml_mapping_value(node: object, key: str) -> object | None:
    if not isinstance(node, MappingNode):
        return None
    for key_node, value_node in node.value:
        if isinstance(key_node, ScalarNode) and key_node.value == key:
            return value_node
    return None


def _yaml_scalar_mapping_value(node: object, key: str) -> str:
    value_node = _yaml_mapping_value(node, key)
    if isinstance(value_node, ScalarNode) and isinstance(value_node.value, str):
        return value_node.value
    return ""


def _find_yaml_excerpt_scalar_span(
    spans: list[_YamlExcerptScalarSpan],
    *,
    rule: str,
    excerpt: str,
    used_span_indexes: set[int],
) -> tuple[int, _YamlExcerptScalarSpan | None]:
    for index, span in enumerate(spans):
        if index in used_span_indexes:
            continue
        if span.rule == rule and span.excerpt == excerpt:
            return index, span
    return -1, None


def _render_yaml_excerpt_scalar_like(original_scalar: str, value: str) -> str:
    stripped = original_scalar.lstrip()
    if stripped.startswith('"'):
        return f'"{_yaml_double_quoted_scalar_text(value)}"'
    if stripped.startswith("'"):
        return f"'{_yaml_single_quoted_scalar_text(value)}'"
    if stripped.startswith("|") or stripped.startswith(">"):
        return _render_yaml_block_scalar_like(original_scalar, value)
    return f'"{_yaml_double_quoted_scalar_text(value)}"'


def _render_yaml_block_scalar_like(original_scalar: str, value: str) -> str:
    lines = original_scalar.splitlines(keepends=True)
    if not lines:
        return f'"{_yaml_double_quoted_scalar_text(value)}"'
    header = lines[0].rstrip("\r\n")
    indent = ""
    for line in lines[1:]:
        if line.strip():
            indent = line[: len(line) - len(line.lstrip())]
            break
    if not indent:
        indent = "  "
    rendered_lines = value.splitlines() or [""]
    rendered = header + "\n" + "\n".join(f"{indent}{line}" for line in rendered_lines)
    if original_scalar.endswith(("\n", "\r\n")):
        rendered += "\n"
    return rendered


def _yaml_double_quoted_scalar_text(value: str) -> str:
    return value.replace("\\", "\\\\").replace('"', '\\"').replace("\n", "\\n")


def _yaml_single_quoted_scalar_text(value: str) -> str:
    return value.replace("'", "''")


def _extend_excerpt_to_anaphoric_scope(
    *,
    source_text: str,
    excerpt: str,
    scope_phrase: str,
) -> str | None:
    source = re.sub(r"\s+", " ", source_text).strip()
    excerpt_text = re.sub(r"\s+", " ", excerpt).strip()
    scope_text = re.sub(r"\s+", " ", scope_phrase).strip()
    if not source or not excerpt_text or not scope_text:
        return None
    match = re.search(re.escape(excerpt_text), source, flags=re.IGNORECASE)
    if match is None:
        return None
    tail = source[match.end() : match.end() + 240]
    scope_match = re.search(re.escape(scope_text), tail, flags=re.IGNORECASE)
    if scope_match is None:
        return None
    sentence_tail = tail[: scope_match.end()]
    if _anaphoric_repair_tail_crosses_boundary(sentence_tail):
        return None
    return source[match.start() : match.end() + scope_match.end()].strip()


def _anaphoric_repair_tail_crosses_boundary(value: str) -> bool:
    boundary_indexes = [
        index for marker in (".", ";", "\n") if (index := value.find(marker)) != -1
    ]
    return bool(boundary_indexes and min(boundary_indexes) < len(value) - 1)


def _repair_input_field_accesses_in_formulas(*, rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "<unknown>").strip() or "<unknown>"
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version_index, version in enumerate(versions):
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            new_formula = _INPUT_FIELD_ACCESS_PATTERN.sub(r"\1", formula)
            if new_formula == formula:
                continue
            version["formula"] = new_formula
            repaired.append(f"{rule_name}:versions[{version_index}].formula")

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _try_repair_generated_source_table_band_scalars_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Normalize generated structural table bounds and remove public scalars."""
    if not any(
        "Source table row/band scalar parameters" in str(issue) for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []

    try:
        original_content = rules_file.read_text()
    except OSError:
        return []

    repaired_content, repaired_rules = repair_source_table_band_scalar_parameters(
        original_content
    )
    if repaired_content == original_content:
        return []

    rules_file.write_text(repaired_content)
    return repaired_rules


def _try_repair_generated_indexed_parameter_values_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Convert generated indexed parameter value tables into derived formulas."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if any(
        "floating point" in str(issue) and "expected i64" in str(issue)
        for issue in issues
    ):
        repaired_float_keys = _repair_float_keyed_indexed_parameter_values(
            rules_file,
            test_file,
        )
        if repaired_float_keys:
            return repaired_float_keys

    if not any("has no formula version" in str(issue) for issue in issues):
        return []
    repaired_top_level_values = _normalize_top_level_parameter_values_to_versions(
        rules_file
    )
    if repaired_top_level_values:
        return repaired_top_level_values
    return _convert_indexed_parameter_values_to_derived_formulas(rules_file, test_file)


def _try_repair_generated_indexed_parameter_lookups_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path | None = None,
    issues: list[str],
) -> list[str]:
    """Rewrite bare generated references to indexed parameter tables."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_bare_indexed_parameter_references(
        rules_file,
        policy_repo_path=policy_repo_path,
    )


def _try_repair_generated_unreferenced_percent_label_parameters_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path | None = None,
    issues: list[str],
) -> list[str]:
    ungrounded_values = _ungrounded_numeric_values_from_issues(issues)
    if not ungrounded_values:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    referenced_names = _referenced_local_rule_names(rules)
    retained_rules: list[object] = []
    removed: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            retained_rules.append(rule)
            continue
        name = str(rule.get("name") or "").strip()
        if (
            not name
            or name in referenced_names
            or not _is_unreferenced_percent_label_parameter(
                rule,
                ungrounded_values=ungrounded_values,
            )
        ):
            retained_rules.append(rule)
            continue
        removed.append(name)

    if not removed:
        return []
    payload["rules"] = retained_rules
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))

    test_file = _rulespec_test_path(rules_file)
    target_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    _remove_companion_outputs_for_removed_rules(
        test_file,
        target_anchor=target_anchor,
        removed_names=set(removed),
    )
    return removed


def _ungrounded_numeric_values_from_issues(issues: list[str]) -> set[float]:
    values: set[float] = set()
    pattern = re.compile(
        r"Ungrounded generated numeric literal:\s+"
        r"(?P<raw>-?[\d,]+(?:\.\d+)?)"
        r"(?:\s+\((?P<normalized>-?[\d,]+(?:\.\d+)?)\))?"
    )
    for issue in issues:
        match = pattern.search(str(issue))
        if match is None:
            continue
        raw_value = match.group("normalized") or match.group("raw")
        with contextlib.suppress(ValueError):
            values.add(float(raw_value.replace(",", "")))
    return values


def _referenced_local_rule_names(rules: list[Any]) -> set[str]:
    referenced: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        for formula in _rulespec_rule_formula_texts_for_generated_repair(rule):
            referenced.update(_formula_identifiers(formula))
        metadata = rule.get("metadata")
        proof = metadata.get("proof") if isinstance(metadata, dict) else None
        atoms = proof.get("atoms") if isinstance(proof, dict) else None
        if not isinstance(atoms, list):
            continue
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            import_payload = atom.get("import")
            if not isinstance(import_payload, dict):
                continue
            output = str(import_payload.get("output") or "").strip()
            if output:
                referenced.add(output)
                continue
            target = str(import_payload.get("target") or "").strip()
            if "#" in target:
                referenced.add(target.rsplit("#", 1)[1].strip())
    return referenced


def _rulespec_rule_formula_texts_for_generated_repair(
    rule: dict[str, Any],
) -> list[str]:
    formulas: list[str] = []
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return formulas
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str) and formula.strip():
            formulas.append(formula)
    return formulas


def _is_unreferenced_percent_label_parameter(
    rule: dict[str, Any],
    *,
    ungrounded_values: set[float],
) -> bool:
    if str(rule.get("kind") or "").strip().lower() != "parameter":
        return False
    value = _single_numeric_formula_value(rule)
    if value is None or not any(
        math.isclose(value, item) for item in ungrounded_values
    ):
        return False
    if value <= 0:
        return False
    percent = value * 100
    if not math.isfinite(percent) or percent <= 0:
        return False
    source_text = _generated_rule_source_context(rule)
    if not source_text:
        return False
    percent_text = ("%f" % percent).rstrip("0").rstrip(".")
    return bool(
        re.search(
            rf"(?<![\d.]){re.escape(percent_text)}\s*(?:%(?!\w)|percent\b)",
            source_text,
            flags=re.IGNORECASE,
        )
    )


def _single_numeric_formula_value(rule: dict[str, Any]) -> float | None:
    versions = rule.get("versions")
    if not isinstance(versions, list) or len(versions) != 1:
        return None
    version = versions[0]
    if not isinstance(version, dict):
        return None
    formula = version.get("formula")
    if isinstance(formula, bool):
        return None
    if isinstance(formula, int | float):
        return float(formula)
    if isinstance(formula, str):
        normalized = formula.strip().replace(",", "")
        if re.fullmatch(r"-?\d+(?:\.\d+)?", normalized):
            return float(normalized)
    return None


def _generated_rule_source_context(rule: dict[str, Any]) -> str:
    parts: list[str] = []
    source = rule.get("source")
    if isinstance(source, str):
        parts.append(source)
    metadata = rule.get("metadata")
    proof = metadata.get("proof") if isinstance(metadata, dict) else None
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    if isinstance(atoms, list):
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source_payload = atom.get("source")
            if not isinstance(source_payload, dict):
                continue
            excerpt = source_payload.get("excerpt")
            if isinstance(excerpt, str):
                parts.append(excerpt)
    return "\n".join(parts)


def _remove_companion_outputs_for_removed_rules(
    test_file: Path,
    *,
    target_anchor: str,
    removed_names: set[str],
) -> None:
    if not removed_names or not test_file.exists():
        return
    try:
        cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(cases, list):
        return
    changed = False
    retained_cases: list[object] = []
    for case in cases:
        if not isinstance(case, dict):
            retained_cases.append(case)
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            retained_cases.append(case)
            continue
        retained_outputs = {
            key: value
            for key, value in outputs.items()
            if not _test_output_targets_removed_rule(
                key,
                target_anchor=target_anchor,
                removed_names=removed_names,
            )
        }
        if len(retained_outputs) != len(outputs):
            changed = True
            if retained_outputs:
                case["output"] = retained_outputs
                retained_cases.append(case)
            continue
        retained_cases.append(case)
    if changed:
        test_file.write_text(
            yaml.safe_dump(retained_cases, sort_keys=False, allow_unicode=False)
        )


def _test_output_targets_removed_rule(
    key: object,
    *,
    target_anchor: str,
    removed_names: set[str],
) -> bool:
    key_text = str(key).strip()
    if "#" in key_text:
        base, fragment = key_text.split("#", 1)
        return base.strip() == target_anchor and fragment.strip() in removed_names
    return key_text in removed_names


def _try_repair_generated_half_unit_add_person_formulas_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Repair generated formulas that apply per-person add-ons per half unit."""
    if not any(
        "expected integer" in str(issue) and "got decimal" in str(issue)
        for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_half_unit_add_person_formulas(rules_file)


def _repair_half_unit_add_person_formulas(rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_repaired = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            updated = _repair_half_unit_add_person_formula_text(formula)
            if updated != formula:
                version["formula"] = updated
                rule_repaired = True
        if rule_repaired:
            repaired.append(str(rule.get("name") or ""))

    repaired = list(dict.fromkeys(name for name in repaired if name))
    if repaired:
        rules_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )
    return repaired


def _repair_half_unit_add_person_formula_text(formula: str) -> str:
    half_unit_delta = (
        r"filing_unit_size_half_units\s*-\s*"
        r"\(\s*maximum_listed_filing_unit_half_units\s*-\s*1\s*\)"
    )
    pattern = re.compile(
        rf"\(\(\s*(?P<delta>{half_unit_delta})\s*\)\s*\*\s*"
        rf"(?P<amount>[A-Za-z_][A-Za-z0-9_]*)\s*\)"
    )

    def replace(match: re.Match[str]) -> str:
        delta = re.sub(r"\s+", " ", match.group("delta")).strip()
        amount = match.group("amount")
        return f"((({delta}) / 2) * {amount})"

    return pattern.sub(replace, formula)


def _repair_bare_indexed_parameter_references(
    rules_file: Path,
    *,
    policy_repo_path: Path | None = None,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    indexed_parameters = _indexed_parameter_reference_selectors_from_payload(payload)
    if policy_repo_path is not None:
        indexed_parameters.update(
            _imported_indexed_parameter_reference_selectors(
                payload,
                policy_repo_path=policy_repo_path,
            )
        )
    if not indexed_parameters:
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_name = str(rule.get("name") or "").strip()
        repaired_rule = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            updated = formula
            for parameter_name, index_name in indexed_parameters.items():
                updated = _rewrite_bare_indexed_parameter_reference(
                    updated,
                    parameter_name=parameter_name,
                    index_name=index_name,
                )
            if updated != formula:
                version["formula"] = updated
                repaired_rule = True
        if repaired_rule:
            repaired.append(rule_name or "<unnamed>")

    if repaired:
        rules_file.write_text(yaml.safe_dump(payload, sort_keys=False))
    return repaired


def _indexed_parameter_reference_selectors_from_payload(
    payload: dict[str, object],
) -> dict[str, str]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return {}

    indexed_parameters: dict[str, str] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        name = str(rule.get("name") or "").strip()
        index_name = _single_parameter_index_name(rule)
        if not name or not index_name:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list) or not any(
            isinstance(version, dict) and isinstance(version.get("values"), dict)
            for version in versions
        ):
            continue
        indexed_parameters[name] = index_name
    return indexed_parameters


def _imported_indexed_parameter_reference_selectors(
    payload: dict[str, object],
    *,
    policy_repo_path: Path,
) -> dict[str, str]:
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return {}

    indexed_parameters: dict[str, str] = {}
    for raw_import in imports:
        if not isinstance(raw_import, str) or "#" not in raw_import:
            continue
        imported_name = raw_import.rsplit("#", 1)[1].strip()
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", imported_name):
            continue
        resolved = _same_repo_import_base_and_file(
            raw_import,
            repo_path=policy_repo_path,
        )
        if resolved is None:
            continue
        _, import_file = resolved
        try:
            imported_payload = yaml.safe_load(import_file.read_text()) or {}
        except (OSError, yaml.YAMLError, ValueError):
            continue
        if not isinstance(imported_payload, dict):
            continue
        imported_selectors = _indexed_parameter_reference_selectors_from_payload(
            imported_payload
        )
        index_name = imported_selectors.get(imported_name)
        if index_name:
            indexed_parameters[imported_name] = index_name
    return indexed_parameters


def _rewrite_bare_indexed_parameter_reference(
    formula: str,
    *,
    parameter_name: str,
    index_name: str,
) -> str:
    pattern = re.compile(
        rf"(?<![A-Za-z0-9_#.\]])\b{re.escape(parameter_name)}\b"
        rf"(?!\s*\[)(?![A-Za-z0-9_])"
    )
    return pattern.sub(f"{parameter_name}[{index_name}]", formula)


def _normalize_top_level_parameter_values_to_versions(rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        if "versions" in rule:
            continue
        values = rule.get("values")
        if not isinstance(values, dict) or not values:
            continue

        versions: list[dict[str, object]] = []
        version_kind: str | None = None
        for effective_key, value in values.items():
            effective_from = _effective_from_from_top_level_values_key(effective_key)
            if effective_from is None:
                versions = []
                break
            if isinstance(value, dict):
                if version_kind not in (None, "values"):
                    versions = []
                    break
                version_kind = "values"
                versions.append(
                    {
                        "effective_from": effective_from,
                        "values": value,
                    }
                )
                continue
            formula = _formula_text_from_top_level_parameter_value(value)
            if formula is None:
                versions = []
                break
            if version_kind not in (None, "formula"):
                versions = []
                break
            version_kind = "formula"
            versions.append(
                {
                    "effective_from": effective_from,
                    "formula": formula,
                }
            )

        if not versions or version_kind is None:
            continue
        rule.pop("values", None)
        rule["versions"] = versions
        _retarget_top_level_values_proof_atoms(
            rule,
            "versions[0].values" if version_kind == "values" else "versions[0].formula",
        )
        repaired.append(str(rule.get("name") or ""))

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _effective_from_from_top_level_values_key(value: object) -> str | None:
    if isinstance(value, datetime):
        return None
    if isinstance(value, date):
        return value.isoformat()
    if isinstance(value, str) and re.fullmatch(r"\d{4}-\d{2}-\d{2}", value.strip()):
        return value.strip()
    return None


def _formula_text_from_top_level_parameter_value(value: object) -> str | None:
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, int | float):
        return str(value)
    if isinstance(value, str) and value.strip():
        return value.strip()
    return None


def _retarget_top_level_values_proof_atoms(
    rule: dict[str, object],
    target_path: str,
) -> None:
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        path = atom.get("path")
        if isinstance(path, str) and (path == "values" or path.startswith("values[")):
            atom["path"] = target_path


def _convert_indexed_parameter_values_to_derived_formulas(
    rules_file: Path,
    test_file: Path | None = None,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    rule_by_name = {
        str(rule.get("name") or ""): rule
        for rule in rules
        if isinstance(rule, dict) and rule.get("name")
    }
    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if rule.get("kind") != "parameter" or "versions" in rule:
            continue
        indexed_by = str(rule.get("indexed_by") or "").strip()
        values = rule.get("values")
        if not indexed_by or not isinstance(values, list):
            continue
        index_rule = rule_by_name.get(indexed_by)
        if not isinstance(index_rule, dict):
            continue
        entity = index_rule.get("entity")
        period = index_rule.get("period")
        if not entity or not period:
            continue
        converted = _formula_from_indexed_value_records(
            rule=rule,
            indexed_by=indexed_by,
            values=values,
        )
        if converted is None:
            continue
        effective_from, formula, selectors = converted

        rule["kind"] = "derived"
        rule["entity"] = entity
        rule["period"] = period
        rule.pop("indexed_by", None)
        rule.pop("values", None)
        rule["versions"] = [
            {
                "effective_from": effective_from,
                "formula": formula,
            }
        ]
        _retarget_formula_proof_atoms_to_first_version(rule)
        repaired.append(str(rule.get("name") or ""))
        if test_file is not None and selectors:
            _add_selector_version_test_inputs(
                test_file,
                [(str(rule.get("name") or "indexed_values_rule"), selectors)],
            )

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _repair_float_keyed_indexed_parameter_values(
    rules_file: Path,
    test_file: Path | None = None,
) -> list[str]:
    """Remap decimal indexed table keys to integer band ids.

    RuleSpec indexed parameter maps are integer-keyed. LLM generations sometimes
    reuse interval lower bounds (for example 1.33, 1.50, 2.00) as lookup keys.
    Preserve the generated table shape by assigning stable integer row ids and
    rewriting the selector output/tests to use those ids.
    """
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    rule_by_name = {
        str(rule.get("name") or ""): rule
        for rule in rules
        if isinstance(rule, dict) and rule.get("name")
    }
    indexed_rules_by_selector: dict[str, list[dict[str, object]]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        indexed_by = str(rule.get("indexed_by") or "").strip()
        if not indexed_by:
            continue
        if not _rule_has_non_integer_versioned_value_key(rule):
            continue
        indexed_rules_by_selector.setdefault(indexed_by, []).append(rule)

    repaired: list[str] = []
    selector_key_maps: dict[str, dict[float, int]] = {}
    for indexed_by, parameter_rules in indexed_rules_by_selector.items():
        key_map = _integer_band_ids_for_parameter_rules(parameter_rules)
        if not key_map:
            continue
        index_rule = rule_by_name.get(indexed_by)
        table_names = [
            str(rule.get("name") or "").strip()
            for rule in parameter_rules
            if str(rule.get("name") or "").strip()
        ]
        created_selector = False
        if not isinstance(index_rule, dict):
            selector_name = _missing_float_key_selector_name(indexed_by, rule_by_name)
            index_rule = _build_float_key_selector_rule(
                selector_name=selector_name,
                source_index_name=indexed_by,
                key_map=key_map,
                parameter_rules=parameter_rules,
                rules=rules,
            )
            if index_rule is None:
                continue
            first_index = min(rules.index(rule) for rule in parameter_rules)
            rules.insert(first_index, index_rule)
            rule_by_name[selector_name] = index_rule
            target_indexed_by = selector_name
            created_selector = True
        else:
            target_indexed_by = indexed_by
        changed = False
        if index_rule.get("dtype") != "Integer":
            index_rule["dtype"] = "Integer"
            changed = True
        if not created_selector and _rewrite_selector_rule_float_returns(
            index_rule, key_map
        ):
            changed = True
        for parameter_rule in parameter_rules:
            if parameter_rule.get("indexed_by") != target_indexed_by:
                parameter_rule["indexed_by"] = target_indexed_by
                changed = True
            if _remap_versioned_values_to_integer_keys(parameter_rule, key_map):
                changed = True
                repaired.append(str(parameter_rule.get("name") or ""))
        if _rewrite_indexed_parameter_lookup_keys(
            rules,
            table_names=table_names,
            old_indexed_by=indexed_by,
            new_indexed_by=target_indexed_by,
            key_map=key_map,
        ):
            changed = True
        if changed:
            repaired.append(target_indexed_by)
            selector_key_maps[target_indexed_by] = key_map

    repaired = list(dict.fromkeys(name for name in repaired if name))
    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    if test_file is not None and selector_key_maps:
        _repair_float_keyed_indexed_parameter_test_outputs(test_file, selector_key_maps)
    return repaired


def _missing_float_key_selector_name(
    indexed_by: str,
    rule_by_name: dict[str, dict[str, object]],
) -> str:
    base = f"{indexed_by}_band"
    if base not in rule_by_name:
        return base
    ordinal = 2
    while f"{base}_{ordinal}" in rule_by_name:
        ordinal += 1
    return f"{base}_{ordinal}"


def _build_float_key_selector_rule(
    *,
    selector_name: str,
    source_index_name: str,
    key_map: dict[float, int],
    parameter_rules: list[dict[str, object]],
    rules: list[object],
) -> dict[str, object] | None:
    if not key_map:
        return None
    entity, period = _infer_float_key_selector_scope(
        table_names=[
            str(rule.get("name") or "").strip()
            for rule in parameter_rules
            if str(rule.get("name") or "").strip()
        ],
        rules=rules,
    )
    if not entity or not period:
        return None
    effective_from = _earliest_parameter_effective_from(parameter_rules)
    if not effective_from:
        return None
    source = _first_rule_source(parameter_rules)
    formula = _exact_key_selector_formula(source_index_name, key_map)
    if not formula:
        return None
    selector: dict[str, object] = {
        "name": selector_name,
        "kind": "derived",
        "entity": entity,
        "dtype": "Integer",
        "period": period,
        "source": source
        or f"Generated integer row selector for {source_index_name} table labels",
        "versions": [
            {
                "effective_from": effective_from,
                "formula": formula,
            }
        ],
    }
    proof = _first_rule_table_source(parameter_rules)
    if proof is not None:
        selector["metadata"] = {
            "proof": {
                "atoms": [
                    {
                        "path": "versions[0].formula",
                        "kind": "parameter_table",
                        "source": proof,
                    }
                ]
            }
        }
    return selector


def _infer_float_key_selector_scope(
    *,
    table_names: list[str],
    rules: list[object],
) -> tuple[str | None, str | None]:
    if not table_names:
        return None, None
    lookup_patterns = [
        re.compile(rf"\b{re.escape(table_name)}\s*\[") for table_name in table_names
    ]
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() not in {
            "derived",
            "derived_relation",
        }:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        formulas = [
            str(version.get("formula") or "")
            for version in versions
            if isinstance(version, dict)
        ]
        if not any(
            pattern.search(formula)
            for pattern in lookup_patterns
            for formula in formulas
        ):
            continue
        entity = str(rule.get("entity") or "").strip()
        period = str(rule.get("period") or "").strip()
        if entity and period:
            return entity, period
    return None, None


def _earliest_parameter_effective_from(
    parameter_rules: list[dict[str, object]],
) -> str | None:
    dates: list[str] = []
    for rule in parameter_rules:
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            effective_from = str(version.get("effective_from") or "").strip()
            if effective_from:
                dates.append(effective_from)
    return min(dates) if dates else None


def _first_rule_source(parameter_rules: list[dict[str, object]]) -> str | None:
    for rule in parameter_rules:
        source = rule.get("source")
        if isinstance(source, str) and source.strip():
            return source.strip()
    return None


def _first_rule_table_source(
    parameter_rules: list[dict[str, object]],
) -> dict[str, object] | None:
    for rule in parameter_rules:
        metadata = rule.get("metadata")
        if not isinstance(metadata, dict):
            continue
        proof = metadata.get("proof")
        if not isinstance(proof, dict):
            continue
        atoms = proof.get("atoms")
        if not isinstance(atoms, list):
            continue
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source = atom.get("source")
            if isinstance(source, dict):
                return copy.deepcopy(source)
    return None


def _exact_key_selector_formula(
    source_index_name: str,
    key_map: dict[float, int],
) -> str | None:
    linear_formula = _linear_integer_band_selector_formula(source_index_name, key_map)
    if linear_formula is not None:
        return linear_formula
    branches = sorted(key_map.items(), key=lambda item: item[0], reverse=True)
    if not branches:
        return None
    formula = "-1"
    for numeric_key, band_id in branches:
        key_literal = _formula_scalar_literal(numeric_key)
        if key_literal is None:
            return None
        formula = f"if {source_index_name} == {key_literal}: {band_id} else: {formula}"
    return formula


def _linear_integer_band_selector_formula(
    source_index_name: str,
    key_map: dict[float, int],
) -> str | None:
    if len(key_map) < 2:
        return None
    try:
        ordered = sorted(
            (Decimal(str(numeric_key)), band_id)
            for numeric_key, band_id in key_map.items()
        )
    except (InvalidOperation, ValueError):
        return None
    band_ids = [band_id for _, band_id in ordered]
    if band_ids != list(range(len(band_ids))):
        return None
    steps = [
        ordered[index + 1][0] - ordered[index][0] for index in range(len(ordered) - 1)
    ]
    if not steps or any(step != steps[0] for step in steps):
        return None
    step = steps[0]
    if step <= 0:
        return None
    multiplier = Decimal(1) / step
    if multiplier != multiplier.to_integral_value():
        return None
    offset = ordered[0][0] * multiplier
    if offset != offset.to_integral_value():
        return None
    multiplier_text = str(int(multiplier))
    offset_int = int(offset)
    formula = f"floor({source_index_name} * {multiplier_text})"
    if offset_int > 0:
        formula = f"{formula} - {offset_int}"
    elif offset_int < 0:
        formula = f"{formula} + {abs(offset_int)}"
    return formula


def _rewrite_indexed_parameter_lookup_keys(
    rules: list[object],
    *,
    table_names: list[str],
    old_indexed_by: str,
    new_indexed_by: str,
    key_map: dict[float, int],
) -> bool:
    if not table_names:
        return False
    scalar_key_map = _scalar_parameter_band_key_map(rules, key_map)
    changed = False
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            updated = formula
            for table_name in table_names:
                updated = _rewrite_single_indexed_parameter_lookup_key(
                    updated,
                    table_name=table_name,
                    old_indexed_by=old_indexed_by,
                    new_indexed_by=new_indexed_by,
                    key_map=key_map,
                    scalar_key_map=scalar_key_map,
                )
            if updated != formula:
                version["formula"] = updated
                changed = True
    return changed


def _scalar_parameter_band_key_map(
    rules: list[object],
    key_map: dict[float, int],
) -> dict[str, int]:
    scalar_map: dict[str, int] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        name = str(rule.get("name") or "").strip()
        versions = rule.get("versions")
        if not name or not isinstance(versions, list) or len(versions) != 1:
            continue
        version = versions[0]
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        numeric = _numeric_value_from_yaml(formula)
        replacement = key_map.get(numeric) if math.isfinite(numeric) else None
        if replacement is not None:
            scalar_map[name] = replacement
    return scalar_map


def _rewrite_single_indexed_parameter_lookup_key(
    formula: str,
    *,
    table_name: str,
    old_indexed_by: str,
    new_indexed_by: str,
    key_map: dict[float, int],
    scalar_key_map: dict[str, int],
) -> str:
    pattern = re.compile(
        rf"\b{re.escape(table_name)}\s*\[\s*(?P<expr>[A-Za-z0-9_#.\-]+)\s*\]"
    )

    def replace(match: re.Match[str]) -> str:
        expr = match.group("expr")
        replacement: str | None = None
        if expr == old_indexed_by:
            replacement = new_indexed_by
        elif expr in scalar_key_map:
            replacement = str(scalar_key_map[expr])
        else:
            numeric = _numeric_value_from_yaml(expr)
            mapped = key_map.get(numeric) if math.isfinite(numeric) else None
            if mapped is not None:
                replacement = str(mapped)
        if replacement is None:
            return match.group(0)
        return f"{table_name}[{replacement}]"

    return pattern.sub(replace, formula)


def _rule_has_non_integer_versioned_value_key(rule: dict[str, object]) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    for version in versions:
        if not isinstance(version, dict):
            continue
        values = version.get("values")
        if not isinstance(values, dict):
            continue
        for key in values:
            numeric = _numeric_value_from_yaml(key)
            if math.isfinite(numeric) and (
                not numeric.is_integer() or isinstance(key, float)
            ):
                return True
    return False


def _integer_band_ids_for_parameter_rules(
    parameter_rules: list[dict[str, object]],
) -> dict[float, int]:
    numeric_keys: set[float] = set()
    requires_remap = False
    for rule in parameter_rules:
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            values = version.get("values")
            if not isinstance(values, dict):
                continue
            for raw_key in values:
                numeric = _numeric_value_from_yaml(raw_key)
                if math.isfinite(numeric):
                    numeric_keys.add(numeric)
                    if not numeric.is_integer() or isinstance(raw_key, float):
                        requires_remap = True
    if not numeric_keys or not requires_remap:
        return {}
    return {key: ordinal for ordinal, key in enumerate(sorted(numeric_keys))}


def _remap_versioned_values_to_integer_keys(
    rule: dict[str, object],
    key_map: dict[float, int],
) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    changed = False
    for version in versions:
        if not isinstance(version, dict):
            continue
        values = version.get("values")
        if not isinstance(values, dict):
            continue
        remapped: dict[object, object] = {}
        version_changed = False
        for raw_key, raw_value in values.items():
            numeric = _numeric_value_from_yaml(raw_key)
            replacement = key_map.get(numeric) if math.isfinite(numeric) else None
            if replacement is None:
                remapped[raw_key] = raw_value
                continue
            remapped[replacement] = raw_value
            if replacement != raw_key:
                version_changed = True
        if version_changed:
            version["values"] = remapped
            changed = True
    return changed


def _rewrite_selector_rule_float_returns(
    rule: dict[str, object],
    key_map: dict[float, int],
) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    changed = False
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        updated = _replace_formula_return_literals_with_band_ids(formula, key_map)
        if updated != formula:
            version["formula"] = updated
            changed = True
    return changed


def _replace_formula_return_literals_with_band_ids(
    formula: str,
    key_map: dict[float, int],
) -> str:
    literal_to_band: dict[str, int] = {}
    for numeric_key, band_id in key_map.items():
        for literal in _numeric_literal_variants(numeric_key):
            literal_to_band[literal] = band_id
    if not literal_to_band:
        return formula
    literal_pattern = "|".join(
        re.escape(literal) for literal in sorted(literal_to_band, key=len, reverse=True)
    )

    def replace_inline(match: re.Match[str]) -> str:
        value = match.group("value")
        return (
            match.group("prefix") + str(literal_to_band[value]) + match.group("suffix")
        )

    formula = re.sub(
        rf"(?P<prefix>:\s*)(?P<value>{literal_pattern})(?P<suffix>\s+(?:else\b|$)|\s*$)",
        replace_inline,
        formula,
        flags=re.MULTILINE,
    )

    def replace_standalone(match: re.Match[str]) -> str:
        value = match.group("value")
        return match.group("indent") + str(literal_to_band[value]) + match.group("tail")

    return re.sub(
        rf"(?P<indent>^[ \t]+)(?P<value>{literal_pattern})(?P<tail>[ \t]*(?:#.*)?$)",
        replace_standalone,
        formula,
        flags=re.MULTILINE,
    )


def _numeric_literal_variants(value: float) -> set[str]:
    variants = {f"{value:g}", f"{value:.1f}", f"{value:.2f}"}
    if value.is_integer():
        variants.add(str(int(value)))
    return {variant for variant in variants if variant}


def _repair_float_keyed_indexed_parameter_test_outputs(
    test_file: Path,
    selector_key_maps: dict[str, dict[float, int]],
) -> bool:
    if not test_file.exists():
        return False
    try:
        cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return False
    if not isinstance(cases, list):
        return False
    changed = False
    for case in cases:
        if not isinstance(case, dict):
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            continue
        for output_ref, output_value in list(outputs.items()):
            output_name = str(output_ref).rsplit("#", 1)[-1]
            key_map = selector_key_maps.get(output_name)
            if not key_map:
                continue
            numeric = _numeric_value_from_yaml(output_value)
            if not math.isfinite(numeric):
                continue
            replacement = key_map.get(numeric)
            if replacement is None or replacement == output_value:
                continue
            outputs[output_ref] = replacement
            changed = True
    if changed:
        test_file.write_text(yaml.safe_dump(cases, sort_keys=False))
    return changed


def _formula_from_indexed_value_records(
    *,
    rule: dict[str, object],
    indexed_by: str,
    values: list[Any],
) -> tuple[str, str, list[dict[str, str]]] | None:
    records: list[tuple[int, date, str, str]] = []
    for ordinal, record in enumerate(values, start=1):
        if not isinstance(record, dict):
            continue
        value_map = record.get("value")
        if not isinstance(value_map, dict):
            continue
        effective_from = str(record.get("effective_from") or "").strip()
        effective_date = _parse_iso_date(effective_from)
        if effective_date is None:
            return None
        record_formula = _formula_from_indexed_value_map(
            indexed_by=indexed_by,
            value_map=value_map,
        )
        if record_formula is None:
            return None
        records.append(
            (
                ordinal,
                effective_date,
                effective_from,
                record_formula,
            )
        )
    if not records:
        return None

    records.sort(key=lambda item: (item[1], item[0]))
    _first_ordinal, _first_date, first_effective_from, formula = records[0]
    selectors: list[dict[str, str]] = []
    for ordinal, _effective_date, effective_from, record_formula in records[1:]:
        predicate = _version_selector_predicate_name(rule, ordinal)
        selectors.append(
            {
                "effective_from": effective_from,
                "predicate": predicate,
                "formula": "",
            }
        )
        formula = f"if {predicate}: ({record_formula}) else: {formula}"

    return first_effective_from, formula, selectors


def _formula_from_indexed_value_map(
    *,
    indexed_by: str,
    value_map: dict[Any, Any],
) -> str | None:
    selected_mapping = value_map

    default = selected_mapping.get(0, selected_mapping.get("0", 0))
    default_literal = _formula_scalar_literal(default)
    default_numeric = _numeric_value_from_yaml(default)
    if default_literal is None or math.isnan(default_numeric):
        return None
    branches: list[tuple[float, str, str]] = []
    for raw_key, raw_value in selected_mapping.items():
        numeric_key = _numeric_value_from_yaml(raw_key)
        numeric_value = _numeric_value_from_yaml(raw_value)
        key_literal = _formula_scalar_literal(raw_key)
        value_literal = _formula_scalar_literal(raw_value)
        if (
            key_literal is None
            or value_literal is None
            or math.isnan(numeric_key)
            or math.isnan(numeric_value)
        ):
            return None
        if numeric_key == 0:
            continue
        if numeric_value == default_numeric:
            continue
        branches.append((numeric_key, key_literal, value_literal))
    if not branches:
        return default_literal

    formula = default_literal
    for _numeric_key, key_literal, value_literal in sorted(
        branches,
        key=lambda item: item[0],
    ):
        formula = f"if {indexed_by} == {key_literal}: {value_literal} else: {formula}"
    return formula


def _numeric_value_from_yaml(value: Any) -> float:
    if isinstance(value, bool):
        return 1.0 if value else 0.0
    try:
        return float(str(value).strip())
    except (TypeError, ValueError):
        return float("nan")


def _formula_scalar_literal(value: Any) -> str | None:
    if isinstance(value, bool):
        return "1" if value else "0"
    if isinstance(value, int):
        return str(value)
    if isinstance(value, float):
        if not math.isfinite(value):
            return None
        return f"{value:g}"
    text = str(value).strip()
    if re.fullmatch(r"[+-]?\d+(?:\.\d+)?", text):
        return text[1:] if text.startswith("+") else text
    return None


