_MISSING_SAME_SECTION_SUBSECTION_IMPORT_RE = re.compile(
    r"Same-section subsection import "
    r"(?P<issue_kind>missing|not operational): source text cites "
    r"(?:subsection\s+)?"
    r"`(?P<target>(?:statutes|regulations)/[^`]+)`"
)


def _try_repair_generated_missing_same_section_subsection_imports_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Add file-level imports for validator-proven same-section dependencies."""
    if not issues:
        return []

    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if not rules_file.exists():
        return []

    content = rules_file.read_text()
    repaired = content
    jurisdiction = _repo_jurisdiction_prefix(policy_repo_path)
    content_root = _rulespec_apply_content_root(policy_repo_path, relative_output)
    generated_target_base = _rulespec_anchor_base_for_output(
        policy_repo_path,
        relative_output,
    )
    added: list[str] = []
    for issue in issues:
        match = _MISSING_SAME_SECTION_SUBSECTION_IMPORT_RE.search(str(issue))
        if match is None:
            continue
        issue_kind = match.group("issue_kind")
        target = match.group("target").strip().strip("/")
        if target.endswith((".yaml", ".yml")):
            target = Path(target).with_suffix("").as_posix()
        relative_target = Path(f"{target}.yaml")
        if (
            relative_target.is_absolute()
            or any(part in {"", ".", ".."} for part in relative_target.parts)
            or relative_target == relative_output
        ):
            continue
        target_file = content_root / relative_target
        if not target_file.is_file():
            output_jurisdiction = _relative_output_jurisdiction_prefix(relative_output)
            if output_jurisdiction is not None:
                target_file = content_root / output_jurisdiction / relative_target
        if not target_file.is_file():
            continue
        imported_output = _single_rulespec_rule_output_name(target_file)
        imported_target = f"{jurisdiction}:{target}"
        before = repaired
        placeholder_repairs: list[str] = []
        referenced_outputs: list[str] = []
        subject_to_outputs: list[str] = []
        subject_to_proof_rule_name: str | None = None
        subject_to_proof_path: str | None = None
        if imported_output is not None:
            import_item = f"{imported_target}#{imported_output}"
            repaired = _ensure_rulespec_import(repaired, import_item)
            repaired = _remove_rulespec_import(repaired, imported_target)
            repaired, placeholder_repairs = (
                _repair_same_section_subsection_placeholder_references(
                    repaired,
                    test_file=test_file,
                    target_base=f"{jurisdiction}:{target}",
                    target_output=imported_output,
                    target_file=target_file,
                    generated_target_base=generated_target_base,
                )
            )
        else:
            target_outputs = _rulespec_rule_output_names(target_file)
            alias_replacements = _formula_alias_rulespec_output_replacements(
                repaired,
                target_outputs,
            )
            if alias_replacements:
                repaired = _replace_rulespec_symbol_references(
                    repaired,
                    alias_replacements,
                )
                placeholder_repairs.extend(
                    _repair_formula_alias_output_test_inputs(
                        test_file=test_file,
                        policy_repo_path=policy_repo_path,
                        generated_target_base=generated_target_base,
                        imported_target=imported_target,
                        alias_replacements=alias_replacements,
                    )
                )
            referenced_outputs = _formula_referenced_rulespec_output_names(
                repaired,
                target_outputs,
            )
            if referenced_outputs:
                placeholder_repairs.extend(
                    _add_imported_output_passthrough_test_overrides(
                        test_file=test_file,
                        rules_content=repaired,
                        generated_target_base=generated_target_base,
                        imported_refs_by_output={
                            referenced_output: (
                                f"{imported_target}#{referenced_output}"
                            )
                            for referenced_output in referenced_outputs
                        },
                    )
                )
                source_hash = _sha256_file(target_file)
                for referenced_output in referenced_outputs:
                    repaired = _ensure_rulespec_import(
                        repaired,
                        f"{imported_target}#{referenced_output}",
                    )
                    repaired = _remove_rulespec_import(repaired, imported_target)
                    repaired = _ensure_import_proof_atoms_for_formula_symbol(
                        repaired,
                        symbol=referenced_output,
                        target=f"{imported_target}#{referenced_output}",
                        output=referenced_output,
                        source_hash=source_hash,
                    )
            if not referenced_outputs:
                imported_outputs = _rulespec_judgment_rule_output_names(target_file)
                if len(imported_outputs) > 1:
                    (
                        candidate,
                        subject_to_outputs,
                        subject_to_repairs,
                        subject_to_proof_rule_name,
                        subject_to_proof_path,
                    ) = _repair_same_section_subsection_subject_to_output_gate(
                        repaired,
                        target=target,
                        target_outputs=imported_outputs,
                    )
                    if subject_to_repairs:
                        repaired = candidate
                        placeholder_repairs.extend(subject_to_repairs)
                        source_hash = _sha256_file(target_file)
                        for subject_to_output in subject_to_outputs:
                            repaired = _ensure_rulespec_import(
                                repaired,
                                f"{imported_target}#{subject_to_output}",
                            )
                            repaired = _remove_rulespec_import(
                                repaired,
                                imported_target,
                            )
                            if (
                                subject_to_proof_rule_name is not None
                                and subject_to_proof_path is not None
                            ):
                                repaired = _ensure_rule_import_proof_atom(
                                    repaired,
                                    rule_name=subject_to_proof_rule_name,
                                    target=f"{imported_target}#{subject_to_output}",
                                    output=subject_to_output,
                                    source_hash=source_hash,
                                    proof_path=subject_to_proof_path,
                                )
                            else:
                                repaired = (
                                    _ensure_import_proof_atoms_for_formula_symbol(
                                        repaired,
                                        symbol=subject_to_output,
                                        target=(
                                            f"{imported_target}#{subject_to_output}"
                                        ),
                                        output=subject_to_output,
                                        source_hash=source_hash,
                                    )
                                )
                            placeholder_repairs.extend(
                                _add_imported_gate_test_overrides(
                                    test_file=test_file,
                                    policy_repo_path=policy_repo_path,
                                    generated_target_base=generated_target_base,
                                    rule_name=subject_to_proof_rule_name
                                    or "is_medicaid_eligible",
                                    imported_ref=(
                                        f"{imported_target}#{subject_to_output}"
                                    ),
                                    stale_input_names=[
                                        repair.split("->", 1)[0]
                                        for repair in subject_to_repairs
                                        if "->" in repair
                                    ],
                                )
                            )
                    else:
                        candidate, placeholder_repairs = (
                            _repair_same_section_subsection_multi_output_placeholder_references(
                                repaired,
                                test_file=test_file,
                                target_base=f"{jurisdiction}:{target}",
                                target_outputs=imported_outputs,
                                target_file=target_file,
                                generated_target_base=generated_target_base,
                            )
                        )
                        if placeholder_repairs:
                            repaired = candidate
                            for imported_output_name in imported_outputs:
                                repaired = _ensure_rulespec_import(
                                    repaired,
                                    f"{imported_target}#{imported_output_name}",
                                )
                                repaired = _remove_rulespec_import(
                                    repaired,
                                    imported_target,
                                )
                        else:
                            if issue_kind != "not operational":
                                import_item = imported_target
                                repaired = _ensure_rulespec_import(
                                    repaired, import_item
                                )
                else:
                    if issue_kind != "not operational":
                        import_item = imported_target
                        repaired = _ensure_rulespec_import(repaired, import_item)
        if repaired != before:
            if imported_output is not None:
                added.append(f"{imported_target}#{imported_output}")
            elif referenced_outputs:
                added.extend(
                    f"{imported_target}#{referenced_output}"
                    for referenced_output in referenced_outputs
                )
            elif placeholder_repairs:
                if subject_to_outputs:
                    added.extend(
                        f"{imported_target}#{subject_to_output}"
                        for subject_to_output in subject_to_outputs
                    )
                else:
                    added.extend(
                        f"{imported_target}#{imported_output_name}"
                        for imported_output_name in imported_outputs
                    )
            else:
                added.append(imported_target)
            added.extend(placeholder_repairs)

    if not added:
        return []
    rules_file.write_text(repaired)
    return added


def _add_imported_output_passthrough_test_overrides(
    *,
    test_file: Path,
    rules_content: str,
    generated_target_base: str,
    imported_refs_by_output: dict[str, str],
) -> list[str]:
    """Add test overrides for imported outputs used as passthrough values."""
    if not test_file.exists() or not imported_refs_by_output:
        return []
    output_refs_by_rule = _passthrough_import_output_refs_by_rule(
        rules_content,
        imported_refs_by_output=imported_refs_by_output,
    )
    if not output_refs_by_rule:
        return []
    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    changed = False
    repairs: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        input_keys = {str(key) for key in _mapping_keys_recursive(inputs)}
        for rule_name, imported_ref in output_refs_by_rule.items():
            expected = _test_output_value_for_rule(
                outputs,
                generated_target_base=generated_target_base,
                rule_name=rule_name,
            )
            if expected is None or isinstance(expected, bool | str | list | dict):
                continue
            if imported_ref in input_keys:
                continue
            inputs[imported_ref] = expected
            input_keys.add(imported_ref)
            changed = True
            case_name = str(test_case.get("name") or "<unnamed>")
            repairs.append(f"test:{case_name}:{imported_ref}")

    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repairs


def _replace_computed_output_test_inputs_with_upstream_inputs(
    *,
    test_file: Path,
    policy_repo_path: Path,
    output_refs: set[str],
) -> list[str]:
    if not test_file.exists() or not output_refs:
        return []
    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    repairs: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        case_name = str(test_case.get("name") or "<unnamed>")
        repairs.extend(
            _replace_computed_output_inputs_in_value(
                inputs,
                case_name=case_name,
                policy_repo_path=policy_repo_path,
                output_refs=output_refs,
            )
        )

    if not repairs:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repairs


def _replace_import_output_placeholders_with_upstream_inputs(
    value: object,
    *,
    placeholder_refs: dict[str, str],
    policy_repo_path: Path,
) -> bool:
    changed = False
    if isinstance(value, dict):
        for key in list(value.keys()):
            key_text = str(key)
            imported_ref = placeholder_refs.get(key_text)
            if imported_ref is not None:
                desired = value.pop(key)
                upstream_inputs = _producer_test_inputs_for_output_value(
                    imported_ref,
                    desired,
                    policy_repo_path=policy_repo_path,
                )
                for input_ref, input_value in upstream_inputs.items():
                    value.setdefault(input_ref, input_value)
                changed = True
                continue
            if _replace_import_output_placeholders_with_upstream_inputs(
                value[key],
                placeholder_refs=placeholder_refs,
                policy_repo_path=policy_repo_path,
            ):
                changed = True
    elif isinstance(value, list):
        for item in value:
            if _replace_import_output_placeholders_with_upstream_inputs(
                item,
                placeholder_refs=placeholder_refs,
                policy_repo_path=policy_repo_path,
            ):
                changed = True
    return changed


def _replace_computed_output_inputs_in_value(
    value: object,
    *,
    case_name: str,
    policy_repo_path: Path,
    output_refs: set[str],
) -> list[str]:
    repairs: list[str] = []
    if isinstance(value, dict):
        for key in list(value.keys()):
            key_text = str(key)
            if key_text in output_refs:
                desired = value[key]
                upstream_inputs = _producer_test_inputs_for_output_value(
                    key_text,
                    desired,
                    policy_repo_path=policy_repo_path,
                )
                if not upstream_inputs:
                    continue
                value.pop(key)
                for input_ref, input_value in upstream_inputs.items():
                    value.setdefault(input_ref, input_value)
                repairs.append(f"test:{case_name}:{key_text}")
                continue
            repairs.extend(
                _replace_computed_output_inputs_in_value(
                    value[key],
                    case_name=case_name,
                    policy_repo_path=policy_repo_path,
                    output_refs=output_refs,
                )
            )
    elif isinstance(value, list):
        for item in value:
            repairs.extend(
                _replace_computed_output_inputs_in_value(
                    item,
                    case_name=case_name,
                    policy_repo_path=policy_repo_path,
                    output_refs=output_refs,
                )
            )
    return repairs


def _producer_test_inputs_for_output_value(
    output_ref: str,
    desired_value: object,
    *,
    policy_repo_path: Path,
) -> dict[object, object]:
    if "#" not in output_ref:
        return {}
    producer_base, output_name = output_ref.rsplit("#", 1)
    producer_file = _import_base_to_repo_file(
        producer_base,
        repo_path=policy_repo_path,
    )
    if producer_file is None or not producer_file.exists():
        return {}
    producer_test_file = _rulespec_test_path(producer_file)
    if not producer_test_file.exists():
        return {}
    try:
        producer_tests = yaml.safe_load(producer_test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return {}
    if not isinstance(producer_tests, list):
        return {}

    amount_passthrough_case: dict[object, object] | None = None
    for test_case in producer_tests:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        output_key = _matching_mapping_key_by_rulespec_ref(outputs, output_ref)
        if output_key is None:
            output_key = _matching_mapping_key_by_rulespec_ref(outputs, output_name)
        if output_key is None:
            continue
        produced_value = outputs[output_key]
        if _generated_test_values_equal(produced_value, desired_value):
            return copy.deepcopy(inputs)
        if amount_passthrough_case is None and _numeric_test_decimal(
            produced_value
        ) not in (None, Decimal("0")):
            amount_passthrough_case = inputs

    if amount_passthrough_case is None or _numeric_test_decimal(desired_value) is None:
        return {}
    retargeted = copy.deepcopy(amount_passthrough_case)
    if _retarget_producer_amount_inputs(
        retargeted,
        producer_base=producer_base,
        output_name=output_name,
        desired_value=desired_value,
    ):
        return retargeted
    return {}


def _producer_test_inputs_and_period_for_output_value(
    output_ref: str,
    desired_value: object,
    *,
    policy_repo_path: Path,
) -> tuple[dict[object, object], object | None]:
    if "#" not in output_ref:
        return {}, None
    producer_base, output_name = output_ref.rsplit("#", 1)
    producer_file = _import_base_to_repo_file(
        producer_base,
        repo_path=policy_repo_path,
    )
    if producer_file is None or not producer_file.exists():
        return {}, None
    producer_test_file = _rulespec_test_path(producer_file)
    if not producer_test_file.exists():
        return {}, None
    try:
        producer_tests = yaml.safe_load(producer_test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return {}, None
    if not isinstance(producer_tests, list):
        return {}, None

    for test_case in producer_tests:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        output_key = _matching_mapping_key_by_rulespec_ref(outputs, output_ref)
        if output_key is None:
            output_key = _matching_mapping_key_by_rulespec_ref(outputs, output_name)
        if output_key is None:
            continue
        produced_value = outputs[output_key]
        if _generated_test_values_equal(produced_value, desired_value):
            return copy.deepcopy(inputs), copy.deepcopy(test_case.get("period"))

    return (
        _producer_test_inputs_for_output_value(
            output_ref,
            desired_value,
            policy_repo_path=policy_repo_path,
        ),
        None,
    )


def _retarget_producer_amount_inputs(
    value: object,
    *,
    producer_base: str,
    output_name: str,
    desired_value: object,
) -> bool:
    changed = False
    if isinstance(value, dict):
        amount_keys = [
            key
            for key in value
            if _computed_output_retarget_amount_key(
                str(key),
                producer_base=producer_base,
                output_name=output_name,
            )
        ]
        preferred_keys = sorted(
            amount_keys,
            key=lambda key: (
                "#input.payment_amount" not in str(key),
                "#input.amount" not in str(key),
                str(key),
            ),
        )
        if preferred_keys:
            value[preferred_keys[0]] = desired_value
            changed = True
        for child in value.values():
            if _retarget_producer_amount_inputs(
                child,
                producer_base=producer_base,
                output_name=output_name,
                desired_value=desired_value,
            ):
                changed = True
    elif isinstance(value, list):
        for item in value:
            if _retarget_producer_amount_inputs(
                item,
                producer_base=producer_base,
                output_name=output_name,
                desired_value=desired_value,
            ):
                changed = True
    return changed


def _computed_output_retarget_amount_key(
    key: str,
    *,
    producer_base: str,
    output_name: str,
) -> bool:
    if "#input." not in key or not _rulespec_ref_matches_base(key, producer_base):
        return False
    input_name = key.rsplit("#input.", 1)[1].strip()
    if not input_name:
        return False
    return input_name in {
        "amount",
        "payment_amount",
        output_name,
    } or input_name.endswith("_amount")


def _generated_test_values_equal(left: object, right: object) -> bool:
    left_decimal = _numeric_test_decimal(left)
    right_decimal = _numeric_test_decimal(right)
    if left_decimal is not None and right_decimal is not None:
        return left_decimal == right_decimal
    left_judgment = _judgment_test_bool(left)
    right_judgment = _judgment_test_bool(right)
    if left_judgment is not None and right_judgment is not None:
        return left_judgment == right_judgment
    return left == right


def _judgment_test_bool(value: object) -> bool | None:
    if isinstance(value, bool):
        return value
    if not isinstance(value, str):
        return None
    normalized = value.strip().lower()
    if normalized in {"holds", "true"}:
        return True
    if normalized in {"not_holds", "false"}:
        return False
    return None


def _numeric_test_decimal(value: object) -> Decimal | None:
    if isinstance(value, bool):
        return None
    if isinstance(value, Decimal):
        return value
    if isinstance(value, int | float):
        try:
            return Decimal(str(value))
        except InvalidOperation:
            return None
    if isinstance(value, str):
        try:
            return Decimal(value.strip())
        except InvalidOperation:
            return None
    return None


def _passthrough_import_output_refs_by_rule(
    rules_content: str,
    *,
    imported_refs_by_output: dict[str, str],
) -> dict[str, str]:
    try:
        payload = yaml.safe_load(rules_content) or {}
    except (ValueError, yaml.YAMLError):
        return {}
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return {}
    refs_by_rule: dict[str, str] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip()
        if not rule_name:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_refs: set[str] = set()
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            output_name = _passthrough_imported_output_name(
                formula,
                imported_outputs=list(imported_refs_by_output),
            )
            if output_name:
                rule_refs.add(imported_refs_by_output[output_name])
        if len(rule_refs) == 1:
            refs_by_rule[rule_name] = next(iter(rule_refs))
    return refs_by_rule


def _passthrough_imported_output_name(
    formula: str,
    *,
    imported_outputs: list[str],
) -> str | None:
    normalized = " ".join(formula.strip().split())
    if not normalized:
        return None
    for output in imported_outputs:
        token = re.escape(output)
        if normalized == output:
            return output
        if re.fullmatch(rf"if\s+.+?:\s*0(?:\.0)?\s+else:\s*{token}", normalized):
            return output
        if re.fullmatch(rf"if\s+.+?:\s*{token}\s+else:\s*0(?:\.0)?", normalized):
            return output
    return None


def _test_output_value_for_rule(
    outputs: dict[object, object],
    *,
    generated_target_base: str,
    rule_name: str,
) -> object | None:
    absolute_ref = f"{generated_target_base}#{rule_name}"
    for candidate in (absolute_ref, rule_name):
        key = _matching_mapping_key_by_rulespec_ref(outputs, candidate)
        if key is not None:
            return outputs[key]
    return None


def _rulespec_rule_output_names(rules_file: Path) -> list[str]:
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return []
    return [
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    ]


def _formula_referenced_rulespec_output_names(
    content: str, target_outputs: list[str]
) -> list[str]:
    if not target_outputs:
        return []
    try:
        payload = yaml.safe_load(content) or {}
    except (ValueError, yaml.YAMLError):
        return []
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return []
    formulas: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if isinstance(formula, str):
                formulas.append(formula)
    referenced: list[str] = []
    for output in target_outputs:
        pattern = re.compile(rf"(?<![A-Za-z0-9_]){re.escape(output)}(?![A-Za-z0-9_])")
        if any(pattern.search(formula) for formula in formulas):
            referenced.append(output)
    return referenced


def _formula_alias_rulespec_output_replacements(
    content: str,
    target_outputs: list[str],
) -> dict[str, str]:
    if not target_outputs:
        return {}
    try:
        payload = yaml.safe_load(content) or {}
    except (ValueError, yaml.YAMLError):
        return {}
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return {}
    local_outputs = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    formulas: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if isinstance(formula, str):
                formulas.append(formula)
    replacements: dict[str, str] = {}
    sorted_outputs = sorted(target_outputs, key=len, reverse=True)
    for formula in formulas:
        for match in re.finditer(
            r"(?<![A-Za-z0-9_])([A-Za-z_][A-Za-z0-9_]*)(?![A-Za-z0-9_])",
            formula,
        ):
            symbol = match.group(1)
            if symbol in local_outputs:
                continue
            for output in sorted_outputs:
                if _is_safe_import_output_alias(symbol, output):
                    replacements[symbol] = output
                    break
    return replacements


_SAFE_IMPORT_OUTPUT_ALIAS_PREFIXES = {
    "applicant",
    "candidate",
    "child",
    "claimant",
    "dependent",
    "household_member",
    "individual",
    "member",
    "parent",
    "payee",
    "payer",
    "payment",
    "person",
    "recipient",
    "spouse",
    "taxpayer",
}


def _is_safe_import_output_alias(symbol: str, output: str) -> bool:
    if symbol == output or not symbol.endswith(f"_{output}"):
        return _is_safe_legal_cross_reference_output_alias(symbol, output)
    prefix = symbol[: -(len(output) + 1)].strip("_")
    if not prefix:
        return False
    return prefix in _SAFE_IMPORT_OUTPUT_ALIAS_PREFIXES


def _is_safe_legal_cross_reference_output_alias(symbol: str, output: str) -> bool:
    """Return whether a local cross-reference fact names a cited output plus qualifiers."""
    symbol_tokens = _identifier_tokens(symbol)
    output_tokens = _identifier_tokens(output)
    if len(output_tokens) < 3 or len(symbol_tokens) <= len(output_tokens):
        return False
    if not any(
        token in symbol_tokens
        for token in ("clause", "paragraph", "section", "subparagraph", "subsection")
    ):
        return False
    if symbol_tokens[0] != output_tokens[0]:
        return False
    return _ordered_subsequence(output_tokens, symbol_tokens)


def _identifier_tokens(value: str) -> list[str]:
    return [
        token for token in re.sub(r"[^a-z0-9]+", "_", value.lower()).split("_") if token
    ]


def _ordered_subsequence(needles: list[str], haystack: list[str]) -> bool:
    cursor = 0
    for token in haystack:
        if cursor < len(needles) and token == needles[cursor]:
            cursor += 1
    return cursor == len(needles)


def _replace_rulespec_symbol_references(
    content: str,
    replacements: dict[str, str],
) -> str:
    if not replacements:
        return content
    pattern = re.compile(
        r"(?<![A-Za-z0-9_])("
        + "|".join(
            re.escape(symbol) for symbol in sorted(replacements, key=len, reverse=True)
        )
        + r")(?![A-Za-z0-9_])"
    )
    return pattern.sub(lambda match: replacements[match.group(1)], content)


def _single_rulespec_rule_output_name(rules_file: Path) -> str | None:
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return None
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return None
    names = [
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    ]
    if len(names) != 1:
        return None
    return names[0]


def _rulespec_judgment_rule_output_names(rules_file: Path) -> list[str]:
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return []
    names: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        kind = str(rule.get("kind") or "").strip().lower()
        dtype = str(rule.get("dtype") or "").strip().lower()
        if kind == "derived" and dtype == "judgment":
            names.append(name)
    return names


_MEDICAID_1396A_XX_COMMUNITY_ENGAGEMENT_OUTPUT = (
    "demonstrated_community_engagement_for_month"
)
_MEDICAID_1396A_XX_SUBJECT_TO_PLACEHOLDERS = (
    "adult_expansion_subject_to_xx",
    "adult_expansion_subject_to_subsection_xx_satisfied",
    "adult_expansion_subject_to_subsections_k_and_xx_satisfied",
)
_MEDICAID_ADULT_EXPANSION_INCOME_LIMIT_LINE = (
    "and income_determined_for_adult_expansion <= "
    "adult_expansion_income_limit_poverty_line_rate * poverty_line_for_family_size"
)


def _repair_same_section_subsection_subject_to_output_gate(
    content: str,
    *,
    target: str,
    target_outputs: list[str],
) -> tuple[str, list[str], list[str], str | None, str | None]:
    if target != "statutes/42/1396a/xx":
        return content, [], [], None, None
    output = _MEDICAID_1396A_XX_COMMUNITY_ENGAGEMENT_OUTPUT
    if output not in target_outputs:
        return content, [], [], None, None

    rule_pattern = re.compile(
        r"(?ms)^  - name: (?P<rule_name>[A-Za-z_][A-Za-z0-9_]*)\n.*?(?=^  - name: |\Z)"
    )
    version_pattern = re.compile(
        r"(?ms)"
        r"(?P<version>"
        r"^      - effective_from: '(?P<effective_from>[^']+)'\n"
        r"        formula: \|-\n"
        r"(?P<formula>(?:^          .*(?:\n|$))+)"
        r")"
    )
    for rule_match in rule_pattern.finditer(content):
        rule_name = rule_match.group("rule_name")
        rule_block = rule_match.group(0)
        for version_index, version_match in enumerate(
            version_pattern.finditer(rule_block)
        ):
            formula_text = version_match.group("formula")
            formula_lines = formula_text.splitlines()
            if output in formula_text:
                continue
            replaced_formula = formula_text
            placeholder_repairs: list[str] = []
            for placeholder in _MEDICAID_1396A_XX_SUBJECT_TO_PLACEHOLDERS:
                updated_formula = re.sub(
                    rf"\b{re.escape(placeholder)}\b",
                    output,
                    replaced_formula,
                )
                if updated_formula == replaced_formula:
                    continue
                replaced_formula = updated_formula
                placeholder_repairs.append(f"{placeholder}->{output}")
            if placeholder_repairs:
                repaired_rule_block = (
                    rule_block[: version_match.start("formula")]
                    + replaced_formula
                    + rule_block[version_match.end("formula") :]
                )
                repaired = (
                    content[: rule_match.start()]
                    + repaired_rule_block
                    + content[rule_match.end() :]
                )
                proof_path = f"versions[{version_index}].formula"
                return repaired, [output], placeholder_repairs, rule_name, proof_path

            gated_lines: list[str] = []
            inserted_imported_adult_group_gate = False
            for line in formula_lines:
                stripped = line.strip()
                indentation = line[: len(line) - len(line.lstrip())]
                if stripped == "adult_group_eligible":
                    gated_lines.append(
                        f"{indentation}(adult_group_eligible and {output})"
                    )
                    inserted_imported_adult_group_gate = True
                    continue
                if stripped == "or adult_group_eligible":
                    gated_lines.append(
                        f"{indentation}or (adult_group_eligible and {output})"
                    )
                    inserted_imported_adult_group_gate = True
                    continue
                gated_lines.append(line)
            if inserted_imported_adult_group_gate:
                gated_formula = "\n".join(gated_lines) + "\n"
                repaired_rule_block = (
                    rule_block[: version_match.start("formula")]
                    + gated_formula
                    + rule_block[version_match.end("formula") :]
                )
                repaired = (
                    content[: rule_match.start()]
                    + repaired_rule_block
                    + content[rule_match.end() :]
                )
                proof_path = f"versions[{version_index}].formula"
                return (
                    repaired,
                    [output],
                    [f"adult_expansion_subject_to_xx->{output}"],
                    rule_name,
                    proof_path,
                )
            if not any(
                line.strip() == _MEDICAID_ADULT_EXPANSION_INCOME_LIMIT_LINE
                for line in formula_lines
            ):
                continue
            gated_lines = []
            inserted_gate = False
            for line in formula_lines:
                gated_lines.append(line)
                if line.strip() != _MEDICAID_ADULT_EXPANSION_INCOME_LIMIT_LINE:
                    continue
                indentation = line[: len(line) - len(line.lstrip())]
                gated_lines.append(f"{indentation}and {output}")
                inserted_gate = True
            if not inserted_gate:
                continue
            gated_formula = "\n".join(gated_lines) + "\n"
            repaired_rule_block = (
                rule_block[: version_match.start("formula")]
                + gated_formula
                + rule_block[version_match.end("formula") :]
            )
            repaired = (
                content[: rule_match.start()]
                + repaired_rule_block
                + content[rule_match.end() :]
            )
            proof_path = f"versions[{version_index}].formula"
            return (
                repaired,
                [output],
                [f"adult_expansion_subject_to_xx->{output}"],
                rule_name,
                proof_path,
            )
    return content, [], [], None, None


def _add_imported_gate_test_overrides(
    *,
    test_file: Path,
    policy_repo_path: Path,
    generated_target_base: str,
    rule_name: str,
    imported_ref: str,
    stale_input_names: list[str] | None = None,
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    changed = False
    repairs: list[str] = []
    stale_input_refs = {
        f"{generated_target_base}#input.{input_name}"
        for input_name in (stale_input_names or [])
        if input_name
    }
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        if (
            _test_output_value_for_rule(
                outputs,
                generated_target_base=generated_target_base,
                rule_name=rule_name,
            )
            is None
        ):
            continue
        upstream_inputs, upstream_period = (
            _producer_test_inputs_and_period_for_output_value(
                imported_ref,
                "holds",
                policy_repo_path=policy_repo_path,
            )
        )
        if not upstream_inputs:
            continue
        removed_stale_inputs = False
        if stale_input_refs:
            removed_stale_inputs = _remove_mapping_keys_recursive(
                inputs,
                stale_input_refs,
            )

        current_period_start = _test_period_start_date(test_case.get("period"))
        upstream_period_start = _test_period_start_date(upstream_period)
        period_changed = False
        if upstream_period_start is not None and (
            current_period_start is None or current_period_start < upstream_period_start
        ):
            test_case["period"] = copy.deepcopy(upstream_period)
            period_changed = True

        input_keys = {str(key) for key in _mapping_keys_recursive(inputs)}
        missing_inputs = [
            (input_ref, input_value)
            for input_ref, input_value in upstream_inputs.items()
            if str(input_ref) not in input_keys
        ]
        if not missing_inputs and not period_changed and not removed_stale_inputs:
            continue
        for input_ref, input_value in missing_inputs:
            inputs[input_ref] = input_value
            input_keys.add(str(input_ref))
        changed = True
        case_name = str(test_case.get("name") or "<unnamed>")
        repairs.append(f"test:{case_name}:{imported_ref}")

    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repairs


def _repair_formula_alias_output_test_inputs(
    *,
    test_file: Path,
    policy_repo_path: Path,
    generated_target_base: str,
    imported_target: str,
    alias_replacements: dict[str, str],
) -> list[str]:
    if not test_file.exists() or not alias_replacements:
        return []
    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    changed = False
    repairs: list[str] = []
    ref_replacements = {
        f"{generated_target_base}#input.{alias}": f"{imported_target}#{output}"
        for alias, output in alias_replacements.items()
    }
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        case_repairs = _replace_alias_output_test_inputs_in_value(
            test_case,
            ref_replacements=ref_replacements,
            policy_repo_path=policy_repo_path,
        )
        if not case_repairs:
            continue
        changed = True
        case_name = str(test_case.get("name") or "<unnamed>")
        repairs.extend(f"test:{case_name}:{repair}" for repair in case_repairs)

    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repairs


def _replace_alias_output_test_inputs_in_value(
    value: object,
    *,
    ref_replacements: dict[str, str],
    policy_repo_path: Path,
) -> list[str]:
    repairs: list[str] = []
    if isinstance(value, dict):
        pending_desired_values: dict[str, object] = {}
        matched_keys: dict[str, list[object]] = {}
        for key, old_value in list(value.items()):
            key_text = str(key)
            new_ref = ref_replacements.get(key_text)
            if new_ref is None:
                continue
            if new_ref in pending_desired_values:
                old_value = _combine_alias_test_input_values(
                    pending_desired_values[new_ref],
                    old_value,
                )
            pending_desired_values[new_ref] = old_value
            matched_keys.setdefault(new_ref, []).append(key)
        upstream_inputs_by_ref: dict[str, dict[object, object]] = {}
        for new_ref, desired_value in pending_desired_values.items():
            upstream_inputs = _producer_test_inputs_for_output_value(
                new_ref,
                desired_value,
                policy_repo_path=policy_repo_path,
            )
            if upstream_inputs:
                upstream_inputs_by_ref[new_ref] = upstream_inputs
        for new_ref, upstream_inputs in upstream_inputs_by_ref.items():
            for key in matched_keys.get(new_ref, []):
                old_key = str(key)
                value.pop(key, None)
                repairs.append(f"{old_key}->{new_ref}")
            for input_ref, input_value in upstream_inputs.items():
                value.setdefault(input_ref, input_value)
        for nested in value.values():
            repairs.extend(
                _replace_alias_output_test_inputs_in_value(
                    nested,
                    ref_replacements=ref_replacements,
                    policy_repo_path=policy_repo_path,
                )
            )
    elif isinstance(value, list):
        for item in value:
            repairs.extend(
                _replace_alias_output_test_inputs_in_value(
                    item,
                    ref_replacements=ref_replacements,
                    policy_repo_path=policy_repo_path,
                )
            )
    return repairs


def _combine_alias_test_input_values(existing: object, incoming: object) -> bool:
    return _test_input_object_truthy(existing) or _test_input_object_truthy(incoming)


def _test_input_object_truthy(value: object) -> bool:
    if isinstance(value, bool):
        return value
    return _test_input_value_truthy(str(value))


def _repair_same_section_subsection_placeholder_references(
    content: str,
    *,
    test_file: Path,
    target_base: str,
    target_output: str,
    target_file: Path,
    generated_target_base: str,
) -> tuple[str, list[str]]:
    repaired = content
    applied: list[str] = []
    target_ref = f"{target_base}#{target_output}"
    placeholders = _same_section_subsection_placeholder_names(target_base)
    for placeholder in placeholders:
        updated = _replace_formula_identifier(
            repaired,
            old=placeholder,
            new=target_output,
        )
        if updated == repaired:
            continue
        repaired = updated
        applied.append(f"{placeholder}->{target_output}")
        if test_file.exists():
            test_content = test_file.read_text()
            repaired_test = _replace_test_input_ref(
                test_content,
                old_ref=f"{generated_target_base}#input.{placeholder}",
                new_ref=target_ref,
            )
            if repaired_test != test_content:
                test_file.write_text(repaired_test)

    if applied:
        repaired = _ensure_import_proof_atoms_for_formula_symbol(
            repaired,
            symbol=target_output,
            target=target_ref,
            output=target_output,
            source_hash=_sha256_file(target_file),
        )
    return repaired, applied


def _repair_same_section_subsection_multi_output_placeholder_references(
    content: str,
    *,
    test_file: Path,
    target_base: str,
    target_outputs: list[str],
    target_file: Path,
    generated_target_base: str,
) -> tuple[str, list[str]]:
    if len(target_outputs) < 2:
        return content, []
    repaired = content
    applied: list[str] = []
    expression = " or ".join(target_outputs)
    placeholders = _same_section_subsection_placeholder_names(target_base)
    for placeholder in placeholders:
        updated = _replace_formula_identifier(
            repaired,
            old=placeholder,
            new=f"({expression})",
        )
        if updated == repaired:
            continue
        repaired = updated
        applied.append(f"{placeholder}->({expression})")
        if test_file.exists():
            test_content = test_file.read_text()
            repaired_test = _replace_test_input_ref_with_disjunction_refs(
                test_content,
                old_ref=f"{generated_target_base}#input.{placeholder}",
                new_refs=[f"{target_base}#{output}" for output in target_outputs],
            )
            if repaired_test != test_content:
                test_file.write_text(repaired_test)

    if applied:
        source_hash = _sha256_file(target_file)
        for output in target_outputs:
            repaired = _ensure_import_proof_atoms_for_formula_symbol(
                repaired,
                symbol=output,
                target=f"{target_base}#{output}",
                output=output,
                source_hash=source_hash,
            )
    return repaired, applied


def _replace_test_input_ref_with_disjunction_refs(
    content: str, *, old_ref: str, new_refs: list[str]
) -> str:
    if not new_refs:
        return content

    def replacement_lines(indent: str, value: str) -> str:
        truthy = _test_input_value_truthy(value)
        rendered: list[str] = []
        for index, new_ref in enumerate(new_refs):
            branch_value = truthy and index == 0
            rendered.append(f"{indent}{new_ref}: {_format_yaml_scalar(branch_value)}\n")
        return "".join(rendered)

    question_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*)\?\s+{re.escape(old_ref)}\n"
        rf"(?P=indent):\s*(?P<value>[^\n]+)\n"
    )
    content = question_key_pattern.sub(
        lambda match: replacement_lines(
            match.group("indent"),
            match.group("value").strip(),
        ),
        content,
    )
    scalar_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*){re.escape(old_ref)}:\s*(?P<value>[^\n]+)\n"
    )
    return scalar_key_pattern.sub(
        lambda match: replacement_lines(
            match.group("indent"),
            match.group("value").strip(),
        ),
        content,
    )


def _same_section_subsection_placeholder_names(target_base: str) -> list[str]:
    _prefix, _separator, target_path = target_base.partition(":")
    parts = Path(target_path).parts
    if len(parts) >= 4 and parts[0] == "statutes":
        fragment_parts = parts[3:]
    elif len(parts) >= 5 and parts[0] == "regulations":
        fragment_parts = parts[4:]
    else:
        fragment_parts = parts[-1:]
    fragment = "_".join(
        re.sub(r"[^a-z0-9]+", "_", part.lower()).strip("_")
        for part in fragment_parts
        if part
    ).strip("_")
    if not fragment:
        return []
    return [
        f"conditions_of_paragraph_{fragment}_are_satisfied",
        f"condition_of_paragraph_{fragment}_is_satisfied",
        f"requirements_of_paragraph_{fragment}_are_satisfied",
        f"requirement_of_paragraph_{fragment}_is_satisfied",
        f"conditions_of_subsection_{fragment}_are_satisfied",
        f"condition_of_subsection_{fragment}_is_satisfied",
        f"requirements_of_subsection_{fragment}_are_satisfied",
        f"requirement_of_subsection_{fragment}_is_satisfied",
    ]


def _try_repair_generated_unreferenced_proof_imports_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Remove proof-import atoms that validator proved are stale."""
    if not issues:
        return []

    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _remove_unreferenced_proof_import_atoms(
        rules_file=rules_file,
        issues=issues,
    )


def _try_repair_generated_self_referential_derived_rules_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Rename generated same-name local facts that cause derived cycles."""
    rule_names = _cyclic_derived_rule_names_from_issues(issues)
    if not rule_names:
        return []

    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    target_anchor = _relative_output_to_anchor(
        relative_output, policy_repo_path=policy_repo_path
    )
    return _rename_self_referential_derived_rule_inputs(
        rules_file=rules_file,
        test_file=test_file,
        target_anchor=target_anchor,
        rule_names=rule_names,
    )


def _cyclic_derived_rule_names_from_issues(issues: list[str]) -> list[str]:
    names: list[str] = []
    seen: set[str] = set()
    pattern = re.compile(
        r"cyclic derived dependency detected involving:\s*"
        r"(?P<name>[A-Za-z_][A-Za-z0-9_]*)"
    )
    for issue in issues:
        for match in pattern.finditer(str(issue)):
            name = match["name"].strip()
            if name and name not in seen:
                seen.add(name)
                names.append(name)
    return names


def _rename_self_referential_derived_rule_inputs(
    *,
    rules_file: Path,
    test_file: Path,
    target_anchor: str,
    rule_names: list[str],
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        rules_payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict):
        return []
    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return []

    existing_rule_names = {
        str(rule.get("name") or "").strip() for rule in rules if isinstance(rule, dict)
    }
    requested = set(rule_names)
    replacements: dict[str, str] = {}
    changed_rules = False
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip()
        if rule_name not in requested or rule.get("kind") != "derived":
            continue
        replacement_name = _self_reference_input_name(
            rule_name, existing_names=existing_rule_names
        )
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_changed = False
        token = re.compile(rf"\b{re.escape(rule_name)}\b")
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            repaired_formula = token.sub(replacement_name, formula)
            if repaired_formula != formula:
                version["formula"] = repaired_formula
                rule_changed = True
        if rule_changed:
            replacements[rule_name] = replacement_name
            changed_rules = True

    if not changed_rules:
        return []
    rules_file.write_text(
        yaml.safe_dump(rules_payload, sort_keys=False, allow_unicode=False)
    )

    if test_file.exists():
        try:
            test_payload = yaml.safe_load(test_file.read_text()) or []
        except (OSError, ValueError, yaml.YAMLError):
            test_payload = None
        if isinstance(test_payload, list):
            key_replacements = {
                f"{target_anchor}#input.{old}": f"{target_anchor}#input.{new}"
                for old, new in replacements.items()
            }
            if _replace_mapping_keys_recursive(test_payload, key_replacements):
                test_file.write_text(
                    yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
                )

    return [f"{old}->{new}" for old, new in sorted(replacements.items())]


def _self_reference_input_name(rule_name: str, *, existing_names: set[str]) -> str:
    base = f"{rule_name}_fact"
    if base not in existing_names:
        return base
    suffix = 2
    while f"{base}_{suffix}" in existing_names:
        suffix += 1
    return f"{base}_{suffix}"


def _try_repair_generated_invalid_test_inputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Remove generated-test input refs that validator proved are invalid."""
    if not issues:
        return []

    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    target_base = (
        f"{_repo_jurisdiction_prefix(policy_repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    repaired_2739_refs = _repair_snap_2739_income_test_inputs(
        test_file=test_file,
        target_base=target_base,
        issues=issues,
    )
    removed_refs = _remove_invalid_test_input_refs(test_file=test_file, issues=issues)
    return [*repaired_2739_refs, *removed_refs]


def _try_repair_generated_wrong_typed_test_inputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Normalize generated-test input values whose scalar type is clearly wrong."""
    if not _issues_mention_test_input_type_mismatch(issues):
        return []

    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if not rules_file.exists() or not test_file.exists():
        return []

    try:
        rules_payload = yaml.safe_load(rules_file.read_text()) or {}
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict) or not isinstance(test_payload, list):
        return []

    target_base = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    repaired: list[str] = []
    for case in test_payload:
        if not isinstance(case, dict):
            continue
        case_name = str(case.get("name") or "<unnamed>")
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        repaired.extend(
            _repair_wrong_typed_test_input_values(
                inputs,
                case_name=case_name,
                target_base=target_base,
                rules_payload=rules_payload,
            )
        )

    if not repaired:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired


def _issues_mention_test_input_type_mismatch(issues: list[str]) -> bool:
    patterns = (
        r"\btype mismatch\b",
        r"\bnot numeric\b",
        r"\bexpected (?:numeric|number|money|boolean|judgment)\b",
        r"\bmust be (?:numeric|a number|money|boolean|a boolean)\b",
    )
    return any(
        re.search(pattern, str(issue), re.IGNORECASE)
        for issue in issues
        for pattern in patterns
    )


def _repair_wrong_typed_test_input_values(
    value: object,
    *,
    case_name: str,
    target_base: str,
    rules_payload: dict[str, object],
) -> list[str]:
    if isinstance(value, list):
        repaired: list[str] = []
        for item in value:
            repaired.extend(
                _repair_wrong_typed_test_input_values(
                    item,
                    case_name=case_name,
                    target_base=target_base,
                    rules_payload=rules_payload,
                )
            )
        return repaired
    if not isinstance(value, dict):
        return []

    repaired = []
    for key, current in list(value.items()):
        key_text = str(key)
        if key_text.startswith(f"{target_base}#input."):
            input_name = key_text.split("#input.", 1)[1].strip()
            replacement = _wrong_typed_test_input_replacement(
                input_name,
                current,
                rules_payload=rules_payload,
            )
            if replacement is not None:
                value[key] = replacement
                repaired.append(f"{case_name}:{key_text}")
        nested = value.get(key)
        if isinstance(nested, (dict, list)):
            repaired.extend(
                _repair_wrong_typed_test_input_values(
                    nested,
                    case_name=case_name,
                    target_base=target_base,
                    rules_payload=rules_payload,
                )
            )
    return repaired


def _wrong_typed_test_input_replacement(
    input_name: str,
    value: object,
    *,
    rules_payload: dict[str, object],
) -> object | None:
    expected = _default_generated_test_input_value(
        input_name,
        rules_payload=rules_payload,
    )
    if isinstance(expected, bool):
        if isinstance(value, bool):
            return None
        if isinstance(value, (int, float)) and not isinstance(value, bool):
            return expected
        return None
    if isinstance(expected, (int, float)) and not isinstance(expected, bool):
        if isinstance(value, bool):
            return expected
        return None
    if isinstance(expected, str):
        if isinstance(value, bool):
            return expected
        return None
    return None


def _try_repair_generated_target_prefix_typos_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Normalize generated-test refs that typo the current target's path."""
    if not issues:
        return []

    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if not test_file.exists():
        return []

    target_base = (
        f"{_repo_jurisdiction_prefix(policy_repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    replacements: dict[str, str] = {}
    for input_ref in _unresolved_test_input_refs_from_issues(issues):
        replacement = _current_target_replacement_for_near_ref_typo(
            input_ref, target_base=target_base
        )
        if replacement is not None:
            replacements[input_ref] = replacement
    if not replacements:
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    if not _replace_mapping_keys_recursive(test_payload, replacements):
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return [f"{old}->{new}" for old, new in sorted(replacements.items())]


def _try_repair_generated_import_target_prefix_typos_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Normalize generated-test refs that typo one of the module's imports."""
    unresolved_refs = _unresolved_test_input_refs_from_issues(issues)
    if not unresolved_refs:
        return []

    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if not rules_file.exists() or not test_file.exists():
        return []
    try:
        rules_payload = yaml.safe_load(rules_file.read_text()) or {}
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict) or not isinstance(test_payload, list):
        return []

    imports = rules_payload.get("imports")
    if not isinstance(imports, list):
        return []
    imported_bases = list(
        dict.fromkeys(
            raw_import.split("#", 1)[0].strip()
            for raw_import in imports
            if isinstance(raw_import, str) and "#" in raw_import
        )
    )
    if not imported_bases:
        return []

    replacements: dict[str, str] = {}
    for input_ref in unresolved_refs:
        replacement = _import_target_replacement_for_near_ref_typo(
            input_ref,
            imported_bases=imported_bases,
            policy_repo_path=policy_repo_path,
        )
        if replacement is not None:
            replacements[input_ref] = replacement
    if not replacements:
        return []
    if not _replace_mapping_keys_recursive(test_payload, replacements):
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return [f"{old}->{new}" for old, new in sorted(replacements.items())]


def _import_target_replacement_for_near_ref_typo(
    input_ref: str,
    *,
    imported_bases: list[str],
    policy_repo_path: Path,
) -> str | None:
    if "#input." not in input_ref:
        return None
    input_base, fragment = input_ref.split("#", 1)
    if not fragment.startswith("input."):
        return None

    input_jurisdiction = _rulespec_ref_jurisdiction(input_base)
    input_tail = _rulespec_ref_without_jurisdiction(input_base).strip("/")
    if not input_tail:
        return None

    candidates: list[tuple[float, str]] = []
    for imported_base in imported_bases:
        if input_base == imported_base:
            continue
        imported_jurisdiction = _rulespec_ref_jurisdiction(imported_base)
        if (
            input_jurisdiction
            and imported_jurisdiction
            and input_jurisdiction != imported_jurisdiction
        ):
            continue
        import_file = _import_base_to_repo_file(
            imported_base,
            repo_path=policy_repo_path,
        )
        if import_file is None or not import_file.exists():
            continue
        imported_tail = _rulespec_ref_without_jurisdiction(imported_base).strip("/")
        if not imported_tail:
            continue
        input_parts = Path(input_tail).parts
        imported_parts = Path(imported_tail).parts
        if len(input_parts) != len(imported_parts) or not input_parts:
            continue
        if input_parts[:-1] != imported_parts[:-1]:
            continue
        similarity = difflib.SequenceMatcher(None, input_tail, imported_tail).ratio()
        if similarity < 0.93:
            continue
        if (similarity, imported_base) not in candidates:
            candidates.append((similarity, imported_base))

    if len(candidates) != 1:
        return None
    return f"{candidates[0][1]}#{fragment}"


def _try_repair_generated_imported_test_inputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Fill deterministic defaults for imported inputs in generated tests."""
    if not issues:
        return []

    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    validation = argparse.Namespace(
        results={
            str(index): argparse.Namespace(error=str(issue))
            for index, issue in enumerate(issues)
        }
    )
    assignments = _missing_input_assignments_from_validation(validation)
    if not assignments:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    repaired = _complete_missing_imported_test_inputs(
        rules_file=rules_file,
        test_file=test_file,
        repo_path=policy_repo_path,
        validation=validation,
    )
    if not repaired:
        return []
    return sorted({assignment["input"] for assignment in assignments})


_SECTION_1401_A_OUTPUT = (
    "us:statutes/26/1401/a#old_age_survivors_and_disability_insurance_tax"
)
_SECTION_1401_B_1_OUTPUT = "us:statutes/26/1401/b/1#self_employment_income_tax"
_SECTION_1402_B_SELF_EMPLOYMENT_INCOME_OUTPUT = (
    "us:statutes/26/1402/b#self_employment_income"
)
_SECTION_1402_B_SELF_EMPLOYMENT_INCOME_FOR_1401_A_OUTPUT = (
    "us:statutes/26/1402/b#self_employment_income_for_section_1401_a"
)
_SECTION_1401_TAXABLE_SELF_EMPLOYMENT_RATE = Decimal("0.9235")
_SECTION_1401_SELF_EMPLOYMENT_THRESHOLD = Decimal("400")
_SECTION_1401_OASDI_BASE_BY_YEAR = {
    2023: Decimal("160200"),
    2024: Decimal("168600"),
    2025: Decimal("176100"),
    2026: Decimal("184500"),
}


def _try_repair_generated_section_1401_b_1_self_employment_income_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Use uncapped 1402(b) self-employment income for 1401(b)(1) Medicare tax."""
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []
    if relative_output.as_posix() != "statutes/26/1401/b/1.yaml":
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    repaired = _repair_section_1401_b_1_self_employment_income_import(
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
    )
    repaired.extend(
        _append_section_1401_b_1_uncapped_self_employment_income_test(
            test_file=test_file,
        )
    )
    return repaired


def _repair_section_1401_b_1_self_employment_income_import(
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []

    repaired: list[str] = []
    imports = payload.get("imports")
    if isinstance(imports, list):
        changed_imports = False
        for index, item in enumerate(imports):
            if item == _SECTION_1402_B_SELF_EMPLOYMENT_INCOME_FOR_1401_A_OUTPUT:
                imports[index] = _SECTION_1402_B_SELF_EMPLOYMENT_INCOME_OUTPUT
                changed_imports = True
        if changed_imports:
            repaired.append("import:self_employment_income")

    imported_file = policy_repo_path / "statutes/26/1402/b.yaml"
    imported_hash = _sha256_file(imported_file) if imported_file.exists() else None
    rules = payload.get("rules")
    if isinstance(rules, list):
        for rule in rules:
            if (
                not isinstance(rule, dict)
                or rule.get("name") != "self_employment_income_tax"
            ):
                continue
            if _repair_section_1401_b_1_rule_formula(rule):
                repaired.append("formula:self_employment_income_tax")
            if _repair_section_1401_b_1_rule_proof_import(
                rule,
                imported_hash=imported_hash,
            ):
                repaired.append("proof:self_employment_income")

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _repair_section_1401_b_1_rule_formula(rule: dict[str, object]) -> bool:
    changed = False
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        repaired_formula = re.sub(
            r"\bself_employment_income_for_section_1401_a\b",
            "self_employment_income",
            formula,
        )
        if repaired_formula != formula:
            version["formula"] = repaired_formula
            changed = True
    return changed


def _repair_section_1401_b_1_rule_proof_import(
    rule: dict[str, object],
    *,
    imported_hash: str | None,
) -> bool:
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return False
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return False
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return False

    changed = False
    for atom in atoms:
        if not isinstance(atom, dict) or atom.get("kind") != "import":
            continue
        import_payload = atom.get("import")
        if not isinstance(import_payload, dict):
            continue
        if (
            import_payload.get("target")
            != _SECTION_1402_B_SELF_EMPLOYMENT_INCOME_FOR_1401_A_OUTPUT
        ):
            continue
        import_payload["target"] = _SECTION_1402_B_SELF_EMPLOYMENT_INCOME_OUTPUT
        import_payload["output"] = "self_employment_income"
        if imported_hash is not None:
            import_payload["hash"] = f"sha256:{imported_hash}"
        changed = True
    return changed


def _append_section_1401_b_1_uncapped_self_employment_income_test(
    *,
    test_file: Path,
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    case_name = "self_employment_income_tax_ignores_section_1401_a_cap"
    if any(
        isinstance(test_case, dict) and test_case.get("name") == case_name
        for test_case in test_payload
    ):
        return []
    test_payload.append(
        {
            "name": case_name,
            "period": {
                "period_kind": "tax_year",
                "start": "2024-01-01",
                "end": "2024-12-31",
            },
            "input": {
                "us:statutes/26/1402/a#input.self_employment_trade_or_business_gross_income": 2500,
                "us:statutes/26/1402/a#input.self_employment_trade_or_business_deductions": 200,
                "us:statutes/26/1402/a#input.partnership_section_702_a_8_income_or_loss": 0,
                "us:statutes/26/1402/b#input.contribution_and_benefit_base_under_section_230_of_social_security_act": 1200,
                "us:statutes/26/1402/b#input.wages_paid_to_individual_for_section_1401_a": 500,
                "us:statutes/26/1402/b#input.individual_is_nonresident_alien": False,
                "us:statutes/26/1402/b#input.social_security_agreement_under_section_233_applies_to_nonresident_alien": False,
                "us:statutes/26/1402/b#input.individual_is_noncitizen_territory_resident": False,
            },
            "output": {
                _SECTION_1401_B_1_OUTPUT: 61.59745,
            },
        }
    )
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return [f"test:{case_name}"]


def _try_repair_generated_policyengine_oracle_inputs_for_apply(
    result,
    *,
    output_root: Path,
) -> list[str]:
    """Add PE-native oracle inputs for generated section 1401 child tax tests."""
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []
    if relative_output.as_posix() not in {
        "statutes/26/1401/a.yaml",
        "statutes/26/1401/b/1.yaml",
    }:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _add_section_1401_policyengine_oracle_inputs(test_file=test_file)


def _add_section_1401_policyengine_oracle_inputs(*, test_file: Path) -> list[str]:
    if not test_file.exists():
        return []
    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    repaired_cases: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue

        policyengine_inputs = _section_1401_policyengine_oracle_inputs(test_case)
        if not policyengine_inputs:
            continue

        oracle_inputs = test_case.get("oracle_inputs")
        if oracle_inputs is None:
            oracle_inputs = {}
            test_case["oracle_inputs"] = oracle_inputs
        if not isinstance(oracle_inputs, dict):
            continue
        raw_policyengine_inputs = oracle_inputs.get("policyengine")
        if raw_policyengine_inputs is None:
            raw_policyengine_inputs = {}
            oracle_inputs["policyengine"] = raw_policyengine_inputs
        if not isinstance(raw_policyengine_inputs, dict):
            continue

        changed = False
        for name, value in policyengine_inputs.items():
            if name in raw_policyengine_inputs:
                continue
            raw_policyengine_inputs[name] = value
            changed = True
        if changed:
            repaired_cases.append(str(test_case.get("name") or "").strip())

    repaired_cases = [case for case in repaired_cases if case]
    if not repaired_cases:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired_cases


def _section_1401_policyengine_oracle_inputs(
    test_case: dict[str, object],
) -> dict[str, int | float] | None:
    inputs = test_case.get("input")
    outputs = test_case.get("output")
    if not isinstance(inputs, dict) or not isinstance(outputs, dict):
        return None

    output_refs = {str(key) for key in outputs}
    if (
        _SECTION_1401_A_OUTPUT not in output_refs
        and _SECTION_1401_B_1_OUTPUT not in output_refs
    ):
        return None

    net_self_employment_income = _section_1401_net_self_employment_income(inputs)
    if net_self_employment_income is None:
        return None

    policyengine_inputs: dict[str, int | float] = {
        "self_employment_income": _decimal_to_yaml_number(net_self_employment_income)
    }
    if _SECTION_1401_A_OUTPUT in output_refs:
        employment_income = _section_1401_policyengine_employment_income(
            inputs,
            test_case=test_case,
            net_self_employment_income=net_self_employment_income,
        )
        if employment_income is not None:
            policyengine_inputs["employment_income"] = _decimal_to_yaml_number(
                employment_income
            )
    return policyengine_inputs


def _section_1401_net_self_employment_income(
    inputs: dict[object, object],
) -> Decimal | None:
    gross = _rulespec_test_numeric_input(
        inputs, "self_employment_trade_or_business_gross_income"
    )
    if gross is None:
        return None
    deductions = _rulespec_test_numeric_input(
        inputs, "self_employment_trade_or_business_deductions"
    ) or Decimal("0")
    partnership = _rulespec_test_numeric_input(
        inputs, "partnership_section_702_a_8_income_or_loss"
    ) or Decimal("0")
    return gross - deductions + partnership


def _section_1401_policyengine_employment_income(
    inputs: dict[object, object],
    *,
    test_case: dict[str, object],
    net_self_employment_income: Decimal,
) -> Decimal | None:
    wages = _rulespec_test_numeric_input(
        inputs, "wages_paid_to_individual_for_section_1401_a"
    ) or Decimal("0")
    contribution_base = _rulespec_test_numeric_input(
        inputs, "contribution_and_benefit_base_under_section_230_of_social_security_act"
    )
    if contribution_base is None:
        return wages

    taxable_self_employment_income = (
        Decimal("0")
        if net_self_employment_income < _SECTION_1401_SELF_EMPLOYMENT_THRESHOLD
        else net_self_employment_income * _SECTION_1401_TAXABLE_SELF_EMPLOYMENT_RATE
    )
    remaining_base = max(Decimal("0"), contribution_base - wages)
    if taxable_self_employment_income <= remaining_base:
        return wages

    year = _rulespec_test_case_year(test_case)
    real_base = _policyengine_us_oasdi_base_for_year(year) if year is not None else None
    if real_base is None and year is not None:
        real_base = _SECTION_1401_OASDI_BASE_BY_YEAR.get(year)
    if real_base is None:
        return None
    return max(Decimal("0"), real_base - remaining_base)


@lru_cache(maxsize=16)
def _policyengine_us_oasdi_base_for_year(year: int) -> Decimal | None:
    try:
        from policyengine_us import CountryTaxBenefitSystem

        params = CountryTaxBenefitSystem().parameters(str(year))
        return Decimal(str(params.gov.irs.payroll.social_security.cap))
    except Exception:
        return None


def _rulespec_test_numeric_input(
    inputs: dict[object, object],
    name: str,
) -> Decimal | None:
    value = _rulespec_test_case_input_value(inputs, name)
    if value is None or isinstance(value, bool):
        return None
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError):
        return None


def _rulespec_test_case_input_value(
    inputs: dict[object, object],
    name: str,
) -> object | None:
    if name in inputs:
        return inputs[name]
    for key, value in inputs.items():
        key_text = str(key)
        if (
            key_text.endswith(f"#input.{name}")
            or key_text.endswith(f"#{name}")
            or key_text.endswith(f".{name}")
        ):
            return value
    return None


def _rulespec_test_case_year(test_case: dict[str, object]) -> int | None:
    period = test_case.get("period") or test_case.get("date")
    raw_year: object | None = None
    if isinstance(period, dict):
        raw_year = period.get("start") or period.get("date") or period.get("year")
    elif period is not None:
        raw_year = period
    if raw_year is None:
        return None
    match = re.match(r"\s*(\d{4})", str(raw_year))
    return int(match.group(1)) if match else None


def _decimal_to_yaml_number(value: Decimal) -> int | float:
    if value == value.to_integral_value():
        return int(value)
    return float(value)


def _try_repair_generated_test_input_assignments_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Fill deterministic explicit defaults for generated tests missing facts."""
    if _indexed_parameter_key_zero_issue_cases(issues):
        try:
            relative_output = _relative_generated_output_path(
                result, output_root=output_root
            )
        except RuntimeError:
            return []
        rules_file = Path(str(getattr(result, "output_file", "") or ""))
        test_file = _rulespec_test_path(rules_file)
        return _fill_current_index_inputs_from_imported_tests(
            rules_file=rules_file,
            test_file=test_file,
            policy_repo_path=policy_repo_path,
            relative_output=relative_output,
            case_names=set(_indexed_parameter_key_zero_issue_cases(issues)),
        )

    if not _only_pending_test_input_assignment_issues(issues):
        return []

    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _fill_missing_test_input_assignments(
        rules_file=rules_file,
        test_file=test_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
        issues=issues,
    )


def _only_pending_test_input_assignment_issues(issues: list[str]) -> bool:
    return bool(issues) and all(
        "Test input assignment missing:" in str(issue) for issue in issues
    )


def _indexed_parameter_key_zero_issue_cases(issues: list[str]) -> list[str]:
    """Return test cases that failed because an indexed import used default key 0."""
    case_names: list[str] = []
    for issue in issues:
        match = re.search(
            r"Test case `(?P<case>[^`]+)` execution failed:\s*"
            r"parameter `[^`]+` has no value for key `0`",
            str(issue),
        )
        if not match:
            continue
        case_name = match.group("case").strip()
        if case_name and case_name not in case_names:
            case_names.append(case_name)
    return case_names


def _fill_current_index_inputs_from_imported_tests(
    *,
    rules_file: Path,
    test_file: Path,
    policy_repo_path: Path,
    relative_output: Path,
    case_names: set[str],
) -> list[str]:
    """Mirror imported indexed inputs onto the current module for generated tests."""
    if not rules_file.exists() or not test_file.exists():
        return []
    try:
        rules_payload = yaml.safe_load(rules_file.read_text()) or {}
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict) or not isinstance(test_payload, list):
        return []

    imported_inputs = _imported_input_refs_by_name(
        rules_file,
        repo_path=policy_repo_path,
    )
    if not imported_inputs:
        return []

    anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    repaired_cases: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        case_name = str(test_case.get("name") or "").strip()
        if case_names and case_name not in case_names:
            continue
        inputs = test_case.get("input")
        if not isinstance(inputs, dict):
            continue
        changed = False
        for input_name, input_refs in sorted(imported_inputs.items()):
            local_key = f"{anchor}#input.{input_name}"
            if local_key in inputs:
                continue
            value = None
            for input_ref in input_refs:
                if input_ref in inputs:
                    value = inputs[input_ref]
                    break
            if value is None:
                value = _lookup_test_input_by_suffix(inputs, input_name)
            if value is None:
                value = _default_generated_test_input_value(
                    input_name,
                    rules_payload=rules_payload,
                    prefer_positive_counts=True,
                )
            inputs[local_key] = value
            changed = True
        if changed:
            repaired_cases.append(case_name)

    if not repaired_cases:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired_cases


def _lookup_test_input_by_suffix(
    inputs: dict[object, object],
    input_name: str,
) -> object | None:
    suffix = f"#input.{input_name}"
    for key, value in inputs.items():
        if str(key).endswith(suffix):
            return value
    return None


def _fill_missing_test_input_assignments(
    *,
    rules_file: Path,
    test_file: Path,
    policy_repo_path: Path,
    relative_output: Path,
    issues: list[str],
) -> list[str]:
    if not rules_file.exists() or not test_file.exists():
        return []

    try:
        rules_payload = yaml.safe_load(rules_file.read_text()) or {}
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict) or not isinstance(test_payload, list):
        return []

    imported_outputs = _imported_output_names_from_payload(rules_payload)
    repairs_by_case: dict[str, set[str]] = {}
    for issue in issues:
        parsed = _parse_test_input_assignment_issue(str(issue))
        if parsed is None:
            return []
        case_name, missing_inputs = parsed
        repairs_by_case.setdefault(case_name, set()).update(
            missing_inputs - imported_outputs
        )
    if not repairs_by_case:
        return []

    anchor = _relative_output_to_anchor(
        relative_output, policy_repo_path=policy_repo_path
    )
    repaired_cases: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        case_name = str(test_case.get("name") or "").strip()
        missing_inputs = repairs_by_case.get(case_name)
        if not missing_inputs:
            continue
        inputs = test_case.get("input")
        if not isinstance(inputs, dict):
            inputs = {}
            test_case["input"] = inputs
        changed = False
        for input_name in sorted(missing_inputs):
            key = f"{anchor}#input.{input_name}"
            if key in inputs:
                continue
            inputs[key] = _default_generated_test_input_value(
                input_name, rules_payload=rules_payload
            )
            changed = True
        if changed:
            repaired_cases.append(case_name)

    if not repaired_cases:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired_cases


def _try_repair_generated_imported_output_test_mismatches_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Update generated expected outputs when imported inputs drive actual values."""
    if not issues:
        return []

    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    repaired_positive_imports = _repair_positive_imported_judgment_composition_tests(
        rules_file=rules_file,
        test_file=test_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
        issues=issues,
    )
    if repaired_positive_imports:
        return repaired_positive_imports
    return _repair_imported_output_test_mismatches(
        rules_file=rules_file,
        test_file=test_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
        issues=issues,
    )


