def cmd_sync_transcripts(args):
    """Sync local transcripts to Supabase."""
    from .supabase_sync import sync_transcripts_to_supabase

    print(
        f"Syncing transcripts{f' for session {args.session}' if args.session else ''}..."
    )

    try:
        stats = sync_transcripts_to_supabase(session_id=args.session)
        print(
            f"Done! {stats['synced']} synced, {stats['failed']} failed of {stats['total']} total"
        )
    except ValueError as e:
        print(f"Error: {e}")
        print(
            "Set AXIOM_ENCODE_SUPABASE_URL and "
            "AXIOM_ENCODE_SUPABASE_SECRET_KEY environment variables"
        )
        sys.exit(1)


def cmd_transcript_stats(args):
    """Show local transcript database stats."""
    from .supabase_sync import get_local_transcript_stats

    stats = get_local_transcript_stats()

    if not stats.get("exists"):
        print("No local transcript database found")
        print("Transcripts are created automatically when subagents complete")
        return

    print("=== Local Transcript Stats ===")
    print(f"Total transcripts: {stats['total']}")
    print(f"Unsynced: {stats['unsynced']}")
    print(f"Synced: {stats['synced']}")
    print()

    if stats.get("by_type"):
        print("By agent type:")
        for agent_type, count in sorted(stats["by_type"].items(), key=lambda x: -x[1]):
            print(f"  {agent_type}: {count}")


def cmd_sync_agent_sessions(args):
    """Sync agent sessions to Supabase."""
    from .supabase_sync import sync_agent_sessions_to_supabase

    print(f"Syncing agent sessions{f' for {args.session}' if args.session else ''}...")

    try:
        stats = sync_agent_sessions_to_supabase(
            session_id=args.session,
            include_all=getattr(args, "all", False) is True,
        )
        print(
            f"Done! {stats['synced']} synced, {stats['failed']} failed of {stats['total']} total"
        )
    except ValueError as e:
        print(f"Error: {e}")
        print(
            "Set AXIOM_ENCODE_SUPABASE_URL and "
            "AXIOM_ENCODE_SUPABASE_SECRET_KEY environment variables"
        )
        sys.exit(1)


def cmd_sync_applied_runs(args):
    """Backfill Supabase encoding_runs from applied-rulespec manifests."""
    from .supabase_sync import sync_applied_manifest_runs

    missing = [repo for repo in args.repos if not Path(repo).is_dir()]
    if missing:
        for repo in missing:
            print(f"Repo checkout not found: {repo}")
        sys.exit(1)

    try:
        stats = sync_applied_manifest_runs(
            [Path(repo) for repo in args.repos],
            dry_run=getattr(args, "dry_run", False) is True,
        )
    except ValueError as e:
        print(f"Error: {e}")
        print(
            "Set AXIOM_ENCODE_SUPABASE_URL and "
            "AXIOM_ENCODE_SUPABASE_SECRET_KEY environment variables"
        )
        sys.exit(1)

    print(
        f"manifests={stats['total']} synced={stats['synced']} "
        f"failed={stats['failed']} skipped={stats['skipped']} "
        f"preserved={stats.get('preserved', 0)}"
    )
    if stats["failed"]:
        sys.exit(1)


def cmd_sign_applied_files(args):
    """Write signed apply manifests attesting existing RuleSpec files.

    For encodings that were committed directly (outside the
    ``encode --apply`` flow), a signing-key holder can attest the exact
    file contents after review. Writes one manifest per encoding (main
    file plus its companion test) covering the files changed against
    ``--base-ref``, mirroring the deterministic repair commands' use of
    ``_write_applied_encoding_manifest`` — the guard verifies the
    signature and file hashes either way.
    """
    repo_path = Path(args.repo).resolve()
    if not (repo_path / ".git").exists():
        print(f"Not a git checkout: {repo_path}")
        sys.exit(1)

    try:
        changed = _git_changed_files(
            repo_path, base_ref=args.base_ref, head_ref=args.head_ref
        )
    except RuntimeError as exc:
        print(str(exc))
        sys.exit(1)

    roots = tuple(sorted(RULESPEC_SOURCE_ROOTS))
    protected = [
        path
        for path in changed
        if _is_protected_rulespec_yaml_path(Path(path), roots=roots)
        and (repo_path / path).exists()
    ]
    if not protected:
        print("No protected RuleSpec changes to attest.")
        return

    groups: dict[str, list[str]] = {}
    for path in protected:
        main_rel = (
            f"{path[: -len('.test.yaml')]}.yaml"
            if path.endswith(".test.yaml")
            else path
        )
        groups.setdefault(main_rel, []).append(path)

    missing_main = sorted(
        main_rel for main_rel in groups if not (repo_path / main_rel).exists()
    )
    if missing_main:
        for main_rel in missing_main:
            print(
                f"Cannot attest {main_rel}: companion test changed but the main RuleSpec file is missing"
            )
        sys.exit(1)

    if getattr(args, "dry_run", False) is True:
        for main_rel in sorted(groups):
            print(f"would sign {main_rel} covering {sorted(groups[main_rel])}")
        print(f"{len(groups)} manifest(s) for {len(protected)} file(s)")
        return

    signing_key = _require_applied_encoding_manifest_signing_key()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()

    manifest_paths: list[Path] = []
    with tempfile.TemporaryDirectory() as tmpdir:
        output_root = Path(tmpdir)
        for main_rel in sorted(groups):
            relative_output = Path(main_rel)
            generated_output = output_root / "sign-applied-files" / relative_output
            generated_output.parent.mkdir(parents=True, exist_ok=True)
            generated_output.write_text((repo_path / relative_output).read_text())
            result = argparse.Namespace(
                output_file=str(generated_output),
                runner="manual-attestation",
                backend="manual",
                model="",
                tool="axiom-encode sign-applied-files",
                citation=_rulespec_anchor_base_for_output(repo_path, relative_output),
                generation_prompt_sha256=None,
                trace_file=None,
                context_manifest_file=None,
            )
            manifest_paths.append(
                _write_applied_encoding_manifest(
                    result,
                    output_root=output_root,
                    policy_repo_path=repo_path,
                    relative_output=relative_output,
                    applied_files=[
                        repo_path / path for path in sorted(groups[main_rel])
                    ],
                    run_id=None,
                    signing_key=signing_key,
                    axiom_encode_git=axiom_encode_git,
                )
            )

    for manifest_path in manifest_paths:
        print(f"signed {manifest_path.relative_to(repo_path).as_posix()}")

    issues = guard_generated_change_issues(
        repo_path,
        base_ref=args.base_ref,
        head_ref=args.head_ref,
        changed_files=sorted(
            set(changed)
            | {path.relative_to(repo_path).as_posix() for path in manifest_paths}
        ),
    )
    if issues:
        print("Guard would still fail after signing:")
        for issue in issues:
            print(f"- {issue}")
        sys.exit(1)
    print(
        f"{len(manifest_paths)} manifest(s) attest {len(protected)} file(s); "
        "guard passes with the new manifests included"
    )


if __name__ == "__main__":  # pragma: no cover
    main()
